INSERT INTO grcmt_vpl VALUES ("MT26_74","070_26_74","MAT","26","74","74","τοτε ηρξατο καταθεματιζειν και ομνυειν οτι ουκ οιδα τον ανθρωπον και ευθεωσ αλεκτωρ εφωνησεν ");
