INSERT INTO grcmt_vpl VALUES ("MK15_31","071_15_31","MRK","15","31","31","ομοιωσ και οι αρχιερεισ εμπαιζοντεσ προσ αλληλουσ μετα των γραμματεων ελεγον αλλουσ εσωσεν εαυτον ου δυναται σωσαι ");
