INSERT INTO grcmt_vpl VALUES ("LK18_30","072_18_30","LUK","18","30","30","οσ ου μη απολαβη πολλαπλασιονα εν τω καιρω τουτω και εν τω αιωνι τω ερχομενω ζωην αιωνιον ");
