INSERT INTO grcmt_vpl VALUES ("LK19_9","072_19_9","LUK","19","9","9","ειπεν δε προσ αυτον ο ιησουσ οτι σημερον σωτηρια τω οικω τουτω εγενετο καθοτι και αυτοσ υιοσ αβρααμ εστιν ");
