INSERT INTO grcmt_vpl VALUES ("LK19_46","072_19_46","LUK","19","46","46","λεγων αυτοισ γεγραπται ο οικοσ μου οικοσ προσευχησ εστιν υμεισ δε αυτον εποιησατε σπηλαιον ληστων ");
