INSERT INTO grcmt_vpl VALUES ("LK20_2","072_20_2","LUK","20","2","2","και ειπον προσ αυτον λεγοντεσ ειπε ημιν εν ποια εξουσια ταυτα ποιεισ η τισ εστιν ο δουσ σοι την εξουσιαν ταυτην ");
