INSERT INTO grcmt_vpl VALUES ("LK20_13","072_20_13","LUK","20","13","13","ειπεν δε ο κυριοσ του αμπελωνοσ τι ποιησω πεμψω τον υιον μου τον αγαπητον ισωσ τουτον ιδοντεσ εντραπησονται ");
