INSERT INTO grcmt_vpl VALUES ("JN8_19","073_8_19","JHN","8","19","19","ελεγον ουν αυτω που εστιν ο πατηρ σου απεκριθη ιησουσ ουτε εμε οιδατε ουτε τον πατερα μου ει εμε ηδειτε και τον πατερα μου ηδειτε αν ");
