INSERT INTO grcmt_vpl VALUES ("AC27_24","074_27_24","ACT","27","24","24","λεγων μη φοβου παυλε καισαρι σε δει παραστηναι και ιδου κεχαρισται σοι ο θεοσ παντασ τουσ πλεοντασ μετα σου ");
