INSERT INTO grcmt_vpl VALUES ("RM6_17","075_6_17","ROM","6","17","17","χαρισ δε τω θεω οτι ητε δουλοι τησ αμαρτιασ υπηκουσατε δε εκ καρδιασ εισ ον παρεδοθητε τυπον διδαχησ ");
