INSERT INTO grcmt_vpl VALUES ("RM7_1","075_7_1","ROM","7","1","1","η αγνοειτε αδελφοι γινωσκουσιν γαρ νομον λαλω οτι ο νομοσ κυριευει του ανθρωπου εφ οσον χρονον ζη ");
