INSERT INTO grcmt_vpl VALUES ("RM8_30","075_8_30","ROM","8","30","30","ουσ δε προωρισεν τουτουσ και εκαλεσεν και ουσ εκαλεσεν τουτουσ και εδικαιωσεν ουσ δε εδικαιωσεν τουτουσ και εδοξασεν ");
