INSERT INTO grcmt_vpl VALUES ("C11_18","076_1_18","1CO","1","18","18","ο λογοσ γαρ ο του σταυρου τοισ μεν απολλυμενοισ μωρια εστιν τοισ δε σωζομενοισ ημιν δυναμισ θεου εστιν ");
