INSERT INTO grcmt_vpl VALUES ("C12_13","076_2_13","1CO","2","13","13","α και λαλουμεν ουκ εν διδακτοισ ανθρωπινησ σοφιασ λογοισ αλλ εν διδακτοισ πνευματοσ αγιου πνευματικοισ 4152 A-DPN πνευματικα συγκρινοντεσ ");
