INSERT INTO grcmt_vpl VALUES ("C111_2","076_11_2","1CO","11","2","2","επαινω δε υμασ αδελφοι οτι παντα μου μεμνησθε και καθωσ παρεδωκα υμιν τασ παραδοσεισ κατεχετε ");
INSERT INTO grcmt_vpl VALUES ("C111_3","076_11_3","1CO","11","3","3","θελω δε υμασ ειδεναι οτι παντοσ ανδροσ η κεφαλη ο χριστοσ εστιν κεφαλη δε γυναικοσ ο ανηρ κεφαλη δε χριστου ο θεοσ ");
INSERT INTO grcmt_vpl VALUES ("C111_4","076_11_4","1CO","11","4","4","πασ ανηρ προσευχομενοσ η προφητευων κατα κεφαλησ εχων καταισχυνει την κεφαλην αυτου ");
INSERT INTO grcmt_vpl VALUES ("C111_5","076_11_5","1CO","11","5","5","πασα δε γυνη προσευχομενη η προφητευουσα ακατακαλυπτω τη κεφαλη καταισχυνει την κεφαλην εαυτησ εν γαρ εστιν και το αυτο τη εξυρημενη ");
INSERT INTO grcmt_vpl VALUES ("C111_6","076_11_6","1CO","11","6","6","ει γαρ ου κατακαλυπτεται γυνη και κειρασθω ει δε αισχρον γυναικι το κειρασθαι η ξυρασθαι κατακαλυπτεσθω ");
INSERT INTO grcmt_vpl VALUES ("C111_7","076_11_7","1CO","11","7","7","ανηρ μεν γαρ ουκ οφειλει κατακαλυπτεσθαι την κεφαλην εικων και δοξα θεου υπαρχων γυνη δε δοξα ανδροσ εστιν ");
INSERT INTO grcmt_vpl VALUES ("C111_8","076_11_8","1CO","11","8","8","ου γαρ εστιν ανηρ εκ γυναικοσ αλλα γυνη εξ ανδροσ ");
INSERT INTO grcmt_vpl VALUES ("C111_9","076_11_9","1CO","11","9","9","και γαρ ουκ εκτισθη ανηρ δια την γυναικα αλλα γυνη δια τον ανδρα ");
INSERT INTO grcmt_vpl VALUES ("C111_10","076_11_10","1CO","11","10","10","δια τουτο οφειλει η γυνη εξουσιαν εχειν επι τησ κεφαλησ δια τουσ αγγελουσ ");
INSERT INTO grcmt_vpl VALUES ("C111_11","076_11_11","1CO","11","11","11","πλην ουτε ανηρ χωρισ γυναικοσ ουτε γυνη χωρισ ανδροσ εν κυριω ");
INSERT INTO grcmt_vpl VALUES ("C111_12","076_11_12","1CO","11","12","12","ωσπερ γαρ η γυνη εκ του ανδροσ ουτωσ και ο ανηρ δια τησ γυναικοσ τα δε παντα εκ του θεου ");
INSERT INTO grcmt_vpl VALUES ("C111_13","076_11_13","1CO","11","13","13","εν υμιν αυτοισ κρινατε πρεπον εστιν γυναικα ακατακαλυπτον τω θεω προσευχεσθαι ");
INSERT INTO grcmt_vpl VALUES ("C111_14","076_11_14","1CO","11","14","14","η ουδε αυτη η φυσισ διδασκει υμασ οτι ανηρ μεν εαν κομα ατιμια αυτω εστιν ");
INSERT INTO grcmt_vpl VALUES ("C111_15","076_11_15","1CO","11","15","15","γυνη δε εαν κομα δοξα αυτη εστιν οτι η κομη αντι περιβολαιου δεδοται ");
INSERT INTO grcmt_vpl VALUES ("C111_16","076_11_16","1CO","11","16","16","ει δε τισ δοκει φιλονεικοσ ειναι ημεισ τοιαυτην συνηθειαν ουκ εχομεν ουδε αι εκκλησιαι του θεου ");
INSERT INTO grcmt_vpl VALUES ("C111_17","076_11_17","1CO","11","17","17","τουτο δε παραγγελλων ουκ επαινω οτι ουκ εισ το κρειττον αλλ εισ το ηττον συνερχεσθε ");
INSERT INTO grcmt_vpl VALUES ("C111_18","076_11_18","1CO","11","18","18","πρωτον μεν γαρ συνερχομενων υμων εν εκκλησια ακουω σχισματα εν υμιν υπαρχειν και μεροσ τι πιστευω ");
INSERT INTO grcmt_vpl VALUES ("C111_19","076_11_19","1CO","11","19","19","δει γαρ και αιρεσεισ εν υμιν ειναι ινα οι δοκιμοι φανεροι γενωνται εν υμιν ");
INSERT INTO grcmt_vpl VALUES ("C111_20","076_11_20","1CO","11","20","20","συνερχομενων ουν υμων επι το αυτο ουκ εστιν κυριακον δειπνον φαγειν ");
INSERT INTO grcmt_vpl VALUES ("C111_21","076_11_21","1CO","11","21","21","εκαστοσ γαρ το ιδιον δειπνον προλαμβανει εν τω φαγειν και οσ μεν πεινα οσ δε μεθυει ");
INSERT INTO grcmt_vpl VALUES ("C111_22","076_11_22","1CO","11","22","22","μη γαρ οικιασ ουκ εχετε εισ το εσθιειν και πινειν η τησ εκκλησιασ του θεου καταφρονειτε και καταισχυνετε τουσ μη εχοντασ τι υμιν ειπω επαινεσω υμασ εν τουτω ουκ επαινω ");
INSERT INTO grcmt_vpl VALUES ("C111_23","076_11_23","1CO","11","23","23","εγω γαρ παρελαβον απο του κυριου ο και παρεδωκα υμιν οτι ο κυριοσ ιησουσ εν τη νυκτι η παρεδιδοτο ελαβεν αρτον ");
INSERT INTO grcmt_vpl VALUES ("C111_24","076_11_24","1CO","11","24","24","και ευχαριστησασ εκλασεν και ειπεν λαβετε φαγετε τουτο μου εστιν το σωμα το υπερ υμων κλωμενον τουτο ποιειτε εισ την εμην αναμνησιν ");
INSERT INTO grcmt_vpl VALUES ("C111_25","076_11_25","1CO","11","25","25","ωσαυτωσ και το ποτηριον μετα το δειπνησαι λεγων τουτο το ποτηριον η καινη διαθηκη εστιν εν τω εμω αιματι τουτο ποιειτε οσακισ αν πινητε εισ την εμην αναμνησιν ");
INSERT INTO grcmt_vpl VALUES ("C111_26","076_11_26","1CO","11","26","26","οσακισ γαρ αν εσθιητε τον αρτον τουτον και το ποτηριον τουτο πινητε τον θανατον του κυριου καταγγελλετε αχρι ου αν ελθη ");
INSERT INTO grcmt_vpl VALUES ("C111_27","076_11_27","1CO","11","27","27","ωστε οσ αν εσθιη τον αρτον τουτον η πινη το ποτηριον του κυριου αναξιωσ του κυριου ενοχοσ εσται του σωματοσ και του αιματοσ του κυριου ");
INSERT INTO grcmt_vpl VALUES ("C111_28","076_11_28","1CO","11","28","28","δοκιμαζετω δε ανθρωποσ εαυτον και ουτωσ εκ του αρτου εσθιετω και εκ του ποτηριου πινετω ");
INSERT INTO grcmt_vpl VALUES ("C111_29","076_11_29","1CO","11","29","29","ο γαρ εσθιων και πινων αναξιωσ κριμα εαυτω εσθιει και πινει μη διακρινων το σωμα του κυριου ");
INSERT INTO grcmt_vpl VALUES ("C111_30","076_11_30","1CO","11","30","30","δια τουτο εν υμιν πολλοι ασθενεισ και αρρωστοι και κοιμωνται ικανοι ");
INSERT INTO grcmt_vpl VALUES ("C111_31","076_11_31","1CO","11","31","31","ει γαρ εαυτουσ διεκρινομεν ουκ αν εκρινομεθα ");
INSERT INTO grcmt_vpl VALUES ("C111_32","076_11_32","1CO","11","32","32","κρινομενοι δε υπο κυριου παιδευομεθα ινα μη συν τω κοσμω κατακριθωμεν ");
INSERT INTO grcmt_vpl VALUES ("C111_33","076_11_33","1CO","11","33","33","ωστε αδελφοι μου συνερχομενοι εισ το φαγειν αλληλουσ εκδεχεσθε ");
INSERT INTO grcmt_vpl VALUES ("C111_34","076_11_34","1CO","11","34","34","ει δε τισ πεινα εν οικω εσθιετω ινα μη εισ κριμα συνερχησθε τα δε λοιπα ωσ αν ελθω διαταξομαι ");
INSERT INTO grcmt_vpl VALUES ("C112_1","076_12_1","1CO","12","1","1","περι δε των πνευματικων αδελφοι ου θελω υμασ αγνοειν ");
INSERT INTO grcmt_vpl VALUES ("C112_2","076_12_2","1CO","12","2","2","οιδατε οτι οτε εθνη ητε προσ τα ειδωλα τα αφωνα ωσ αν ηγεσθε απαγομενοι ");
INSERT INTO grcmt_vpl VALUES ("C112_3","076_12_3","1CO","12","3","3","διο γνωριζω υμιν οτι ουδεισ εν πνευματι θεου λαλων λεγει αναθεμα ιησουν και ουδεισ δυναται ειπειν κυριον ιησουν ει μη εν πνευματι αγιω ");
INSERT INTO grcmt_vpl VALUES ("C112_4","076_12_4","1CO","12","4","4","διαιρεσεισ δε χαρισματων εισιν το δε αυτο πνευμα ");
INSERT INTO grcmt_vpl VALUES ("C112_5","076_12_5","1CO","12","5","5","και διαιρεσεισ διακονιων εισιν και ο αυτοσ κυριοσ ");
INSERT INTO grcmt_vpl VALUES ("C112_6","076_12_6","1CO","12","6","6","και διαιρεσεισ ενεργηματων εισιν ο δε αυτοσ εστιν θεοσ ο ενεργων τα παντα εν πασιν ");
INSERT INTO grcmt_vpl VALUES ("C112_7","076_12_7","1CO","12","7","7","εκαστω δε διδοται η φανερωσισ του πνευματοσ προσ το συμφερον ");
INSERT INTO grcmt_vpl VALUES ("C112_8","076_12_8","1CO","12","8","8","ω μεν γαρ δια του πνευματοσ διδοται λογοσ σοφιασ αλλω δε λογοσ γνωσεωσ κατα το αυτο πνευμα ");
INSERT INTO grcmt_vpl VALUES ("C112_9","076_12_9","1CO","12","9","9","ετερω δε πιστισ εν τω αυτω πνευματι αλλω δε χαρισματα ιαματων εν τω αυτω πνευματι ");
INSERT INTO grcmt_vpl VALUES ("C112_10","076_12_10","1CO","12","10","10","αλλω δε ενεργηματα δυναμεων αλλω δε προφητεια αλλω δε διακρισεισ πνευματων ετερω δε γενη γλωσσων αλλω δε ερμηνεια γλωσσων ");
INSERT INTO grcmt_vpl VALUES ("C112_11","076_12_11","1CO","12","11","11","παντα δε ταυτα ενεργει το εν και το αυτο πνευμα διαιρουν ιδια εκαστω καθωσ βουλεται ");
INSERT INTO grcmt_vpl VALUES ("C112_12","076_12_12","1CO","12","12","12","καθαπερ γαρ το σωμα εν εστιν και μελη εχει πολλα παντα δε τα μελη του σωματοσ του ενοσ πολλα οντα εν εστιν σωμα ουτωσ και ο χριστοσ ");
INSERT INTO grcmt_vpl VALUES ("C112_13","076_12_13","1CO","12","13","13","και γαρ εν ενι πνευματι ημεισ παντεσ εισ εν σωμα εβαπτισθημεν ειτε ιουδαιοι ειτε ελληνεσ ειτε δουλοι ειτε ελευθεροι και παντεσ εισ εν πνευμα εποτισθημεν ");
INSERT INTO grcmt_vpl VALUES ("C112_14","076_12_14","1CO","12","14","14","και γαρ το σωμα ουκ εστιν εν μελοσ αλλα πολλα ");
INSERT INTO grcmt_vpl VALUES ("C112_15","076_12_15","1CO","12","15","15","εαν ειπη ο πουσ οτι ουκ ειμι χειρ ουκ ειμι εκ του σωματοσ ου παρα τουτο ουκ εστιν εκ του σωματοσ ");
INSERT INTO grcmt_vpl VALUES ("C112_16","076_12_16","1CO","12","16","16","και εαν ειπη το ουσ οτι ουκ ειμι οφθαλμοσ ουκ ειμι εκ του σωματοσ ου παρα τουτο ουκ εστιν εκ του σωματοσ ");
INSERT INTO grcmt_vpl VALUES ("C112_17","076_12_17","1CO","12","17","17","ει ολον το σωμα οφθαλμοσ που η ακοη ει ολον ακοη που η οσφρησισ ");
INSERT INTO grcmt_vpl VALUES ("C112_18","076_12_18","1CO","12","18","18","νυνι δε ο θεοσ εθετο τα μελη εν εκαστον αυτων εν τω σωματι καθωσ ηθελησεν ");
INSERT INTO grcmt_vpl VALUES ("C112_19","076_12_19","1CO","12","19","19","ει δε ην τα παντα εν μελοσ που το σωμα ");
INSERT INTO grcmt_vpl VALUES ("C112_20","076_12_20","1CO","12","20","20","νυν δε πολλα μεν μελη εν δε σωμα ");
INSERT INTO grcmt_vpl VALUES ("C112_21","076_12_21","1CO","12","21","21","ου δυναται δε ο οφθαλμοσ ειπειν τη χειρι χρειαν σου ουκ εχω η παλιν η κεφαλη τοισ ποσιν χρειαν υμων ουκ εχω ");
INSERT INTO grcmt_vpl VALUES ("C112_22","076_12_22","1CO","12","22","22","αλλα πολλω μαλλον τα δοκουντα μελη του σωματοσ ασθενεστερα υπαρχειν αναγκαια εστιν ");
INSERT INTO grcmt_vpl VALUES ("C112_23","076_12_23","1CO","12","23","23","και α δοκουμεν ατιμοτερα ειναι του σωματοσ τουτοισ τιμην περισσοτεραν περιτιθεμεν και τα ασχημονα ημων ευσχημοσυνην περισσοτεραν εχει ");
INSERT INTO grcmt_vpl VALUES ("C112_24","076_12_24","1CO","12","24","24","τα δε ευσχημονα ημων ου χρειαν εχει αλλ ο θεοσ συνεκερασεν το σωμα τω υστερουντι περισσοτεραν δουσ τιμην ");
INSERT INTO grcmt_vpl VALUES ("C112_25","076_12_25","1CO","12","25","25","ινα μη η σχισματα εν τω σωματι αλλα το αυτο υπερ αλληλων μεριμνωσιν τα μελη ");
INSERT INTO grcmt_vpl VALUES ("C112_26","076_12_26","1CO","12","26","26","και ειτε πασχει εν μελοσ συμπασχει παντα τα μελη ειτε δοξαζεται εν μελοσ συγχαιρει παντα τα μελη ");
INSERT INTO grcmt_vpl VALUES ("C112_27","076_12_27","1CO","12","27","27","υμεισ δε εστε σωμα χριστου και μελη εκ μερουσ ");
INSERT INTO grcmt_vpl VALUES ("C112_28","076_12_28","1CO","12","28","28","και ουσ μεν εθετο ο θεοσ εν τη εκκλησια πρωτον αποστολουσ δευτερον προφητασ τριτον διδασκαλουσ επειτα δυναμεισ ειτα χαρισματα ιαματων αντιληψεισ κυβερνησεισ γενη γλωσσων ");
INSERT INTO grcmt_vpl VALUES ("C112_29","076_12_29","1CO","12","29","29","μη παντεσ αποστολοι μη παντεσ προφηται μη παντεσ διδασκαλοι μη παντεσ δυναμεισ ");
INSERT INTO grcmt_vpl VALUES ("C112_30","076_12_30","1CO","12","30","30","μη παντεσ χαρισματα εχουσιν ιαματων μη παντεσ γλωσσαισ λαλουσιν μη παντεσ διερμηνευουσιν ");
INSERT INTO grcmt_vpl VALUES ("C112_31","076_12_31","1CO","12","31","31","ζηλουτε δε τα χαρισματα τα κρειττονα και ετι καθ υπερβολην οδον υμιν δεικνυμι ");
INSERT INTO grcmt_vpl VALUES ("C113_1","076_13_1","1CO","13","1","1","εαν ταισ γλωσσαισ των ανθρωπων λαλω και των αγγελων αγαπην δε μη εχω γεγονα χαλκοσ ηχων η κυμβαλον αλαλαζον ");
INSERT INTO grcmt_vpl VALUES ("C113_2","076_13_2","1CO","13","2","2","και εαν εχω προφητειαν και ειδω τα μυστηρια παντα και πασαν την γνωσιν και εαν εχω πασαν την πιστιν ωστε ορη μεθιστανειν αγαπην δε μη εχω ουθεν ειμι ");
INSERT INTO grcmt_vpl VALUES ("C113_3","076_13_3","1CO","13","3","3","και εαν ψωμισω παντα τα υπαρχοντα μου και εαν παραδω το σωμα μου ινα καυθησωμαι αγαπην δε μη εχω ουδεν ωφελουμαι ");
INSERT INTO grcmt_vpl VALUES ("C113_4","076_13_4","1CO","13","4","4","η αγαπη μακροθυμει χρηστευεται η αγαπη ου ζηλοι η αγαπη ου περπερευεται ου φυσιουται ");
INSERT INTO grcmt_vpl VALUES ("C113_5","076_13_5","1CO","13","5","5","ουκ ασχημονει ου ζητει τα εαυτησ ου παροξυνεται ου λογιζεται το κακον ");
INSERT INTO grcmt_vpl VALUES ("C113_6","076_13_6","1CO","13","6","6","ου χαιρει επι τη αδικια συγχαιρει δε τη αληθεια ");
INSERT INTO grcmt_vpl VALUES ("C113_7","076_13_7","1CO","13","7","7","παντα στεγει παντα πιστευει παντα ελπιζει παντα υπομενει ");
INSERT INTO grcmt_vpl VALUES ("C113_8","076_13_8","1CO","13","8","8","η αγαπη ουδεποτε εκπιπτει ειτε δε προφητειαι καταργηθησονται ειτε γλωσσαι παυσονται ειτε γνωσισ καταργηθησεται ");
INSERT INTO grcmt_vpl VALUES ("C113_9","076_13_9","1CO","13","9","9","εκ μερουσ δε γινωσκομεν και εκ μερουσ προφητευομεν ");
INSERT INTO grcmt_vpl VALUES ("C113_10","076_13_10","1CO","13","10","10","οταν δε ελθη το τελειον τοτε το εκ μερουσ καταργηθησεται ");
INSERT INTO grcmt_vpl VALUES ("C113_11","076_13_11","1CO","13","11","11","οτε ημην νηπιοσ ωσ νηπιοσ ελαλουν ωσ νηπιοσ εφρονουν ωσ νηπιοσ ελογιζομην οτε δε γεγονα ανηρ κατηργηκα τα του νηπιου ");
INSERT INTO grcmt_vpl VALUES ("C113_12","076_13_12","1CO","13","12","12","βλεπομεν γαρ αρτι δι εσοπτρου εν αινιγματι τοτε δε προσωπον προσ προσωπον αρτι γινωσκω εκ μερουσ τοτε δε επιγνωσομαι καθωσ και επεγνωσθην ");
INSERT INTO grcmt_vpl VALUES ("C113_13","076_13_13","1CO","13","13","13","νυνι δε μενει πιστισ ελπισ αγαπη τα τρια ταυτα μειζων δε τουτων η αγαπη ");
INSERT INTO grcmt_vpl VALUES ("C114_1","076_14_1","1CO","14","1","1","διωκετε την αγαπην ζηλουτε δε τα πνευματικα μαλλον δε ινα προφητευητε ");
INSERT INTO grcmt_vpl VALUES ("C114_2","076_14_2","1CO","14","2","2","ο γαρ λαλων γλωσση ουκ ανθρωποισ λαλει αλλα τω θεω ουδεισ γαρ ακουει πνευματι δε λαλει μυστηρια ");
INSERT INTO grcmt_vpl VALUES ("C114_3","076_14_3","1CO","14","3","3","ο δε προφητευων ανθρωποισ λαλει οικοδομην και παρακλησιν και παραμυθιαν ");
INSERT INTO grcmt_vpl VALUES ("C114_4","076_14_4","1CO","14","4","4","ο λαλων γλωσση εαυτον οικοδομει ο δε προφητευων εκκλησιαν οικοδομει ");
INSERT INTO grcmt_vpl VALUES ("C114_5","076_14_5","1CO","14","5","5","θελω δε παντασ υμασ λαλειν γλωσσαισ μαλλον δε ινα προφητευητε μειζων γαρ ο προφητευων η ο λαλων γλωσσαισ εκτοσ ει μη διερμηνευει ινα η εκκλησια οικοδομην λαβη ");
INSERT INTO grcmt_vpl VALUES ("C114_6","076_14_6","1CO","14","6","6","νυνι δε αδελφοι εαν ελθω προσ υμασ γλωσσαισ λαλων τι υμασ ωφελησω εαν μη υμιν λαλησω η εν αποκαλυψει η εν γνωσει η εν προφητεια η εν διδαχη ");
INSERT INTO grcmt_vpl VALUES ("C114_7","076_14_7","1CO","14","7","7","ομωσ τα αψυχα φωνην διδοντα ειτε αυλοσ ειτε κιθαρα εαν διαστολην τοισ φθογγοισ μη διδω πωσ γνωσθησεται το αυλουμενον η το κιθαριζομενον ");
INSERT INTO grcmt_vpl VALUES ("C114_8","076_14_8","1CO","14","8","8","και γαρ εαν αδηλον φωνην σαλπιγξ δω τισ παρασκευασεται εισ πολεμον ");
INSERT INTO grcmt_vpl VALUES ("C114_9","076_14_9","1CO","14","9","9","ουτωσ και υμεισ δια τησ γλωσσησ εαν μη ευσημον λογον δωτε πωσ γνωσθησεται το λαλουμενον εσεσθε γαρ εισ αερα λαλουντεσ ");
INSERT INTO grcmt_vpl VALUES ("C114_10","076_14_10","1CO","14","10","10","τοσαυτα ει τυχοι γενη φωνων εστιν εν κοσμω και ουδεν αυτων αφωνον ");
INSERT INTO grcmt_vpl VALUES ("C114_11","076_14_11","1CO","14","11","11","εαν ουν μη ειδω την δυναμιν τησ φωνησ εσομαι τω λαλουντι βαρβαροσ και ο λαλων εν εμοι βαρβαροσ ");
INSERT INTO grcmt_vpl VALUES ("C114_12","076_14_12","1CO","14","12","12","ουτωσ και υμεισ επει ζηλωται εστε πνευματων προσ την οικοδομην τησ εκκλησιασ ζητειτε ινα περισσευητε ");
INSERT INTO grcmt_vpl VALUES ("C114_13","076_14_13","1CO","14","13","13","διοπερ ο λαλων γλωσση προσευχεσθω ινα διερμηνευη ");
INSERT INTO grcmt_vpl VALUES ("C114_14","076_14_14","1CO","14","14","14","εαν γαρ προσευχωμαι γλωσση το πνευμα μου προσευχεται ο δε νουσ μου ακαρποσ εστιν ");
INSERT INTO grcmt_vpl VALUES ("C114_15","076_14_15","1CO","14","15","15","τι ουν εστιν προσευξομαι τω πνευματι προσευξομαι δε και τω νοι ψαλω τω πνευματι ψαλω δε και τω νοι ");
INSERT INTO grcmt_vpl VALUES ("C114_16","076_14_16","1CO","14","16","16","επει εαν ευλογησησ τω πνευματι ο αναπληρων τον τοπον του ιδιωτου πωσ ερει το αμην επι τη ση ευχαριστια επειδη τι λεγεισ ουκ οιδεν ");
INSERT INTO grcmt_vpl VALUES ("C114_17","076_14_17","1CO","14","17","17","συ μεν γαρ καλωσ ευχαριστεισ αλλ ο ετεροσ ουκ οικοδομειται ");
INSERT INTO grcmt_vpl VALUES ("C114_18","076_14_18","1CO","14","18","18","ευχαριστω τω θεω μου παντων υμων μαλλον γλωσσαισ λαλων ");
INSERT INTO grcmt_vpl VALUES ("C114_19","076_14_19","1CO","14","19","19","αλλ εν εκκλησια θελω πεντε λογουσ δια του νοοσ μου λαλησαι ινα και αλλουσ κατηχησω η μυριουσ λογουσ εν γλωσση ");
INSERT INTO grcmt_vpl VALUES ("C114_20","076_14_20","1CO","14","20","20","αδελφοι μη παιδια γινεσθε ταισ φρεσιν αλλα τη κακια νηπιαζετε ταισ δε φρεσιν τελειοι γινεσθε ");
INSERT INTO grcmt_vpl VALUES ("C114_21","076_14_21","1CO","14","21","21","εν τω νομω γεγραπται οτι εν ετερογλωσσοισ και εν χειλεσιν ετεροισ λαλησω τω λαω τουτω και ουδ ουτωσ εισακουσονται μου λεγει κυριοσ ");
INSERT INTO grcmt_vpl VALUES ("C114_22","076_14_22","1CO","14","22","22","ωστε αι γλωσσαι εισ σημειον εισιν ου τοισ πιστευουσιν αλλα τοισ απιστοισ η δε προφητεια ου τοισ απιστοισ αλλα τοισ πιστευουσιν ");
INSERT INTO grcmt_vpl VALUES ("C114_23","076_14_23","1CO","14","23","23","εαν ουν συνελθη η εκκλησια ολη επι το αυτο και παντεσ γλωσσαισ λαλωσιν εισελθωσιν δε ιδιωται η απιστοι ουκ ερουσιν οτι μαινεσθε ");
INSERT INTO grcmt_vpl VALUES ("C114_24","076_14_24","1CO","14","24","24","εαν δε παντεσ προφητευωσιν εισελθη δε τισ απιστοσ η ιδιωτησ ελεγχεται υπο παντων ανακρινεται υπο παντων ");
INSERT INTO grcmt_vpl VALUES ("C114_25","076_14_25","1CO","14","25","25","και ουτωσ τα κρυπτα τησ καρδιασ αυτου φανερα γινεται και ουτωσ πεσων επι προσωπον προσκυνησει τω θεω απαγγελλων οτι ο θεοσ οντωσ εν υμιν εστιν ");
INSERT INTO grcmt_vpl VALUES ("C114_26","076_14_26","1CO","14","26","26","τι ουν εστιν αδελφοι οταν συνερχησθε εκαστοσ υμων ψαλμον εχει διδαχην εχει γλωσσαν εχει αποκαλυψιν εχει ερμηνειαν εχει παντα προσ οικοδομην γινεσθω ");
INSERT INTO grcmt_vpl VALUES ("C114_27","076_14_27","1CO","14","27","27","ειτε γλωσση τισ λαλει κατα δυο η το πλειστον τρεισ και ανα μεροσ και εισ διερμηνευετω ");
INSERT INTO grcmt_vpl VALUES ("C114_28","076_14_28","1CO","14","28","28","εαν δε μη η διερμηνευτησ σιγατω εν εκκλησια εαυτω δε λαλειτω και τω θεω ");
INSERT INTO grcmt_vpl VALUES ("C114_29","076_14_29","1CO","14","29","29","προφηται δε δυο η τρεισ λαλειτωσαν και οι αλλοι διακρινετωσαν ");
INSERT INTO grcmt_vpl VALUES ("C114_30","076_14_30","1CO","14","30","30","εαν δε αλλω αποκαλυφθη καθημενω ο πρωτοσ σιγατω ");
INSERT INTO grcmt_vpl VALUES ("C114_31","076_14_31","1CO","14","31","31","δυνασθε γαρ καθ ενα παντεσ προφητευειν ινα παντεσ μανθανωσιν και παντεσ παρακαλωνται ");
INSERT INTO grcmt_vpl VALUES ("C114_32","076_14_32","1CO","14","32","32","και πνευματα προφητων προφηταισ υποτασσεται ");
INSERT INTO grcmt_vpl VALUES ("C114_33","076_14_33","1CO","14","33","33","ου γαρ εστιν ακαταστασιασ ο θεοσ αλλα ειρηνησ ωσ εν πασαισ ταισ εκκλησιαισ των αγιων ");
INSERT INTO grcmt_vpl VALUES ("C114_34","076_14_34","1CO","14","34","34","αι γυναικεσ υμων εν ταισ εκκλησιαισ σιγατωσαν ου γαρ επιτετραπται αυταισ λαλειν αλλ υποτασσεσθαι καθωσ και ο νομοσ λεγει ");
INSERT INTO grcmt_vpl VALUES ("C114_35","076_14_35","1CO","14","35","35","ει δε τι μαθειν θελουσιν εν οικω τουσ ιδιουσ ανδρασ επερωτατωσαν αισχρον γαρ εστιν γυναιξιν εν εκκλησια λαλειν ");
INSERT INTO grcmt_vpl VALUES ("C114_36","076_14_36","1CO","14","36","36","η αφ υμων ο λογοσ του θεου εξηλθεν η εισ υμασ μονουσ κατηντησεν ");
INSERT INTO grcmt_vpl VALUES ("C114_37","076_14_37","1CO","14","37","37","ει τισ δοκει προφητησ ειναι η πνευματικοσ επιγινωσκετω α γραφω υμιν οτι κυριου εισιν εντολαι ");
INSERT INTO grcmt_vpl VALUES ("C114_38","076_14_38","1CO","14","38","38","ει δε τισ αγνοει αγνοειτω ");
INSERT INTO grcmt_vpl VALUES ("C114_39","076_14_39","1CO","14","39","39","ωστε αδελφοι ζηλουτε το προφητευειν και το λαλειν γλωσσαισ μη κωλυετε ");
INSERT INTO grcmt_vpl VALUES ("C114_40","076_14_40","1CO","14","40","40","παντα ευσχημονωσ και κατα ταξιν γινεσθω ");
INSERT INTO grcmt_vpl VALUES ("C115_1","076_15_1","1CO","15","1","1","γνωριζω δε υμιν αδελφοι το ευαγγελιον ο ευηγγελισαμην υμιν ο και παρελαβετε εν ω και εστηκατε ");
INSERT INTO grcmt_vpl VALUES ("C115_2","076_15_2","1CO","15","2","2","δι ου και σωζεσθε τινι λογω ευηγγελισαμην υμιν ει κατεχετε εκτοσ ει μη εικη επιστευσατε ");
INSERT INTO grcmt_vpl VALUES ("C115_3","076_15_3","1CO","15","3","3","παρεδωκα γαρ υμιν εν πρωτοισ ο και παρελαβον οτι χριστοσ απεθανεν υπερ των αμαρτιων ημων κατα τασ γραφασ ");
INSERT INTO grcmt_vpl VALUES ("C115_4","076_15_4","1CO","15","4","4","και οτι εταφη και οτι εγηγερται τη τριτη ημερα κατα τασ γραφασ ");
INSERT INTO grcmt_vpl VALUES ("C115_5","076_15_5","1CO","15","5","5","και οτι ωφθη κηφα ειτα τοισ δωδεκα ");
INSERT INTO grcmt_vpl VALUES ("C115_6","076_15_6","1CO","15","6","6","επειτα ωφθη επανω πεντακοσιοισ αδελφοισ εφαπαξ εξ ων οι πλειουσ μενουσιν εωσ αρτι τινεσ δε και εκοιμηθησαν ");
INSERT INTO grcmt_vpl VALUES ("C115_7","076_15_7","1CO","15","7","7","επειτα ωφθη ιακωβω ειτα τοισ αποστολοισ πασιν ");
INSERT INTO grcmt_vpl VALUES ("C115_8","076_15_8","1CO","15","8","8","εσχατον δε παντων ωσπερει τω εκτρωματι ωφθη καμοι ");
INSERT INTO grcmt_vpl VALUES ("C115_9","076_15_9","1CO","15","9","9","εγω γαρ ειμι ο ελαχιστοσ των αποστολων οσ ουκ ειμι ικανοσ καλεισθαι αποστολοσ διοτι εδιωξα την εκκλησιαν του θεου ");
INSERT INTO grcmt_vpl VALUES ("C115_10","076_15_10","1CO","15","10","10","χαριτι δε θεου ειμι ο ειμι και η χαρισ αυτου η εισ εμε ου κενη εγενηθη αλλα περισσοτερον αυτων παντων εκοπιασα ουκ εγω δε αλλ η χαρισ του θεου η συν εμοι ");
INSERT INTO grcmt_vpl VALUES ("C115_11","076_15_11","1CO","15","11","11","ειτε ουν εγω ειτε εκεινοι ουτωσ κηρυσσομεν και ουτωσ επιστευσατε ");
INSERT INTO grcmt_vpl VALUES ("C115_12","076_15_12","1CO","15","12","12","ει δε χριστοσ κηρυσσεται οτι εκ νεκρων εγηγερται πωσ λεγουσιν τινεσ εν υμιν οτι αναστασισ νεκρων ουκ εστιν ");
INSERT INTO grcmt_vpl VALUES ("C115_13","076_15_13","1CO","15","13","13","ει δε αναστασισ νεκρων ουκ εστιν ουδε χριστοσ εγηγερται ");
INSERT INTO grcmt_vpl VALUES ("C115_14","076_15_14","1CO","15","14","14","ει δε χριστοσ ουκ εγηγερται κενον αρα το κηρυγμα ημων κενη δε και η πιστισ υμων ");
INSERT INTO grcmt_vpl VALUES ("C115_15","076_15_15","1CO","15","15","15","ευρισκομεθα δε και ψευδομαρτυρεσ του θεου οτι εμαρτυρησαμεν κατα του θεου οτι ηγειρεν τον χριστον ον ουκ ηγειρεν ειπερ αρα νεκροι ουκ εγειρονται ");
INSERT INTO grcmt_vpl VALUES ("C115_16","076_15_16","1CO","15","16","16","ει γαρ νεκροι ουκ εγειρονται ουδε χριστοσ εγηγερται ");
INSERT INTO grcmt_vpl VALUES ("C115_17","076_15_17","1CO","15","17","17","ει δε χριστοσ ουκ εγηγερται ματαια η πιστισ υμων ετι εστε εν ταισ αμαρτιαισ υμων ");
INSERT INTO grcmt_vpl VALUES ("C115_18","076_15_18","1CO","15","18","18","αρα και οι κοιμηθεντεσ εν χριστω απωλοντο ");
INSERT INTO grcmt_vpl VALUES ("C115_19","076_15_19","1CO","15","19","19","ει εν τη ζωη ταυτη ηλπικοτεσ εσμεν εν χριστω μονον ελεεινοτεροι παντων ανθρωπων εσμεν ");
INSERT INTO grcmt_vpl VALUES ("C115_20","076_15_20","1CO","15","20","20","νυνι δε χριστοσ εγηγερται εκ νεκρων απαρχη των κεκοιμημενων εγενετο ");
INSERT INTO grcmt_vpl VALUES ("C115_21","076_15_21","1CO","15","21","21","επειδη γαρ δι ανθρωπου ο θανατοσ και δι ανθρωπου αναστασισ νεκρων ");
INSERT INTO grcmt_vpl VALUES ("C115_22","076_15_22","1CO","15","22","22","ωσπερ γαρ εν τω αδαμ παντεσ αποθνησκουσιν ουτωσ και εν τω χριστω παντεσ ζωοποιηθησονται ");
INSERT INTO grcmt_vpl VALUES ("C115_23","076_15_23","1CO","15","23","23","εκαστοσ δε εν τω ιδιω ταγματι απαρχη χριστοσ επειτα οι του χριστου εν τη παρουσια αυτου ");
INSERT INTO grcmt_vpl VALUES ("C115_24","076_15_24","1CO","15","24","24","ειτα το τελοσ οταν παραδω την βασιλειαν τω θεω και πατρι οταν καταργηση πασαν αρχην και πασαν εξουσιαν και δυναμιν ");
INSERT INTO grcmt_vpl VALUES ("C115_25","076_15_25","1CO","15","25","25","δει γαρ αυτον βασιλευειν αχρι ου αν θη παντασ τουσ εχθρουσ υπο τουσ ποδασ αυτου ");
INSERT INTO grcmt_vpl VALUES ("C115_26","076_15_26","1CO","15","26","26","εσχατοσ εχθροσ καταργειται ο θανατοσ ");
INSERT INTO grcmt_vpl VALUES ("C115_27","076_15_27","1CO","15","27","27","παντα γαρ υπεταξεν υπο τουσ ποδασ αυτου οταν δε ειπη οτι παντα υποτετακται δηλον οτι εκτοσ του υποταξαντοσ αυτω τα παντα ");
INSERT INTO grcmt_vpl VALUES ("C115_28","076_15_28","1CO","15","28","28","οταν δε υποταγη αυτω τα παντα τοτε και αυτοσ ο υιοσ υποταγησεται τω υποταξαντι αυτω τα παντα ινα η ο θεοσ τα παντα εν πασιν ");
INSERT INTO grcmt_vpl VALUES ("C115_29","076_15_29","1CO","15","29","29","επει τι ποιησουσιν οι βαπτιζομενοι υπερ των νεκρων ει ολωσ νεκροι ουκ εγειρονται τι και βαπτιζονται υπερ των νεκρων ");
INSERT INTO grcmt_vpl VALUES ("C115_30","076_15_30","1CO","15","30","30","τι και ημεισ κινδυνευομεν πασαν ωραν ");
INSERT INTO grcmt_vpl VALUES ("C115_31","076_15_31","1CO","15","31","31","καθ ημεραν αποθνησκω νη την υμετεραν καυχησιν ην εχω εν χριστω ιησου τω κυριω ημων ");
INSERT INTO grcmt_vpl VALUES ("C115_32","076_15_32","1CO","15","32","32","ει κατα ανθρωπον εθηριομαχησα εν εφεσω τι μοι το οφελοσ ει νεκροι ουκ εγειρονται φαγωμεν και πιωμεν αυριον γαρ αποθνησκομεν ");
INSERT INTO grcmt_vpl VALUES ("C115_33","076_15_33","1CO","15","33","33","μη πλανασθε φθειρουσιν ηθη χρηστα ομιλιαι κακαι ");
INSERT INTO grcmt_vpl VALUES ("C115_34","076_15_34","1CO","15","34","34","εκνηψατε δικαιωσ και μη αμαρτανετε αγνωσιαν γαρ θεου τινεσ εχουσιν προσ εντροπην υμιν λεγω ");
INSERT INTO grcmt_vpl VALUES ("C115_35","076_15_35","1CO","15","35","35","αλλ ερει τισ πωσ εγειρονται οι νεκροι ποιω δε σωματι ερχονται ");
INSERT INTO grcmt_vpl VALUES ("C115_36","076_15_36","1CO","15","36","36","αφρον συ ο σπειρεισ ου ζωοποιειται εαν μη αποθανη ");
INSERT INTO grcmt_vpl VALUES ("C115_37","076_15_37","1CO","15","37","37","και ο σπειρεισ ου το σωμα το γενησομενον σπειρεισ αλλα γυμνον κοκκον ει τυχοι σιτου η τινοσ των λοιπων ");
INSERT INTO grcmt_vpl VALUES ("C115_38","076_15_38","1CO","15","38","38","ο δε θεοσ αυτω διδωσιν σωμα καθωσ ηθελησεν και εκαστω των σπερματων το ιδιον σωμα ");
INSERT INTO grcmt_vpl VALUES ("C115_39","076_15_39","1CO","15","39","39","ου πασα σαρξ η αυτη σαρξ αλλα αλλη μεν ανθρωπων αλλη δε σαρξ κτηνων αλλη δε ιχθυων αλλη δε πτηνων ");
INSERT INTO grcmt_vpl VALUES ("C115_40","076_15_40","1CO","15","40","40","και σωματα επουρανια και σωματα επιγεια αλλ ετερα μεν η των επουρανιων δοξα ετερα δε η των επιγειων ");
INSERT INTO grcmt_vpl VALUES ("C115_41","076_15_41","1CO","15","41","41","αλλη δοξα ηλιου και αλλη δοξα σεληνησ και αλλη δοξα αστερων αστηρ γαρ αστεροσ διαφερει εν δοξη ");
INSERT INTO grcmt_vpl VALUES ("C115_42","076_15_42","1CO","15","42","42","ουτωσ και η αναστασισ των νεκρων σπειρεται εν φθορα εγειρεται εν αφθαρσια ");
INSERT INTO grcmt_vpl VALUES ("C115_43","076_15_43","1CO","15","43","43","σπειρεται εν ατιμια εγειρεται εν δοξη σπειρεται εν ασθενεια εγειρεται εν δυναμει ");
INSERT INTO grcmt_vpl VALUES ("C115_44","076_15_44","1CO","15","44","44","σπειρεται σωμα ψυχικον εγειρεται σωμα πνευματικον εστιν σωμα ψυχικον και εστιν σωμα πνευματικον ");
INSERT INTO grcmt_vpl VALUES ("C115_45","076_15_45","1CO","15","45","45","ουτωσ και γεγραπται εγενετο ο πρωτοσ ανθρωποσ αδαμ εισ ψυχην ζωσαν ο εσχατοσ αδαμ εισ πνευμα ζωοποιουν ");
INSERT INTO grcmt_vpl VALUES ("C115_46","076_15_46","1CO","15","46","46","αλλ ου πρωτον το πνευματικον αλλα το ψυχικον επειτα το πνευματικον ");
INSERT INTO grcmt_vpl VALUES ("C115_47","076_15_47","1CO","15","47","47","ο πρωτοσ ανθρωποσ εκ γησ χοικοσ ο δευτεροσ ανθρωποσ ο κυριοσ εξ ουρανου ");
INSERT INTO grcmt_vpl VALUES ("C115_48","076_15_48","1CO","15","48","48","οιοσ ο χοικοσ τοιουτοι και οι χοικοι και οιοσ ο επουρανιοσ τοιουτοι και οι επουρανιοι ");
INSERT INTO grcmt_vpl VALUES ("C115_49","076_15_49","1CO","15","49","49","και καθωσ εφορεσαμεν την εικονα του χοικου φορεσωμεν και την εικονα του επουρανιου ");
INSERT INTO grcmt_vpl VALUES ("C115_50","076_15_50","1CO","15","50","50","τουτο δε φημι αδελφοι οτι σαρξ και αιμα βασιλειαν θεου κληρονομησαι ου δυνανται ουδε η φθορα την αφθαρσιαν κληρονομει ");
INSERT INTO grcmt_vpl VALUES ("C115_51","076_15_51","1CO","15","51","51","ιδου μυστηριον υμιν λεγω παντεσ μεν ου κοιμηθησομεθα παντεσ δε αλλαγησομεθα ");
INSERT INTO grcmt_vpl VALUES ("C115_52","076_15_52","1CO","15","52","52","εν ατομω εν ριπη οφθαλμου εν τη εσχατη σαλπιγγι σαλπισει γαρ και οι νεκροι εγερθησονται αφθαρτοι και ημεισ αλλαγησομεθα ");
INSERT INTO grcmt_vpl VALUES ("C115_53","076_15_53","1CO","15","53","53","δει γαρ το φθαρτον τουτο ενδυσασθαι αφθαρσιαν και το θνητον τουτο ενδυσασθαι αθανασιαν ");
INSERT INTO grcmt_vpl VALUES ("C115_54","076_15_54","1CO","15","54","54","οταν δε το φθαρτον τουτο ενδυσηται αφθαρσιαν και το θνητον τουτο ενδυσηται αθανασιαν τοτε γενησεται ο λογοσ ο γεγραμμενοσ κατεποθη ο θανατοσ εισ νικοσ ");
INSERT INTO grcmt_vpl VALUES ("C115_55","076_15_55","1CO","15","55","55","που σου θανατε το κεντρον που σου αδη το νικοσ ");
INSERT INTO grcmt_vpl VALUES ("C115_56","076_15_56","1CO","15","56","56","το δε κεντρον του θανατου η αμαρτια η δε δυναμισ τησ αμαρτιασ ο νομοσ ");
INSERT INTO grcmt_vpl VALUES ("C115_57","076_15_57","1CO","15","57","57","τω δε θεω χαρισ τω διδοντι ημιν το νικοσ δια του κυριου ημων ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("C115_58","076_15_58","1CO","15","58","58","ωστε αδελφοι μου αγαπητοι εδραιοι γινεσθε αμετακινητοι περισσευοντεσ εν τω εργω του κυριου παντοτε ειδοτεσ οτι ο κοποσ υμων ουκ εστιν κενοσ εν κυριω ");
INSERT INTO grcmt_vpl VALUES ("C116_1","076_16_1","1CO","16","1","1","περι δε τησ λογιασ τησ εισ τουσ αγιουσ ωσπερ διεταξα ταισ εκκλησιαισ τησ γαλατιασ ουτωσ και υμεισ ποιησατε ");
INSERT INTO grcmt_vpl VALUES ("C116_2","076_16_2","1CO","16","2","2","κατα μιαν σαββατων εκαστοσ υμων παρ εαυτω τιθετω θησαυριζων ο τι αν ευοδωται ινα μη οταν ελθω τοτε λογιαι γινωνται ");
INSERT INTO grcmt_vpl VALUES ("C116_3","076_16_3","1CO","16","3","3","οταν δε παραγενωμαι ουσ εαν δοκιμασητε δι επιστολων τουτουσ πεμψω απενεγκειν την χαριν υμων εισ ιερουσαλημ ");
INSERT INTO grcmt_vpl VALUES ("C116_4","076_16_4","1CO","16","4","4","εαν δε η αξιον του καμε πορευεσθαι συν εμοι πορευσονται ");
INSERT INTO grcmt_vpl VALUES ("C116_5","076_16_5","1CO","16","5","5","ελευσομαι δε προσ υμασ οταν μακεδονιαν διελθω μακεδονιαν γαρ διερχομαι ");
INSERT INTO grcmt_vpl VALUES ("C116_6","076_16_6","1CO","16","6","6","προσ υμασ δε τυχον παραμενω η και παραχειμασω ινα υμεισ με προπεμψητε ου εαν πορευωμαι ");
INSERT INTO grcmt_vpl VALUES ("C116_7","076_16_7","1CO","16","7","7","ου θελω γαρ υμασ αρτι εν παροδω ιδειν ελπιζω δε χρονον τινα επιμειναι προσ υμασ εαν ο κυριοσ επιτρεπη ");
INSERT INTO grcmt_vpl VALUES ("C116_8","076_16_8","1CO","16","8","8","επιμενω δε εν εφεσω εωσ τησ πεντηκοστησ ");
INSERT INTO grcmt_vpl VALUES ("C116_9","076_16_9","1CO","16","9","9","θυρα γαρ μοι ανεωγεν μεγαλη και ενεργησ και αντικειμενοι πολλοι ");
INSERT INTO grcmt_vpl VALUES ("C116_10","076_16_10","1CO","16","10","10","εαν δε ελθη τιμοθεοσ βλεπετε ινα αφοβωσ γενηται προσ υμασ το γαρ εργον κυριου εργαζεται ωσ και εγω ");
INSERT INTO grcmt_vpl VALUES ("C116_11","076_16_11","1CO","16","11","11","μη τισ ουν αυτον εξουθενηση προπεμψατε δε αυτον εν ειρηνη ινα ελθη προσ με εκδεχομαι γαρ αυτον μετα των αδελφων ");
INSERT INTO grcmt_vpl VALUES ("C116_12","076_16_12","1CO","16","12","12","περι δε απολλω του αδελφου πολλα παρεκαλεσα αυτον ινα ελθη προσ υμασ μετα των αδελφων και παντωσ ουκ ην θελημα ινα νυν ελθη ελευσεται δε οταν ευκαιρηση ");
INSERT INTO grcmt_vpl VALUES ("C116_13","076_16_13","1CO","16","13","13","γρηγορειτε στηκετε εν τη πιστει ανδριζεσθε κραταιουσθε ");
INSERT INTO grcmt_vpl VALUES ("C116_14","076_16_14","1CO","16","14","14","παντα υμων εν αγαπη γινεσθω ");
INSERT INTO grcmt_vpl VALUES ("C116_15","076_16_15","1CO","16","15","15","παρακαλω δε υμασ αδελφοι οιδατε την οικιαν στεφανα οτι εστιν απαρχη τησ αχαιασ και εισ διακονιαν τοισ αγιοισ εταξαν εαυτουσ ");
INSERT INTO grcmt_vpl VALUES ("C116_16","076_16_16","1CO","16","16","16","ινα και υμεισ υποτασσησθε τοισ τοιουτοισ και παντι τω συνεργουντι και κοπιωντι ");
INSERT INTO grcmt_vpl VALUES ("C116_17","076_16_17","1CO","16","17","17","χαιρω δε επι τη παρουσια στεφανα και φουρτουνατου και αχαικου οτι το υμων υστερημα ουτοι ανεπληρωσαν ");
INSERT INTO grcmt_vpl VALUES ("C116_18","076_16_18","1CO","16","18","18","ανεπαυσαν γαρ το εμον πνευμα και το υμων επιγινωσκετε ουν τουσ τοιουτουσ ");
INSERT INTO grcmt_vpl VALUES ("C116_19","076_16_19","1CO","16","19","19","ασπαζονται υμασ αι εκκλησιαι τησ ασιασ ασπαζονται υμασ εν κυριω πολλα ακυλασ και πρισκιλλα συν τη κατ οικον αυτων εκκλησια ");
INSERT INTO grcmt_vpl VALUES ("C116_20","076_16_20","1CO","16","20","20","ασπαζονται υμασ οι αδελφοι παντεσ ασπασασθε αλληλουσ εν φιληματι αγιω ");
INSERT INTO grcmt_vpl VALUES ("C116_21","076_16_21","1CO","16","21","21","ο ασπασμοσ τη εμη χειρι παυλου ");
INSERT INTO grcmt_vpl VALUES ("C116_22","076_16_22","1CO","16","22","22","ει τισ ου φιλει τον κυριον ιησουν χριστον ητω αναθεμα μαραν αθα ");
INSERT INTO grcmt_vpl VALUES ("C116_23","076_16_23","1CO","16","23","23","η χαρισ του κυριου ιησου χριστου μεθ υμων ");
INSERT INTO grcmt_vpl VALUES ("C116_24","076_16_24","1CO","16","24","24","η αγαπη μου μετα παντων υμων εν χριστω ιησου αμην ");
INSERT INTO grcmt_vpl VALUES ("C21_1","077_1_1","2CO","1","1","1","παυλοσ αποστολοσ ιησου χριστου δια θεληματοσ θεου και τιμοθεοσ ο αδελφοσ τη εκκλησια του θεου τη ουση εν κορινθω συν τοισ αγιοισ πασιν τοισ ουσιν εν ολη τη αχαια ");
INSERT INTO grcmt_vpl VALUES ("C21_2","077_1_2","2CO","1","2","2","χαρισ υμιν και ειρηνη απο θεου πατροσ ημων και κυριου ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("C21_3","077_1_3","2CO","1","3","3","ευλογητοσ ο θεοσ και πατηρ του κυριου ημων ιησου χριστου ο πατηρ των οικτιρμων και θεοσ πασησ παρακλησεωσ ");
INSERT INTO grcmt_vpl VALUES ("C21_4","077_1_4","2CO","1","4","4","ο παρακαλων ημασ επι παση τη θλιψει ημων εισ το δυνασθαι ημασ παρακαλειν τουσ εν παση θλιψει δια τησ παρακλησεωσ ησ παρακαλουμεθα αυτοι υπο του θεου ");
INSERT INTO grcmt_vpl VALUES ("C21_5","077_1_5","2CO","1","5","5","οτι καθωσ περισσευει τα παθηματα του χριστου εισ ημασ ουτωσ δια του χριστου περισσευει και η παρακλησισ ημων ");
INSERT INTO grcmt_vpl VALUES ("C21_6","077_1_6","2CO","1","6","6","ειτε δε θλιβομεθα υπερ τησ υμων παρακλησεωσ και σωτηριασ τησ ενεργουμενησ εν υπομονη των αυτων παθηματων ων και ημεισ πασχομεν και η ελπισ ημων βεβαια υπερ υμων ειτε παρακαλουμεθα υπερ τησ υμων παρακλησεωσ και σωτηριασ ");
INSERT INTO grcmt_vpl VALUES ("C21_7","077_1_7","2CO","1","7","7","ειδοτεσ οτι ωσπερ κοινωνοι εστε των παθηματων ουτωσ και τησ παρακλησεωσ ");
INSERT INTO grcmt_vpl VALUES ("C21_8","077_1_8","2CO","1","8","8","ου γαρ θελομεν υμασ αγνοειν αδελφοι υπερ τησ θλιψεωσ ημων τησ γενομενησ ημιν εν τη ασια οτι καθ υπερβολην εβαρηθημεν υπερ δυναμιν ωστε εξαπορηθηναι ημασ και του ζην ");
INSERT INTO grcmt_vpl VALUES ("C21_9","077_1_9","2CO","1","9","9","αλλα αυτοι εν εαυτοισ το αποκριμα του θανατου εσχηκαμεν ινα μη πεποιθοτεσ ωμεν εφ εαυτοισ αλλ επι τω θεω τω εγειροντι τουσ νεκρουσ ");
INSERT INTO grcmt_vpl VALUES ("C21_10","077_1_10","2CO","1","10","10","οσ εκ τηλικουτου θανατου ερρυσατο ημασ και ρυεται εισ ον ηλπικαμεν οτι και ετι ρυσεται ");
INSERT INTO grcmt_vpl VALUES ("C21_11","077_1_11","2CO","1","11","11","συνυπουργουντων και υμων υπερ ημων τη δεησει ινα εκ πολλων προσωπων το εισ ημασ χαρισμα δια πολλων ευχαριστηθη υπερ υμων ");
INSERT INTO grcmt_vpl VALUES ("C21_12","077_1_12","2CO","1","12","12","η γαρ καυχησισ ημων αυτη εστιν το μαρτυριον τησ συνειδησεωσ ημων οτι εν απλοτητι και ειλικρινεια θεου ουκ εν σοφια σαρκικη αλλ εν χαριτι θεου ανεστραφημεν εν τω κοσμω περισσοτερωσ δε προσ υμασ ");
INSERT INTO grcmt_vpl VALUES ("C21_13","077_1_13","2CO","1","13","13","ου γαρ αλλα γραφομεν υμιν αλλ η α αναγινωσκετε η και επιγινωσκετε ελπιζω δε οτι και εωσ τελουσ επιγνωσεσθε ");
INSERT INTO grcmt_vpl VALUES ("C21_14","077_1_14","2CO","1","14","14","καθωσ και επεγνωτε ημασ απο μερουσ οτι καυχημα υμων εσμεν καθαπερ και υμεισ ημων εν τη ημερα του κυριου ιησου ");
INSERT INTO grcmt_vpl VALUES ("C21_15","077_1_15","2CO","1","15","15","και ταυτη τη πεποιθησει εβουλομην ελθειν προσ υμασ το προτερον ινα δευτεραν χαριν εχητε ");
INSERT INTO grcmt_vpl VALUES ("C21_16","077_1_16","2CO","1","16","16","και δι υμων διελθειν εισ μακεδονιαν και παλιν απο μακεδονιασ ελθειν προσ υμασ και υφ υμων προπεμφθηναι εισ την ιουδαιαν ");
INSERT INTO grcmt_vpl VALUES ("C21_17","077_1_17","2CO","1","17","17","τουτο ουν βουλευομενοσ μητι αρα τη ελαφρια εχρησαμην η α βουλευομαι κατα σαρκα βουλευομαι ινα η παρ εμοι το ναι ναι και το ου ου ");
INSERT INTO grcmt_vpl VALUES ("C21_18","077_1_18","2CO","1","18","18","πιστοσ δε ο θεοσ οτι ο λογοσ ημων ο προσ υμασ ουκ εγενετο ναι και ου ");
INSERT INTO grcmt_vpl VALUES ("C21_19","077_1_19","2CO","1","19","19","ο γαρ του θεου υιοσ ιησουσ χριστοσ ο εν υμιν δι ημων κηρυχθεισ δι εμου και σιλουανου και τιμοθεου ουκ εγενετο ναι και ου αλλα ναι εν αυτω γεγονεν ");
INSERT INTO grcmt_vpl VALUES ("C21_20","077_1_20","2CO","1","20","20","οσαι γαρ επαγγελιαι θεου εν αυτω το ναι και εν αυτω το αμην τω θεω προσ δοξαν δι ημων ");
INSERT INTO grcmt_vpl VALUES ("C21_21","077_1_21","2CO","1","21","21","ο δε βεβαιων ημασ συν υμιν εισ χριστον και χρισασ ημασ θεοσ ");
INSERT INTO grcmt_vpl VALUES ("C21_22","077_1_22","2CO","1","22","22","ο και σφραγισαμενοσ ημασ και δουσ τον αρραβωνα του πνευματοσ εν ταισ καρδιαισ ημων ");
INSERT INTO grcmt_vpl VALUES ("C21_23","077_1_23","2CO","1","23","23","εγω δε μαρτυρα τον θεον επικαλουμαι επι την εμην ψυχην οτι φειδομενοσ υμων ουκετι ηλθον εισ κορινθον ");
INSERT INTO grcmt_vpl VALUES ("C21_24","077_1_24","2CO","1","24","24","ουχ οτι κυριευομεν υμων τησ πιστεωσ αλλα συνεργοι εσμεν τησ χαρασ υμων τη γαρ πιστει εστηκατε ");
INSERT INTO grcmt_vpl VALUES ("C22_1","077_2_1","2CO","2","1","1","εκρινα δε εμαυτω τουτο το μη παλιν εν λυπη προσ υμασ ελθειν ");
INSERT INTO grcmt_vpl VALUES ("C22_2","077_2_2","2CO","2","2","2","ει γαρ εγω λυπω υμασ και τισ εστιν ο ευφραινων με ει μη ο λυπουμενοσ εξ εμου ");
INSERT INTO grcmt_vpl VALUES ("C22_3","077_2_3","2CO","2","3","3","και εγραψα υμιν τουτο αυτο ινα μη ελθων λυπην εχω αφ ων εδει με χαιρειν πεποιθωσ επι παντασ υμασ οτι η εμη χαρα παντων υμων εστιν ");
INSERT INTO grcmt_vpl VALUES ("C22_4","077_2_4","2CO","2","4","4","εκ γαρ πολλησ θλιψεωσ και συνοχησ καρδιασ εγραψα υμιν δια πολλων δακρυων ουχ ινα λυπηθητε αλλα την αγαπην ινα γνωτε ην εχω περισσοτερωσ εισ υμασ ");
INSERT INTO grcmt_vpl VALUES ("C22_5","077_2_5","2CO","2","5","5","ει δε τισ λελυπηκεν ουκ εμε λελυπηκεν αλλα απο μερουσ ινα μη επιβαρω παντασ υμασ ");
INSERT INTO grcmt_vpl VALUES ("C22_6","077_2_6","2CO","2","6","6","ικανον τω τοιουτω η επιτιμια αυτη η υπο των πλειονων ");
INSERT INTO grcmt_vpl VALUES ("C22_7","077_2_7","2CO","2","7","7","ωστε τουναντιον μαλλον υμασ χαρισασθαι και παρακαλεσαι μηπωσ τη περισσοτερα λυπη καταποθη ο τοιουτοσ ");
INSERT INTO grcmt_vpl VALUES ("C22_8","077_2_8","2CO","2","8","8","διο παρακαλω υμασ κυρωσαι εισ αυτον αγαπην ");
INSERT INTO grcmt_vpl VALUES ("C22_9","077_2_9","2CO","2","9","9","εισ τουτο γαρ και εγραψα ινα γνω την δοκιμην υμων ει εισ παντα υπηκοοι εστε ");
INSERT INTO grcmt_vpl VALUES ("C22_10","077_2_10","2CO","2","10","10","ω δε τι χαριζεσθε και εγω και γαρ εγω ει τι κεχαρισμαι ω κεχαρισμαι δι υμασ εν προσωπω χριστου ");
INSERT INTO grcmt_vpl VALUES ("C22_11","077_2_11","2CO","2","11","11","ινα μη πλεονεκτηθωμεν υπο του σατανα ου γαρ αυτου τα νοηματα αγνοουμεν ");
INSERT INTO grcmt_vpl VALUES ("C22_12","077_2_12","2CO","2","12","12","ελθων δε εισ την τρωαδα εισ το ευαγγελιον του χριστου και θυρασ μοι ανεωγμενησ εν κυριω ");
INSERT INTO grcmt_vpl VALUES ("C22_13","077_2_13","2CO","2","13","13","ουκ εσχηκα ανεσιν τω πνευματι μου τω μη ευρειν με τιτον τον αδελφον μου αλλα αποταξαμενοσ αυτοισ εξηλθον εισ μακεδονιαν ");
INSERT INTO grcmt_vpl VALUES ("C22_14","077_2_14","2CO","2","14","14","τω δε θεω χαρισ τω παντοτε θριαμβευοντι ημασ εν τω χριστω και την οσμην τησ γνωσεωσ αυτου φανερουντι δι ημων εν παντι τοπω ");
INSERT INTO grcmt_vpl VALUES ("C22_15","077_2_15","2CO","2","15","15","οτι χριστου ευωδια εσμεν τω θεω εν τοισ σωζομενοισ και εν τοισ απολλυμενοισ ");
INSERT INTO grcmt_vpl VALUES ("C22_16","077_2_16","2CO","2","16","16","οισ μεν οσμη θανατου εισ θανατον οισ δε οσμη ζωησ εισ ζωην και προσ ταυτα τισ ικανοσ ");
INSERT INTO grcmt_vpl VALUES ("C22_17","077_2_17","2CO","2","17","17","ου γαρ εσμεν ωσ οι λοιποι καπηλευοντεσ τον λογον του θεου αλλ ωσ εξ ειλικρινειασ αλλ ωσ εκ θεου κατενωπιον του θεου εν χριστω λαλουμεν ");
INSERT INTO grcmt_vpl VALUES ("C23_1","077_3_1","2CO","3","1","1","αρχομεθα παλιν εαυτουσ συνιστανειν ει μη χρηζομεν ωσ τινεσ συστατικων επιστολων προσ υμασ η εξ υμων συστατικων ");
INSERT INTO grcmt_vpl VALUES ("C23_2","077_3_2","2CO","3","2","2","η επιστολη ημων υμεισ εστε εγγεγραμμενη εν ταισ καρδιαισ ημων γινωσκομενη και αναγινωσκομενη υπο παντων ανθρωπων ");
INSERT INTO grcmt_vpl VALUES ("C23_3","077_3_3","2CO","3","3","3","φανερουμενοι οτι εστε επιστολη χριστου διακονηθεισα υφ ημων εγγεγραμμενη ου μελανι αλλα πνευματι θεου ζωντοσ ουκ εν πλαξιν λιθιναισ αλλ εν πλαξιν καρδιαισ σαρκιναισ ");
INSERT INTO grcmt_vpl VALUES ("C23_4","077_3_4","2CO","3","4","4","πεποιθησιν δε τοιαυτην εχομεν δια του χριστου προσ τον θεον ");
INSERT INTO grcmt_vpl VALUES ("C23_5","077_3_5","2CO","3","5","5","ουχ οτι ικανοι εσμεν αφ εαυτων λογισασθαι τι ωσ εξ εαυτων αλλ η ικανοτησ ημων εκ του θεου ");
INSERT INTO grcmt_vpl VALUES ("C23_6","077_3_6","2CO","3","6","6","οσ και ικανωσεν ημασ διακονουσ καινησ διαθηκησ ου γραμματοσ αλλα πνευματοσ το γαρ γραμμα αποκτενει το δε πνευμα ζωοποιει ");
INSERT INTO grcmt_vpl VALUES ("C23_7","077_3_7","2CO","3","7","7","ει δε η διακονια του θανατου εν γραμμασιν εντετυπωμενη εν λιθοισ εγενηθη εν δοξη ωστε μη δυνασθαι ατενισαι τουσ υιουσ ισραηλ εισ το προσωπον μωυσεωσ δια την δοξαν του προσωπου αυτου την καταργουμενην ");
INSERT INTO grcmt_vpl VALUES ("C23_8","077_3_8","2CO","3","8","8","πωσ ουχι μαλλον η διακονια του πνευματοσ εσται εν δοξη ");
INSERT INTO grcmt_vpl VALUES ("C23_9","077_3_9","2CO","3","9","9","ει γαρ η διακονια τησ κατακρισεωσ δοξα πολλω μαλλον περισσευει η διακονια τησ δικαιοσυνησ εν δοξη ");
INSERT INTO grcmt_vpl VALUES ("C23_10","077_3_10","2CO","3","10","10","και γαρ ου δεδοξασται το δεδοξασμενον εν τουτω τω μερει ενεκεν τησ υπερβαλλουσησ δοξησ ");
INSERT INTO grcmt_vpl VALUES ("C23_11","077_3_11","2CO","3","11","11","ει γαρ το καταργουμενον δια δοξησ πολλω μαλλον το μενον εν δοξη ");
INSERT INTO grcmt_vpl VALUES ("C23_12","077_3_12","2CO","3","12","12","εχοντεσ ουν τοιαυτην ελπιδα πολλη παρρησια χρωμεθα ");
INSERT INTO grcmt_vpl VALUES ("C23_13","077_3_13","2CO","3","13","13","και ου καθαπερ μωυσησ ετιθει καλυμμα επι το προσωπον εαυτου προσ το μη ατενισαι τουσ υιουσ ισραηλ εισ το τελοσ του καταργουμενου ");
INSERT INTO grcmt_vpl VALUES ("C23_14","077_3_14","2CO","3","14","14","αλλ επωρωθη τα νοηματα αυτων αχρι γαρ τησ σημερον το αυτο καλυμμα επι τη αναγνωσει τησ παλαιασ διαθηκησ μενει μη ανακαλυπτομενον ο τι εν χριστω καταργειται ");
INSERT INTO grcmt_vpl VALUES ("C23_15","077_3_15","2CO","3","15","15","αλλ εωσ σημερον ηνικα αναγινωσκεται μωυσησ καλυμμα επι την καρδιαν αυτων κειται ");
INSERT INTO grcmt_vpl VALUES ("C23_16","077_3_16","2CO","3","16","16","ηνικα δ αν επιστρεψη προσ κυριον περιαιρειται το καλυμμα ");
INSERT INTO grcmt_vpl VALUES ("C23_17","077_3_17","2CO","3","17","17","ο δε κυριοσ το πνευμα εστιν ου δε το πνευμα κυριου εκει ελευθερια ");
INSERT INTO grcmt_vpl VALUES ("C23_18","077_3_18","2CO","3","18","18","ημεισ δε παντεσ ανακεκαλυμμενω προσωπω την δοξαν κυριου κατοπτριζομενοι την αυτην εικονα μεταμορφουμεθα απο δοξησ εισ δοξαν καθαπερ απο κυριου πνευματοσ ");
INSERT INTO grcmt_vpl VALUES ("C24_1","077_4_1","2CO","4","1","1","δια τουτο εχοντεσ την διακονιαν ταυτην καθωσ ηλεηθημεν ουκ εκκακουμεν ");
INSERT INTO grcmt_vpl VALUES ("C24_2","077_4_2","2CO","4","2","2","αλλα απειπαμεθα τα κρυπτα τησ αισχυνησ μη περιπατουντεσ εν πανουργια μηδε δολουντεσ τον λογον του θεου αλλα τη φανερωσει τησ αληθειασ συνιστωντεσ εαυτουσ προσ πασαν συνειδησιν ανθρωπων ενωπιον του θεου ");
INSERT INTO grcmt_vpl VALUES ("C24_3","077_4_3","2CO","4","3","3","ει δε και εστιν κεκαλυμμενον το ευαγγελιον ημων εν τοισ απολλυμενοισ εστιν κεκαλυμμενον ");
INSERT INTO grcmt_vpl VALUES ("C24_4","077_4_4","2CO","4","4","4","εν οισ ο θεοσ του αιωνοσ τουτου ετυφλωσεν τα νοηματα των απιστων εισ το μη αυγασαι αυτοισ τον φωτισμον του ευαγγελιου τησ δοξησ του χριστου οσ εστιν εικων του θεου ");
INSERT INTO grcmt_vpl VALUES ("C24_5","077_4_5","2CO","4","5","5","ου γαρ εαυτουσ κηρυσσομεν αλλα χριστον ιησουν κυριον εαυτουσ δε δουλουσ υμων δια ιησουν ");
INSERT INTO grcmt_vpl VALUES ("C24_6","077_4_6","2CO","4","6","6","οτι ο θεοσ ο ειπων εκ σκοτουσ φωσ λαμψαι οσ ελαμψεν εν ταισ καρδιαισ ημων προσ φωτισμον τησ γνωσεωσ τησ δοξησ του θεου εν προσωπω ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("C24_7","077_4_7","2CO","4","7","7","εχομεν δε τον θησαυρον τουτον εν οστρακινοισ σκευεσιν ινα η υπερβολη τησ δυναμεωσ η του θεου και μη εξ ημων ");
INSERT INTO grcmt_vpl VALUES ("C24_8","077_4_8","2CO","4","8","8","εν παντι θλιβομενοι αλλ ου στενοχωρουμενοι απορουμενοι αλλ ουκ εξαπορουμενοι ");
INSERT INTO grcmt_vpl VALUES ("C24_9","077_4_9","2CO","4","9","9","διωκομενοι αλλ ουκ εγκαταλειπομενοι καταβαλλομενοι αλλ ουκ απολλυμενοι ");
INSERT INTO grcmt_vpl VALUES ("C24_10","077_4_10","2CO","4","10","10","παντοτε την νεκρωσιν του κυριου ιησου εν τω σωματι περιφεροντεσ ινα και η ζωη του ιησου εν τω σωματι ημων φανερωθη ");
INSERT INTO grcmt_vpl VALUES ("C24_11","077_4_11","2CO","4","11","11","αει γαρ ημεισ οι ζωντεσ εισ θανατον παραδιδομεθα δια ιησουν ινα και η ζωη του ιησου φανερωθη εν τη θνητη σαρκι ημων ");
INSERT INTO grcmt_vpl VALUES ("C24_12","077_4_12","2CO","4","12","12","ωστε ο μεν θανατοσ εν ημιν ενεργειται η δε ζωη εν υμιν ");
INSERT INTO grcmt_vpl VALUES ("C24_13","077_4_13","2CO","4","13","13","εχοντεσ δε το αυτο πνευμα τησ πιστεωσ κατα το γεγραμμενον επιστευσα διο ελαλησα και ημεισ πιστευομεν διο και λαλουμεν ");
INSERT INTO grcmt_vpl VALUES ("C24_14","077_4_14","2CO","4","14","14","ειδοτεσ οτι ο εγειρασ τον κυριον ιησουν και ημασ δια ιησου εγερει και παραστησει συν υμιν ");
INSERT INTO grcmt_vpl VALUES ("C24_15","077_4_15","2CO","4","15","15","τα γαρ παντα δι υμασ ινα η χαρισ πλεονασασα δια των πλειονων την ευχαριστιαν περισσευση εισ την δοξαν του θεου ");
INSERT INTO grcmt_vpl VALUES ("C24_16","077_4_16","2CO","4","16","16","διο ουκ εκκακουμεν αλλ ει και ο εξω ημων ανθρωποσ διαφθειρεται αλλ ο εσωθεν ανακαινουται ημερα και ημερα ");
INSERT INTO grcmt_vpl VALUES ("C24_17","077_4_17","2CO","4","17","17","το γαρ παραυτικα ελαφρον τησ θλιψεωσ ημων καθ υπερβολην εισ υπερβολην αιωνιον βαροσ δοξησ κατεργαζεται ημιν ");
INSERT INTO grcmt_vpl VALUES ("C24_18","077_4_18","2CO","4","18","18","μη σκοπουντων ημων τα βλεπομενα αλλα τα μη βλεπομενα τα γαρ βλεπομενα προσκαιρα τα δε μη βλεπομενα αιωνια ");
INSERT INTO grcmt_vpl VALUES ("C25_1","077_5_1","2CO","5","1","1","οιδαμεν γαρ οτι εαν η επιγειοσ ημων οικια του σκηνουσ καταλυθη οικοδομην εκ θεου εχομεν οικιαν αχειροποιητον αιωνιον εν τοισ ουρανοισ ");
INSERT INTO grcmt_vpl VALUES ("C25_2","077_5_2","2CO","5","2","2","και γαρ εν τουτω στεναζομεν το οικητηριον ημων το εξ ουρανου επενδυσασθαι επιποθουντεσ ");
INSERT INTO grcmt_vpl VALUES ("C25_3","077_5_3","2CO","5","3","3","ειγε και ενδυσαμενοι ου γυμνοι ευρεθησομεθα ");
INSERT INTO grcmt_vpl VALUES ("C25_4","077_5_4","2CO","5","4","4","και γαρ οι οντεσ εν τω σκηνει στεναζομεν βαρουμενοι εφ ω ου θελομεν εκδυσασθαι αλλ επενδυσασθαι ινα καταποθη το θνητον υπο τησ ζωησ ");
INSERT INTO grcmt_vpl VALUES ("C25_5","077_5_5","2CO","5","5","5","ο δε κατεργασαμενοσ ημασ εισ αυτο τουτο θεοσ ο και δουσ ημιν τον αρραβωνα του πνευματοσ ");
INSERT INTO grcmt_vpl VALUES ("C25_6","077_5_6","2CO","5","6","6","θαρρουντεσ ουν παντοτε και ειδοτεσ οτι ενδημουντεσ εν τω σωματι εκδημουμεν απο του κυριου ");
INSERT INTO grcmt_vpl VALUES ("C25_7","077_5_7","2CO","5","7","7","δια πιστεωσ γαρ περιπατουμεν ου δια ειδουσ ");
INSERT INTO grcmt_vpl VALUES ("C25_8","077_5_8","2CO","5","8","8","θαρρουμεν δε και ευδοκουμεν μαλλον εκδημησαι εκ του σωματοσ και ενδημησαι προσ τον κυριον ");
INSERT INTO grcmt_vpl VALUES ("C25_9","077_5_9","2CO","5","9","9","διο και φιλοτιμουμεθα ειτε ενδημουντεσ ειτε εκδημουντεσ ευαρεστοι αυτω ειναι ");
INSERT INTO grcmt_vpl VALUES ("C25_10","077_5_10","2CO","5","10","10","τουσ γαρ παντασ ημασ φανερωθηναι δει εμπροσθεν του βηματοσ του χριστου ινα κομισηται εκαστοσ τα δια του σωματοσ προσ α επραξεν ειτε αγαθον ειτε κακον ");
INSERT INTO grcmt_vpl VALUES ("C25_11","077_5_11","2CO","5","11","11","ειδοτεσ ουν τον φοβον του κυριου ανθρωπουσ πειθομεν θεω δε πεφανερωμεθα ελπιζω δε και εν ταισ συνειδησεσιν υμων πεφανερωσθαι ");
INSERT INTO grcmt_vpl VALUES ("C25_12","077_5_12","2CO","5","12","12","ου γαρ παλιν εαυτουσ συνιστανομεν υμιν αλλα αφορμην διδοντεσ υμιν καυχηματοσ υπερ ημων ινα εχητε προσ τουσ εν προσωπω καυχωμενουσ και ου καρδια ");
INSERT INTO grcmt_vpl VALUES ("C25_13","077_5_13","2CO","5","13","13","ειτε γαρ εξεστημεν θεω ειτε σωφρονουμεν υμιν ");
INSERT INTO grcmt_vpl VALUES ("C25_14","077_5_14","2CO","5","14","14","η γαρ αγαπη του χριστου συνεχει ημασ κριναντασ τουτο οτι ει εισ υπερ παντων απεθανεν αρα οι παντεσ απεθανον ");
INSERT INTO grcmt_vpl VALUES ("C25_15","077_5_15","2CO","5","15","15","και υπερ παντων απεθανεν ινα οι ζωντεσ μηκετι εαυτοισ ζωσιν αλλα τω υπερ αυτων αποθανοντι και εγερθεντι ");
INSERT INTO grcmt_vpl VALUES ("C25_16","077_5_16","2CO","5","16","16","ωστε ημεισ απο του νυν ουδενα οιδαμεν κατα σαρκα ει δε και εγνωκαμεν κατα σαρκα χριστον αλλα νυν ουκετι γινωσκομεν ");
INSERT INTO grcmt_vpl VALUES ("C25_17","077_5_17","2CO","5","17","17","ωστε ει τισ εν χριστω καινη κτισισ τα αρχαια παρηλθεν ιδου γεγονεν καινα τα παντα ");
INSERT INTO grcmt_vpl VALUES ("C25_18","077_5_18","2CO","5","18","18","τα δε παντα εκ του θεου του καταλλαξαντοσ ημασ εαυτω δια ιησου χριστου και δοντοσ ημιν την διακονιαν τησ καταλλαγησ ");
INSERT INTO grcmt_vpl VALUES ("C25_19","077_5_19","2CO","5","19","19","ωσ οτι θεοσ ην εν χριστω κοσμον καταλλασσων εαυτω μη λογιζομενοσ αυτοισ τα παραπτωματα αυτων και θεμενοσ εν ημιν τον λογον τησ καταλλαγησ ");
INSERT INTO grcmt_vpl VALUES ("C25_20","077_5_20","2CO","5","20","20","υπερ χριστου ουν πρεσβευομεν ωσ του θεου παρακαλουντοσ δι ημων δεομεθα υπερ χριστου καταλλαγητε τω θεω ");
INSERT INTO grcmt_vpl VALUES ("C25_21","077_5_21","2CO","5","21","21","τον γαρ μη γνοντα αμαρτιαν υπερ ημων αμαρτιαν εποιησεν ινα ημεισ γενωμεθα δικαιοσυνη θεου εν αυτω ");
INSERT INTO grcmt_vpl VALUES ("C26_1","077_6_1","2CO","6","1","1","συνεργουντεσ δε και παρακαλουμεν μη εισ κενον την χαριν του θεου δεξασθαι υμασ ");
INSERT INTO grcmt_vpl VALUES ("C26_2","077_6_2","2CO","6","2","2","λεγει γαρ καιρω δεκτω επηκουσα σου και εν ημερα σωτηριασ εβοηθησα σοι ιδου νυν καιροσ ευπροσδεκτοσ ιδου νυν ημερα σωτηριασ ");
INSERT INTO grcmt_vpl VALUES ("C26_3","077_6_3","2CO","6","3","3","μηδεμιαν εν μηδενι διδοντεσ προσκοπην ινα μη μωμηθη η διακονια ");
INSERT INTO grcmt_vpl VALUES ("C26_4","077_6_4","2CO","6","4","4","αλλ εν παντι συνιστωντεσ εαυτουσ ωσ θεου διακονοι εν υπομονη πολλη εν θλιψεσιν εν αναγκαισ εν στενοχωριαισ ");
INSERT INTO grcmt_vpl VALUES ("C26_5","077_6_5","2CO","6","5","5","εν πληγαισ εν φυλακαισ εν ακαταστασιαισ εν κοποισ εν αγρυπνιαισ εν νηστειαισ ");
INSERT INTO grcmt_vpl VALUES ("C26_6","077_6_6","2CO","6","6","6","εν αγνοτητι εν γνωσει εν μακροθυμια εν χρηστοτητι εν πνευματι αγιω εν αγαπη ανυποκριτω ");
INSERT INTO grcmt_vpl VALUES ("C26_7","077_6_7","2CO","6","7","7","εν λογω αληθειασ εν δυναμει θεου δια των οπλων τησ δικαιοσυνησ των δεξιων και αριστερων ");
INSERT INTO grcmt_vpl VALUES ("C26_8","077_6_8","2CO","6","8","8","δια δοξησ και ατιμιασ δια δυσφημιασ και ευφημιασ ωσ πλανοι και αληθεισ ");
INSERT INTO grcmt_vpl VALUES ("C26_9","077_6_9","2CO","6","9","9","ωσ αγνοουμενοι και επιγινωσκομενοι ωσ αποθνησκοντεσ και ιδου ζωμεν ωσ παιδευομενοι και μη θανατουμενοι ");
INSERT INTO grcmt_vpl VALUES ("C26_10","077_6_10","2CO","6","10","10","ωσ λυπουμενοι αει δε χαιροντεσ ωσ πτωχοι πολλουσ δε πλουτιζοντεσ ωσ μηδεν εχοντεσ και παντα κατεχοντεσ ");
INSERT INTO grcmt_vpl VALUES ("C26_11","077_6_11","2CO","6","11","11","το στομα ημων ανεωγεν προσ υμασ κορινθιοι η καρδια ημων πεπλατυνται ");
INSERT INTO grcmt_vpl VALUES ("C26_12","077_6_12","2CO","6","12","12","ου στενοχωρεισθε εν ημιν στενοχωρεισθε δε εν τοισ σπλαγχνοισ υμων ");
INSERT INTO grcmt_vpl VALUES ("C26_13","077_6_13","2CO","6","13","13","την δε αυτην αντιμισθιαν ωσ τεκνοισ λεγω πλατυνθητε και υμεισ ");
INSERT INTO grcmt_vpl VALUES ("C26_14","077_6_14","2CO","6","14","14","μη γινεσθε ετεροζυγουντεσ απιστοισ τισ γαρ μετοχη δικαιοσυνη και ανομια τισ δε κοινωνια φωτι προσ σκοτοσ ");
INSERT INTO grcmt_vpl VALUES ("C26_15","077_6_15","2CO","6","15","15","τισ δε συμφωνησισ χριστω προσ βελιαρ η τισ μερισ πιστω μετα απιστου ");
INSERT INTO grcmt_vpl VALUES ("C26_16","077_6_16","2CO","6","16","16","τισ δε συγκαταθεσισ ναω θεου μετα ειδωλων υμεισ γαρ ναοσ θεου εστε ζωντοσ καθωσ ειπεν ο θεοσ οτι ενοικησω εν αυτοισ και εμπεριπατησω και εσομαι αυτων θεοσ και αυτοι εσονται μοι λαοσ ");
INSERT INTO grcmt_vpl VALUES ("C26_17","077_6_17","2CO","6","17","17","διο εξελθετε εκ μεσου αυτων και αφορισθητε λεγει κυριοσ και ακαθαρτου μη απτεσθε καγω εισδεξομαι υμασ ");
INSERT INTO grcmt_vpl VALUES ("C26_18","077_6_18","2CO","6","18","18","και εσομαι υμιν εισ πατερα και υμεισ εσεσθε μοι εισ υιουσ και θυγατερασ λεγει κυριοσ παντοκρατωρ ");
INSERT INTO grcmt_vpl VALUES ("C27_1","077_7_1","2CO","7","1","1","ταυτασ ουν εχοντεσ τασ επαγγελιασ αγαπητοι καθαρισωμεν εαυτουσ απο παντοσ μολυσμου σαρκοσ και πνευματοσ επιτελουντεσ αγιωσυνην εν φοβω θεου ");
INSERT INTO grcmt_vpl VALUES ("C27_2","077_7_2","2CO","7","2","2","χωρησατε ημασ ουδενα ηδικησαμεν ουδενα εφθειραμεν ουδενα επλεονεκτησαμεν ");
INSERT INTO grcmt_vpl VALUES ("C27_3","077_7_3","2CO","7","3","3","ου προσ κατακρισιν λεγω προειρηκα γαρ οτι εν ταισ καρδιαισ ημων εστε εισ το συναποθανειν και συζην ");
INSERT INTO grcmt_vpl VALUES ("C27_4","077_7_4","2CO","7","4","4","πολλη μοι παρρησια προσ υμασ πολλη μοι καυχησισ υπερ υμων πεπληρωμαι τη παρακλησει υπερπερισσευομαι τη χαρα επι παση τη θλιψει ημων ");
INSERT INTO grcmt_vpl VALUES ("C27_5","077_7_5","2CO","7","5","5","και γαρ ελθοντων ημων εισ μακεδονιαν ουδεμιαν εσχηκεν ανεσιν η σαρξ ημων αλλ εν παντι θλιβομενοι εξωθεν μαχαι εσωθεν φοβοι ");
INSERT INTO grcmt_vpl VALUES ("C27_6","077_7_6","2CO","7","6","6","αλλ ο παρακαλων τουσ ταπεινουσ παρεκαλεσεν ημασ ο θεοσ εν τη παρουσια τιτου ");
INSERT INTO grcmt_vpl VALUES ("C27_7","077_7_7","2CO","7","7","7","ου μονον δε εν τη παρουσια αυτου αλλα και εν τη παρακλησει η παρεκληθη εφ υμιν αναγγελλων ημιν την υμων επιποθησιν τον υμων οδυρμον τον υμων ζηλον υπερ εμου ωστε με μαλλον χαρηναι ");
INSERT INTO grcmt_vpl VALUES ("C27_8","077_7_8","2CO","7","8","8","οτι ει και ελυπησα υμασ εν τη επιστολη ου μεταμελομαι ει και μετεμελομην βλεπω γαρ οτι η επιστολη εκεινη ει και προσ ωραν ελυπησεν υμασ ");
INSERT INTO grcmt_vpl VALUES ("C27_9","077_7_9","2CO","7","9","9","νυν χαιρω ουχ οτι ελυπηθητε αλλ οτι ελυπηθητε εισ μετανοιαν ελυπηθητε γαρ κατα θεον ινα εν μηδενι ζημιωθητε εξ ημων ");
INSERT INTO grcmt_vpl VALUES ("C27_10","077_7_10","2CO","7","10","10","η γαρ κατα θεον λυπη μετανοιαν εισ σωτηριαν αμεταμελητον κατεργαζεται η δε του κοσμου λυπη θανατον κατεργαζεται ");
INSERT INTO grcmt_vpl VALUES ("C27_11","077_7_11","2CO","7","11","11","ιδου γαρ αυτο τουτο το κατα θεον λυπηθηναι υμασ ποσην κατειργασατο υμιν σπουδην αλλα απολογιαν αλλα αγανακτησιν αλλα φοβον αλλα επιποθησιν αλλα ζηλον αλλα εκδικησιν εν παντι συνεστησατε εαυτουσ αγνουσ ειναι εν τω πραγματι ");
INSERT INTO grcmt_vpl VALUES ("C27_12","077_7_12","2CO","7","12","12","αρα ει και εγραψα υμιν ουχ εινεκεν του αδικησαντοσ ουδε εινεκεν του αδικηθεντοσ αλλ εινεκεν του φανερωθηναι την σπουδην υμων την υπερ ημων προσ υμασ ενωπιον του θεου ");
INSERT INTO grcmt_vpl VALUES ("C27_13","077_7_13","2CO","7","13","13","δια τουτο παρακεκλημεθα επι δε τη παρακλησει υμων περισσοτερωσ μαλλον εχαρημεν επι τη χαρα τιτου οτι αναπεπαυται το πνευμα αυτου απο παντων υμων ");
INSERT INTO grcmt_vpl VALUES ("C27_14","077_7_14","2CO","7","14","14","οτι ει τι αυτω υπερ υμων κεκαυχημαι ου κατησχυνθην αλλ ωσ παντα εν αληθεια ελαλησαμεν υμιν ουτωσ και η καυχησισ ημων η επι τιτου αληθεια εγενηθη ");
INSERT INTO grcmt_vpl VALUES ("C27_15","077_7_15","2CO","7","15","15","και τα σπλαγχνα αυτου περισσοτερωσ εισ υμασ εστιν αναμιμνησκομενου την παντων υμων υπακοην ωσ μετα φοβου και τρομου εδεξασθε αυτον ");
INSERT INTO grcmt_vpl VALUES ("C27_16","077_7_16","2CO","7","16","16","χαιρω οτι εν παντι θαρρω εν υμιν ");
INSERT INTO grcmt_vpl VALUES ("C28_1","077_8_1","2CO","8","1","1","γνωριζομεν δε υμιν αδελφοι την χαριν του θεου την δεδομενην εν ταισ εκκλησιαισ τησ μακεδονιασ ");
INSERT INTO grcmt_vpl VALUES ("C28_2","077_8_2","2CO","8","2","2","οτι εν πολλη δοκιμη θλιψεωσ η περισσεια τησ χαρασ αυτων και η κατα βαθουσ πτωχεια αυτων επερισσευσεν εισ τον πλουτον τησ απλοτητοσ αυτων ");
INSERT INTO grcmt_vpl VALUES ("C28_3","077_8_3","2CO","8","3","3","οτι κατα δυναμιν μαρτυρω και υπερ δυναμιν αυθαιρετοι ");
INSERT INTO grcmt_vpl VALUES ("C28_4","077_8_4","2CO","8","4","4","μετα πολλησ παρακλησεωσ δεομενοι ημων την χαριν και την κοινωνιαν τησ διακονιασ τησ εισ τουσ αγιουσ ");
INSERT INTO grcmt_vpl VALUES ("C28_5","077_8_5","2CO","8","5","5","και ου καθωσ ηλπισαμεν αλλ εαυτουσ εδωκαν πρωτον τω κυριω και ημιν δια θεληματοσ θεου ");
INSERT INTO grcmt_vpl VALUES ("C28_6","077_8_6","2CO","8","6","6","εισ το παρακαλεσαι ημασ τιτον ινα καθωσ προενηρξατο ουτωσ και επιτελεση εισ υμασ και την χαριν ταυτην ");
INSERT INTO grcmt_vpl VALUES ("C28_7","077_8_7","2CO","8","7","7","αλλ ωσπερ εν παντι περισσευετε πιστει και λογω και γνωσει και παση σπουδη και τη εξ υμων εν ημιν αγαπη ινα και εν ταυτη τη χαριτι περισσευητε ");
INSERT INTO grcmt_vpl VALUES ("C28_8","077_8_8","2CO","8","8","8","ου κατ επιταγην λεγω αλλα δια τησ ετερων σπουδησ και το τησ υμετερασ αγαπησ γνησιον δοκιμαζων ");
INSERT INTO grcmt_vpl VALUES ("C28_9","077_8_9","2CO","8","9","9","γινωσκετε γαρ την χαριν του κυριου ημων ιησου χριστου οτι δι υμασ επτωχευσεν πλουσιοσ ων ινα υμεισ τη εκεινου πτωχεια πλουτησητε ");
INSERT INTO grcmt_vpl VALUES ("C28_10","077_8_10","2CO","8","10","10","και γνωμην εν τουτω διδωμι τουτο γαρ υμιν συμφερει οιτινεσ ου μονον το ποιησαι αλλα και το θελειν προενηρξασθε απο περυσι ");
INSERT INTO grcmt_vpl VALUES ("C28_11","077_8_11","2CO","8","11","11","νυνι δε και το ποιησαι επιτελεσατε οπωσ καθαπερ η προθυμια του θελειν ουτωσ και το επιτελεσαι εκ του εχειν ");
INSERT INTO grcmt_vpl VALUES ("C28_12","077_8_12","2CO","8","12","12","ει γαρ η προθυμια προκειται καθο εαν εχη τισ ευπροσδεκτοσ ου καθο ουκ εχει ");
INSERT INTO grcmt_vpl VALUES ("C28_13","077_8_13","2CO","8","13","13","ου γαρ ινα αλλοισ ανεσισ υμιν δε θλιψισ αλλ εξ ισοτητοσ εν τω νυν καιρω το υμων περισσευμα εισ το εκεινων υστερημα ");
INSERT INTO grcmt_vpl VALUES ("C28_14","077_8_14","2CO","8","14","14","ινα και το εκεινων περισσευμα γενηται εισ το υμων υστερημα οπωσ γενηται ισοτησ ");
INSERT INTO grcmt_vpl VALUES ("C28_15","077_8_15","2CO","8","15","15","καθωσ γεγραπται ο το πολυ ουκ επλεονασεν και ο το ολιγον ουκ ηλαττονησεν ");
INSERT INTO grcmt_vpl VALUES ("C28_16","077_8_16","2CO","8","16","16","χαρισ δε τω θεω τω διδοντι την αυτην σπουδην υπερ υμων εν τη καρδια τιτου ");
INSERT INTO grcmt_vpl VALUES ("C28_17","077_8_17","2CO","8","17","17","οτι την μεν παρακλησιν εδεξατο σπουδαιοτεροσ δε υπαρχων αυθαιρετοσ εξηλθεν προσ υμασ ");
INSERT INTO grcmt_vpl VALUES ("C28_18","077_8_18","2CO","8","18","18","συνεπεμψαμεν δε μετ αυτου τον αδελφον ου ο επαινοσ εν τω ευαγγελιω δια πασων των εκκλησιων ");
INSERT INTO grcmt_vpl VALUES ("C28_19","077_8_19","2CO","8","19","19","ου μονον δε αλλα και χειροτονηθεισ υπο των εκκλησιων συνεκδημοσ ημων συν τη χαριτι ταυτη τη διακονουμενη υφ ημων προσ την αυτου του κυριου δοξαν και προθυμιαν ημων ");
INSERT INTO grcmt_vpl VALUES ("C28_20","077_8_20","2CO","8","20","20","στελλομενοι τουτο μη τισ ημασ μωμησηται εν τη αδροτητι ταυτη τη διακονουμενη υφ ημων ");
INSERT INTO grcmt_vpl VALUES ("C28_21","077_8_21","2CO","8","21","21","προνοουμενοι καλα ου μονον ενωπιον κυριου αλλα και ενωπιον ανθρωπων ");
INSERT INTO grcmt_vpl VALUES ("C28_22","077_8_22","2CO","8","22","22","συνεπεμψαμεν δε αυτοισ τον αδελφον ημων ον εδοκιμασαμεν εν πολλοισ πολλακισ σπουδαιον οντα νυνι δε πολυ σπουδαιοτερον πεποιθησει πολλη τη εισ υμασ ");
INSERT INTO grcmt_vpl VALUES ("C28_23","077_8_23","2CO","8","23","23","ειτε υπερ τιτου κοινωνοσ εμοσ και εισ υμασ συνεργοσ ειτε αδελφοι ημων αποστολοι εκκλησιων δοξα χριστου ");
INSERT INTO grcmt_vpl VALUES ("C28_24","077_8_24","2CO","8","24","24","την ουν ενδειξιν τησ αγαπησ υμων και ημων καυχησεωσ υπερ υμων εισ αυτουσ ενδειξασθε εισ προσωπον των εκκλησιων ");
INSERT INTO grcmt_vpl VALUES ("C29_1","077_9_1","2CO","9","1","1","περι μεν γαρ τησ διακονιασ τησ εισ τουσ αγιουσ περισσον μοι εστιν το γραφειν υμιν ");
INSERT INTO grcmt_vpl VALUES ("C29_2","077_9_2","2CO","9","2","2","οιδα γαρ την προθυμιαν υμων ην υπερ υμων καυχωμαι μακεδοσιν οτι αχαια παρεσκευασται απο περυσι και ο εξ υμων ζηλοσ ηρεθισεν τουσ πλειονασ ");
INSERT INTO grcmt_vpl VALUES ("C29_3","077_9_3","2CO","9","3","3","επεμψα δε τουσ αδελφουσ ινα μη το καυχημα ημων το υπερ υμων κενωθη εν τω μερει τουτω ινα καθωσ ελεγον παρεσκευασμενοι ητε ");
INSERT INTO grcmt_vpl VALUES ("C29_4","077_9_4","2CO","9","4","4","μηπωσ εαν ελθωσιν συν εμοι μακεδονεσ και ευρωσιν υμασ απαρασκευαστουσ καταισχυνθωμεν ημεισ ινα μη λεγωμεν υμεισ εν τη υποστασει ταυτη τησ καυχησεωσ ");
INSERT INTO grcmt_vpl VALUES ("C29_5","077_9_5","2CO","9","5","5","αναγκαιον ουν ηγησαμην παρακαλεσαι τουσ αδελφουσ ινα προελθωσιν εισ υμασ και προκαταρτισωσιν την προκατηγγελμενην ευλογιαν υμων ταυτην ετοιμην ειναι ουτωσ ωσ ευλογιαν και μη ωσ πλεονεξιαν ");
INSERT INTO grcmt_vpl VALUES ("C29_6","077_9_6","2CO","9","6","6","τουτο δε ο σπειρων φειδομενωσ φειδομενωσ και θερισει και ο σπειρων επ ευλογιαισ επ ευλογιαισ και θερισει ");
INSERT INTO grcmt_vpl VALUES ("C29_7","077_9_7","2CO","9","7","7","εκαστοσ καθωσ προαιρειται τη καρδια μη εκ λυπησ η εξ αναγκησ ιλαρον γαρ δοτην αγαπα ο θεοσ ");
INSERT INTO grcmt_vpl VALUES ("C29_8","077_9_8","2CO","9","8","8","δυνατοσ δε ο θεοσ πασαν χαριν περισσευσαι εισ υμασ ινα εν παντι παντοτε πασαν αυταρκειαν εχοντεσ περισσευητε εισ παν εργον αγαθον ");
INSERT INTO grcmt_vpl VALUES ("C29_9","077_9_9","2CO","9","9","9","καθωσ γεγραπται εσκορπισεν εδωκεν τοισ πενησιν η δικαιοσυνη αυτου μενει εισ τον αιωνα ");
INSERT INTO grcmt_vpl VALUES ("C29_10","077_9_10","2CO","9","10","10","ο δε επιχορηγων σπερμα τω σπειροντι και αρτον εισ βρωσιν χορηγησαι και πληθυναι τον σπορον υμων και αυξησαι τα γενηματα τησ δικαιοσυνησ υμων ");
INSERT INTO grcmt_vpl VALUES ("C29_11","077_9_11","2CO","9","11","11","εν παντι πλουτιζομενοι εισ πασαν απλοτητα ητισ κατεργαζεται δι ημων ευχαριστιαν τω θεω ");
INSERT INTO grcmt_vpl VALUES ("C29_12","077_9_12","2CO","9","12","12","οτι η διακονια τησ λειτουργιασ ταυτησ ου μονον εστιν προσαναπληρουσα τα υστερηματα των αγιων αλλα και περισσευουσα δια πολλων ευχαριστιων τω θεω ");
INSERT INTO grcmt_vpl VALUES ("C29_13","077_9_13","2CO","9","13","13","δια τησ δοκιμησ τησ διακονιασ ταυτησ δοξαζοντεσ τον θεον επι τη υποταγη τησ ομολογιασ υμων εισ το ευαγγελιον του χριστου και απλοτητι τησ κοινωνιασ εισ αυτουσ και εισ παντασ ");
INSERT INTO grcmt_vpl VALUES ("C29_14","077_9_14","2CO","9","14","14","και αυτων δεησει υπερ υμων επιποθουντων υμασ δια την υπερβαλλουσαν χαριν του θεου εφ υμιν ");
INSERT INTO grcmt_vpl VALUES ("C29_15","077_9_15","2CO","9","15","15","χαρισ δε τω θεω επι τη ανεκδιηγητω αυτου δωρεα ");
INSERT INTO grcmt_vpl VALUES ("C210_1","077_10_1","2CO","10","1","1","αυτοσ δε εγω παυλοσ παρακαλω υμασ δια τησ πραοτητοσ και επιεικειασ του χριστου οσ κατα προσωπον μεν ταπεινοσ εν υμιν απων δε θαρρω εισ υμασ ");
INSERT INTO grcmt_vpl VALUES ("C210_2","077_10_2","2CO","10","2","2","δεομαι δε το μη παρων θαρρησαι τη πεποιθησει η λογιζομαι τολμησαι επι τινασ τουσ λογιζομενουσ ημασ ωσ κατα σαρκα περιπατουντασ ");
INSERT INTO grcmt_vpl VALUES ("C210_3","077_10_3","2CO","10","3","3","εν σαρκι γαρ περιπατουντεσ ου κατα σαρκα στρατευομεθα ");
INSERT INTO grcmt_vpl VALUES ("C210_4","077_10_4","2CO","10","4","4","τα γαρ οπλα τησ στρατειασ ημων ου σαρκικα αλλα δυνατα τω θεω προσ καθαιρεσιν οχυρωματων ");
INSERT INTO grcmt_vpl VALUES ("C210_5","077_10_5","2CO","10","5","5","λογισμουσ καθαιρουντεσ και παν υψωμα επαιρομενον κατα τησ γνωσεωσ του θεου και αιχμαλωτιζοντεσ παν νοημα εισ την υπακοην του χριστου ");
INSERT INTO grcmt_vpl VALUES ("C210_6","077_10_6","2CO","10","6","6","και εν ετοιμω εχοντεσ εκδικησαι πασαν παρακοην οταν πληρωθη υμων η υπακοη ");
INSERT INTO grcmt_vpl VALUES ("C210_7","077_10_7","2CO","10","7","7","τα κατα προσωπον βλεπετε ει τισ πεποιθεν εαυτω χριστου ειναι τουτο λογιζεσθω παλιν αφ εαυτου οτι καθωσ αυτοσ χριστου ουτωσ και ημεισ χριστου ");
INSERT INTO grcmt_vpl VALUES ("C210_8","077_10_8","2CO","10","8","8","εαν τε γαρ και περισσοτερον τι καυχησωμαι περι τησ εξουσιασ ημων ησ εδωκεν ο κυριοσ ημιν εισ οικοδομην και ουκ εισ καθαιρεσιν υμων ουκ αισχυνθησομαι ");
INSERT INTO grcmt_vpl VALUES ("C210_9","077_10_9","2CO","10","9","9","ινα μη δοξω ωσ αν εκφοβειν υμασ δια των επιστολων ");
INSERT INTO grcmt_vpl VALUES ("C210_10","077_10_10","2CO","10","10","10","οτι αι μεν επιστολαι φησιν βαρειαι και ισχυραι η δε παρουσια του σωματοσ ασθενησ και ο λογοσ εξουθενημενοσ ");
INSERT INTO grcmt_vpl VALUES ("C210_11","077_10_11","2CO","10","11","11","τουτο λογιζεσθω ο τοιουτοσ οτι οιοι εσμεν τω λογω δι επιστολων αποντεσ τοιουτοι και παροντεσ τω εργω ");
INSERT INTO grcmt_vpl VALUES ("C210_12","077_10_12","2CO","10","12","12","ου γαρ τολμωμεν εγκριναι η συγκριναι εαυτουσ τισιν των εαυτουσ συνιστανοντων αλλα αυτοι εν εαυτοισ εαυτουσ μετρουντεσ και συγκρινοντεσ εαυτουσ εαυτοισ ου συνιουσιν ");
INSERT INTO grcmt_vpl VALUES ("C210_13","077_10_13","2CO","10","13","13","ημεισ δε ουχι εισ τα αμετρα καυχησομεθα αλλα κατα το μετρον του κανονοσ ου εμερισεν ημιν ο θεοσ μετρου εφικεσθαι αχρι και υμων ");
INSERT INTO grcmt_vpl VALUES ("C210_14","077_10_14","2CO","10","14","14","ου γαρ ωσ μη εφικνουμενοι εισ υμασ υπερεκτεινομεν εαυτουσ αχρι γαρ και υμων εφθασαμεν εν τω ευαγγελιω του χριστου ");
INSERT INTO grcmt_vpl VALUES ("C210_15","077_10_15","2CO","10","15","15","ουκ εισ τα αμετρα καυχωμενοι εν αλλοτριοισ κοποισ ελπιδα δε εχοντεσ αυξανομενησ τησ πιστεωσ υμων εν υμιν μεγαλυνθηναι κατα τον κανονα ημων εισ περισσειαν ");
INSERT INTO grcmt_vpl VALUES ("C210_16","077_10_16","2CO","10","16","16","εισ τα υπερεκεινα υμων ευαγγελισασθαι ουκ εν αλλοτριω κανονι εισ τα ετοιμα καυχησασθαι ");
INSERT INTO grcmt_vpl VALUES ("C210_17","077_10_17","2CO","10","17","17","ο δε καυχωμενοσ εν κυριω καυχασθω ");
INSERT INTO grcmt_vpl VALUES ("C210_18","077_10_18","2CO","10","18","18","ου γαρ ο εαυτον συνιστων εκεινοσ εστιν δοκιμοσ αλλ ον ο κυριοσ συνιστησιν ");
INSERT INTO grcmt_vpl VALUES ("C211_1","077_11_1","2CO","11","1","1","οφελον ανειχεσθε μου μικρον τη αφροσυνη αλλα και ανεχεσθε μου ");
INSERT INTO grcmt_vpl VALUES ("C211_2","077_11_2","2CO","11","2","2","ζηλω γαρ υμασ θεου ζηλω ηρμοσαμην γαρ υμασ ενι ανδρι παρθενον αγνην παραστησαι τω χριστω ");
INSERT INTO grcmt_vpl VALUES ("C211_3","077_11_3","2CO","11","3","3","φοβουμαι δε μηπωσ ωσ ο οφισ ευαν εξηπατησεν εν τη πανουργια αυτου ουτωσ φθαρη τα νοηματα υμων απο τησ απλοτητοσ τησ εισ τον χριστον ");
INSERT INTO grcmt_vpl VALUES ("C211_4","077_11_4","2CO","11","4","4","ει μεν γαρ ο ερχομενοσ αλλον ιησουν κηρυσσει ον ουκ εκηρυξαμεν η πνευμα ετερον λαμβανετε ο ουκ ελαβετε η ευαγγελιον ετερον ο ουκ εδεξασθε καλωσ ηνειχεσθε ");
INSERT INTO grcmt_vpl VALUES ("C211_5","077_11_5","2CO","11","5","5","λογιζομαι γαρ μηδεν υστερηκεναι των υπερ λιαν αποστολων ");
INSERT INTO grcmt_vpl VALUES ("C211_6","077_11_6","2CO","11","6","6","ει δε και ιδιωτησ τω λογω αλλ ου τη γνωσει αλλ εν παντι φανερωθεντεσ εν πασιν εισ υμασ ");
INSERT INTO grcmt_vpl VALUES ("C211_7","077_11_7","2CO","11","7","7","η αμαρτιαν εποιησα εμαυτον ταπεινων ινα υμεισ υψωθητε οτι δωρεαν το του θεου ευαγγελιον ευηγγελισαμην υμιν ");
INSERT INTO grcmt_vpl VALUES ("C211_8","077_11_8","2CO","11","8","8","αλλασ εκκλησιασ εσυλησα λαβων οψωνιον προσ την υμων διακονιαν ");
INSERT INTO grcmt_vpl VALUES ("C211_9","077_11_9","2CO","11","9","9","και παρων προσ υμασ και υστερηθεισ ου κατεναρκησα ουδενοσ το γαρ υστερημα μου προσανεπληρωσαν οι αδελφοι ελθοντεσ απο μακεδονιασ και εν παντι αβαρη υμιν εμαυτον ετηρησα και τηρησω ");
INSERT INTO grcmt_vpl VALUES ("C211_10","077_11_10","2CO","11","10","10","εστιν αληθεια χριστου εν εμοι οτι η καυχησισ αυτη ου φραγησεται εισ εμε εν τοισ κλιμασιν τησ αχαιασ ");
INSERT INTO grcmt_vpl VALUES ("C211_11","077_11_11","2CO","11","11","11","δια τι οτι ουκ αγαπω υμασ ο θεοσ οιδεν ");
INSERT INTO grcmt_vpl VALUES ("C211_12","077_11_12","2CO","11","12","12","ο δε ποιω και ποιησω ινα εκκοψω την αφορμην των θελοντων αφορμην ινα εν ω καυχωνται ευρεθωσιν καθωσ και ημεισ ");
INSERT INTO grcmt_vpl VALUES ("C211_13","077_11_13","2CO","11","13","13","οι γαρ τοιουτοι ψευδαποστολοι εργαται δολιοι μετασχηματιζομενοι εισ αποστολουσ χριστου ");
INSERT INTO grcmt_vpl VALUES ("C211_14","077_11_14","2CO","11","14","14","και ου θαυμαστον αυτοσ γαρ ο σατανασ μετασχηματιζεται εισ αγγελον φωτοσ ");
INSERT INTO grcmt_vpl VALUES ("C211_15","077_11_15","2CO","11","15","15","ου μεγα ουν ει και οι διακονοι αυτου μετασχηματιζονται ωσ διακονοι δικαιοσυνησ ων το τελοσ εσται κατα τα εργα αυτων ");
INSERT INTO grcmt_vpl VALUES ("C211_16","077_11_16","2CO","11","16","16","παλιν λεγω μη τισ με δοξη αφρονα ειναι ει δε μηγε καν ωσ αφρονα δεξασθε με ινα καγω μικρον τι καυχησωμαι ");
INSERT INTO grcmt_vpl VALUES ("C211_17","077_11_17","2CO","11","17","17","ο λαλω ου λαλω κατα κυριον αλλ ωσ εν αφροσυνη εν ταυτη τη υποστασει τησ καυχησεωσ ");
INSERT INTO grcmt_vpl VALUES ("C211_18","077_11_18","2CO","11","18","18","επει πολλοι καυχωνται κατα την σαρκα καγω καυχησομαι ");
INSERT INTO grcmt_vpl VALUES ("C211_19","077_11_19","2CO","11","19","19","ηδεωσ γαρ ανεχεσθε των αφρονων φρονιμοι οντεσ ");
INSERT INTO grcmt_vpl VALUES ("C211_20","077_11_20","2CO","11","20","20","ανεχεσθε γαρ ει τισ υμασ καταδουλοι ει τισ κατεσθιει ει τισ λαμβανει ει τισ επαιρεται ει τισ υμασ εισ προσωπον δερει ");
INSERT INTO grcmt_vpl VALUES ("C211_21","077_11_21","2CO","11","21","21","κατα ατιμιαν λεγω ωσ οτι ημεισ ησθενησαμεν εν ω δ αν τισ τολμα εν αφροσυνη λεγω τολμω καγω ");
INSERT INTO grcmt_vpl VALUES ("C211_22","077_11_22","2CO","11","22","22","εβραιοι εισιν καγω ισραηλιται εισιν καγω σπερμα αβρααμ εισιν καγω ");
INSERT INTO grcmt_vpl VALUES ("C211_23","077_11_23","2CO","11","23","23","διακονοι χριστου εισιν παραφρονων λαλω υπερ εγω εν κοποισ περισσοτερωσ εν πληγαισ υπερβαλλοντωσ εν φυλακαισ περισσοτερωσ εν θανατοισ πολλακισ ");
INSERT INTO grcmt_vpl VALUES ("C211_24","077_11_24","2CO","11","24","24","υπο ιουδαιων πεντακισ τεσσαρακοντα παρα μιαν ελαβον ");
INSERT INTO grcmt_vpl VALUES ("C211_25","077_11_25","2CO","11","25","25","τρισ εραβδισθην απαξ ελιθασθην τρισ εναυαγησα νυχθημερον εν τω βυθω πεποιηκα ");
INSERT INTO grcmt_vpl VALUES ("C211_26","077_11_26","2CO","11","26","26","οδοιποριαισ πολλακισ κινδυνοισ ποταμων κινδυνοισ ληστων κινδυνοισ εκ γενουσ κινδυνοισ εξ εθνων κινδυνοισ εν πολει κινδυνοισ εν ερημια κινδυνοισ εν θαλασση κινδυνοισ εν ψευδαδελφοισ ");
INSERT INTO grcmt_vpl VALUES ("C211_27","077_11_27","2CO","11","27","27","εν κοπω και μοχθω εν αγρυπνιαισ πολλακισ εν λιμω και διψει εν νηστειαισ πολλακισ εν ψυχει και γυμνοτητι ");
INSERT INTO grcmt_vpl VALUES ("C211_28","077_11_28","2CO","11","28","28","χωρισ των παρεκτοσ η επισυστασισ μου η καθ ημεραν η μεριμνα πασων των εκκλησιων ");
INSERT INTO grcmt_vpl VALUES ("C211_29","077_11_29","2CO","11","29","29","τισ ασθενει και ουκ ασθενω τισ σκανδαλιζεται και ουκ εγω πυρουμαι ");
INSERT INTO grcmt_vpl VALUES ("C211_30","077_11_30","2CO","11","30","30","ει καυχασθαι δει τα τησ ασθενειασ μου καυχησομαι ");
INSERT INTO grcmt_vpl VALUES ("C211_31","077_11_31","2CO","11","31","31","ο θεοσ και πατηρ του κυριου ιησου χριστου οιδεν ο ων ευλογητοσ εισ τουσ αιωνασ οτι ου ψευδομαι ");
INSERT INTO grcmt_vpl VALUES ("C211_32","077_11_32","2CO","11","32","32","εν δαμασκω ο εθναρχησ αρετα του βασιλεωσ εφρουρει την δαμασκηνων πολιν πιασαι με θελων ");
INSERT INTO grcmt_vpl VALUES ("C211_33","077_11_33","2CO","11","33","33","και δια θυριδοσ εν σαργανη εχαλασθην δια του τειχουσ και εξεφυγον τασ χειρασ αυτου ");
INSERT INTO grcmt_vpl VALUES ("C212_1","077_12_1","2CO","12","1","1","καυχασθαι δη ου συμφερει μοι ελευσομαι γαρ εισ οπτασιασ και αποκαλυψεισ κυριου ");
INSERT INTO grcmt_vpl VALUES ("C212_2","077_12_2","2CO","12","2","2","οιδα ανθρωπον εν χριστω προ ετων δεκατεσσαρων ειτε εν σωματι ουκ οιδα ειτε εκτοσ του σωματοσ ουκ οιδα ο θεοσ οιδεν αρπαγεντα τον τοιουτον εωσ τριτου ουρανου ");
INSERT INTO grcmt_vpl VALUES ("C212_3","077_12_3","2CO","12","3","3","και οιδα τον τοιουτον ανθρωπον ειτε εν σωματι ειτε εκτοσ του σωματοσ ουκ οιδα ο θεοσ οιδεν ");
INSERT INTO grcmt_vpl VALUES ("C212_4","077_12_4","2CO","12","4","4","οτι ηρπαγη εισ τον παραδεισον και ηκουσεν αρρητα ρηματα α ουκ εξον ανθρωπω λαλησαι ");
INSERT INTO grcmt_vpl VALUES ("C212_5","077_12_5","2CO","12","5","5","υπερ του τοιουτου καυχησομαι υπερ δε εμαυτου ου καυχησομαι ει μη εν ταισ ασθενειαισ μου ");
INSERT INTO grcmt_vpl VALUES ("C212_6","077_12_6","2CO","12","6","6","εαν γαρ θελησω καυχησασθαι ουκ εσομαι αφρων αληθειαν γαρ ερω φειδομαι δε μη τισ εισ εμε λογισηται υπερ ο βλεπει με η ακουει τι εξ εμου ");
INSERT INTO grcmt_vpl VALUES ("C212_7","077_12_7","2CO","12","7","7","και τη υπερβολη των αποκαλυψεων ινα μη υπεραιρωμαι εδοθη μοι σκολοψ τη σαρκι αγγελοσ σαταν ινα με κολαφιζη ινα μη υπεραιρωμαι ");
INSERT INTO grcmt_vpl VALUES ("C212_8","077_12_8","2CO","12","8","8","υπερ τουτου τρισ τον κυριον παρεκαλεσα ινα αποστη απ εμου ");
INSERT INTO grcmt_vpl VALUES ("C212_9","077_12_9","2CO","12","9","9","και ειρηκεν μοι αρκει σοι η χαρισ μου η γαρ δυναμισ μου εν ασθενεια τελειουται ηδιστα ουν μαλλον καυχησομαι εν ταισ ασθενειαισ μου ινα επισκηνωση επ εμε η δυναμισ του χριστου ");
INSERT INTO grcmt_vpl VALUES ("C212_10","077_12_10","2CO","12","10","10","διο ευδοκω εν ασθενειαισ εν υβρεσιν εν αναγκαισ εν διωγμοισ εν στενοχωριαισ υπερ χριστου οταν γαρ ασθενω τοτε δυνατοσ ειμι ");
INSERT INTO grcmt_vpl VALUES ("C212_11","077_12_11","2CO","12","11","11","γεγονα αφρων καυχωμενοσ υμεισ με ηναγκασατε εγω γαρ ωφειλον υφ υμων συνιστασθαι ουδεν γαρ υστερησα των υπερ λιαν αποστολων ει και ουδεν ειμι ");
INSERT INTO grcmt_vpl VALUES ("C212_12","077_12_12","2CO","12","12","12","τα μεν σημεια του αποστολου κατειργασθη εν υμιν εν παση υπομονη εν σημειοισ και τερασιν και δυναμεσιν ");
INSERT INTO grcmt_vpl VALUES ("C212_13","077_12_13","2CO","12","13","13","τι γαρ εστιν ο ηττηθητε υπερ τασ λοιπασ εκκλησιασ ει μη οτι αυτοσ εγω ου κατεναρκησα υμων χαρισασθε μοι την αδικιαν ταυτην ");
INSERT INTO grcmt_vpl VALUES ("C212_14","077_12_14","2CO","12","14","14","ιδου τριτον ετοιμωσ εχω ελθειν προσ υμασ και ου καταναρκησω υμων ου γαρ ζητω τα υμων αλλα υμασ ου γαρ οφειλει τα τεκνα τοισ γονευσιν θησαυριζειν αλλ οι γονεισ τοισ τεκνοισ ");
INSERT INTO grcmt_vpl VALUES ("C212_15","077_12_15","2CO","12","15","15","εγω δε ηδιστα δαπανησω και εκδαπανηθησομαι υπερ των ψυχων υμων ει και περισσοτερωσ υμασ αγαπων ηττον αγαπωμαι ");
INSERT INTO grcmt_vpl VALUES ("C212_16","077_12_16","2CO","12","16","16","εστω δε εγω ου κατεβαρησα υμασ αλλ υπαρχων πανουργοσ δολω υμασ ελαβον ");
INSERT INTO grcmt_vpl VALUES ("C212_17","077_12_17","2CO","12","17","17","μη τινα ων απεσταλκα προσ υμασ δι αυτου επλεονεκτησα υμασ ");
INSERT INTO grcmt_vpl VALUES ("C212_18","077_12_18","2CO","12","18","18","παρεκαλεσα τιτον και συναπεστειλα τον αδελφον μητι επλεονεκτησεν υμασ τιτοσ ου τω αυτω πνευματι περιεπατησαμεν ου τοισ αυτοισ ιχνεσιν ");
INSERT INTO grcmt_vpl VALUES ("C212_19","077_12_19","2CO","12","19","19","παλιν δοκειτε οτι υμιν απολογουμεθα κατενωπιον του θεου εν χριστω λαλουμεν τα δε παντα αγαπητοι υπερ τησ υμων οικοδομησ ");
INSERT INTO grcmt_vpl VALUES ("C212_20","077_12_20","2CO","12","20","20","φοβουμαι γαρ μηπωσ ελθων ουχ οιουσ θελω ευρω υμασ καγω ευρεθω υμιν οιον ου θελετε μηπωσ ερεισ ζηλοι θυμοι εριθειαι καταλαλιαι ψιθυρισμοι φυσιωσεισ ακαταστασιαι ");
INSERT INTO grcmt_vpl VALUES ("C212_21","077_12_21","2CO","12","21","21","μη παλιν ελθοντα με ταπεινωσει ο θεοσ μου προσ υμασ και πενθησω πολλουσ των προημαρτηκοτων και μη μετανοησαντων επι τη ακαθαρσια και πορνεια και ασελγεια η επραξαν ");
INSERT INTO grcmt_vpl VALUES ("C213_1","077_13_1","2CO","13","1","1","τριτον τουτο ερχομαι προσ υμασ επι στοματοσ δυο μαρτυρων και τριων σταθησεται παν ρημα ");
INSERT INTO grcmt_vpl VALUES ("C213_2","077_13_2","2CO","13","2","2","προειρηκα και προλεγω ωσ παρων το δευτερον και απων νυν γραφω τοισ προημαρτηκοσιν και τοισ λοιποισ πασιν οτι εαν ελθω εισ το παλιν ου φεισομαι ");
INSERT INTO grcmt_vpl VALUES ("C213_3","077_13_3","2CO","13","3","3","επει δοκιμην ζητειτε του εν εμοι λαλουντοσ χριστου οσ εισ υμασ ουκ ασθενει αλλα δυνατει εν υμιν ");
INSERT INTO grcmt_vpl VALUES ("C213_4","077_13_4","2CO","13","4","4","και γαρ ει εσταυρωθη εξ ασθενειασ αλλα ζη εκ δυναμεωσ θεου και γαρ ημεισ ασθενουμεν εν αυτω αλλα ζησομεθα συν αυτω εκ δυναμεωσ θεου εισ υμασ ");
INSERT INTO grcmt_vpl VALUES ("C213_5","077_13_5","2CO","13","5","5","εαυτουσ πειραζετε ει εστε εν τη πιστει εαυτουσ δοκιμαζετε η ουκ επιγινωσκετε εαυτουσ οτι ιησουσ χριστοσ εν υμιν εστιν ει μητι αδοκιμοι εστε ");
INSERT INTO grcmt_vpl VALUES ("C213_6","077_13_6","2CO","13","6","6","ελπιζω δε οτι γνωσεσθε οτι ημεισ ουκ εσμεν αδοκιμοι ");
INSERT INTO grcmt_vpl VALUES ("C213_7","077_13_7","2CO","13","7","7","ευχομαι δε προσ τον θεον μη ποιησαι υμασ κακον μηδεν ουχ ινα ημεισ δοκιμοι φανωμεν αλλ ινα υμεισ το καλον ποιητε ημεισ δε ωσ αδοκιμοι ωμεν ");
INSERT INTO grcmt_vpl VALUES ("C213_8","077_13_8","2CO","13","8","8","ου γαρ δυναμεθα τι κατα τησ αληθειασ αλλ υπερ τησ αληθειασ ");
INSERT INTO grcmt_vpl VALUES ("C213_9","077_13_9","2CO","13","9","9","χαιρομεν γαρ οταν ημεισ ασθενωμεν υμεισ δε δυνατοι ητε τουτο δε και ευχομεθα την υμων καταρτισιν ");
INSERT INTO grcmt_vpl VALUES ("C213_10","077_13_10","2CO","13","10","10","δια τουτο ταυτα απων γραφω ινα παρων μη αποτομωσ χρησωμαι κατα την εξουσιαν ην εδωκεν μοι ο κυριοσ εισ οικοδομην και ουκ εισ καθαιρεσιν ");
INSERT INTO grcmt_vpl VALUES ("C213_11","077_13_11","2CO","13","11","11","λοιπον αδελφοι χαιρετε καταρτιζεσθε παρακαλεισθε το αυτο φρονειτε ειρηνευετε και ο θεοσ τησ αγαπησ και ειρηνησ εσται μεθ υμων ");
INSERT INTO grcmt_vpl VALUES ("C213_12","077_13_12","2CO","13","12","12","ασπασασθε αλληλουσ εν αγιω φιληματι ");
INSERT INTO grcmt_vpl VALUES ("C213_13","077_13_13","2CO","13","13","13","ασπαζονται υμασ οι αγιοι παντεσ ");
INSERT INTO grcmt_vpl VALUES ("C213_14","077_13_14","2CO","13","14","14","η χαρισ του κυριου ιησου χριστου και η αγαπη του θεου και η κοινωνια του αγιου πνευματοσ μετα παντων υμων αμην ");
INSERT INTO grcmt_vpl VALUES ("GL1_1","078_1_1","GAL","1","1","1","παυλοσ αποστολοσ ουκ απ ανθρωπων ουδε δι ανθρωπου αλλα δια ιησου χριστου και θεου πατροσ του εγειραντοσ αυτον εκ νεκρων ");
INSERT INTO grcmt_vpl VALUES ("GL1_2","078_1_2","GAL","1","2","2","και οι συν εμοι παντεσ αδελφοι ταισ εκκλησιαισ τησ γαλατιασ ");
INSERT INTO grcmt_vpl VALUES ("GL1_3","078_1_3","GAL","1","3","3","χαρισ υμιν και ειρηνη απο θεου πατροσ και κυριου ημων ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("GL1_4","078_1_4","GAL","1","4","4","του δοντοσ εαυτον περι των αμαρτιων ημων οπωσ εξεληται ημασ εκ του ενεστωτοσ αιωνοσ πονηρου κατα το θελημα του θεου και πατροσ ημων ");
INSERT INTO grcmt_vpl VALUES ("GL1_5","078_1_5","GAL","1","5","5","ω η δοξα εισ τουσ αιωνασ των αιωνων αμην ");
INSERT INTO grcmt_vpl VALUES ("GL1_6","078_1_6","GAL","1","6","6","θαυμαζω οτι ουτωσ ταχεωσ μετατιθεσθε απο του καλεσαντοσ υμασ εν χαριτι χριστου εισ ετερον ευαγγελιον ");
INSERT INTO grcmt_vpl VALUES ("GL1_7","078_1_7","GAL","1","7","7","ο ουκ εστιν αλλο ει μη τινεσ εισιν οι ταρασσοντεσ υμασ και θελοντεσ μεταστρεψαι το ευαγγελιον του χριστου ");
INSERT INTO grcmt_vpl VALUES ("GL1_8","078_1_8","GAL","1","8","8","αλλα και εαν ημεισ η αγγελοσ εξ ουρανου ευαγγελιζηται υμιν παρ ο ευηγγελισαμεθα υμιν αναθεμα εστω ");
INSERT INTO grcmt_vpl VALUES ("GL1_9","078_1_9","GAL","1","9","9","ωσ προειρηκαμεν και αρτι παλιν λεγω ει τισ υμασ ευαγγελιζεται παρ ο παρελαβετε αναθεμα εστω ");
INSERT INTO grcmt_vpl VALUES ("GL1_10","078_1_10","GAL","1","10","10","αρτι γαρ ανθρωπουσ πειθω η τον θεον η ζητω ανθρωποισ αρεσκειν ει γαρ ετι ανθρωποισ ηρεσκον χριστου δουλοσ ουκ αν ημην ");
INSERT INTO grcmt_vpl VALUES ("GL1_11","078_1_11","GAL","1","11","11","γνωριζω δε υμιν αδελφοι το ευαγγελιον το ευαγγελισθεν υπ εμου οτι ουκ εστιν κατα ανθρωπον ");
INSERT INTO grcmt_vpl VALUES ("GL1_12","078_1_12","GAL","1","12","12","ουδε γαρ εγω παρα ανθρωπου παρελαβον αυτο ουτε εδιδαχθην αλλα δι αποκαλυψεωσ ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("GL1_13","078_1_13","GAL","1","13","13","ηκουσατε γαρ την εμην αναστροφην ποτε εν τω ιουδαισμω οτι καθ υπερβολην εδιωκον την εκκλησιαν του θεου και επορθουν αυτην ");
INSERT INTO grcmt_vpl VALUES ("GL1_14","078_1_14","GAL","1","14","14","και προεκοπτον εν τω ιουδαισμω υπερ πολλουσ συνηλικιωτασ εν τω γενει μου περισσοτερωσ ζηλωτησ υπαρχων των πατρικων μου παραδοσεων ");
INSERT INTO grcmt_vpl VALUES ("GL1_15","078_1_15","GAL","1","15","15","οτε δε ευδοκησεν ο θεοσ ο αφορισασ με εκ κοιλιασ μητροσ μου και καλεσασ δια τησ χαριτοσ αυτου ");
INSERT INTO grcmt_vpl VALUES ("GL1_16","078_1_16","GAL","1","16","16","αποκαλυψαι τον υιον αυτου εν εμοι ινα ευαγγελιζωμαι αυτον εν τοισ εθνεσιν ευθεωσ ου προσανεθεμην σαρκι και αιματι ");
INSERT INTO grcmt_vpl VALUES ("GL1_17","078_1_17","GAL","1","17","17","ουδε ανηλθον εισ ιεροσολυμα προσ τουσ προ εμου αποστολουσ αλλα απηλθον εισ αραβιαν και παλιν υπεστρεψα εισ δαμασκον ");
INSERT INTO grcmt_vpl VALUES ("GL1_18","078_1_18","GAL","1","18","18","επειτα μετα ετη τρια ανηλθον εισ ιεροσολυμα ιστορησαι πετρον και επεμεινα προσ αυτον ημερασ δεκαπεντε ");
INSERT INTO grcmt_vpl VALUES ("GL1_19","078_1_19","GAL","1","19","19","ετερον δε των αποστολων ουκ ειδον ει μη ιακωβον τον αδελφον του κυριου ");
INSERT INTO grcmt_vpl VALUES ("GL1_20","078_1_20","GAL","1","20","20","α δε γραφω υμιν ιδου ενωπιον του θεου οτι ου ψευδομαι ");
INSERT INTO grcmt_vpl VALUES ("GL1_21","078_1_21","GAL","1","21","21","επειτα ηλθον εισ τα κλιματα τησ συριασ και τησ κιλικιασ ");
INSERT INTO grcmt_vpl VALUES ("GL1_22","078_1_22","GAL","1","22","22","ημην δε αγνοουμενοσ τω προσωπω ταισ εκκλησιαισ τησ ιουδαιασ ταισ εν χριστω ");
INSERT INTO grcmt_vpl VALUES ("GL1_23","078_1_23","GAL","1","23","23","μονον δε ακουοντεσ ησαν οτι ο διωκων ημασ ποτε νυν ευαγγελιζεται την πιστιν ην ποτε επορθει ");
INSERT INTO grcmt_vpl VALUES ("GL1_24","078_1_24","GAL","1","24","24","και εδοξαζον εν εμοι τον θεον ");
INSERT INTO grcmt_vpl VALUES ("GL2_1","078_2_1","GAL","2","1","1","επειτα δια δεκατεσσαρων ετων παλιν ανεβην εισ ιεροσολυμα μετα βαρναβα συμπαραλαβων και τιτον ");
INSERT INTO grcmt_vpl VALUES ("GL2_2","078_2_2","GAL","2","2","2","ανεβην δε κατα αποκαλυψιν και ανεθεμην αυτοισ το ευαγγελιον ο κηρυσσω εν τοισ εθνεσιν κατ ιδιαν δε τοισ δοκουσιν μηπωσ εισ κενον τρεχω η εδραμον ");
INSERT INTO grcmt_vpl VALUES ("GL2_3","078_2_3","GAL","2","3","3","αλλ ουδε τιτοσ ο συν εμοι ελλην ων ηναγκασθη περιτμηθηναι ");
INSERT INTO grcmt_vpl VALUES ("GL2_4","078_2_4","GAL","2","4","4","δια δε τουσ παρεισακτουσ ψευδαδελφουσ οιτινεσ παρεισηλθον κατασκοπησαι την ελευθεριαν ημων ην εχομεν εν χριστω ιησου ινα ημασ καταδουλωσωνται ");
INSERT INTO grcmt_vpl VALUES ("GL2_5","078_2_5","GAL","2","5","5","οισ ουδε προσ ωραν ειξαμεν τη υποταγη ινα η αληθεια του ευαγγελιου διαμεινη προσ υμασ ");
INSERT INTO grcmt_vpl VALUES ("GL2_6","078_2_6","GAL","2","6","6","απο δε των δοκουντων ειναι τι οποιοι ποτε ησαν ουδεν μοι διαφερει προσωπον θεοσ ανθρωπου ου λαμβανει εμοι γαρ οι δοκουντεσ ουδεν προσανεθεντο ");
INSERT INTO grcmt_vpl VALUES ("GL2_7","078_2_7","GAL","2","7","7","αλλα τουναντιον ιδοντεσ οτι πεπιστευμαι το ευαγγελιον τησ ακροβυστιασ καθωσ πετροσ τησ περιτομησ ");
INSERT INTO grcmt_vpl VALUES ("GL2_8","078_2_8","GAL","2","8","8","ο γαρ ενεργησασ πετρω εισ αποστολην τησ περιτομησ ενηργησεν και εμοι εισ τα εθνη ");
INSERT INTO grcmt_vpl VALUES ("GL2_9","078_2_9","GAL","2","9","9","και γνοντεσ την χαριν την δοθεισαν μοι ιακωβοσ και κηφασ και ιωαννησ οι δοκουντεσ στυλοι ειναι δεξιασ εδωκαν εμοι και βαρναβα κοινωνιασ ινα ημεισ μεν εισ τα εθνη αυτοι δε εισ την περιτομην ");
INSERT INTO grcmt_vpl VALUES ("GL2_10","078_2_10","GAL","2","10","10","μονον των πτωχων ινα μνημονευωμεν ο και εσπουδασα αυτο τουτο ποιησαι ");
INSERT INTO grcmt_vpl VALUES ("GL2_11","078_2_11","GAL","2","11","11","οτε δε ηλθεν πετροσ εισ αντιοχειαν κατα προσωπον αυτω αντεστην οτι κατεγνωσμενοσ ην ");
INSERT INTO grcmt_vpl VALUES ("GL2_12","078_2_12","GAL","2","12","12","προ του γαρ ελθειν τινασ απο ιακωβου μετα των εθνων συνησθιεν οτε δε ηλθον υπεστελλεν και αφωριζεν εαυτον φοβουμενοσ τουσ εκ περιτομησ ");
INSERT INTO grcmt_vpl VALUES ("GL2_13","078_2_13","GAL","2","13","13","και συνυπεκριθησαν αυτω και οι λοιποι ιουδαιοι ωστε και βαρναβασ συναπηχθη αυτων τη υποκρισει ");
INSERT INTO grcmt_vpl VALUES ("GL2_14","078_2_14","GAL","2","14","14","αλλ οτε ειδον οτι ουκ ορθοποδουσιν προσ την αληθειαν του ευαγγελιου ειπον τω πετρω εμπροσθεν παντων ει συ ιουδαιοσ υπαρχων εθνικωσ ζησ και ουκ ιουδαικωσ τι τα εθνη αναγκαζεισ ιουδαιζειν ");
INSERT INTO grcmt_vpl VALUES ("GL2_15","078_2_15","GAL","2","15","15","ημεισ φυσει ιουδαιοι και ουκ εξ εθνων αμαρτωλοι ");
INSERT INTO grcmt_vpl VALUES ("GL2_16","078_2_16","GAL","2","16","16","ειδοτεσ οτι ου δικαιουται ανθρωποσ εξ εργων νομου εαν μη δια πιστεωσ ιησου χριστου και ημεισ εισ χριστον ιησουν επιστευσαμεν ινα δικαιωθωμεν εκ πιστεωσ χριστου και ουκ εξ εργων νομου διοτι ου δικαιωθησεται εξ εργων νομου πασα σαρξ ");
INSERT INTO grcmt_vpl VALUES ("GL2_17","078_2_17","GAL","2","17","17","ει δε ζητουντεσ δικαιωθηναι εν χριστω ευρεθημεν και αυτοι αμαρτωλοι αρα χριστοσ αμαρτιασ διακονοσ μη γενοιτο ");
INSERT INTO grcmt_vpl VALUES ("GL2_18","078_2_18","GAL","2","18","18","ει γαρ α κατελυσα ταυτα παλιν οικοδομω παραβατην εμαυτον συνιστημι ");
INSERT INTO grcmt_vpl VALUES ("GL2_19","078_2_19","GAL","2","19","19","εγω γαρ δια νομου νομω απεθανον ινα θεω ζησω ");
INSERT INTO grcmt_vpl VALUES ("GL2_20","078_2_20","GAL","2","20","20","χριστω συνεσταυρωμαι ζω δε ουκετι εγω ζη δε εν εμοι χριστοσ ο δε νυν ζω εν σαρκι εν πιστει ζω τη του υιου του θεου του αγαπησαντοσ με και παραδοντοσ εαυτον υπερ εμου ");
INSERT INTO grcmt_vpl VALUES ("GL2_21","078_2_21","GAL","2","21","21","ουκ αθετω την χαριν του θεου ει γαρ δια νομου δικαιοσυνη αρα χριστοσ δωρεαν απεθανεν ");
INSERT INTO grcmt_vpl VALUES ("GL3_1","078_3_1","GAL","3","1","1","ω ανοητοι γαλαται τισ υμασ εβασκανεν τη αληθεια μη πειθεσθαι οισ κατ οφθαλμουσ ιησουσ χριστοσ προεγραφη εν υμιν εσταυρωμενοσ ");
INSERT INTO grcmt_vpl VALUES ("GL3_2","078_3_2","GAL","3","2","2","τουτο μονον θελω μαθειν αφ υμων εξ εργων νομου το πνευμα ελαβετε η εξ ακοησ πιστεωσ ");
INSERT INTO grcmt_vpl VALUES ("GL3_3","078_3_3","GAL","3","3","3","ουτωσ ανοητοι εστε εναρξαμενοι πνευματι νυν σαρκι επιτελεισθε ");
INSERT INTO grcmt_vpl VALUES ("GL3_4","078_3_4","GAL","3","4","4","τοσαυτα επαθετε εικη ειγε και εικη ");
INSERT INTO grcmt_vpl VALUES ("GL3_5","078_3_5","GAL","3","5","5","ο ουν επιχορηγων υμιν το πνευμα και ενεργων δυναμεισ εν υμιν εξ εργων νομου η εξ ακοησ πιστεωσ ");
INSERT INTO grcmt_vpl VALUES ("GL3_6","078_3_6","GAL","3","6","6","καθωσ αβρααμ επιστευσεν τω θεω και ελογισθη αυτω εισ δικαιοσυνην ");
INSERT INTO grcmt_vpl VALUES ("GL3_7","078_3_7","GAL","3","7","7","γινωσκετε 1097 V-PAI-2P αρα οτι οι εκ πιστεωσ ουτοι εισιν υιοι αβρααμ ");
INSERT INTO grcmt_vpl VALUES ("GL3_8","078_3_8","GAL","3","8","8","προιδουσα δε η γραφη οτι εκ πιστεωσ δικαιοι τα εθνη ο θεοσ προευηγγελισατο τω αβρααμ οτι ενευλογηθησονται εν σοι παντα τα εθνη ");
INSERT INTO grcmt_vpl VALUES ("GL3_9","078_3_9","GAL","3","9","9","ωστε οι εκ πιστεωσ ευλογουνται συν τω πιστω αβρααμ ");
INSERT INTO grcmt_vpl VALUES ("GL3_10","078_3_10","GAL","3","10","10","οσοι γαρ εξ εργων νομου εισιν υπο καταραν εισιν γεγραπται γαρ επικαταρατοσ πασ οσ ουκ εμμενει εν πασιν τοισ γεγραμμενοισ εν τω βιβλιω του νομου του ποιησαι αυτα ");
INSERT INTO grcmt_vpl VALUES ("GL3_11","078_3_11","GAL","3","11","11","οτι δε εν νομω ουδεισ δικαιουται παρα τω θεω δηλον οτι ο δικαιοσ εκ πιστεωσ ζησεται ");
INSERT INTO grcmt_vpl VALUES ("GL3_12","078_3_12","GAL","3","12","12","ο δε νομοσ ουκ εστιν εκ πιστεωσ αλλ ο ποιησασ αυτα ανθρωποσ ζησεται εν αυτοισ ");
INSERT INTO grcmt_vpl VALUES ("GL3_13","078_3_13","GAL","3","13","13","χριστοσ ημασ εξηγορασεν εκ τησ καταρασ του νομου γενομενοσ υπερ ημων καταρα γεγραπται γαρ επικαταρατοσ πασ ο κρεμαμενοσ επι ξυλου ");
INSERT INTO grcmt_vpl VALUES ("GL3_14","078_3_14","GAL","3","14","14","ινα εισ τα εθνη η ευλογια του αβρααμ γενηται εν χριστω ιησου ινα την επαγγελιαν του πνευματοσ λαβωμεν δια τησ πιστεωσ ");
INSERT INTO grcmt_vpl VALUES ("GL3_15","078_3_15","GAL","3","15","15","αδελφοι κατα ανθρωπον λεγω ομωσ ανθρωπου κεκυρωμενην διαθηκην ουδεισ αθετει η επιδιατασσεται ");
INSERT INTO grcmt_vpl VALUES ("GL3_16","078_3_16","GAL","3","16","16","τω δε αβρααμ ερρηθησαν αι επαγγελιαι και τω σπερματι αυτου ου λεγει και τοισ σπερμασιν ωσ επι πολλων αλλ ωσ εφ ενοσ και τω σπερματι σου οσ εστιν χριστοσ ");
INSERT INTO grcmt_vpl VALUES ("GL3_17","078_3_17","GAL","3","17","17","τουτο δε λεγω διαθηκην προκεκυρωμενην υπο του θεου εισ χριστον ο μετα ετη τετρακοσια και τριακοντα γεγονωσ νομοσ ουκ ακυροι εισ το καταργησαι την επαγγελιαν ");
INSERT INTO grcmt_vpl VALUES ("GL3_18","078_3_18","GAL","3","18","18","ει γαρ εκ νομου η κληρονομια ουκετι εξ επαγγελιασ τω δε αβρααμ δι επαγγελιασ κεχαρισται ο θεοσ ");
INSERT INTO grcmt_vpl VALUES ("GL3_19","078_3_19","GAL","3","19","19","τι ουν ο νομοσ των παραβασεων χαριν προσετεθη αχρι ου ελθη το σπερμα ω επηγγελται διαταγεισ δι αγγελων εν χειρι μεσιτου ");
INSERT INTO grcmt_vpl VALUES ("GL3_20","078_3_20","GAL","3","20","20","ο δε μεσιτησ ενοσ ουκ εστιν ο δε θεοσ εισ εστιν ");
INSERT INTO grcmt_vpl VALUES ("GL3_21","078_3_21","GAL","3","21","21","ο ουν νομοσ κατα των επαγγελιων του θεου μη γενοιτο ει γαρ εδοθη νομοσ ο δυναμενοσ ζωοποιησαι οντωσ αν εκ νομου ην η δικαιοσυνη ");
INSERT INTO grcmt_vpl VALUES ("GL3_22","078_3_22","GAL","3","22","22","αλλα συνεκλεισεν η γραφη τα παντα υπο αμαρτιαν ινα η επαγγελια εκ πιστεωσ ιησου χριστου δοθη τοισ πιστευουσιν ");
INSERT INTO grcmt_vpl VALUES ("GL3_23","078_3_23","GAL","3","23","23","προ του δε ελθειν την πιστιν υπο νομον εφρουρουμεθα συγκεκλεισμενοι εισ την μελλουσαν πιστιν αποκαλυφθηναι ");
