INSERT INTO grcmt_vpl VALUES ("EP1_18","079_1_18","EPH","1","18","18","πεφωτισμενουσ τουσ οφθαλμουσ τησ καρδιασ υμων εισ το ειδεναι υμασ τισ εστιν η ελπισ τησ κλησεωσ αυτου και τισ ο πλουτοσ τησ δοξησ τησ κληρονομιασ αυτου εν τοισ αγιοισ ");
INSERT INTO grcmt_vpl VALUES ("EP1_19","079_1_19","EPH","1","19","19","και τι το υπερβαλλον μεγεθοσ τησ δυναμεωσ αυτου εισ ημασ τουσ πιστευοντασ κατα την ενεργειαν του κρατουσ τησ ισχυοσ αυτου ");
INSERT INTO grcmt_vpl VALUES ("EP1_20","079_1_20","EPH","1","20","20","ην ενηργησεν εν τω χριστω εγειρασ αυτον εκ των νεκρων και εκαθισεν εν δεξια αυτου εν τοισ επουρανιοισ ");
INSERT INTO grcmt_vpl VALUES ("EP1_21","079_1_21","EPH","1","21","21","υπερανω πασησ αρχησ και εξουσιασ και δυναμεωσ και κυριοτητοσ και παντοσ ονοματοσ ονομαζομενου ου μονον εν τω αιωνι τουτω αλλα και εν τω μελλοντι ");
INSERT INTO grcmt_vpl VALUES ("EP1_22","079_1_22","EPH","1","22","22","και παντα υπεταξεν υπο τουσ ποδασ αυτου και αυτον εδωκεν κεφαλην υπερ παντα τη εκκλησια ");
INSERT INTO grcmt_vpl VALUES ("EP1_23","079_1_23","EPH","1","23","23","ητισ εστιν το σωμα αυτου το πληρωμα του τα παντα εν πασιν πληρουμενου ");
INSERT INTO grcmt_vpl VALUES ("EP2_1","079_2_1","EPH","2","1","1","και υμασ οντασ νεκρουσ τοισ παραπτωμασιν και ταισ αμαρτιαισ ");
INSERT INTO grcmt_vpl VALUES ("EP2_2","079_2_2","EPH","2","2","2","εν αισ ποτε περιεπατησατε κατα τον αιωνα του κοσμου τουτου κατα τον αρχοντα τησ εξουσιασ του αεροσ του πνευματοσ του νυν ενεργουντοσ εν τοισ υιοισ τησ απειθειασ ");
INSERT INTO grcmt_vpl VALUES ("EP2_3","079_2_3","EPH","2","3","3","εν οισ και ημεισ παντεσ ανεστραφημεν ποτε εν ταισ επιθυμιαισ τησ σαρκοσ ημων ποιουντεσ τα θεληματα τησ σαρκοσ και των διανοιων και ημεν τεκνα φυσει οργησ ωσ και οι λοιποι ");
INSERT INTO grcmt_vpl VALUES ("EP2_4","079_2_4","EPH","2","4","4","ο δε θεοσ πλουσιοσ ων εν ελεει δια την πολλην αγαπην αυτου ην ηγαπησεν ημασ ");
INSERT INTO grcmt_vpl VALUES ("EP2_5","079_2_5","EPH","2","5","5","και οντασ ημασ νεκρουσ τοισ παραπτωμασιν συνεζωοποιησεν τω χριστω χαριτι εστε σεσωσμενοι ");
INSERT INTO grcmt_vpl VALUES ("EP2_6","079_2_6","EPH","2","6","6","και συνηγειρεν και συνεκαθισεν εν τοισ επουρανιοισ εν χριστω ιησου ");
INSERT INTO grcmt_vpl VALUES ("EP2_7","079_2_7","EPH","2","7","7","ινα ενδειξηται εν τοισ αιωσιν τοισ επερχομενοισ τον υπερβαλλοντα πλουτον τησ χαριτοσ αυτου εν χρηστοτητι εφ ημασ εν χριστω ιησου ");
INSERT INTO grcmt_vpl VALUES ("EP2_8","079_2_8","EPH","2","8","8","τη γαρ χαριτι εστε σεσωσμενοι δια τησ πιστεωσ και τουτο ουκ εξ υμων θεου το δωρον ");
INSERT INTO grcmt_vpl VALUES ("EP2_9","079_2_9","EPH","2","9","9","ουκ εξ εργων ινα μη τισ καυχησηται ");
INSERT INTO grcmt_vpl VALUES ("EP2_10","079_2_10","EPH","2","10","10","αυτου γαρ εσμεν ποιημα κτισθεντεσ εν χριστω ιησου επι εργοισ αγαθοισ οισ προητοιμασεν ο θεοσ ινα εν αυτοισ περιπατησωμεν ");
INSERT INTO grcmt_vpl VALUES ("EP2_11","079_2_11","EPH","2","11","11","διο μνημονευετε οτι υμεισ ποτε τα εθνη εν σαρκι οι λεγομενοι ακροβυστια υπο τησ λεγομενησ περιτομησ εν σαρκι χειροποιητου ");
INSERT INTO grcmt_vpl VALUES ("EP2_12","079_2_12","EPH","2","12","12","οτι ητε εν τω καιρω εκεινω χωρισ χριστου απηλλοτριωμενοι τησ πολιτειασ του ισραηλ και ξενοι των διαθηκων τησ επαγγελιασ ελπιδα μη εχοντεσ και αθεοι εν τω κοσμω ");
INSERT INTO grcmt_vpl VALUES ("EP2_13","079_2_13","EPH","2","13","13","νυνι δε εν χριστω ιησου υμεισ οι ποτε οντεσ μακραν εγγυσ εγενηθητε εν τω αιματι του χριστου ");
INSERT INTO grcmt_vpl VALUES ("EP2_14","079_2_14","EPH","2","14","14","αυτοσ γαρ εστιν η ειρηνη ημων ο ποιησασ τα αμφοτερα εν και το μεσοτοιχον του φραγμου λυσασ ");
INSERT INTO grcmt_vpl VALUES ("EP2_15","079_2_15","EPH","2","15","15","την εχθραν εν τη σαρκι αυτου τον νομον των εντολων εν δογμασιν καταργησασ ινα τουσ δυο κτιση εν εαυτω εισ ενα καινον ανθρωπον ποιων ειρηνην ");
INSERT INTO grcmt_vpl VALUES ("EP2_16","079_2_16","EPH","2","16","16","και αποκαταλλαξη τουσ αμφοτερουσ εν ενι σωματι τω θεω δια του σταυρου αποκτεινασ την εχθραν εν αυτω ");
INSERT INTO grcmt_vpl VALUES ("EP2_17","079_2_17","EPH","2","17","17","και ελθων ευηγγελισατο ειρηνην υμιν τοισ μακραν και τοισ εγγυσ ");
INSERT INTO grcmt_vpl VALUES ("EP2_18","079_2_18","EPH","2","18","18","οτι δι αυτου εχομεν την προσαγωγην οι αμφοτεροι εν ενι πνευματι προσ τον πατερα ");
INSERT INTO grcmt_vpl VALUES ("EP2_19","079_2_19","EPH","2","19","19","αρα ουν ουκετι εστε ξενοι και παροικοι αλλα συμπολιται των αγιων και οικειοι του θεου ");
INSERT INTO grcmt_vpl VALUES ("EP2_20","079_2_20","EPH","2","20","20","εποικοδομηθεντεσ επι τω θεμελιω των αποστολων και προφητων οντοσ ακρογωνιαιου αυτου ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("EP2_21","079_2_21","EPH","2","21","21","εν ω πασα οικοδομη συναρμολογουμενη αυξει εισ ναον αγιον εν κυριω ");
INSERT INTO grcmt_vpl VALUES ("EP2_22","079_2_22","EPH","2","22","22","εν ω και υμεισ συνοικοδομεισθε εισ κατοικητηριον του θεου εν πνευματι ");
INSERT INTO grcmt_vpl VALUES ("EP3_1","079_3_1","EPH","3","1","1","τουτου χαριν εγω παυλοσ ο δεσμιοσ του χριστου ιησου υπερ υμων των εθνων ");
