INSERT INTO grcmt_vpl VALUES ("EP3_3","079_3_3","EPH","3","3","3","οτι κατα αποκαλυψιν εγνωρισεν μοι το μυστηριον καθωσ προεγραψα εν ολιγω ");
INSERT INTO grcmt_vpl VALUES ("EP3_4","079_3_4","EPH","3","4","4","προσ ο δυνασθε αναγινωσκοντεσ νοησαι την συνεσιν μου εν τω μυστηριω του χριστου ");
INSERT INTO grcmt_vpl VALUES ("EP3_5","079_3_5","EPH","3","5","5","ο ετεραισ γενεαισ ουκ εγνωρισθη τοισ υιοισ των ανθρωπων ωσ νυν απεκαλυφθη τοισ αγιοισ αποστολοισ αυτου και προφηταισ εν πνευματι ");
