INSERT INTO grcmt_vpl VALUES ("EP3_7","079_3_7","EPH","3","7","7","ου εγενομην διακονοσ κατα την δωρεαν τησ χαριτοσ του θεου την δοθεισαν μοι κατα την ενεργειαν τησ δυναμεωσ αυτου ");
