INSERT INTO grcmt_vpl VALUES ("EP3_9","079_3_9","EPH","3","9","9","και φωτισαι παντασ τισ η οικονομια του μυστηριου του αποκεκρυμμενου απο των αιωνων εν τω θεω τω τα παντα κτισαντι δια ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("EP3_10","079_3_10","EPH","3","10","10","ινα γνωρισθη νυν ταισ αρχαισ και ταισ εξουσιαισ εν τοισ επουρανιοισ δια τησ εκκλησιασ η πολυποικιλοσ σοφια του θεου ");
