INSERT INTO grcmt_vpl VALUES ("EP3_14","079_3_14","EPH","3","14","14","τουτου χαριν καμπτω τα γονατα μου προσ τον πατερα του κυριου ημων ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("EP3_15","079_3_15","EPH","3","15","15","εξ ου πασα πατρια εν ουρανοισ και επι γησ ονομαζεται ");
