INSERT INTO grcmt_vpl VALUES ("EP3_17","079_3_17","EPH","3","17","17","κατοικησαι τον χριστον δια τησ πιστεωσ εν ταισ καρδιαισ υμων ");
INSERT INTO grcmt_vpl VALUES ("EP3_18","079_3_18","EPH","3","18","18","εν αγαπη ερριζωμενοι και τεθεμελιωμενοι ινα εξισχυσητε καταλαβεσθαι συν πασιν τοισ αγιοισ τι το πλατοσ και μηκοσ και βαθοσ και υψοσ ");
