INSERT INTO grcmt_vpl VALUES ("EP3_20","079_3_20","EPH","3","20","20","τω δε δυναμενω υπερ παντα ποιησαι υπερ εκπερισσου ων αιτουμεθα η νοουμεν κατα την δυναμιν την ενεργουμενην εν ημιν ");
