INSERT INTO grcmt_vpl VALUES ("EP4_8","079_4_8","EPH","4","8","8","διο λεγει αναβασ εισ υψοσ ηχμαλωτευσεν αιχμαλωσιαν και εδωκεν δοματα τοισ ανθρωποισ ");
