INSERT INTO grcmt_vpl VALUES ("EP4_10","079_4_10","EPH","4","10","10","ο καταβασ αυτοσ εστιν και ο αναβασ υπερανω παντων των ουρανων ινα πληρωση τα παντα ");
INSERT INTO grcmt_vpl VALUES ("EP4_11","079_4_11","EPH","4","11","11","και αυτοσ εδωκεν τουσ μεν αποστολουσ τουσ δε προφητασ τουσ δε ευαγγελιστασ τουσ δε ποιμενασ και διδασκαλουσ ");
