INSERT INTO grcmt_vpl VALUES ("EP4_15","079_4_15","EPH","4","15","15","αληθευοντεσ δε εν αγαπη αυξησωμεν εισ αυτον τα παντα οσ εστιν η κεφαλη ο χριστοσ ");
INSERT INTO grcmt_vpl VALUES ("EP4_16","079_4_16","EPH","4","16","16","εξ ου παν το σωμα συναρμολογουμενον και συμβιβαζομενον δια πασησ αφησ τησ επιχορηγιασ κατ ενεργειαν εν μετρω ενοσ εκαστου μερουσ την αυξησιν του σωματοσ ποιειται εισ οικοδομην εαυτου εν αγαπη ");
