INSERT INTO grcmt_vpl VALUES ("EP4_18","079_4_18","EPH","4","18","18","εσκοτισμενοι τη διανοια οντεσ απηλλοτριωμενοι τησ ζωησ του θεου δια την αγνοιαν την ουσαν εν αυτοισ δια την πωρωσιν τησ καρδιασ αυτων ");
