INSERT INTO grcmt_vpl VALUES ("EP4_20","079_4_20","EPH","4","20","20","υμεισ δε ουχ ουτωσ εμαθετε τον χριστον ");
INSERT INTO grcmt_vpl VALUES ("EP4_21","079_4_21","EPH","4","21","21","ειγε αυτον ηκουσατε και εν αυτω εδιδαχθητε καθωσ εστιν αληθεια εν τω ιησου ");
INSERT INTO grcmt_vpl VALUES ("EP4_22","079_4_22","EPH","4","22","22","αποθεσθαι υμασ κατα την προτεραν αναστροφην τον παλαιον ανθρωπον τον φθειρομενον κατα τασ επιθυμιασ τησ απατησ ");
INSERT INTO grcmt_vpl VALUES ("EP4_23","079_4_23","EPH","4","23","23","ανανεουσθαι δε τω πνευματι του νοοσ υμων ");
INSERT INTO grcmt_vpl VALUES ("EP4_24","079_4_24","EPH","4","24","24","και ενδυσασθαι τον καινον ανθρωπον τον κατα θεον κτισθεντα εν δικαιοσυνη και οσιοτητι τησ αληθειασ ");
INSERT INTO grcmt_vpl VALUES ("EP4_25","079_4_25","EPH","4","25","25","διο αποθεμενοι το ψευδοσ λαλειτε αληθειαν εκαστοσ μετα του πλησιον αυτου οτι εσμεν αλληλων μελη ");
INSERT INTO grcmt_vpl VALUES ("EP4_26","079_4_26","EPH","4","26","26","οργιζεσθε και μη αμαρτανετε ο ηλιοσ μη επιδυετω επι τω παροργισμω υμων ");
