INSERT INTO grcmt_vpl VALUES ("EP4_28","079_4_28","EPH","4","28","28","ο κλεπτων μηκετι κλεπτετω μαλλον δε κοπιατω εργαζομενοσ το αγαθον ταισ χερσιν ινα εχη μεταδιδοναι τω χρειαν εχοντι ");
INSERT INTO grcmt_vpl VALUES ("EP4_29","079_4_29","EPH","4","29","29","πασ λογοσ σαπροσ εκ του στοματοσ υμων μη εκπορευεσθω αλλ ει τισ αγαθοσ προσ οικοδομην τησ χρειασ ινα δω χαριν τοισ ακουουσιν ");
INSERT INTO grcmt_vpl VALUES ("EP4_30","079_4_30","EPH","4","30","30","και μη λυπειτε το πνευμα το αγιον του θεου εν ω εσφραγισθητε εισ ημεραν απολυτρωσεωσ ");
INSERT INTO grcmt_vpl VALUES ("EP4_31","079_4_31","EPH","4","31","31","πασα πικρια και θυμοσ και οργη και κραυγη και βλασφημια αρθητω αφ υμων συν παση κακια ");
INSERT INTO grcmt_vpl VALUES ("EP4_32","079_4_32","EPH","4","32","32","γινεσθε δε εισ αλληλουσ χρηστοι ευσπλαγχνοι χαριζομενοι εαυτοισ καθωσ και ο θεοσ εν χριστω εχαρισατο ημιν ");
INSERT INTO grcmt_vpl VALUES ("EP5_1","079_5_1","EPH","5","1","1","γινεσθε ουν μιμηται του θεου ωσ τεκνα αγαπητα ");
INSERT INTO grcmt_vpl VALUES ("EP5_2","079_5_2","EPH","5","2","2","και περιπατειτε εν αγαπη καθωσ και ο χριστοσ ηγαπησεν ημασ και παρεδωκεν εαυτον υπερ ημων προσφοραν και θυσιαν τω θεω εισ οσμην ευωδιασ ");
