INSERT INTO grcmt_vpl VALUES ("EP5_4","079_5_4","EPH","5","4","4","και αισχροτησ και μωρολογια η ευτραπελια τα ουκ ανηκοντα αλλα μαλλον ευχαριστια ");
INSERT INTO grcmt_vpl VALUES ("EP5_5","079_5_5","EPH","5","5","5","τουτο γαρ εστε γινωσκοντεσ οτι πασ πορνοσ η ακαθαρτοσ η πλεονεκτησ οσ εστιν ειδωλολατρησ ουκ εχει κληρονομιαν εν τη βασιλεια του χριστου και θεου ");
