INSERT INTO grcmt_vpl VALUES ("EP5_28","079_5_28","EPH","5","28","28","ουτωσ οφειλουσιν οι ανδρεσ αγαπαν τασ εαυτων γυναικασ ωσ τα εαυτων σωματα ο αγαπων την εαυτου γυναικα εαυτον αγαπα ");
