INSERT INTO grcmt_vpl VALUES ("EP5_31","079_5_31","EPH","5","31","31","αντι τουτου καταλειψει ανθρωποσ τον πατερα αυτου και την μητερα και προσκολληθησεται προσ την γυναικα αυτου και εσονται οι δυο εισ σαρκα μιαν ");
