INSERT INTO grcmt_vpl VALUES ("EP5_33","079_5_33","EPH","5","33","33","πλην και υμεισ οι καθ ενα εκαστοσ την εαυτου γυναικα ουτωσ αγαπατω ωσ εαυτον η δε γυνη ινα φοβηται τον ανδρα ");
