INSERT INTO grcmt_vpl VALUES ("EP6_18","079_6_18","EPH","6","18","18","δια πασησ προσευχησ και δεησεωσ προσευχομενοι εν παντι καιρω εν πνευματι και εισ αυτο τουτο αγρυπνουντεσ εν παση προσκαρτερησει και δεησει περι παντων των αγιων ");
INSERT INTO grcmt_vpl VALUES ("EP6_19","079_6_19","EPH","6","19","19","και υπερ εμου ινα μοι δοθη λογοσ εν ανοιξει του στοματοσ μου εν παρρησια γνωρισαι το μυστηριον του ευαγγελιου ");
