INSERT INTO grcmt_vpl VALUES ("PP1_6","080_1_6","PHP","1","6","6","πεποιθωσ αυτο τουτο οτι ο εναρξαμενοσ εν υμιν εργον αγαθον επιτελεσει αχρι ημερασ χριστου ιησου ");
