INSERT INTO grcmt_vpl VALUES ("PP1_17","080_1_17","PHP","1","17","17","οι δε εξ αγαπησ ειδοτεσ οτι εισ απολογιαν του ευαγγελιου κειμαι ");
INSERT INTO grcmt_vpl VALUES ("PP1_18","080_1_18","PHP","1","18","18","τι γαρ πλην παντι τροπω ειτε προφασει ειτε αληθεια χριστοσ καταγγελλεται και εν τουτω χαιρω αλλα και χαρησομαι ");
