INSERT INTO grcmt_vpl VALUES ("PP1_21","080_1_21","PHP","1","21","21","εμοι γαρ το ζην χριστοσ και το αποθανειν κερδοσ ");
INSERT INTO grcmt_vpl VALUES ("PP1_22","080_1_22","PHP","1","22","22","ει δε το ζην εν σαρκι τουτο μοι καρποσ εργου και τι αιρησομαι ου γνωριζω ");
