INSERT INTO grcmt_vpl VALUES ("PP1_28","080_1_28","PHP","1","28","28","και μη πτυρομενοι εν μηδενι υπο των αντικειμενων ητισ αυτοισ μεν εστιν ενδειξισ απωλειασ υμιν δε σωτηριασ και τουτο απο θεου ");
