INSERT INTO grcmt_vpl VALUES ("PP2_9","080_2_9","PHP","2","9","9","διο και ο θεοσ αυτον υπερυψωσεν και εχαρισατο αυτω ονομα το υπερ παν ονομα ");
INSERT INTO grcmt_vpl VALUES ("PP2_10","080_2_10","PHP","2","10","10","ινα εν τω ονοματι ιησου παν γονυ καμψη επουρανιων και επιγειων και καταχθονιων ");
INSERT INTO grcmt_vpl VALUES ("PP2_11","080_2_11","PHP","2","11","11","και πασα γλωσσα εξομολογησηται οτι κυριοσ ιησουσ χριστοσ εισ δοξαν θεου πατροσ ");
INSERT INTO grcmt_vpl VALUES ("PP2_12","080_2_12","PHP","2","12","12","ωστε αγαπητοι μου καθωσ παντοτε υπηκουσατε μη ωσ εν τη παρουσια μου μονον αλλα νυν πολλω μαλλον εν τη απουσια μου μετα φοβου και τρομου την εαυτων σωτηριαν κατεργαζεσθε ");
INSERT INTO grcmt_vpl VALUES ("PP2_13","080_2_13","PHP","2","13","13","ο θεοσ γαρ εστιν ο ενεργων εν υμιν και το θελειν και το ενεργειν υπερ τησ ευδοκιασ ");
