INSERT INTO grcmt_vpl VALUES ("PP2_15","080_2_15","PHP","2","15","15","ινα γενησθε αμεμπτοι και ακεραιοι τεκνα θεου αμωμητα εν μεσω γενεασ σκολιασ και διεστραμμενησ εν οισ φαινεσθε ωσ φωστηρεσ εν κοσμω ");
INSERT INTO grcmt_vpl VALUES ("PP2_16","080_2_16","PHP","2","16","16","λογον ζωησ επεχοντεσ εισ καυχημα εμοι εισ ημεραν χριστου οτι ουκ εισ κενον εδραμον ουδε εισ κενον εκοπιασα ");
INSERT INTO grcmt_vpl VALUES ("PP2_17","080_2_17","PHP","2","17","17","αλλ ει και σπενδομαι επι τη θυσια και λειτουργια τησ πιστεωσ υμων χαιρω και συγχαιρω πασιν υμιν ");
INSERT INTO grcmt_vpl VALUES ("PP2_18","080_2_18","PHP","2","18","18","το δ αυτο και υμεισ χαιρετε και συγχαιρετε μοι ");
INSERT INTO grcmt_vpl VALUES ("PP2_19","080_2_19","PHP","2","19","19","ελπιζω δε εν κυριω ιησου τιμοθεον ταχεωσ πεμψαι υμιν ινα καγω ευψυχω γνουσ τα περι υμων ");
