INSERT INTO grcmt_vpl VALUES ("PP2_22","080_2_22","PHP","2","22","22","την δε δοκιμην αυτου γινωσκετε οτι ωσ πατρι τεκνον συν εμοι εδουλευσεν εισ το ευαγγελιον ");
INSERT INTO grcmt_vpl VALUES ("PP2_23","080_2_23","PHP","2","23","23","τουτον μεν ουν ελπιζω πεμψαι ωσ αν απιδω τα περι εμε εξαυτησ ");
INSERT INTO grcmt_vpl VALUES ("PP2_24","080_2_24","PHP","2","24","24","πεποιθα δε εν κυριω οτι και αυτοσ ταχεωσ ελευσομαι ");
INSERT INTO grcmt_vpl VALUES ("PP2_25","080_2_25","PHP","2","25","25","αναγκαιον δε ηγησαμην επαφροδιτον τον αδελφον και συνεργον και συστρατιωτην μου υμων δε αποστολον και λειτουργον τησ χρειασ μου πεμψαι προσ υμασ ");
INSERT INTO grcmt_vpl VALUES ("PP2_26","080_2_26","PHP","2","26","26","επειδη επιποθων ην παντασ υμασ και αδημονων διοτι ηκουσατε οτι ησθενησεν ");
INSERT INTO grcmt_vpl VALUES ("PP2_27","080_2_27","PHP","2","27","27","και γαρ ησθενησεν παραπλησιον θανατω αλλα ο θεοσ αυτον ηλεησεν ουκ αυτον δε μονον αλλα και εμε ινα μη λυπην επι λυπην σχω ");
INSERT INTO grcmt_vpl VALUES ("PP2_28","080_2_28","PHP","2","28","28","σπουδαιοτερωσ ουν επεμψα αυτον ινα ιδοντεσ αυτον παλιν χαρητε καγω αλυποτεροσ ω ");
INSERT INTO grcmt_vpl VALUES ("PP2_29","080_2_29","PHP","2","29","29","προσδεχεσθε ουν αυτον εν κυριω μετα πασησ χαρασ και τουσ τοιουτουσ εντιμουσ εχετε ");
INSERT INTO grcmt_vpl VALUES ("PP2_30","080_2_30","PHP","2","30","30","οτι δια το εργον του χριστου μεχρι θανατου ηγγισεν παραβουλευσαμενοσ τη ψυχη ινα αναπληρωση το υμων υστερημα τησ προσ με λειτουργιασ ");
INSERT INTO grcmt_vpl VALUES ("PP3_1","080_3_1","PHP","3","1","1","το λοιπον αδελφοι μου χαιρετε εν κυριω τα αυτα γραφειν υμιν εμοι μεν ουκ οκνηρον υμιν δε ασφαλεσ ");
INSERT INTO grcmt_vpl VALUES ("PP3_2","080_3_2","PHP","3","2","2","βλεπετε τουσ κυνασ βλεπετε τουσ κακουσ εργατασ βλεπετε την κατατομην ");
INSERT INTO grcmt_vpl VALUES ("PP3_3","080_3_3","PHP","3","3","3","ημεισ γαρ εσμεν η περιτομη οι πνευματι θεου λατρευοντεσ και καυχωμενοι εν χριστω ιησου και ουκ εν σαρκι πεποιθοτεσ ");
INSERT INTO grcmt_vpl VALUES ("PP3_4","080_3_4","PHP","3","4","4","καιπερ εγω εχων πεποιθησιν και εν σαρκι ει τισ δοκει αλλοσ πεποιθεναι εν σαρκι εγω μαλλον ");
INSERT INTO grcmt_vpl VALUES ("PP3_5","080_3_5","PHP","3","5","5","περιτομη οκταημεροσ εκ γενουσ ισραηλ φυλησ βενιαμιν εβραιοσ εξ εβραιων κατα νομον φαρισαιοσ ");
INSERT INTO grcmt_vpl VALUES ("PP3_6","080_3_6","PHP","3","6","6","κατα ζηλον διωκων την εκκλησιαν κατα δικαιοσυνην την εν νομω γενομενοσ αμεμπτοσ ");
INSERT INTO grcmt_vpl VALUES ("PP3_7","080_3_7","PHP","3","7","7","αλλ ατινα ην μοι κερδη ταυτα ηγημαι δια τον χριστον ζημιαν ");
INSERT INTO grcmt_vpl VALUES ("PP3_8","080_3_8","PHP","3","8","8","αλλα μεν ουν και ηγουμαι παντα ζημιαν ειναι δια το υπερεχον τησ γνωσεωσ χριστου ιησου του κυριου μου δι ον τα παντα εζημιωθην και ηγουμαι σκυβαλα ειναι ινα χριστον κερδησω ");
INSERT INTO grcmt_vpl VALUES ("PP3_9","080_3_9","PHP","3","9","9","και ευρεθω εν αυτω μη εχων εμην δικαιοσυνην την εκ νομου αλλα την δια πιστεωσ χριστου την εκ θεου δικαιοσυνην επι τη πιστει ");
INSERT INTO grcmt_vpl VALUES ("PP3_10","080_3_10","PHP","3","10","10","του γνωναι αυτον και την δυναμιν τησ αναστασεωσ αυτου και την κοινωνιαν των παθηματων αυτου συμμορφουμενοσ τω θανατω αυτου ");
INSERT INTO grcmt_vpl VALUES ("PP3_11","080_3_11","PHP","3","11","11","ει πωσ καταντησω εισ την εξαναστασιν των νεκρων ");
INSERT INTO grcmt_vpl VALUES ("PP3_12","080_3_12","PHP","3","12","12","ουχ οτι ηδη ελαβον η ηδη τετελειωμαι διωκω δε ει και καταλαβω εφ ω και κατεληφθην υπο του χριστου ιησου ");
INSERT INTO grcmt_vpl VALUES ("PP3_13","080_3_13","PHP","3","13","13","αδελφοι εγω εμαυτον ου λογιζομαι κατειληφεναι εν δε τα μεν οπισω επιλανθανομενοσ τοισ δε εμπροσθεν επεκτεινομενοσ ");
INSERT INTO grcmt_vpl VALUES ("PP3_14","080_3_14","PHP","3","14","14","κατα σκοπον διωκω επι το βραβειον τησ ανω κλησεωσ του θεου εν χριστω ιησου ");
INSERT INTO grcmt_vpl VALUES ("PP3_15","080_3_15","PHP","3","15","15","οσοι ουν τελειοι τουτο φρονωμεν και ει τι ετερωσ φρονειτε και τουτο ο θεοσ υμιν αποκαλυψει ");
INSERT INTO grcmt_vpl VALUES ("PP3_16","080_3_16","PHP","3","16","16","πλην εισ ο εφθασαμεν τω αυτω στοιχειν κανονι το αυτο φρονειν ");
INSERT INTO grcmt_vpl VALUES ("PP3_17","080_3_17","PHP","3","17","17","συμμιμηται μου γινεσθε αδελφοι και σκοπειτε τουσ ουτωσ περιπατουντασ καθωσ εχετε τυπον ημασ ");
INSERT INTO grcmt_vpl VALUES ("PP3_18","080_3_18","PHP","3","18","18","πολλοι γαρ περιπατουσιν ουσ πολλακισ ελεγον υμιν νυν δε και κλαιων λεγω τουσ εχθρουσ του σταυρου του χριστου ");
INSERT INTO grcmt_vpl VALUES ("PP3_19","080_3_19","PHP","3","19","19","ων το τελοσ απωλεια ων ο θεοσ η κοιλια και η δοξα εν τη αισχυνη αυτων οι τα επιγεια φρονουντεσ ");
INSERT INTO grcmt_vpl VALUES ("PP3_20","080_3_20","PHP","3","20","20","ημων γαρ το πολιτευμα εν ουρανοισ υπαρχει εξ ου και σωτηρα απεκδεχομεθα κυριον ιησουν χριστον ");
INSERT INTO grcmt_vpl VALUES ("PP3_21","080_3_21","PHP","3","21","21","οσ μετασχηματισει το σωμα τησ ταπεινωσεωσ ημων εισ το γενεσθαι αυτο συμμορφον τω σωματι τησ δοξησ αυτου κατα την ενεργειαν του δυνασθαι αυτον και υποταξαι εαυτω τα παντα ");
INSERT INTO grcmt_vpl VALUES ("PP4_1","080_4_1","PHP","4","1","1","ωστε αδελφοι μου αγαπητοι και επιποθητοι χαρα και στεφανοσ μου ουτωσ στηκετε εν κυριω αγαπητοι ");
INSERT INTO grcmt_vpl VALUES ("PP4_2","080_4_2","PHP","4","2","2","ευοδιαν παρακαλω και συντυχην παρακαλω το αυτο φρονειν εν κυριω ");
INSERT INTO grcmt_vpl VALUES ("PP4_3","080_4_3","PHP","4","3","3","ναι ερωτω και σε συζυγε γνησιε συλλαμβανου αυταισ αιτινεσ εν τω ευαγγελιω συνηθλησαν μοι μετα και κλημεντοσ και των λοιπων συνεργων μου ων τα ονοματα εν βιβλω ζωησ ");
INSERT INTO grcmt_vpl VALUES ("PP4_4","080_4_4","PHP","4","4","4","χαιρετε εν κυριω παντοτε παλιν ερω χαιρετε ");
INSERT INTO grcmt_vpl VALUES ("PP4_5","080_4_5","PHP","4","5","5","το επιεικεσ υμων γνωσθητω πασιν ανθρωποισ ο κυριοσ εγγυσ ");
INSERT INTO grcmt_vpl VALUES ("PP4_6","080_4_6","PHP","4","6","6","μηδεν μεριμνατε αλλ εν παντι τη προσευχη και τη δεησει μετα ευχαριστιασ τα αιτηματα υμων γνωριζεσθω προσ τον θεον ");
INSERT INTO grcmt_vpl VALUES ("PP4_7","080_4_7","PHP","4","7","7","και η ειρηνη του θεου η υπερεχουσα παντα νουν φρουρησει τασ καρδιασ υμων και τα νοηματα υμων εν χριστω ιησου ");
INSERT INTO grcmt_vpl VALUES ("PP4_8","080_4_8","PHP","4","8","8","το λοιπον αδελφοι οσα εστιν αληθη οσα σεμνα οσα δικαια οσα αγνα οσα προσφιλη οσα ευφημα ει τισ αρετη και ει τισ επαινοσ ταυτα λογιζεσθε ");
INSERT INTO grcmt_vpl VALUES ("PP4_9","080_4_9","PHP","4","9","9","α και εμαθετε και παρελαβετε και ηκουσατε και ειδετε εν εμοι ταυτα πρασσετε και ο θεοσ τησ ειρηνησ εσται μεθ υμων ");
INSERT INTO grcmt_vpl VALUES ("PP4_10","080_4_10","PHP","4","10","10","εχαρην δε εν κυριω μεγαλωσ οτι ηδη ποτε ανεθαλετε το υπερ εμου φρονειν εφ ω και εφρονειτε ηκαιρεισθε δε ");
INSERT INTO grcmt_vpl VALUES ("PP4_11","080_4_11","PHP","4","11","11","ουχ οτι καθ υστερησιν λεγω εγω γαρ εμαθον εν οισ ειμι αυταρκησ ειναι ");
INSERT INTO grcmt_vpl VALUES ("PP4_12","080_4_12","PHP","4","12","12","οιδα και ταπεινουσθαι οιδα και περισσευειν εν παντι και εν πασιν μεμυημαι και χορταζεσθαι και πειναν και περισσευειν και υστερεισθαι ");
INSERT INTO grcmt_vpl VALUES ("PP4_13","080_4_13","PHP","4","13","13","παντα ισχυω εν τω ενδυναμουντι με χριστω ");
INSERT INTO grcmt_vpl VALUES ("PP4_14","080_4_14","PHP","4","14","14","πλην καλωσ εποιησατε συγκοινωνησαντεσ μου τη θλιψει ");
INSERT INTO grcmt_vpl VALUES ("PP4_15","080_4_15","PHP","4","15","15","οιδατε δε και υμεισ φιλιππησιοι οτι εν αρχη του ευαγγελιου οτε εξηλθον απο μακεδονιασ ουδεμια μοι εκκλησια εκοινωνησεν εισ λογον δοσεωσ και ληψεωσ ει μη υμεισ μονοι ");
INSERT INTO grcmt_vpl VALUES ("PP4_16","080_4_16","PHP","4","16","16","οτι και εν θεσσαλονικη και απαξ και δισ εισ την χρειαν μοι επεμψατε ");
INSERT INTO grcmt_vpl VALUES ("PP4_17","080_4_17","PHP","4","17","17","ουχ οτι επιζητω το δομα αλλ επιζητω τον καρπον τον πλεοναζοντα εισ λογον υμων ");
INSERT INTO grcmt_vpl VALUES ("PP4_18","080_4_18","PHP","4","18","18","απεχω δε παντα και περισσευω πεπληρωμαι δεξαμενοσ παρα επαφροδιτου τα παρ υμων οσμην ευωδιασ θυσιαν δεκτην ευαρεστον τω θεω ");
INSERT INTO grcmt_vpl VALUES ("PP4_19","080_4_19","PHP","4","19","19","ο δε θεοσ μου πληρωσει πασαν χρειαν υμων κατα τον πλουτον αυτου εν δοξη εν χριστω ιησου ");
INSERT INTO grcmt_vpl VALUES ("PP4_20","080_4_20","PHP","4","20","20","τω δε θεω και πατρι ημων η δοξα εισ τουσ αιωνασ των αιωνων αμην ");
INSERT INTO grcmt_vpl VALUES ("PP4_21","080_4_21","PHP","4","21","21","ασπασασθε παντα αγιον εν χριστω ιησου ασπαζονται υμασ οι συν εμοι αδελφοι ");
INSERT INTO grcmt_vpl VALUES ("PP4_22","080_4_22","PHP","4","22","22","ασπαζονται υμασ παντεσ οι αγιοι μαλιστα δε οι εκ τησ καισαροσ οικιασ ");
INSERT INTO grcmt_vpl VALUES ("PP4_23","080_4_23","PHP","4","23","23","η χαρισ του κυριου ιησου χριστου μετα παντων υμων αμην ");
INSERT INTO grcmt_vpl VALUES ("CL1_1","081_1_1","COL","1","1","1","παυλοσ αποστολοσ ιησου χριστου δια θεληματοσ θεου και τιμοθεοσ ο αδελφοσ ");
INSERT INTO grcmt_vpl VALUES ("CL1_2","081_1_2","COL","1","2","2","τοισ εν κολασσαισ αγιοισ και πιστοισ αδελφοισ εν χριστω χαρισ υμιν και ειρηνη απο θεου πατροσ ημων και κυριου ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("CL1_3","081_1_3","COL","1","3","3","ευχαριστουμεν τω θεω και πατρι του κυριου ημων ιησου χριστου παντοτε περι υμων προσευχομενοι ");
INSERT INTO grcmt_vpl VALUES ("CL1_4","081_1_4","COL","1","4","4","ακουσαντεσ την πιστιν υμων εν χριστω ιησου και την αγαπην την εισ παντασ τουσ αγιουσ ");
INSERT INTO grcmt_vpl VALUES ("CL1_5","081_1_5","COL","1","5","5","δια την ελπιδα την αποκειμενην υμιν εν τοισ ουρανοισ ην προηκουσατε εν τω λογω τησ αληθειασ του ευαγγελιου ");
INSERT INTO grcmt_vpl VALUES ("CL1_6","081_1_6","COL","1","6","6","του παροντοσ εισ υμασ καθωσ και εν παντι τω κοσμω και εστιν καρποφορουμενον και αυξανομενον καθωσ και εν υμιν αφ ησ ημερασ ηκουσατε και επεγνωτε την χαριν του θεου εν αληθεια ");
INSERT INTO grcmt_vpl VALUES ("CL1_7","081_1_7","COL","1","7","7","καθωσ και εμαθετε απο επαφρα του αγαπητου συνδουλου ημων οσ εστιν πιστοσ υπερ υμων διακονοσ του χριστου ");
INSERT INTO grcmt_vpl VALUES ("CL1_8","081_1_8","COL","1","8","8","ο και δηλωσασ ημιν την υμων αγαπην εν πνευματι ");
INSERT INTO grcmt_vpl VALUES ("CL1_9","081_1_9","COL","1","9","9","δια τουτο και ημεισ αφ ησ ημερασ ηκουσαμεν ου παυομεθα υπερ υμων προσευχομενοι και αιτουμενοι ινα πληρωθητε την επιγνωσιν του θεληματοσ αυτου εν παση σοφια και συνεσει πνευματικη ");
INSERT INTO grcmt_vpl VALUES ("CL1_10","081_1_10","COL","1","10","10","περιπατησαι υμασ αξιωσ του κυριου εισ πασαν αρεσκειαν εν παντι εργω αγαθω καρποφορουντεσ και αυξανομενοι εισ την επιγνωσιν του θεου ");
INSERT INTO grcmt_vpl VALUES ("CL1_11","081_1_11","COL","1","11","11","εν παση δυναμει δυναμουμενοι κατα το κρατοσ τησ δοξησ αυτου εισ πασαν υπομονην και μακροθυμιαν μετα χαρασ ");
INSERT INTO grcmt_vpl VALUES ("CL1_12","081_1_12","COL","1","12","12","ευχαριστουντεσ τω πατρι τω ικανωσαντι ημασ εισ την μεριδα του κληρου των αγιων εν τω φωτι ");
INSERT INTO grcmt_vpl VALUES ("CL1_13","081_1_13","COL","1","13","13","οσ ερρυσατο ημασ εκ τησ εξουσιασ του σκοτουσ και μετεστησεν εισ την βασιλειαν του υιου τησ αγαπησ αυτου ");
INSERT INTO grcmt_vpl VALUES ("CL1_14","081_1_14","COL","1","14","14","εν ω εχομεν την απολυτρωσιν την αφεσιν των αμαρτιων ");
INSERT INTO grcmt_vpl VALUES ("CL1_15","081_1_15","COL","1","15","15","οσ εστιν εικων του θεου του αορατου πρωτοτοκοσ πασησ κτισεωσ ");
INSERT INTO grcmt_vpl VALUES ("CL1_16","081_1_16","COL","1","16","16","οτι εν αυτω εκτισθη τα παντα τα εν τοισ ουρανοισ και τα επι τησ γησ τα ορατα και τα αορατα ειτε θρονοι ειτε κυριοτητεσ ειτε αρχαι ειτε εξουσιαι τα παντα δι αυτου και εισ αυτον εκτισται ");
INSERT INTO grcmt_vpl VALUES ("CL1_17","081_1_17","COL","1","17","17","και αυτοσ εστιν προ παντων και τα παντα εν αυτω συνεστηκεν ");
INSERT INTO grcmt_vpl VALUES ("CL1_18","081_1_18","COL","1","18","18","και αυτοσ εστιν η κεφαλη του σωματοσ τησ εκκλησιασ οσ εστιν αρχη πρωτοτοκοσ εκ των νεκρων ινα γενηται εν πασιν αυτοσ πρωτευων ");
INSERT INTO grcmt_vpl VALUES ("CL1_19","081_1_19","COL","1","19","19","οτι εν αυτω ευδοκησεν παν το πληρωμα κατοικησαι ");
INSERT INTO grcmt_vpl VALUES ("CL1_20","081_1_20","COL","1","20","20","και δι αυτου αποκαταλλαξαι τα παντα εισ αυτον ειρηνοποιησασ δια του αιματοσ του σταυρου αυτου δι αυτου ειτε τα επι τησ γησ ειτε τα επι τοισ ουρανοισ ");
INSERT INTO grcmt_vpl VALUES ("CL1_21","081_1_21","COL","1","21","21","και υμασ ποτε οντασ απηλλοτριωμενουσ και εχθρουσ τη διανοια εν τοισ εργοισ τοισ πονηροισ νυνι δε αποκατηλλαξεν ");
INSERT INTO grcmt_vpl VALUES ("CL1_22","081_1_22","COL","1","22","22","εν τω σωματι τησ σαρκοσ αυτου δια του θανατου παραστησαι υμασ αγιουσ και αμωμουσ και ανεγκλητουσ κατενωπιον αυτου ");
INSERT INTO grcmt_vpl VALUES ("CL1_23","081_1_23","COL","1","23","23","ειγε επιμενετε τη πιστει τεθεμελιωμενοι και εδραιοι και μη μετακινουμενοι απο τησ ελπιδοσ του ευαγγελιου ου ηκουσατε του κηρυχθεντοσ εν παση τη κτισει τη υπο τον ουρανον ου εγενομην εγω παυλοσ διακονοσ ");
INSERT INTO grcmt_vpl VALUES ("CL1_24","081_1_24","COL","1","24","24","νυν χαιρω εν τοισ παθημασιν υπερ υμων και ανταναπληρω τα υστερηματα των θλιψεων του χριστου εν τη σαρκι μου υπερ του σωματοσ αυτου ο εστιν η εκκλησια ");
INSERT INTO grcmt_vpl VALUES ("CL1_25","081_1_25","COL","1","25","25","ησ εγενομην εγω διακονοσ κατα την οικονομιαν του θεου την δοθεισαν μοι εισ υμασ πληρωσαι τον λογον του θεου ");
INSERT INTO grcmt_vpl VALUES ("CL1_26","081_1_26","COL","1","26","26","το μυστηριον το αποκεκρυμμενον απο των αιωνων και απο των γενεων νυνι δε εφανερωθη τοισ αγιοισ αυτου ");
INSERT INTO grcmt_vpl VALUES ("CL1_27","081_1_27","COL","1","27","27","οισ ηθελησεν ο θεοσ γνωρισαι τι το πλουτοσ τησ δοξησ του μυστηριου τουτου εν τοισ εθνεσιν οσ εστιν χριστοσ εν υμιν η ελπισ τησ δοξησ ");
INSERT INTO grcmt_vpl VALUES ("CL1_28","081_1_28","COL","1","28","28","ον ημεισ καταγγελλομεν νουθετουντεσ παντα ανθρωπον και διδασκοντεσ παντα ανθρωπον εν παση σοφια ινα παραστησωμεν παντα ανθρωπον τελειον εν χριστω ιησου ");
INSERT INTO grcmt_vpl VALUES ("CL1_29","081_1_29","COL","1","29","29","εισ ο και κοπιω αγωνιζομενοσ κατα την ενεργειαν αυτου την ενεργουμενην εν εμοι εν δυναμει ");
INSERT INTO grcmt_vpl VALUES ("CL2_1","081_2_1","COL","2","1","1","θελω γαρ υμασ ειδεναι ηλικον αγωνα εχω περι υμων και των εν λαοδικεια και οσοι ουχ εωρακασιν το προσωπον μου εν σαρκι ");
INSERT INTO grcmt_vpl VALUES ("CL2_2","081_2_2","COL","2","2","2","ινα παρακληθωσιν αι καρδιαι αυτων συμβιβασθεντων εν αγαπη και εισ παντα πλουτον τησ πληροφοριασ τησ συνεσεωσ εισ επιγνωσιν του μυστηριου του θεου και πατροσ και του χριστου ");
INSERT INTO grcmt_vpl VALUES ("CL2_3","081_2_3","COL","2","3","3","εν ω εισιν παντεσ οι θησαυροι τησ σοφιασ και τησ γνωσεωσ αποκρυφοι ");
INSERT INTO grcmt_vpl VALUES ("CL2_4","081_2_4","COL","2","4","4","τουτο δε λεγω ινα μη τισ υμασ παραλογιζηται εν πιθανολογια ");
INSERT INTO grcmt_vpl VALUES ("CL2_5","081_2_5","COL","2","5","5","ει γαρ και τη σαρκι απειμι αλλα τω πνευματι συν υμιν ειμι χαιρων και βλεπων υμων την ταξιν και το στερεωμα τησ εισ χριστον πιστεωσ υμων ");
INSERT INTO grcmt_vpl VALUES ("CL2_6","081_2_6","COL","2","6","6","ωσ ουν παρελαβετε τον χριστον ιησουν τον κυριον εν αυτω περιπατειτε ");
INSERT INTO grcmt_vpl VALUES ("CL2_7","081_2_7","COL","2","7","7","ερριζωμενοι και εποικοδομουμενοι εν αυτω και βεβαιουμενοι εν τη πιστει καθωσ εδιδαχθητε περισσευοντεσ εν αυτη εν ευχαριστια ");
INSERT INTO grcmt_vpl VALUES ("CL2_8","081_2_8","COL","2","8","8","βλεπετε μη τισ υμασ εσται ο συλαγωγων δια τησ φιλοσοφιασ και κενησ απατησ κατα την παραδοσιν των ανθρωπων κατα τα στοιχεια του κοσμου και ου κατα χριστον ");
INSERT INTO grcmt_vpl VALUES ("CL2_9","081_2_9","COL","2","9","9","οτι εν αυτω κατοικει παν το πληρωμα τησ θεοτητοσ σωματικωσ ");
INSERT INTO grcmt_vpl VALUES ("CL2_10","081_2_10","COL","2","10","10","και εστε εν αυτω πεπληρωμενοι οσ εστιν η κεφαλη πασησ αρχησ και εξουσιασ ");
INSERT INTO grcmt_vpl VALUES ("CL2_11","081_2_11","COL","2","11","11","εν ω και περιετμηθητε περιτομη αχειροποιητω εν τη απεκδυσει του σωματοσ των αμαρτιων τησ σαρκοσ εν τη περιτομη του χριστου ");
INSERT INTO grcmt_vpl VALUES ("CL2_12","081_2_12","COL","2","12","12","συνταφεντεσ αυτω εν τω βαπτισματι εν ω και συνηγερθητε δια τησ πιστεωσ τησ ενεργειασ του θεου του εγειραντοσ αυτον εκ των νεκρων ");
INSERT INTO grcmt_vpl VALUES ("CL2_13","081_2_13","COL","2","13","13","και υμασ νεκρουσ οντασ εν τοισ παραπτωμασιν και τη ακροβυστια τησ σαρκοσ υμων συνεζωοποιησεν υμασ συν αυτω χαρισαμενοσ ημιν παντα τα παραπτωματα ");
INSERT INTO grcmt_vpl VALUES ("CL2_14","081_2_14","COL","2","14","14","εξαλειψασ το καθ ημων χειρογραφον τοισ δογμασιν ο ην υπεναντιον ημιν και αυτο ηρκεν εκ του μεσου προσηλωσασ αυτο τω σταυρω ");
INSERT INTO grcmt_vpl VALUES ("CL2_15","081_2_15","COL","2","15","15","απεκδυσαμενοσ τασ αρχασ και τασ εξουσιασ εδειγματισεν εν παρρησια θριαμβευσασ αυτουσ εν αυτω ");
INSERT INTO grcmt_vpl VALUES ("CL2_16","081_2_16","COL","2","16","16","μη ουν τισ υμασ κρινετω εν βρωσει η εν ποσει η εν μερει εορτησ η νουμηνιασ η σαββατων ");
INSERT INTO grcmt_vpl VALUES ("CL2_17","081_2_17","COL","2","17","17","α εστιν σκια των μελλοντων το δε σωμα χριστου ");
INSERT INTO grcmt_vpl VALUES ("CL2_18","081_2_18","COL","2","18","18","μηδεισ υμασ καταβραβευετω θελων εν ταπεινοφροσυνη και θρησκεια των αγγελων α μη εωρακεν εμβατευων εικη φυσιουμενοσ υπο του νοοσ τησ σαρκοσ αυτου ");
INSERT INTO grcmt_vpl VALUES ("CL2_19","081_2_19","COL","2","19","19","και ου κρατων την κεφαλην εξ ου παν το σωμα δια των αφων και συνδεσμων επιχορηγουμενον και συμβιβαζομενον αυξει την αυξησιν του θεου ");
INSERT INTO grcmt_vpl VALUES ("CL2_20","081_2_20","COL","2","20","20","ει απεθανετε συν χριστω απο των στοιχειων του κοσμου τι ωσ ζωντεσ εν κοσμω δογματιζεσθε ");
INSERT INTO grcmt_vpl VALUES ("CL2_21","081_2_21","COL","2","21","21","μη αψη μηδε γευση μηδε θιγησ ");
INSERT INTO grcmt_vpl VALUES ("CL2_22","081_2_22","COL","2","22","22","α εστιν παντα εισ φθοραν τη αποχρησει κατα τα ενταλματα και διδασκαλιασ των ανθρωπων ");
INSERT INTO grcmt_vpl VALUES ("CL2_23","081_2_23","COL","2","23","23","ατινα εστιν λογον μεν εχοντα σοφιασ εν εθελοθρησκεια και ταπεινοφροσυνη και αφειδια σωματοσ ουκ εν τιμη τινι προσ πλησμονην τησ σαρκοσ ");
INSERT INTO grcmt_vpl VALUES ("CL3_1","081_3_1","COL","3","1","1","ει ουν συνηγερθητε τω χριστω τα ανω ζητειτε ου ο χριστοσ εστιν εν δεξια του θεου καθημενοσ ");
INSERT INTO grcmt_vpl VALUES ("CL3_2","081_3_2","COL","3","2","2","τα ανω φρονειτε μη τα επι τησ γησ ");
INSERT INTO grcmt_vpl VALUES ("CL3_3","081_3_3","COL","3","3","3","απεθανετε γαρ και η ζωη υμων κεκρυπται συν τω χριστω εν τω θεω ");
INSERT INTO grcmt_vpl VALUES ("CL3_4","081_3_4","COL","3","4","4","οταν ο χριστοσ φανερωθη η ζωη ημων τοτε και υμεισ συν αυτω φανερωθησεσθε εν δοξη ");
INSERT INTO grcmt_vpl VALUES ("CL3_5","081_3_5","COL","3","5","5","νεκρωσατε ουν τα μελη υμων τα επι τησ γησ πορνειαν ακαθαρσιαν παθοσ επιθυμιαν κακην και την πλεονεξιαν ητισ εστιν ειδωλολατρεια ");
INSERT INTO grcmt_vpl VALUES ("CL3_6","081_3_6","COL","3","6","6","δι α ερχεται η οργη του θεου επι τουσ υιουσ τησ απειθειασ ");
INSERT INTO grcmt_vpl VALUES ("CL3_7","081_3_7","COL","3","7","7","εν οισ και υμεισ περιεπατησατε ποτε οτε εζητε εν αυτοισ ");
INSERT INTO grcmt_vpl VALUES ("CL3_8","081_3_8","COL","3","8","8","νυνι δε αποθεσθε και υμεισ τα παντα οργην θυμον κακιαν βλασφημιαν αισχρολογιαν εκ του στοματοσ υμων ");
INSERT INTO grcmt_vpl VALUES ("CL3_9","081_3_9","COL","3","9","9","μη ψευδεσθε εισ αλληλουσ απεκδυσαμενοι τον παλαιον ανθρωπον συν ταισ πραξεσιν αυτου ");
INSERT INTO grcmt_vpl VALUES ("CL3_10","081_3_10","COL","3","10","10","και ενδυσαμενοι τον νεον τον ανακαινουμενον εισ επιγνωσιν κατ εικονα του κτισαντοσ αυτον ");
INSERT INTO grcmt_vpl VALUES ("CL3_11","081_3_11","COL","3","11","11","οπου ουκ ενι ελλην και ιουδαιοσ περιτομη και ακροβυστια βαρβαροσ σκυθησ δουλοσ ελευθεροσ αλλα τα παντα και εν πασιν χριστοσ ");
INSERT INTO grcmt_vpl VALUES ("CL3_12","081_3_12","COL","3","12","12","ενδυσασθε ουν ωσ εκλεκτοι του θεου αγιοι και ηγαπημενοι σπλαγχνα οικτιρμου χρηστοτητα ταπεινοφροσυνην πραοτητα μακροθυμιαν ");
INSERT INTO grcmt_vpl VALUES ("CL3_13","081_3_13","COL","3","13","13","ανεχομενοι αλληλων και χαριζομενοι εαυτοισ εαν τισ προσ τινα εχη μομφην καθωσ και ο χριστοσ εχαρισατο υμιν ουτωσ και υμεισ ");
INSERT INTO grcmt_vpl VALUES ("CL3_14","081_3_14","COL","3","14","14","επι πασιν δε τουτοισ την αγαπην ητισ εστιν συνδεσμοσ τησ τελειοτητοσ ");
INSERT INTO grcmt_vpl VALUES ("CL3_15","081_3_15","COL","3","15","15","και η ειρηνη του θεου βραβευετω εν ταισ καρδιαισ υμων εισ ην και εκληθητε εν ενι σωματι και ευχαριστοι γινεσθε ");
INSERT INTO grcmt_vpl VALUES ("CL3_16","081_3_16","COL","3","16","16","ο λογοσ του χριστου ενοικειτω εν υμιν πλουσιωσ εν παση σοφια διδασκοντεσ και νουθετουντεσ εαυτουσ ψαλμοισ και υμνοισ και ωδαισ πνευματικαισ εν χαριτι αδοντεσ εν τη καρδια υμων τω κυριω ");
INSERT INTO grcmt_vpl VALUES ("CL3_17","081_3_17","COL","3","17","17","και παν ο τι αν ποιητε εν λογω η εν εργω παντα εν ονοματι κυριου ιησου ευχαριστουντεσ τω θεω και πατρι δι αυτου ");
INSERT INTO grcmt_vpl VALUES ("CL3_18","081_3_18","COL","3","18","18","αι γυναικεσ υποτασσεσθε τοισ ιδιοισ ανδρασιν ωσ ανηκεν εν κυριω ");
INSERT INTO grcmt_vpl VALUES ("CL3_19","081_3_19","COL","3","19","19","οι ανδρεσ αγαπατε τασ γυναικασ και μη πικραινεσθε προσ αυτασ ");
INSERT INTO grcmt_vpl VALUES ("CL3_20","081_3_20","COL","3","20","20","τα τεκνα υπακουετε τοισ γονευσιν κατα παντα τουτο γαρ εστιν ευαρεστον εν κυριω ");
INSERT INTO grcmt_vpl VALUES ("CL3_21","081_3_21","COL","3","21","21","οι πατερεσ μη ερεθιζετε τα τεκνα υμων ινα μη αθυμωσιν ");
INSERT INTO grcmt_vpl VALUES ("CL3_22","081_3_22","COL","3","22","22","οι δουλοι υπακουετε κατα παντα τοισ κατα σαρκα κυριοισ μη εν οφθαλμοδουλειαισ ωσ ανθρωπαρεσκοι αλλ εν απλοτητι καρδιασ φοβουμενοι τον θεον ");
INSERT INTO grcmt_vpl VALUES ("CL3_23","081_3_23","COL","3","23","23","και παν ο τι εαν ποιητε εκ ψυχησ εργαζεσθε ωσ τω κυριω και ουκ ανθρωποισ ");
INSERT INTO grcmt_vpl VALUES ("CL3_24","081_3_24","COL","3","24","24","ειδοτεσ οτι απο κυριου ληψεσθε την ανταποδοσιν τησ κληρονομιασ τω γαρ κυριω χριστω δουλευετε 1398 V-PAI-2P ");
INSERT INTO grcmt_vpl VALUES ("CL3_25","081_3_25","COL","3","25","25","ο δε αδικων κομιειται ο ηδικησεν και ουκ εστιν προσωποληψια ");
INSERT INTO grcmt_vpl VALUES ("CL4_1","081_4_1","COL","4","1","1","οι κυριοι το δικαιον και την ισοτητα τοισ δουλοισ παρεχεσθε ειδοτεσ οτι και υμεισ εχετε κυριον εν ουρανοισ ");
INSERT INTO grcmt_vpl VALUES ("CL4_2","081_4_2","COL","4","2","2","τη προσευχη προσκαρτερειτε γρηγορουντεσ εν αυτη εν ευχαριστια ");
INSERT INTO grcmt_vpl VALUES ("CL4_3","081_4_3","COL","4","3","3","προσευχομενοι αμα και περι ημων ινα ο θεοσ ανοιξη ημιν θυραν του λογου λαλησαι το μυστηριον του χριστου δι ο και δεδεμαι ");
INSERT INTO grcmt_vpl VALUES ("CL4_4","081_4_4","COL","4","4","4","ινα φανερωσω αυτο ωσ δει με λαλησαι ");
INSERT INTO grcmt_vpl VALUES ("CL4_5","081_4_5","COL","4","5","5","εν σοφια περιπατειτε προσ τουσ εξω τον καιρον εξαγοραζομενοι ");
INSERT INTO grcmt_vpl VALUES ("CL4_6","081_4_6","COL","4","6","6","ο λογοσ υμων παντοτε εν χαριτι αλατι ηρτυμενοσ ειδεναι πωσ δει υμασ ενι εκαστω αποκρινεσθαι ");
INSERT INTO grcmt_vpl VALUES ("CL4_7","081_4_7","COL","4","7","7","τα κατ εμε παντα γνωρισει υμιν τυχικοσ ο αγαπητοσ αδελφοσ και πιστοσ διακονοσ και συνδουλοσ εν κυριω ");
INSERT INTO grcmt_vpl VALUES ("CL4_8","081_4_8","COL","4","8","8","ον επεμψα προσ υμασ εισ αυτο τουτο ινα γνω τα περι υμων και παρακαλεση τασ καρδιασ υμων ");
INSERT INTO grcmt_vpl VALUES ("CL4_9","081_4_9","COL","4","9","9","συν ονησιμω τω πιστω και αγαπητω αδελφω οσ εστιν εξ υμων παντα υμιν γνωριουσιν τα ωδε ");
INSERT INTO grcmt_vpl VALUES ("CL4_10","081_4_10","COL","4","10","10","ασπαζεται υμασ αρισταρχοσ ο συναιχμαλωτοσ μου και μαρκοσ ο ανεψιοσ βαρναβα περι ου ελαβετε εντολασ εαν ελθη προσ υμασ δεξασθε αυτον ");
INSERT INTO grcmt_vpl VALUES ("CL4_11","081_4_11","COL","4","11","11","και ιησουσ ο λεγομενοσ ιουστοσ οι οντεσ εκ περιτομησ ουτοι μονοι συνεργοι εισ την βασιλειαν του θεου οιτινεσ εγενηθησαν μοι παρηγορια ");
INSERT INTO grcmt_vpl VALUES ("CL4_12","081_4_12","COL","4","12","12","ασπαζεται υμασ επαφρασ ο εξ υμων δουλοσ χριστου παντοτε αγωνιζομενοσ υπερ υμων εν ταισ προσευχαισ ινα στητε τελειοι και πεπληρωμενοι εν παντι θεληματι του θεου ");
INSERT INTO grcmt_vpl VALUES ("CL4_13","081_4_13","COL","4","13","13","μαρτυρω γαρ αυτω οτι εχει ζηλον πολυν υπερ υμων και των εν λαοδικεια και των εν ιεραπολει ");
INSERT INTO grcmt_vpl VALUES ("CL4_14","081_4_14","COL","4","14","14","ασπαζεται υμασ λουκασ ο ιατροσ ο αγαπητοσ και δημασ ");
INSERT INTO grcmt_vpl VALUES ("CL4_15","081_4_15","COL","4","15","15","ασπασασθε τουσ εν λαοδικεια αδελφουσ και νυμφαν και την κατ οικον αυτου εκκλησιαν ");
INSERT INTO grcmt_vpl VALUES ("CL4_16","081_4_16","COL","4","16","16","και οταν αναγνωσθη παρ υμιν η επιστολη ποιησατε ινα και εν τη λαοδικαιων εκκλησια αναγνωσθη και την εκ λαοδικειασ ινα και υμεισ αναγνωτε ");
INSERT INTO grcmt_vpl VALUES ("CL4_17","081_4_17","COL","4","17","17","και ειπατε αρχιππω βλεπε την διακονιαν ην παρελαβεσ εν κυριω ινα αυτην πληροισ ");
INSERT INTO grcmt_vpl VALUES ("CL4_18","081_4_18","COL","4","18","18","ο ασπασμοσ τη εμη χειρι παυλου μνημονευετε μου των δεσμων η χαρισ μεθ υμων αμην ");
INSERT INTO grcmt_vpl VALUES ("H11_1","082_1_1","1TH","1","1","1","παυλοσ και σιλουανοσ και τιμοθεοσ τη εκκλησια θεσσαλονικεων εν θεω πατρι και κυριω ιησου χριστω χαρισ υμιν και ειρηνη απο θεου πατροσ ημων και κυριου ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("H11_2","082_1_2","1TH","1","2","2","ευχαριστουμεν τω θεω παντοτε περι παντων υμων μνειαν υμων ποιουμενοι επι των προσευχων ημων ");
INSERT INTO grcmt_vpl VALUES ("H11_3","082_1_3","1TH","1","3","3","αδιαλειπτωσ μνημονευοντεσ υμων του εργου τησ πιστεωσ και του κοπου τησ αγαπησ και τησ υπομονησ τησ ελπιδοσ του κυριου ημων ιησου χριστου εμπροσθεν του θεου και πατροσ ημων ");
INSERT INTO grcmt_vpl VALUES ("H11_4","082_1_4","1TH","1","4","4","ειδοτεσ αδελφοι ηγαπημενοι υπο θεου την εκλογην υμων ");
INSERT INTO grcmt_vpl VALUES ("H11_5","082_1_5","1TH","1","5","5","οτι το ευαγγελιον ημων ουκ εγενηθη εισ υμασ εν λογω μονον αλλα και εν δυναμει και εν πνευματι αγιω και εν πληροφορια πολλη καθωσ οιδατε οιοι εγενηθημεν εν υμιν δι υμασ ");
INSERT INTO grcmt_vpl VALUES ("H11_6","082_1_6","1TH","1","6","6","και υμεισ μιμηται ημων εγενηθητε και του κυριου δεξαμενοι τον λογον εν θλιψει πολλη μετα χαρασ πνευματοσ αγιου ");
INSERT INTO grcmt_vpl VALUES ("H11_7","082_1_7","1TH","1","7","7","ωστε γενεσθαι υμασ τυπουσ πασιν τοισ πιστευουσιν εν τη μακεδονια και τη αχαια ");
INSERT INTO grcmt_vpl VALUES ("H11_8","082_1_8","1TH","1","8","8","αφ υμων γαρ εξηχηται ο λογοσ του κυριου ου μονον εν τη μακεδονια και εν τη αχαια αλλα και εν παντι τοπω η πιστισ υμων η προσ τον θεον εξεληλυθεν ωστε μη χρειαν ημασ εχειν λαλειν τι ");
INSERT INTO grcmt_vpl VALUES ("H11_9","082_1_9","1TH","1","9","9","αυτοι γαρ περι ημων απαγγελλουσιν οποιαν εισοδον εσχομεν προσ υμασ και πωσ επεστρεψατε προσ τον θεον απο των ειδωλων δουλευειν θεω ζωντι και αληθινω ");
INSERT INTO grcmt_vpl VALUES ("H11_10","082_1_10","1TH","1","10","10","και αναμενειν τον υιον αυτου εκ των ουρανων ον ηγειρεν εκ των νεκρων ιησουν τον ρυομενον ημασ απο τησ οργησ τησ ερχομενησ ");
INSERT INTO grcmt_vpl VALUES ("H12_1","082_2_1","1TH","2","1","1","αυτοι γαρ οιδατε αδελφοι την εισοδον ημων την προσ υμασ οτι ου κενη γεγονεν ");
INSERT INTO grcmt_vpl VALUES ("H12_2","082_2_2","1TH","2","2","2","αλλα προπαθοντεσ και υβρισθεντεσ καθωσ οιδατε εν φιλιπποισ επαρρησιασαμεθα εν τω θεω ημων λαλησαι προσ υμασ το ευαγγελιον του θεου εν πολλω αγωνι ");
INSERT INTO grcmt_vpl VALUES ("H12_3","082_2_3","1TH","2","3","3","η γαρ παρακλησισ ημων ουκ εκ πλανησ ουδε εξ ακαθαρσιασ ουτε εν δολω ");
INSERT INTO grcmt_vpl VALUES ("H12_4","082_2_4","1TH","2","4","4","αλλα καθωσ δεδοκιμασμεθα υπο του θεου πιστευθηναι το ευαγγελιον ουτωσ λαλουμεν ουχ ωσ ανθρωποισ αρεσκοντεσ αλλα τω θεω τω δοκιμαζοντι τασ καρδιασ ημων ");
INSERT INTO grcmt_vpl VALUES ("H12_5","082_2_5","1TH","2","5","5","ουτε γαρ ποτε εν λογω κολακειασ εγενηθημεν καθωσ οιδατε ουτε εν προφασει πλεονεξιασ θεοσ μαρτυσ ");
INSERT INTO grcmt_vpl VALUES ("H12_6","082_2_6","1TH","2","6","6","ουτε ζητουντεσ εξ ανθρωπων δοξαν ουτε αφ υμων ουτε απο αλλων δυναμενοι εν βαρει ειναι ωσ χριστου αποστολοι ");
INSERT INTO grcmt_vpl VALUES ("H12_7","082_2_7","1TH","2","7","7","αλλ εγενηθημεν ηπιοι εν μεσω υμων ωσ αν τροφοσ θαλπη τα εαυτησ τεκνα ");
INSERT INTO grcmt_vpl VALUES ("H12_8","082_2_8","1TH","2","8","8","ουτωσ ομειρομενοι υμων ευδοκουμεν μεταδουναι υμιν ου μονον το ευαγγελιον του θεου αλλα και τασ εαυτων ψυχασ διοτι αγαπητοι ημιν γεγενησθε ");
INSERT INTO grcmt_vpl VALUES ("H12_9","082_2_9","1TH","2","9","9","μνημονευετε γαρ αδελφοι τον κοπον ημων και τον μοχθον νυκτοσ γαρ και ημερασ εργαζομενοι προσ το μη επιβαρησαι τινα υμων εκηρυξαμεν εισ υμασ το ευαγγελιον του θεου ");
INSERT INTO grcmt_vpl VALUES ("H12_10","082_2_10","1TH","2","10","10","υμεισ μαρτυρεσ και ο θεοσ ωσ οσιωσ και δικαιωσ και αμεμπτωσ υμιν τοισ πιστευουσιν εγενηθημεν ");
INSERT INTO grcmt_vpl VALUES ("H12_11","082_2_11","1TH","2","11","11","καθαπερ οιδατε ωσ ενα εκαστον υμων ωσ πατηρ τεκνα εαυτου παρακαλουντεσ υμασ και παραμυθουμενοι ");
INSERT INTO grcmt_vpl VALUES ("H12_12","082_2_12","1TH","2","12","12","και μαρτυρομενοι εισ το περιπατησαι υμασ αξιωσ του θεου του καλουντοσ υμασ εισ την εαυτου βασιλειαν και δοξαν ");
INSERT INTO grcmt_vpl VALUES ("H12_13","082_2_13","1TH","2","13","13","δια τουτο και ημεισ ευχαριστουμεν τω θεω αδιαλειπτωσ οτι παραλαβοντεσ λογον ακοησ παρ ημων του θεου εδεξασθε ου λογον ανθρωπων αλλα καθωσ εστιν αληθωσ λογον θεου οσ και ενεργειται εν υμιν τοισ πιστευουσιν ");
INSERT INTO grcmt_vpl VALUES ("H12_14","082_2_14","1TH","2","14","14","υμεισ γαρ μιμηται εγενηθητε αδελφοι των εκκλησιων του θεου των ουσων εν τη ιουδαια εν χριστω ιησου οτι τα αυτα επαθετε και υμεισ υπο των ιδιων συμφυλετων καθωσ και αυτοι υπο των ιουδαιων ");
INSERT INTO grcmt_vpl VALUES ("H12_15","082_2_15","1TH","2","15","15","των και τον κυριον αποκτειναντων ιησουν και τουσ ιδιουσ προφητασ και ημασ εκδιωξαντων και θεω μη αρεσκοντων και πασιν ανθρωποισ εναντιων ");
INSERT INTO grcmt_vpl VALUES ("H12_16","082_2_16","1TH","2","16","16","κωλυοντων ημασ τοισ εθνεσιν λαλησαι ινα σωθωσιν εισ το αναπληρωσαι αυτων τασ αμαρτιασ παντοτε εφθασεν δε επ αυτουσ η οργη εισ τελοσ ");
INSERT INTO grcmt_vpl VALUES ("H12_17","082_2_17","1TH","2","17","17","ημεισ δε αδελφοι απορφανισθεντεσ αφ υμων προσ καιρον ωρασ προσωπω ου καρδια περισσοτερωσ εσπουδασαμεν το προσωπον υμων ιδειν εν πολλη επιθυμια ");
INSERT INTO grcmt_vpl VALUES ("H12_18","082_2_18","1TH","2","18","18","διο ηθελησαμεν ελθειν προσ υμασ εγω μεν παυλοσ και απαξ και δισ και ενεκοψεν ημασ ο σατανασ ");
INSERT INTO grcmt_vpl VALUES ("H12_19","082_2_19","1TH","2","19","19","τισ γαρ ημων ελπισ η χαρα η στεφανοσ καυχησεωσ η ουχι και υμεισ εμπροσθεν του κυριου ημων ιησου εν τη αυτου παρουσια ");
INSERT INTO grcmt_vpl VALUES ("H12_20","082_2_20","1TH","2","20","20","υμεισ γαρ εστε η δοξα ημων και η χαρα ");
INSERT INTO grcmt_vpl VALUES ("H13_1","082_3_1","1TH","3","1","1","διο μηκετι στεγοντεσ ευδοκησαμεν καταλειφθηναι εν αθηναισ μονοι ");
INSERT INTO grcmt_vpl VALUES ("H13_2","082_3_2","1TH","3","2","2","και επεμψαμεν τιμοθεον τον αδελφον ημων και διακονον του θεου και συνεργον ημων εν τω ευαγγελιω του χριστου εισ το στηριξαι υμασ και παρακαλεσαι υμασ περι τησ πιστεωσ υμων ");
INSERT INTO grcmt_vpl VALUES ("H13_3","082_3_3","1TH","3","3","3","το μηδενα σαινεσθαι εν ταισ θλιψεσιν ταυταισ αυτοι γαρ οιδατε οτι εισ τουτο κειμεθα ");
INSERT INTO grcmt_vpl VALUES ("H13_4","082_3_4","1TH","3","4","4","και γαρ οτε προσ υμασ ημεν προελεγομεν υμιν οτι μελλομεν θλιβεσθαι καθωσ και εγενετο και οιδατε ");
INSERT INTO grcmt_vpl VALUES ("H13_5","082_3_5","1TH","3","5","5","δια τουτο καγω μηκετι στεγων επεμψα εισ το γνωναι την πιστιν υμων μηπωσ επειρασεν υμασ ο πειραζων και εισ κενον γενηται ο κοποσ ημων ");
INSERT INTO grcmt_vpl VALUES ("H13_6","082_3_6","1TH","3","6","6","αρτι δε ελθοντοσ τιμοθεου προσ ημασ αφ υμων και ευαγγελισαμενου ημιν την πιστιν και την αγαπην υμων και οτι εχετε μνειαν ημων αγαθην παντοτε επιποθουντεσ ημασ ιδειν καθαπερ και ημεισ υμασ ");
INSERT INTO grcmt_vpl VALUES ("H13_7","082_3_7","1TH","3","7","7","δια τουτο παρεκληθημεν αδελφοι εφ υμιν επι παση τη θλιψει και αναγκη ημων δια τησ υμων πιστεωσ ");
INSERT INTO grcmt_vpl VALUES ("H13_8","082_3_8","1TH","3","8","8","οτι νυν ζωμεν εαν υμεισ στηκετε εν κυριω ");
INSERT INTO grcmt_vpl VALUES ("H13_9","082_3_9","1TH","3","9","9","τινα γαρ ευχαριστιαν δυναμεθα τω θεω ανταποδουναι περι υμων επι παση τη χαρα η χαιρομεν δι υμασ εμπροσθεν του θεου ημων ");
INSERT INTO grcmt_vpl VALUES ("H13_10","082_3_10","1TH","3","10","10","νυκτοσ και ημερασ υπερ εκπερισσου δεομενοι εισ το ιδειν υμων το προσωπον και καταρτισαι τα υστερηματα τησ πιστεωσ υμων ");
INSERT INTO grcmt_vpl VALUES ("H13_11","082_3_11","1TH","3","11","11","αυτοσ δε ο θεοσ και πατηρ ημων και ο κυριοσ ημων ιησουσ χριστοσ κατευθυναι την οδον ημων προσ υμασ ");
INSERT INTO grcmt_vpl VALUES ("H13_12","082_3_12","1TH","3","12","12","υμασ δε ο κυριοσ πλεονασαι και περισσευσαι τη αγαπη εισ αλληλουσ και εισ παντασ καθαπερ και ημεισ εισ υμασ ");
INSERT INTO grcmt_vpl VALUES ("H13_13","082_3_13","1TH","3","13","13","εισ το στηριξαι υμων τασ καρδιασ αμεμπτουσ εν αγιωσυνη εμπροσθεν του θεου και πατροσ ημων εν τη παρουσια του κυριου ημων ιησου χριστου μετα παντων των αγιων αυτου ");
INSERT INTO grcmt_vpl VALUES ("H14_1","082_4_1","1TH","4","1","1","λοιπον ουν αδελφοι ερωτωμεν υμασ και παρακαλουμεν εν κυριω ιησου καθωσ παρελαβετε παρ ημων το πωσ δει υμασ περιπατειν και αρεσκειν θεω ινα περισσευητε μαλλον ");
INSERT INTO grcmt_vpl VALUES ("H14_2","082_4_2","1TH","4","2","2","οιδατε γαρ τινασ παραγγελιασ εδωκαμεν υμιν δια του κυριου ιησου ");
INSERT INTO grcmt_vpl VALUES ("H14_3","082_4_3","1TH","4","3","3","τουτο γαρ εστιν θελημα του θεου ο αγιασμοσ υμων απεχεσθαι υμασ απο τησ πορνειασ ");
INSERT INTO grcmt_vpl VALUES ("H14_4","082_4_4","1TH","4","4","4","ειδεναι εκαστον υμων το εαυτου σκευοσ κτασθαι εν αγιασμω και τιμη ");
INSERT INTO grcmt_vpl VALUES ("H14_5","082_4_5","1TH","4","5","5","μη εν παθει επιθυμιασ καθαπερ και τα εθνη τα μη ειδοτα τον θεον ");
INSERT INTO grcmt_vpl VALUES ("H14_6","082_4_6","1TH","4","6","6","το μη υπερβαινειν και πλεονεκτειν εν τω πραγματι τον αδελφον αυτου διοτι εκδικοσ ο κυριοσ περι παντων τουτων καθωσ και προειπομεν υμιν και διεμαρτυραμεθα ");
INSERT INTO grcmt_vpl VALUES ("H14_7","082_4_7","1TH","4","7","7","ου γαρ εκαλεσεν ημασ ο θεοσ επι ακαθαρσια αλλ εν αγιασμω ");
INSERT INTO grcmt_vpl VALUES ("H14_8","082_4_8","1TH","4","8","8","τοιγαρουν ο αθετων ουκ ανθρωπον αθετει αλλα τον θεον τον και δοντα το πνευμα αυτου το αγιον εισ υμασ ");
INSERT INTO grcmt_vpl VALUES ("H14_9","082_4_9","1TH","4","9","9","περι δε τησ φιλαδελφιασ ου χρειαν εχετε γραφειν υμιν αυτοι γαρ υμεισ θεοδιδακτοι εστε εισ το αγαπαν αλληλουσ ");
INSERT INTO grcmt_vpl VALUES ("H14_10","082_4_10","1TH","4","10","10","και γαρ ποιειτε αυτο εισ παντασ τουσ αδελφουσ τουσ εν ολη τη μακεδονια παρακαλουμεν δε υμασ αδελφοι περισσευειν μαλλον ");
INSERT INTO grcmt_vpl VALUES ("H14_11","082_4_11","1TH","4","11","11","και φιλοτιμεισθαι ησυχαζειν και πρασσειν τα ιδια και εργαζεσθαι ταισ ιδιαισ χερσιν υμων καθωσ υμιν παρηγγειλαμεν ");
INSERT INTO grcmt_vpl VALUES ("H14_12","082_4_12","1TH","4","12","12","ινα περιπατητε ευσχημονωσ προσ τουσ εξω και μηδενοσ χρειαν εχητε ");
INSERT INTO grcmt_vpl VALUES ("H14_13","082_4_13","1TH","4","13","13","ου θελομεν δε υμασ αγνοειν αδελφοι περι των κεκοιμημενων ινα μη λυπησθε καθωσ και οι λοιποι οι μη εχοντεσ ελπιδα ");
INSERT INTO grcmt_vpl VALUES ("H14_14","082_4_14","1TH","4","14","14","ει γαρ πιστευομεν οτι ιησουσ απεθανεν και ανεστη ουτωσ και ο θεοσ τουσ κοιμηθεντασ δια του ιησου αξει συν αυτω ");
INSERT INTO grcmt_vpl VALUES ("H14_15","082_4_15","1TH","4","15","15","τουτο γαρ υμιν λεγομεν εν λογω κυριου οτι ημεισ οι ζωντεσ οι περιλειπομενοι εισ την παρουσιαν του κυριου ου μη φθασωμεν τουσ κοιμηθεντασ ");
INSERT INTO grcmt_vpl VALUES ("H14_16","082_4_16","1TH","4","16","16","οτι αυτοσ ο κυριοσ εν κελευσματι εν φωνη αρχαγγελου και εν σαλπιγγι θεου καταβησεται απ ουρανου και οι νεκροι εν χριστω αναστησονται πρωτον ");
INSERT INTO grcmt_vpl VALUES ("H14_17","082_4_17","1TH","4","17","17","επειτα ημεισ οι ζωντεσ οι περιλειπομενοι αμα συν αυτοισ αρπαγησομεθα εν νεφελαισ εισ απαντησιν του κυριου εισ αερα και ουτωσ παντοτε συν κυριω εσομεθα ");
INSERT INTO grcmt_vpl VALUES ("H14_18","082_4_18","1TH","4","18","18","ωστε παρακαλειτε αλληλουσ εν τοισ λογοισ τουτοισ ");
INSERT INTO grcmt_vpl VALUES ("H15_1","082_5_1","1TH","5","1","1","περι δε των χρονων και των καιρων αδελφοι ου χρειαν εχετε υμιν γραφεσθαι ");
INSERT INTO grcmt_vpl VALUES ("H15_2","082_5_2","1TH","5","2","2","αυτοι γαρ ακριβωσ οιδατε οτι η ημερα κυριου ωσ κλεπτησ εν νυκτι ουτωσ ερχεται ");
INSERT INTO grcmt_vpl VALUES ("H15_3","082_5_3","1TH","5","3","3","οταν γαρ λεγωσιν ειρηνη και ασφαλεια τοτε αιφνιδιοσ αυτοισ εφισταται ολεθροσ ωσπερ η ωδιν τη εν γαστρι εχουση και ου μη εκφυγωσιν ");
INSERT INTO grcmt_vpl VALUES ("H15_4","082_5_4","1TH","5","4","4","υμεισ δε αδελφοι ουκ εστε εν σκοτει ινα η ημερα υμασ ωσ κλεπτησ καταλαβη ");
INSERT INTO grcmt_vpl VALUES ("H15_5","082_5_5","1TH","5","5","5","παντεσ υμεισ υιοι φωτοσ εστε και υιοι ημερασ ουκ εσμεν νυκτοσ ουδε σκοτουσ ");
INSERT INTO grcmt_vpl VALUES ("H15_6","082_5_6","1TH","5","6","6","αρα ουν μη καθευδωμεν ωσ και οι λοιποι αλλα γρηγορωμεν και νηφωμεν ");
INSERT INTO grcmt_vpl VALUES ("H15_7","082_5_7","1TH","5","7","7","οι γαρ καθευδοντεσ νυκτοσ καθευδουσιν και οι μεθυσκομενοι νυκτοσ μεθυουσιν ");
INSERT INTO grcmt_vpl VALUES ("H15_8","082_5_8","1TH","5","8","8","ημεισ δε ημερασ οντεσ νηφωμεν ενδυσαμενοι θωρακα πιστεωσ και αγαπησ και περικεφαλαιαν ελπιδα σωτηριασ ");
INSERT INTO grcmt_vpl VALUES ("H15_9","082_5_9","1TH","5","9","9","οτι ουκ εθετο ημασ ο θεοσ εισ οργην αλλ εισ περιποιησιν σωτηριασ δια του κυριου ημων ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("H15_10","082_5_10","1TH","5","10","10","του αποθανοντοσ υπερ ημων ινα ειτε γρηγορωμεν ειτε καθευδωμεν αμα συν αυτω ζησωμεν ");
INSERT INTO grcmt_vpl VALUES ("H15_11","082_5_11","1TH","5","11","11","διο παρακαλειτε αλληλουσ και οικοδομειτε εισ τον ενα καθωσ και ποιειτε ");
INSERT INTO grcmt_vpl VALUES ("H15_12","082_5_12","1TH","5","12","12","ερωτωμεν δε υμασ αδελφοι ειδεναι τουσ κοπιωντασ εν υμιν και προισταμενουσ υμων εν κυριω και νουθετουντασ υμασ ");
INSERT INTO grcmt_vpl VALUES ("H15_13","082_5_13","1TH","5","13","13","και ηγεισθαι αυτουσ υπερ εκπερισσου εν αγαπη δια το εργον αυτων ειρηνευετε εν εαυτοισ ");
INSERT INTO grcmt_vpl VALUES ("H15_14","082_5_14","1TH","5","14","14","παρακαλουμεν δε υμασ αδελφοι νουθετειτε τουσ ατακτουσ παραμυθεισθε τουσ ολιγοψυχουσ αντεχεσθε των ασθενων μακροθυμειτε προσ παντασ ");
INSERT INTO grcmt_vpl VALUES ("H15_15","082_5_15","1TH","5","15","15","ορατε μη τισ κακον αντι κακου τινι αποδω αλλα παντοτε το αγαθον διωκετε και εισ αλληλουσ και εισ παντασ ");
INSERT INTO grcmt_vpl VALUES ("H15_16","082_5_16","1TH","5","16","16","παντοτε χαιρετε ");
INSERT INTO grcmt_vpl VALUES ("H15_17","082_5_17","1TH","5","17","17","αδιαλειπτωσ προσευχεσθε ");
INSERT INTO grcmt_vpl VALUES ("H15_18","082_5_18","1TH","5","18","18","εν παντι ευχαριστειτε τουτο γαρ θελημα θεου εν χριστω ιησου εισ υμασ ");
INSERT INTO grcmt_vpl VALUES ("H15_19","082_5_19","1TH","5","19","19","το πνευμα μη σβεννυτε ");
INSERT INTO grcmt_vpl VALUES ("H15_20","082_5_20","1TH","5","20","20","προφητειασ μη εξουθενειτε ");
INSERT INTO grcmt_vpl VALUES ("H15_21","082_5_21","1TH","5","21","21","παντα δε δοκιμαζετε το καλον κατεχετε ");
INSERT INTO grcmt_vpl VALUES ("H15_22","082_5_22","1TH","5","22","22","απο παντοσ ειδουσ πονηρου απεχεσθε ");
INSERT INTO grcmt_vpl VALUES ("H15_23","082_5_23","1TH","5","23","23","αυτοσ δε ο θεοσ τησ ειρηνησ αγιασαι υμασ ολοτελεισ και ολοκληρον υμων το πνευμα και η ψυχη και το σωμα αμεμπτωσ εν τη παρουσια του κυριου ημων ιησου χριστου τηρηθειη ");
INSERT INTO grcmt_vpl VALUES ("H15_24","082_5_24","1TH","5","24","24","πιστοσ ο καλων υμασ οσ και ποιησει ");
INSERT INTO grcmt_vpl VALUES ("H15_25","082_5_25","1TH","5","25","25","αδελφοι προσευχεσθε περι ημων ");
INSERT INTO grcmt_vpl VALUES ("H15_26","082_5_26","1TH","5","26","26","ασπασασθε τουσ αδελφουσ παντασ εν φιληματι αγιω ");
INSERT INTO grcmt_vpl VALUES ("H15_27","082_5_27","1TH","5","27","27","ορκιζω υμασ τον κυριον αναγνωσθηναι την επιστολην πασιν τοισ αγιοισ αδελφοισ ");
INSERT INTO grcmt_vpl VALUES ("H15_28","082_5_28","1TH","5","28","28","η χαρισ του κυριου ημων ιησου χριστου μεθ υμων αμην ");
INSERT INTO grcmt_vpl VALUES ("H21_1","083_1_1","2TH","1","1","1","παυλοσ και σιλουανοσ και τιμοθεοσ τη εκκλησια θεσσαλονικεων εν θεω πατρι ημων και κυριω ιησου χριστω ");
INSERT INTO grcmt_vpl VALUES ("H21_2","083_1_2","2TH","1","2","2","χαρισ υμιν και ειρηνη απο θεου πατροσ ημων και κυριου ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("H21_3","083_1_3","2TH","1","3","3","ευχαριστειν οφειλομεν τω θεω παντοτε περι υμων αδελφοι καθωσ αξιον εστιν οτι υπεραυξανει η πιστισ υμων και πλεοναζει η αγαπη ενοσ εκαστου παντων υμων εισ αλληλουσ ");
INSERT INTO grcmt_vpl VALUES ("H21_4","083_1_4","2TH","1","4","4","ωστε ημασ αυτουσ εν υμιν καυχασθαι εν ταισ εκκλησιαισ του θεου υπερ τησ υπομονησ υμων και πιστεωσ εν πασιν τοισ διωγμοισ υμων και ταισ θλιψεσιν αισ ανεχεσθε ");
INSERT INTO grcmt_vpl VALUES ("H21_5","083_1_5","2TH","1","5","5","ενδειγμα τησ δικαιασ κρισεωσ του θεου εισ το καταξιωθηναι υμασ τησ βασιλειασ του θεου υπερ ησ και πασχετε ");
INSERT INTO grcmt_vpl VALUES ("H21_6","083_1_6","2TH","1","6","6","ειπερ δικαιον παρα θεω ανταποδουναι τοισ θλιβουσιν υμασ θλιψιν ");
INSERT INTO grcmt_vpl VALUES ("H21_7","083_1_7","2TH","1","7","7","και υμιν τοισ θλιβομενοισ ανεσιν μεθ ημων εν τη αποκαλυψει του κυριου ιησου απ ουρανου μετ αγγελων δυναμεωσ αυτου ");
INSERT INTO grcmt_vpl VALUES ("H21_8","083_1_8","2TH","1","8","8","εν πυρι φλογοσ διδοντοσ εκδικησιν τοισ μη ειδοσιν θεον και τοισ μη υπακουουσιν τω ευαγγελιω του κυριου ημων ιησου ");
INSERT INTO grcmt_vpl VALUES ("H21_9","083_1_9","2TH","1","9","9","οιτινεσ δικην τισουσιν ολεθρον αιωνιον απο προσωπου του κυριου και απο τησ δοξησ τησ ισχυοσ αυτου ");
INSERT INTO grcmt_vpl VALUES ("H21_10","083_1_10","2TH","1","10","10","οταν ελθη ενδοξασθηναι εν τοισ αγιοισ αυτου και θαυμασθηναι εν πασιν τοισ πιστευσασιν οτι επιστευθη το μαρτυριον ημων εφ υμασ εν τη ημερα εκεινη ");
INSERT INTO grcmt_vpl VALUES ("H21_11","083_1_11","2TH","1","11","11","εισ ο και προσευχομεθα παντοτε περι υμων ινα υμασ αξιωση τησ κλησεωσ ο θεοσ ημων και πληρωση πασαν ευδοκιαν αγαθωσυνησ και εργον πιστεωσ εν δυναμει ");
INSERT INTO grcmt_vpl VALUES ("H21_12","083_1_12","2TH","1","12","12","οπωσ ενδοξασθη το ονομα του κυριου ημων ιησου εν υμιν και υμεισ εν αυτω κατα την χαριν του θεου ημων και κυριου ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("H22_1","083_2_1","2TH","2","1","1","ερωτωμεν δε υμασ αδελφοι υπερ τησ παρουσιασ του κυριου ημων ιησου χριστου και ημων επισυναγωγησ επ αυτον ");
INSERT INTO grcmt_vpl VALUES ("H22_2","083_2_2","2TH","2","2","2","εισ το μη ταχεωσ σαλευθηναι υμασ απο του νοοσ μητε θροεισθαι μητε δια πνευματοσ μητε δια λογου μητε δι επιστολησ ωσ δι ημων ωσ οτι ενεστηκεν η ημερα του χριστου ");
INSERT INTO grcmt_vpl VALUES ("H22_3","083_2_3","2TH","2","3","3","μη τισ υμασ εξαπατηση κατα μηδενα τροπον οτι εαν μη ελθη η αποστασια πρωτον και αποκαλυφθη ο ανθρωποσ τησ αμαρτιασ ο υιοσ τησ απωλειασ ");
INSERT INTO grcmt_vpl VALUES ("H22_4","083_2_4","2TH","2","4","4","ο αντικειμενοσ και υπεραιρομενοσ επι παντα λεγομενον θεον η σεβασμα ωστε αυτον εισ τον ναον του θεου ωσ θεον καθισαι αποδεικνυντα εαυτον οτι εστιν θεοσ ");
INSERT INTO grcmt_vpl VALUES ("H22_5","083_2_5","2TH","2","5","5","ου μνημονευετε οτι ετι ων προσ υμασ ταυτα ελεγον υμιν ");
INSERT INTO grcmt_vpl VALUES ("H22_6","083_2_6","2TH","2","6","6","και νυν το κατεχον οιδατε εισ το αποκαλυφθηναι αυτον εν τω εαυτου καιρω ");
INSERT INTO grcmt_vpl VALUES ("H22_7","083_2_7","2TH","2","7","7","το γαρ μυστηριον ηδη ενεργειται τησ ανομιασ μονον ο κατεχων αρτι εωσ εκ μεσου γενηται ");
INSERT INTO grcmt_vpl VALUES ("H22_8","083_2_8","2TH","2","8","8","και τοτε αποκαλυφθησεται ο ανομοσ ον ο κυριοσ αναλωσει τω πνευματι του στοματοσ αυτου και καταργησει τη επιφανεια τησ παρουσιασ αυτου ");
INSERT INTO grcmt_vpl VALUES ("H22_9","083_2_9","2TH","2","9","9","ου εστιν η παρουσια κατ ενεργειαν του σατανα εν παση δυναμει και σημειοισ και τερασιν ψευδουσ ");
INSERT INTO grcmt_vpl VALUES ("H22_10","083_2_10","2TH","2","10","10","και εν παση απατη τησ αδικιασ εν τοισ απολλυμενοισ ανθ ων την αγαπην τησ αληθειασ ουκ εδεξαντο εισ το σωθηναι αυτουσ ");
INSERT INTO grcmt_vpl VALUES ("H22_11","083_2_11","2TH","2","11","11","και δια τουτο πεμψει αυτοισ ο θεοσ ενεργειαν πλανησ εισ το πιστευσαι αυτουσ τω ψευδει ");
INSERT INTO grcmt_vpl VALUES ("H22_12","083_2_12","2TH","2","12","12","ινα κριθωσιν παντεσ οι μη πιστευσαντεσ τη αληθεια αλλ ευδοκησαντεσ εν τη αδικια ");
INSERT INTO grcmt_vpl VALUES ("H22_13","083_2_13","2TH","2","13","13","ημεισ δε οφειλομεν ευχαριστειν τω θεω παντοτε περι υμων αδελφοι ηγαπημενοι υπο κυριου οτι ειλετο υμασ ο θεοσ απ αρχησ εισ σωτηριαν εν αγιασμω πνευματοσ και πιστει αληθειασ ");
INSERT INTO grcmt_vpl VALUES ("H22_14","083_2_14","2TH","2","14","14","εισ ο εκαλεσεν υμασ δια του ευαγγελιου ημων εισ περιποιησιν δοξησ του κυριου ημων ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("H22_15","083_2_15","2TH","2","15","15","αρα ουν αδελφοι στηκετε και κρατειτε τασ παραδοσεισ ασ εδιδαχθητε ειτε δια λογου ειτε δι επιστολησ ημων ");
INSERT INTO grcmt_vpl VALUES ("H22_16","083_2_16","2TH","2","16","16","αυτοσ δε ο κυριοσ ημων ιησουσ χριστοσ και ο θεοσ και πατηρ ημων ο αγαπησασ ημασ και δουσ παρακλησιν αιωνιαν και ελπιδα αγαθην εν χαριτι ");
INSERT INTO grcmt_vpl VALUES ("H22_17","083_2_17","2TH","2","17","17","παρακαλεσαι υμων τασ καρδιασ και στηριξαι υμασ εν παντι λογω και εργω αγαθω ");
INSERT INTO grcmt_vpl VALUES ("H23_1","083_3_1","2TH","3","1","1","το λοιπον προσευχεσθε αδελφοι περι ημων ινα ο λογοσ του κυριου τρεχη και δοξαζηται καθωσ και προσ υμασ ");
INSERT INTO grcmt_vpl VALUES ("H23_2","083_3_2","2TH","3","2","2","και ινα ρυσθωμεν απο των ατοπων και πονηρων ανθρωπων ου γαρ παντων η πιστισ ");
INSERT INTO grcmt_vpl VALUES ("H23_3","083_3_3","2TH","3","3","3","πιστοσ δε εστιν ο κυριοσ οσ στηριξει υμασ και φυλαξει απο του πονηρου ");
INSERT INTO grcmt_vpl VALUES ("H23_4","083_3_4","2TH","3","4","4","πεποιθαμεν δε εν κυριω εφ υμασ οτι α παραγγελλομεν υμιν και ποιειτε και ποιησετε ");
INSERT INTO grcmt_vpl VALUES ("H23_5","083_3_5","2TH","3","5","5","ο δε κυριοσ κατευθυναι υμων τασ καρδιασ εισ την αγαπην του θεου και εισ την υπομονην του χριστου ");
INSERT INTO grcmt_vpl VALUES ("H23_6","083_3_6","2TH","3","6","6","παραγγελλομεν δε υμιν αδελφοι εν ονοματι του κυριου ημων ιησου χριστου στελλεσθαι υμασ απο παντοσ αδελφου ατακτωσ περιπατουντοσ και μη κατα την παραδοσιν ην παρελαβον παρ ημων ");
INSERT INTO grcmt_vpl VALUES ("H23_7","083_3_7","2TH","3","7","7","αυτοι γαρ οιδατε πωσ δει μιμεισθαι ημασ οτι ουκ ητακτησαμεν εν υμιν ");
INSERT INTO grcmt_vpl VALUES ("H23_8","083_3_8","2TH","3","8","8","ουδε δωρεαν αρτον εφαγομεν παρα τινοσ αλλ εν κοπω και μοχθω νυκτα και ημεραν εργαζομενοι προσ το μη επιβαρησαι τινα υμων ");
INSERT INTO grcmt_vpl VALUES ("H23_9","083_3_9","2TH","3","9","9","ουχ οτι ουκ εχομεν εξουσιαν αλλ ινα εαυτουσ τυπον δωμεν υμιν εισ το μιμεισθαι ημασ ");
INSERT INTO grcmt_vpl VALUES ("H23_10","083_3_10","2TH","3","10","10","και γαρ οτε ημεν προσ υμασ τουτο παρηγγελλομεν υμιν οτι ει τισ ου θελει εργαζεσθαι μηδε εσθιετω ");
INSERT INTO grcmt_vpl VALUES ("H23_11","083_3_11","2TH","3","11","11","ακουομεν γαρ τινασ περιπατουντασ εν υμιν ατακτωσ μηδεν εργαζομενουσ αλλα περιεργαζομενουσ ");
INSERT INTO grcmt_vpl VALUES ("H23_12","083_3_12","2TH","3","12","12","τοισ δε τοιουτοισ παραγγελλομεν και παρακαλουμεν δια του κυριου ημων ιησου χριστου ινα μετα ησυχιασ εργαζομενοι τον εαυτων αρτον εσθιωσιν ");
INSERT INTO grcmt_vpl VALUES ("H23_13","083_3_13","2TH","3","13","13","υμεισ δε αδελφοι μη εκκακησητε καλοποιουντεσ ");
INSERT INTO grcmt_vpl VALUES ("H23_14","083_3_14","2TH","3","14","14","ει δε τισ ουχ υπακουει τω λογω ημων δια τησ επιστολησ τουτον σημειουσθε και μη συναναμιγνυσθε αυτω ινα εντραπη ");
INSERT INTO grcmt_vpl VALUES ("H23_15","083_3_15","2TH","3","15","15","και μη ωσ εχθρον ηγεισθε αλλα νουθετειτε ωσ αδελφον ");
INSERT INTO grcmt_vpl VALUES ("H23_16","083_3_16","2TH","3","16","16","αυτοσ δε ο κυριοσ τησ ειρηνησ δωη υμιν την ειρηνην δια παντοσ εν παντι τροπω ο κυριοσ μετα παντων υμων ");
INSERT INTO grcmt_vpl VALUES ("H23_17","083_3_17","2TH","3","17","17","ο ασπασμοσ τη εμη χειρι παυλου ο εστιν σημειον εν παση επιστολη ουτωσ γραφω ");
INSERT INTO grcmt_vpl VALUES ("H23_18","083_3_18","2TH","3","18","18","η χαρισ του κυριου ημων ιησου χριστου μετα παντων υμων αμην ");
INSERT INTO grcmt_vpl VALUES ("T11_1","084_1_1","1TI","1","1","1","παυλοσ αποστολοσ ιησου χριστου κατ επιταγην θεου σωτηροσ ημων και κυριου ιησου χριστου τησ ελπιδοσ ημων ");
INSERT INTO grcmt_vpl VALUES ("T11_2","084_1_2","1TI","1","2","2","τιμοθεω γνησιω τεκνω εν πιστει χαρισ ελεοσ ειρηνη απο θεου πατροσ ημων και χριστου ιησου του κυριου ημων ");
INSERT INTO grcmt_vpl VALUES ("T11_3","084_1_3","1TI","1","3","3","καθωσ παρεκαλεσα σε προσμειναι εν εφεσω πορευομενοσ εισ μακεδονιαν ινα παραγγειλησ τισιν μη ετεροδιδασκαλειν ");
INSERT INTO grcmt_vpl VALUES ("T11_4","084_1_4","1TI","1","4","4","μηδε προσεχειν μυθοισ και γενεαλογιαισ απεραντοισ αιτινεσ ζητησεισ παρεχουσιν μαλλον η οικονομιαν θεου την εν πιστει ");
INSERT INTO grcmt_vpl VALUES ("T11_5","084_1_5","1TI","1","5","5","το δε τελοσ τησ παραγγελιασ εστιν αγαπη εκ καθαρασ καρδιασ και συνειδησεωσ αγαθησ και πιστεωσ ανυποκριτου ");
INSERT INTO grcmt_vpl VALUES ("T11_6","084_1_6","1TI","1","6","6","ων τινεσ αστοχησαντεσ εξετραπησαν εισ ματαιολογιαν ");
INSERT INTO grcmt_vpl VALUES ("T11_7","084_1_7","1TI","1","7","7","θελοντεσ ειναι νομοδιδασκαλοι μη νοουντεσ μητε α λεγουσιν μητε περι τινων διαβεβαιουνται ");
INSERT INTO grcmt_vpl VALUES ("T11_8","084_1_8","1TI","1","8","8","οιδαμεν δε οτι καλοσ ο νομοσ εαν τισ αυτω νομιμωσ χρηται ");
INSERT INTO grcmt_vpl VALUES ("T11_9","084_1_9","1TI","1","9","9","ειδωσ τουτο οτι δικαιω νομοσ ου κειται ανομοισ δε και ανυποτακτοισ ασεβεσιν και αμαρτωλοισ ανοσιοισ και βεβηλοισ πατρολωαισ και μητρολωαισ ανδροφονοισ ");
INSERT INTO grcmt_vpl VALUES ("T11_10","084_1_10","1TI","1","10","10","πορνοισ αρσενοκοιταισ ανδραποδισταισ ψευσταισ επιορκοισ και ει τι ετερον τη υγιαινουση διδασκαλια αντικειται ");
INSERT INTO grcmt_vpl VALUES ("T11_11","084_1_11","1TI","1","11","11","κατα το ευαγγελιον τησ δοξησ του μακαριου θεου ο επιστευθην εγω ");
INSERT INTO grcmt_vpl VALUES ("T11_12","084_1_12","1TI","1","12","12","και χαριν εχω τω ενδυναμωσαντι με χριστω ιησου τω κυριω ημων οτι πιστον με ηγησατο θεμενοσ εισ διακονιαν ");
INSERT INTO grcmt_vpl VALUES ("T11_13","084_1_13","1TI","1","13","13","τον προτερον οντα βλασφημον και διωκτην και υβριστην αλλα ηλεηθην οτι αγνοων εποιησα εν απιστια ");
INSERT INTO grcmt_vpl VALUES ("T11_14","084_1_14","1TI","1","14","14","υπερεπλεονασεν δε η χαρισ του κυριου ημων μετα πιστεωσ και αγαπησ τησ εν χριστω ιησου ");
INSERT INTO grcmt_vpl VALUES ("T11_15","084_1_15","1TI","1","15","15","πιστοσ ο λογοσ και πασησ αποδοχησ αξιοσ οτι χριστοσ ιησουσ ηλθεν εισ τον κοσμον αμαρτωλουσ σωσαι ων πρωτοσ ειμι εγω ");
INSERT INTO grcmt_vpl VALUES ("T11_16","084_1_16","1TI","1","16","16","αλλα δια τουτο ηλεηθην ινα εν εμοι πρωτω ενδειξηται ιησουσ χριστοσ την πασαν μακροθυμιαν προσ υποτυπωσιν των μελλοντων πιστευειν επ αυτω εισ ζωην αιωνιον ");
INSERT INTO grcmt_vpl VALUES ("T11_17","084_1_17","1TI","1","17","17","τω δε βασιλει των αιωνων αφθαρτω αορατω μονω σοφω θεω τιμη και δοξα εισ τουσ αιωνασ των αιωνων αμην ");
INSERT INTO grcmt_vpl VALUES ("T11_18","084_1_18","1TI","1","18","18","ταυτην την παραγγελιαν παρατιθεμαι σοι τεκνον τιμοθεε κατα τασ προαγουσασ επι σε προφητειασ ινα στρατευη εν αυταισ την καλην στρατειαν ");
INSERT INTO grcmt_vpl VALUES ("T11_19","084_1_19","1TI","1","19","19","εχων πιστιν και αγαθην συνειδησιν ην τινεσ απωσαμενοι περι την πιστιν εναυαγησαν ");
INSERT INTO grcmt_vpl VALUES ("T11_20","084_1_20","1TI","1","20","20","ων εστιν υμεναιοσ και αλεξανδροσ ουσ παρεδωκα τω σατανα ινα παιδευθωσιν μη βλασφημειν ");
INSERT INTO grcmt_vpl VALUES ("T12_1","084_2_1","1TI","2","1","1","παρακαλω ουν πρωτον παντων ποιεισθαι δεησεισ προσευχασ εντευξεισ ευχαριστιασ υπερ παντων ανθρωπων ");
INSERT INTO grcmt_vpl VALUES ("T12_2","084_2_2","1TI","2","2","2","υπερ βασιλεων και παντων των εν υπεροχη οντων ινα ηρεμον και ησυχιον βιον διαγωμεν εν παση ευσεβεια και σεμνοτητι ");
INSERT INTO grcmt_vpl VALUES ("T12_3","084_2_3","1TI","2","3","3","τουτο γαρ καλον και αποδεκτον ενωπιον του σωτηροσ ημων θεου ");
INSERT INTO grcmt_vpl VALUES ("T12_4","084_2_4","1TI","2","4","4","οσ παντασ ανθρωπουσ θελει σωθηναι και εισ επιγνωσιν αληθειασ ελθειν ");
INSERT INTO grcmt_vpl VALUES ("T12_5","084_2_5","1TI","2","5","5","εισ γαρ θεοσ εισ και μεσιτησ θεου και ανθρωπων ανθρωποσ χριστοσ ιησουσ ");
INSERT INTO grcmt_vpl VALUES ("T12_6","084_2_6","1TI","2","6","6","ο δουσ εαυτον αντιλυτρον υπερ παντων το μαρτυριον καιροισ ιδιοισ ");
INSERT INTO grcmt_vpl VALUES ("T12_7","084_2_7","1TI","2","7","7","εισ ο ετεθην εγω κηρυξ και αποστολοσ αληθειαν λεγω εν χριστω ου ψευδομαι διδασκαλοσ εθνων εν πιστει και αληθεια ");
INSERT INTO grcmt_vpl VALUES ("T12_8","084_2_8","1TI","2","8","8","βουλομαι ουν προσευχεσθαι τουσ ανδρασ εν παντι τοπω επαιροντασ οσιουσ χειρασ χωρισ οργησ και διαλογισμου ");
INSERT INTO grcmt_vpl VALUES ("T12_9","084_2_9","1TI","2","9","9","ωσαυτωσ και τασ γυναικασ εν καταστολη κοσμιω μετα αιδουσ και σωφροσυνησ κοσμειν εαυτασ μη εν πλεγμασιν η χρυσω η μαργαριταισ η ιματισμω πολυτελει ");
INSERT INTO grcmt_vpl VALUES ("T12_10","084_2_10","1TI","2","10","10","αλλ ο πρεπει γυναιξιν επαγγελλομεναισ θεοσεβειαν δι εργων αγαθων ");
INSERT INTO grcmt_vpl VALUES ("T12_11","084_2_11","1TI","2","11","11","γυνη εν ησυχια μανθανετω εν παση υποταγη ");
INSERT INTO grcmt_vpl VALUES ("T12_12","084_2_12","1TI","2","12","12","γυναικι δε διδασκειν ουκ επιτρεπω ουδε αυθεντειν ανδροσ αλλ ειναι εν ησυχια ");
INSERT INTO grcmt_vpl VALUES ("T12_13","084_2_13","1TI","2","13","13","αδαμ γαρ πρωτοσ επλασθη ειτα ευα ");
INSERT INTO grcmt_vpl VALUES ("T12_14","084_2_14","1TI","2","14","14","και αδαμ ουκ ηπατηθη η δε γυνη απατηθεισα εν παραβασει γεγονεν ");
INSERT INTO grcmt_vpl VALUES ("T12_15","084_2_15","1TI","2","15","15","σωθησεται δε δια τησ τεκνογονιασ εαν μεινωσιν εν πιστει και αγαπη και αγιασμω μετα σωφροσυνησ ");
INSERT INTO grcmt_vpl VALUES ("T13_1","084_3_1","1TI","3","1","1","πιστοσ ο λογοσ ει τισ επισκοπησ ορεγεται καλου εργου επιθυμει ");
INSERT INTO grcmt_vpl VALUES ("T13_2","084_3_2","1TI","3","2","2","δει ουν τον επισκοπον ανεπιληπτον ειναι μιασ γυναικοσ ανδρα νηφαλεον σωφρονα κοσμιον φιλοξενον διδακτικον ");
INSERT INTO grcmt_vpl VALUES ("T13_3","084_3_3","1TI","3","3","3","μη παροινον μη πληκτην μη αισχροκερδη αλλ επιεικη αμαχον αφιλαργυρον ");
INSERT INTO grcmt_vpl VALUES ("T13_4","084_3_4","1TI","3","4","4","του ιδιου οικου καλωσ προισταμενον τεκνα εχοντα εν υποταγη μετα πασησ σεμνοτητοσ ");
INSERT INTO grcmt_vpl VALUES ("T13_5","084_3_5","1TI","3","5","5","ει δε τισ του ιδιου οικου προστηναι ουκ οιδεν πωσ εκκλησιασ θεου επιμελησεται ");
INSERT INTO grcmt_vpl VALUES ("T13_6","084_3_6","1TI","3","6","6","μη νεοφυτον ινα μη τυφωθεισ εισ κριμα εμπεση του διαβολου ");
INSERT INTO grcmt_vpl VALUES ("T13_7","084_3_7","1TI","3","7","7","δει δε αυτον και μαρτυριαν καλην εχειν απο των εξωθεν ινα μη εισ ονειδισμον εμπεση και παγιδα του διαβολου ");
INSERT INTO grcmt_vpl VALUES ("T13_8","084_3_8","1TI","3","8","8","διακονουσ ωσαυτωσ σεμνουσ μη διλογουσ μη οινω πολλω προσεχοντασ μη αισχροκερδεισ ");
INSERT INTO grcmt_vpl VALUES ("T13_9","084_3_9","1TI","3","9","9","εχοντασ το μυστηριον τησ πιστεωσ εν καθαρα συνειδησει ");
INSERT INTO grcmt_vpl VALUES ("T13_10","084_3_10","1TI","3","10","10","και ουτοι δε δοκιμαζεσθωσαν πρωτον ειτα διακονειτωσαν ανεγκλητοι οντεσ ");
INSERT INTO grcmt_vpl VALUES ("T13_11","084_3_11","1TI","3","11","11","γυναικασ ωσαυτωσ σεμνασ μη διαβολουσ νηφαλεουσ πιστασ εν πασιν ");
INSERT INTO grcmt_vpl VALUES ("T13_12","084_3_12","1TI","3","12","12","διακονοι εστωσαν μιασ γυναικοσ ανδρεσ τεκνων καλωσ προισταμενοι και των ιδιων οικων ");
INSERT INTO grcmt_vpl VALUES ("T13_13","084_3_13","1TI","3","13","13","οι γαρ καλωσ διακονησαντεσ βαθμον εαυτοισ καλον περιποιουνται και πολλην παρρησιαν εν πιστει τη εν χριστω ιησου ");
INSERT INTO grcmt_vpl VALUES ("T13_14","084_3_14","1TI","3","14","14","ταυτα σοι γραφω ελπιζων ελθειν προσ σε ταχιον ");
INSERT INTO grcmt_vpl VALUES ("T13_15","084_3_15","1TI","3","15","15","εαν δε βραδυνω ινα ειδησ πωσ δει εν οικω θεου αναστρεφεσθαι ητισ εστιν εκκλησια θεου ζωντοσ στυλοσ και εδραιωμα τησ αληθειασ ");
INSERT INTO grcmt_vpl VALUES ("T13_16","084_3_16","1TI","3","16","16","και ομολογουμενωσ μεγα εστιν το τησ ευσεβειασ μυστηριον θεοσ εφανερωθη εν σαρκι εδικαιωθη εν πνευματι ωφθη αγγελοισ εκηρυχθη εν εθνεσιν επιστευθη εν κοσμω ανεληφθη εν δοξη ");
INSERT INTO grcmt_vpl VALUES ("T14_1","084_4_1","1TI","4","1","1","το δε πνευμα ρητωσ λεγει οτι εν υστεροισ καιροισ αποστησονται τινεσ τησ πιστεωσ προσεχοντεσ πνευμασιν πλανοισ και διδασκαλιαισ δαιμονιων ");
INSERT INTO grcmt_vpl VALUES ("T14_2","084_4_2","1TI","4","2","2","εν υποκρισει ψευδολογων κεκαυτηριασμενων την ιδιαν συνειδησιν ");
INSERT INTO grcmt_vpl VALUES ("T14_3","084_4_3","1TI","4","3","3","κωλυοντων γαμειν απεχεσθαι βρωματων α ο θεοσ εκτισεν εισ μεταληψιν μετα ευχαριστιασ τοισ πιστοισ και επεγνωκοσιν την αληθειαν ");
INSERT INTO grcmt_vpl VALUES ("T14_4","084_4_4","1TI","4","4","4","οτι παν κτισμα θεου καλον και ουδεν αποβλητον μετα ευχαριστιασ λαμβανομενον ");
INSERT INTO grcmt_vpl VALUES ("T14_5","084_4_5","1TI","4","5","5","αγιαζεται γαρ δια λογου θεου και εντευξεωσ ");
INSERT INTO grcmt_vpl VALUES ("T14_6","084_4_6","1TI","4","6","6","ταυτα υποτιθεμενοσ τοισ αδελφοισ καλοσ εση διακονοσ ιησου χριστου εντρεφομενοσ τοισ λογοισ τησ πιστεωσ και τησ καλησ διδασκαλιασ η παρηκολουθηκασ ");
INSERT INTO grcmt_vpl VALUES ("T14_7","084_4_7","1TI","4","7","7","τουσ δε βεβηλουσ και γραωδεισ μυθουσ παραιτου γυμναζε δε σεαυτον προσ ευσεβειαν ");
INSERT INTO grcmt_vpl VALUES ("T14_8","084_4_8","1TI","4","8","8","η γαρ σωματικη γυμνασια προσ ολιγον εστιν ωφελιμοσ η δε ευσεβεια προσ παντα ωφελιμοσ εστιν επαγγελιαν εχουσα ζωησ τησ νυν και τησ μελλουσησ ");
INSERT INTO grcmt_vpl VALUES ("T14_9","084_4_9","1TI","4","9","9","πιστοσ ο λογοσ και πασησ αποδοχησ αξιοσ ");
INSERT INTO grcmt_vpl VALUES ("T14_10","084_4_10","1TI","4","10","10","εισ τουτο γαρ και κοπιωμεν και ονειδιζομεθα οτι ηλπικαμεν επι θεω ζωντι οσ εστιν σωτηρ παντων ανθρωπων μαλιστα πιστων ");
INSERT INTO grcmt_vpl VALUES ("T14_11","084_4_11","1TI","4","11","11","παραγγελλε ταυτα και διδασκε ");
INSERT INTO grcmt_vpl VALUES ("T14_12","084_4_12","1TI","4","12","12","μηδεισ σου τησ νεοτητοσ καταφρονειτω αλλα τυποσ γινου των πιστων εν λογω εν αναστροφη εν αγαπη εν πνευματι εν πιστει εν αγνεια ");
INSERT INTO grcmt_vpl VALUES ("T14_13","084_4_13","1TI","4","13","13","εωσ ερχομαι προσεχε τη αναγνωσει τη παρακλησει τη διδασκαλια ");
INSERT INTO grcmt_vpl VALUES ("T14_14","084_4_14","1TI","4","14","14","μη αμελει του εν σοι χαρισματοσ ο εδοθη σοι δια προφητειασ μετα επιθεσεωσ των χειρων του πρεσβυτεριου ");
INSERT INTO grcmt_vpl VALUES ("T14_15","084_4_15","1TI","4","15","15","ταυτα μελετα εν τουτοισ ισθι ινα σου η προκοπη φανερα η εν πασιν ");
INSERT INTO grcmt_vpl VALUES ("T14_16","084_4_16","1TI","4","16","16","επεχε σεαυτω και τη διδασκαλια επιμενε αυτοισ τουτο γαρ ποιων και σεαυτον σωσεισ και τουσ ακουοντασ σου ");
