INSERT INTO grcmt_vpl VALUES ("T22_2","085_2_2","2TI","2","2","2","και α ηκουσασ παρ εμου δια πολλων μαρτυρων ταυτα παραθου πιστοισ ανθρωποισ οιτινεσ ικανοι εσονται και ετερουσ διδαξαι ");
