INSERT INTO grcmt_vpl VALUES ("T22_10","085_2_10","2TI","2","10","10","δια τουτο παντα υπομενω δια τουσ εκλεκτουσ ινα και αυτοι σωτηριασ τυχωσιν τησ εν χριστω ιησου μετα δοξησ αιωνιου ");
