INSERT INTO grcmt_vpl VALUES ("T22_17","085_2_17","2TI","2","17","17","και ο λογοσ αυτων ωσ γαγγραινα νομην εξει ων εστιν υμεναιοσ και φιλητοσ ");
INSERT INTO grcmt_vpl VALUES ("T22_18","085_2_18","2TI","2","18","18","οιτινεσ περι την αληθειαν ηστοχησαν λεγοντεσ την αναστασιν ηδη γεγονεναι και ανατρεπουσιν την τινων πιστιν ");
