INSERT INTO grcmt_vpl VALUES ("T22_20","085_2_20","2TI","2","20","20","εν μεγαλη δε οικια ουκ εστιν μονον σκευη χρυσα και αργυρα αλλα και ξυλινα και οστρακινα και α μεν εισ τιμην α δε εισ ατιμιαν ");
INSERT INTO grcmt_vpl VALUES ("T22_21","085_2_21","2TI","2","21","21","εαν ουν τισ εκκαθαρη εαυτον απο τουτων εσται σκευοσ εισ τιμην ηγιασμενον και ευχρηστον τω δεσποτη εισ παν εργον αγαθον ητοιμασμενον ");
INSERT INTO grcmt_vpl VALUES ("T22_22","085_2_22","2TI","2","22","22","τασ δε νεωτερικασ επιθυμιασ φευγε διωκε δε δικαιοσυνην πιστιν αγαπην ειρηνην μετα των επικαλουμενων τον κυριον εκ καθαρασ καρδιασ ");
INSERT INTO grcmt_vpl VALUES ("T22_23","085_2_23","2TI","2","23","23","τασ δε μωρασ και απαιδευτουσ ζητησεισ παραιτου ειδωσ οτι γεννωσιν μαχασ ");
INSERT INTO grcmt_vpl VALUES ("T22_24","085_2_24","2TI","2","24","24","δουλον δε κυριου ου δει μαχεσθαι αλλ ηπιον ειναι προσ παντασ διδακτικον ανεξικακον ");
INSERT INTO grcmt_vpl VALUES ("T22_25","085_2_25","2TI","2","25","25","εν πραοτητι παιδευοντα τουσ αντιδιατιθεμενουσ μηποτε δω αυτοισ ο θεοσ μετανοιαν εισ επιγνωσιν αληθειασ ");
INSERT INTO grcmt_vpl VALUES ("T22_26","085_2_26","2TI","2","26","26","και ανανηψωσιν εκ τησ του διαβολου παγιδοσ εζωγρημενοι υπ αυτου εισ το εκεινου θελημα ");
INSERT INTO grcmt_vpl VALUES ("T23_1","085_3_1","2TI","3","1","1","τουτο δε γινωσκε οτι εν εσχαταισ ημεραισ ενστησονται καιροι χαλεποι ");
INSERT INTO grcmt_vpl VALUES ("T23_2","085_3_2","2TI","3","2","2","εσονται γαρ οι ανθρωποι φιλαυτοι φιλαργυροι αλαζονεσ υπερηφανοι βλασφημοι γονευσιν απειθεισ αχαριστοι ανοσιοι ");
INSERT INTO grcmt_vpl VALUES ("T23_3","085_3_3","2TI","3","3","3","αστοργοι ασπονδοι διαβολοι ακρατεισ ανημεροι αφιλαγαθοι ");
INSERT INTO grcmt_vpl VALUES ("T23_4","085_3_4","2TI","3","4","4","προδοται προπετεισ τετυφωμενοι φιληδονοι μαλλον η φιλοθεοι ");
INSERT INTO grcmt_vpl VALUES ("T23_5","085_3_5","2TI","3","5","5","εχοντεσ μορφωσιν ευσεβειασ την δε δυναμιν αυτησ ηρνημενοι και τουτουσ αποτρεπου ");
INSERT INTO grcmt_vpl VALUES ("T23_6","085_3_6","2TI","3","6","6","εκ τουτων γαρ εισιν οι ενδυνοντεσ εισ τασ οικιασ και αιχμαλωτευοντεσ γυναικαρια σεσωρευμενα αμαρτιαισ αγομενα επιθυμιαισ ποικιλαισ ");
INSERT INTO grcmt_vpl VALUES ("T23_7","085_3_7","2TI","3","7","7","παντοτε μανθανοντα και μηδεποτε εισ επιγνωσιν αληθειασ ελθειν δυναμενα ");
INSERT INTO grcmt_vpl VALUES ("T23_8","085_3_8","2TI","3","8","8","ον τροπον δε ιαννησ και ιαμβρησ αντεστησαν μωυση ουτωσ και ουτοι ανθιστανται τη αληθεια ανθρωποι κατεφθαρμενοι τον νουν αδοκιμοι περι την πιστιν ");
INSERT INTO grcmt_vpl VALUES ("T23_9","085_3_9","2TI","3","9","9","αλλ ου προκοψουσιν επι πλειον η γαρ ανοια αυτων εκδηλοσ εσται πασιν ωσ και η εκεινων εγενετο ");
INSERT INTO grcmt_vpl VALUES ("T23_10","085_3_10","2TI","3","10","10","συ δε παρηκολουθηκασ μου τη διδασκαλια τη αγωγη τη προθεσει τη πιστει τη μακροθυμια τη αγαπη τη υπομονη ");
INSERT INTO grcmt_vpl VALUES ("T23_11","085_3_11","2TI","3","11","11","τοισ διωγμοισ τοισ παθημασιν οια μοι εγενετο εν αντιοχεια εν ικονιω εν λυστροισ οιουσ διωγμουσ υπηνεγκα και εκ παντων με ερρυσατο ο κυριοσ ");
INSERT INTO grcmt_vpl VALUES ("T23_12","085_3_12","2TI","3","12","12","και παντεσ δε οι θελοντεσ ευσεβωσ ζην εν χριστω ιησου διωχθησονται ");
INSERT INTO grcmt_vpl VALUES ("T23_13","085_3_13","2TI","3","13","13","πονηροι δε ανθρωποι και γοητεσ προκοψουσιν επι το χειρον πλανωντεσ και πλανωμενοι ");
INSERT INTO grcmt_vpl VALUES ("T23_14","085_3_14","2TI","3","14","14","συ δε μενε εν οισ εμαθεσ και επιστωθησ ειδωσ παρα τινοσ εμαθεσ ");
INSERT INTO grcmt_vpl VALUES ("T23_15","085_3_15","2TI","3","15","15","και οτι απο βρεφουσ τα ιερα γραμματα οιδασ τα δυναμενα σε σοφισαι εισ σωτηριαν δια πιστεωσ τησ εν χριστω ιησου ");
INSERT INTO grcmt_vpl VALUES ("T23_16","085_3_16","2TI","3","16","16","πασα γραφη θεοπνευστοσ και ωφελιμοσ προσ διδασκαλιαν προσ ελεγχον προσ επανορθωσιν προσ παιδειαν την εν δικαιοσυνη ");
INSERT INTO grcmt_vpl VALUES ("T23_17","085_3_17","2TI","3","17","17","ινα αρτιοσ η ο του θεου ανθρωποσ προσ παν εργον αγαθον εξηρτισμενοσ ");
INSERT INTO grcmt_vpl VALUES ("T24_1","085_4_1","2TI","4","1","1","διαμαρτυρομαι ουν εγω ενωπιον του θεου και του κυριου ιησου χριστου του μελλοντοσ κρινειν ζωντασ και νεκρουσ κατα την επιφανειαν αυτου και την βασιλειαν αυτου ");
INSERT INTO grcmt_vpl VALUES ("T24_2","085_4_2","2TI","4","2","2","κηρυξον τον λογον επιστηθι ευκαιρωσ ακαιρωσ ελεγξον επιτιμησον παρακαλεσον εν παση μακροθυμια και διδαχη ");
INSERT INTO grcmt_vpl VALUES ("T24_3","085_4_3","2TI","4","3","3","εσται γαρ καιροσ οτε τησ υγιαινουσησ διδασκαλιασ ουκ ανεξονται αλλα κατα τασ επιθυμιασ τασ ιδιασ εαυτοισ επισωρευσουσιν διδασκαλουσ κνηθομενοι την ακοην ");
INSERT INTO grcmt_vpl VALUES ("T24_4","085_4_4","2TI","4","4","4","και απο μεν τησ αληθειασ την ακοην αποστρεψουσιν επι δε τουσ μυθουσ εκτραπησονται ");
INSERT INTO grcmt_vpl VALUES ("T24_5","085_4_5","2TI","4","5","5","συ δε νηφε εν πασιν κακοπαθησον εργον ποιησον ευαγγελιστου την διακονιαν σου πληροφορησον ");
INSERT INTO grcmt_vpl VALUES ("T24_6","085_4_6","2TI","4","6","6","εγω γαρ ηδη σπενδομαι και ο καιροσ τησ εμησ αναλυσεωσ εφεστηκεν ");
INSERT INTO grcmt_vpl VALUES ("T24_7","085_4_7","2TI","4","7","7","τον αγωνα τον καλον ηγωνισμαι τον δρομον τετελεκα την πιστιν τετηρηκα ");
INSERT INTO grcmt_vpl VALUES ("T24_8","085_4_8","2TI","4","8","8","λοιπον αποκειται μοι ο τησ δικαιοσυνησ στεφανοσ ον αποδωσει μοι ο κυριοσ εν εκεινη τη ημερα ο δικαιοσ κριτησ ου μονον δε εμοι αλλα και πασιν τοισ ηγαπηκοσιν την επιφανειαν αυτου ");
INSERT INTO grcmt_vpl VALUES ("T24_9","085_4_9","2TI","4","9","9","σπουδασον ελθειν προσ με ταχεωσ ");
INSERT INTO grcmt_vpl VALUES ("T24_10","085_4_10","2TI","4","10","10","δημασ γαρ με εγκατελιπεν αγαπησασ τον νυν αιωνα και επορευθη εισ θεσσαλονικην κρησκησ εισ γαλατιαν τιτοσ εισ δαλματιαν ");
INSERT INTO grcmt_vpl VALUES ("T24_11","085_4_11","2TI","4","11","11","λουκασ εστιν μονοσ μετ εμου μαρκον αναλαβων αγε μετα σεαυτου εστιν γαρ μοι ευχρηστοσ εισ διακονιαν ");
INSERT INTO grcmt_vpl VALUES ("T24_12","085_4_12","2TI","4","12","12","τυχικον δε απεστειλα εισ εφεσον ");
INSERT INTO grcmt_vpl VALUES ("T24_13","085_4_13","2TI","4","13","13","τον φελονην ον απελιπον εν τρωαδι παρα καρπω ερχομενοσ φερε και τα βιβλια μαλιστα τασ μεμβρανασ ");
INSERT INTO grcmt_vpl VALUES ("T24_14","085_4_14","2TI","4","14","14","αλεξανδροσ ο χαλκευσ πολλα μοι κακα ενεδειξατο αποδωη αυτω ο κυριοσ κατα τα εργα αυτου ");
INSERT INTO grcmt_vpl VALUES ("T24_15","085_4_15","2TI","4","15","15","ον και συ φυλασσου λιαν γαρ ανθεστηκεν τοισ ημετεροισ λογοισ ");
INSERT INTO grcmt_vpl VALUES ("T24_16","085_4_16","2TI","4","16","16","εν τη πρωτη μου απολογια ουδεισ μοι συμπαρεγενετο αλλα παντεσ με εγκατελιπον μη αυτοισ λογισθειη ");
INSERT INTO grcmt_vpl VALUES ("T24_17","085_4_17","2TI","4","17","17","ο δε κυριοσ μοι παρεστη και ενεδυναμωσεν με ινα δι εμου το κηρυγμα πληροφορηθη και ακουση παντα τα εθνη και ερρυσθην εκ στοματοσ λεοντοσ ");
INSERT INTO grcmt_vpl VALUES ("T24_18","085_4_18","2TI","4","18","18","και ρυσεται με ο κυριοσ απο παντοσ εργου πονηρου και σωσει εισ την βασιλειαν αυτου την επουρανιον ω η δοξα εισ τουσ αιωνασ των αιωνων αμην ");
INSERT INTO grcmt_vpl VALUES ("T24_19","085_4_19","2TI","4","19","19","ασπασαι πρισκαν και ακυλαν και τον ονησιφορου οικον ");
INSERT INTO grcmt_vpl VALUES ("T24_20","085_4_20","2TI","4","20","20","εραστοσ εμεινεν εν κορινθω τροφιμον δε απελιπον εν μιλητω ασθενουντα ");
INSERT INTO grcmt_vpl VALUES ("T24_21","085_4_21","2TI","4","21","21","σπουδασον προ χειμωνοσ ελθειν ασπαζεται σε ευβουλοσ και πουδησ και λινοσ και κλαυδια και οι αδελφοι παντεσ ");
INSERT INTO grcmt_vpl VALUES ("T24_22","085_4_22","2TI","4","22","22","ο κυριοσ ιησουσ χριστοσ μετα του πνευματοσ σου η χαρισ μεθ υμων αμην ");
INSERT INTO grcmt_vpl VALUES ("TT1_1","086_1_1","TIT","1","1","1","παυλοσ δουλοσ θεου αποστολοσ δε ιησου χριστου κατα πιστιν εκλεκτων θεου και επιγνωσιν αληθειασ τησ κατ ευσεβειαν ");
INSERT INTO grcmt_vpl VALUES ("TT1_2","086_1_2","TIT","1","2","2","επ ελπιδι ζωησ αιωνιου ην επηγγειλατο ο αψευδησ θεοσ προ χρονων αιωνιων ");
INSERT INTO grcmt_vpl VALUES ("TT1_3","086_1_3","TIT","1","3","3","εφανερωσεν δε καιροισ ιδιοισ τον λογον αυτου εν κηρυγματι ο επιστευθην εγω κατ επιταγην του σωτηροσ ημων θεου ");
INSERT INTO grcmt_vpl VALUES ("TT1_4","086_1_4","TIT","1","4","4","τιτω γνησιω τεκνω κατα κοινην πιστιν χαρισ ελεοσ ειρηνη απο θεου πατροσ και κυριου ιησου χριστου του σωτηροσ ημων ");
INSERT INTO grcmt_vpl VALUES ("TT1_5","086_1_5","TIT","1","5","5","τουτου χαριν κατελιπον σε εν κρητη ινα τα λειποντα επιδιορθωση και καταστησησ κατα πολιν πρεσβυτερουσ ωσ εγω σοι διεταξαμην ");
INSERT INTO grcmt_vpl VALUES ("TT1_6","086_1_6","TIT","1","6","6","ει τισ εστιν ανεγκλητοσ μιασ γυναικοσ ανηρ τεκνα εχων πιστα μη εν κατηγορια ασωτιασ η ανυποτακτα ");
INSERT INTO grcmt_vpl VALUES ("TT1_7","086_1_7","TIT","1","7","7","δει γαρ τον επισκοπον ανεγκλητον ειναι ωσ θεου οικονομον μη αυθαδη μη οργιλον μη παροινον μη πληκτην μη αισχροκερδη ");
INSERT INTO grcmt_vpl VALUES ("TT1_8","086_1_8","TIT","1","8","8","αλλα φιλοξενον φιλαγαθον σωφρονα δικαιον οσιον εγκρατη ");
INSERT INTO grcmt_vpl VALUES ("TT1_9","086_1_9","TIT","1","9","9","αντεχομενον του κατα την διδαχην πιστου λογου ινα δυνατοσ η και παρακαλειν εν τη διδασκαλια τη υγιαινουση και τουσ αντιλεγοντασ ελεγχειν ");
INSERT INTO grcmt_vpl VALUES ("TT1_10","086_1_10","TIT","1","10","10","εισιν γαρ πολλοι και ανυποτακτοι ματαιολογοι και φρεναπαται μαλιστα οι εκ περιτομησ ");
INSERT INTO grcmt_vpl VALUES ("TT1_11","086_1_11","TIT","1","11","11","ουσ δει επιστομιζειν οιτινεσ ολουσ οικουσ ανατρεπουσιν διδασκοντεσ α μη δει αισχρου κερδουσ χαριν ");
INSERT INTO grcmt_vpl VALUES ("TT1_12","086_1_12","TIT","1","12","12","ειπεν τισ εξ αυτων ιδιοσ αυτων προφητησ κρητεσ αει ψευσται κακα θηρια γαστερεσ αργαι ");
INSERT INTO grcmt_vpl VALUES ("TT1_13","086_1_13","TIT","1","13","13","η μαρτυρια αυτη εστιν αληθησ δι ην αιτιαν ελεγχε αυτουσ αποτομωσ ινα υγιαινωσιν εν τη πιστει ");
INSERT INTO grcmt_vpl VALUES ("TT1_14","086_1_14","TIT","1","14","14","μη προσεχοντεσ ιουδαικοισ μυθοισ και εντολαισ ανθρωπων αποστρεφομενων την αληθειαν ");
INSERT INTO grcmt_vpl VALUES ("TT1_15","086_1_15","TIT","1","15","15","παντα μεν καθαρα τοισ καθαροισ τοισ δε μεμιασμενοισ και απιστοισ ουδεν καθαρον αλλα μεμιανται αυτων και ο νουσ και η συνειδησισ ");
INSERT INTO grcmt_vpl VALUES ("TT1_16","086_1_16","TIT","1","16","16","θεον ομολογουσιν ειδεναι τοισ δε εργοισ αρνουνται βδελυκτοι οντεσ και απειθεισ και προσ παν εργον αγαθον αδοκιμοι ");
INSERT INTO grcmt_vpl VALUES ("TT2_1","086_2_1","TIT","2","1","1","συ δε λαλει α πρεπει τη υγιαινουση διδασκαλια ");
INSERT INTO grcmt_vpl VALUES ("TT2_2","086_2_2","TIT","2","2","2","πρεσβυτασ νηφαλεουσ ειναι σεμνουσ σωφρονασ υγιαινοντασ τη πιστει τη αγαπη τη υπομονη ");
INSERT INTO grcmt_vpl VALUES ("TT2_3","086_2_3","TIT","2","3","3","πρεσβυτιδασ ωσαυτωσ εν καταστηματι ιεροπρεπεισ μη διαβολουσ μη οινω πολλω δεδουλωμενασ καλοδιδασκαλουσ ");
INSERT INTO grcmt_vpl VALUES ("TT2_4","086_2_4","TIT","2","4","4","ινα σωφρονιζωσιν τασ νεασ φιλανδρουσ ειναι φιλοτεκνουσ ");
INSERT INTO grcmt_vpl VALUES ("TT2_5","086_2_5","TIT","2","5","5","σωφρονασ αγνασ οικουρουσ αγαθασ υποτασσομενασ τοισ ιδιοισ ανδρασιν ινα μη ο λογοσ του θεου βλασφημηται ");
INSERT INTO grcmt_vpl VALUES ("TT2_6","086_2_6","TIT","2","6","6","τουσ νεωτερουσ ωσαυτωσ παρακαλει σωφρονειν ");
INSERT INTO grcmt_vpl VALUES ("TT2_7","086_2_7","TIT","2","7","7","περι παντα σεαυτον παρεχομενοσ τυπον καλων εργων εν τη διδασκαλια αδιαφθοριαν σεμνοτητα αφθαρσιαν ");
INSERT INTO grcmt_vpl VALUES ("TT2_8","086_2_8","TIT","2","8","8","λογον υγιη ακαταγνωστον ινα ο εξ εναντιασ εντραπη μηδεν εχων περι ημων λεγειν φαυλον ");
INSERT INTO grcmt_vpl VALUES ("TT2_9","086_2_9","TIT","2","9","9","δουλουσ ιδιοισ δεσποταισ υποτασσεσθαι εν πασιν ευαρεστουσ ειναι μη αντιλεγοντασ ");
INSERT INTO grcmt_vpl VALUES ("TT2_10","086_2_10","TIT","2","10","10","μη νοσφιζομενουσ αλλα πιστιν πασαν ενδεικνυμενουσ αγαθην ινα την διδασκαλιαν του σωτηροσ ημων θεου κοσμωσιν εν πασιν ");
INSERT INTO grcmt_vpl VALUES ("TT2_11","086_2_11","TIT","2","11","11","επεφανη γαρ η χαρισ του θεου η σωτηριοσ πασιν ανθρωποισ ");
INSERT INTO grcmt_vpl VALUES ("TT2_12","086_2_12","TIT","2","12","12","παιδευουσα ημασ ινα αρνησαμενοι την ασεβειαν και τασ κοσμικασ επιθυμιασ σωφρονωσ και δικαιωσ και ευσεβωσ ζησωμεν εν τω νυν αιωνι ");
INSERT INTO grcmt_vpl VALUES ("TT2_13","086_2_13","TIT","2","13","13","προσδεχομενοι την μακαριαν ελπιδα και επιφανειαν τησ δοξησ του μεγαλου θεου και σωτηροσ ημων ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("TT2_14","086_2_14","TIT","2","14","14","οσ εδωκεν εαυτον υπερ ημων ινα λυτρωσηται ημασ απο πασησ ανομιασ και καθαριση εαυτω λαον περιουσιον ζηλωτην καλων εργων ");
INSERT INTO grcmt_vpl VALUES ("TT2_15","086_2_15","TIT","2","15","15","ταυτα λαλει και παρακαλει και ελεγχε μετα πασησ επιταγησ μηδεισ σου περιφρονειτω ");
INSERT INTO grcmt_vpl VALUES ("TT3_1","086_3_1","TIT","3","1","1","υπομιμνησκε αυτουσ αρχαισ και εξουσιαισ υποτασσεσθαι πειθαρχειν προσ παν εργον αγαθον ετοιμουσ ειναι ");
INSERT INTO grcmt_vpl VALUES ("TT3_2","086_3_2","TIT","3","2","2","μηδενα βλασφημειν αμαχουσ ειναι επιεικεισ πασαν ενδεικνυμενουσ πραοτητα προσ παντασ ανθρωπουσ ");
INSERT INTO grcmt_vpl VALUES ("TT3_3","086_3_3","TIT","3","3","3","ημεν γαρ ποτε και ημεισ ανοητοι απειθεισ πλανωμενοι δουλευοντεσ επιθυμιαισ και ηδοναισ ποικιλαισ εν κακια και φθονω διαγοντεσ στυγητοι μισουντεσ αλληλουσ ");
INSERT INTO grcmt_vpl VALUES ("TT3_4","086_3_4","TIT","3","4","4","οτε δε η χρηστοτησ και η φιλανθρωπια επεφανη του σωτηροσ ημων θεου ");
INSERT INTO grcmt_vpl VALUES ("TT3_5","086_3_5","TIT","3","5","5","ουκ εξ εργων των εν δικαιοσυνη ων εποιησαμεν ημεισ αλλα κατα τον αυτου ελεον εσωσεν ημασ δια λουτρου παλιγγενεσιασ και ανακαινωσεωσ πνευματοσ αγιου ");
INSERT INTO grcmt_vpl VALUES ("TT3_6","086_3_6","TIT","3","6","6","ου εξεχεεν εφ ημασ πλουσιωσ δια ιησου χριστου του σωτηροσ ημων ");
INSERT INTO grcmt_vpl VALUES ("TT3_7","086_3_7","TIT","3","7","7","ινα δικαιωθεντεσ τη εκεινου χαριτι κληρονομοι γενωμεθα κατ ελπιδα ζωησ αιωνιου ");
INSERT INTO grcmt_vpl VALUES ("TT3_8","086_3_8","TIT","3","8","8","πιστοσ ο λογοσ και περι τουτων βουλομαι σε διαβεβαιουσθαι ινα φροντιζωσιν καλων εργων προιστασθαι οι πεπιστευκοτεσ θεω ταυτα εστιν τα καλα και ωφελιμα τοισ ανθρωποισ ");
INSERT INTO grcmt_vpl VALUES ("TT3_9","086_3_9","TIT","3","9","9","μωρασ δε ζητησεισ και γενεαλογιασ και ερεισ και μαχασ νομικασ περιιστασο εισιν γαρ ανωφελεισ και ματαιοι ");
INSERT INTO grcmt_vpl VALUES ("TT3_10","086_3_10","TIT","3","10","10","αιρετικον ανθρωπον μετα μιαν και δευτεραν νουθεσιαν παραιτου ");
INSERT INTO grcmt_vpl VALUES ("TT3_11","086_3_11","TIT","3","11","11","ειδωσ οτι εξεστραπται ο τοιουτοσ και αμαρτανει ων αυτοκατακριτοσ ");
INSERT INTO grcmt_vpl VALUES ("TT3_12","086_3_12","TIT","3","12","12","οταν πεμψω αρτεμαν προσ σε η τυχικον σπουδασον ελθειν προσ με εισ νικοπολιν εκει γαρ κεκρικα παραχειμασαι ");
INSERT INTO grcmt_vpl VALUES ("TT3_13","086_3_13","TIT","3","13","13","ζηναν τον νομικον και απολλω σπουδαιωσ προπεμψον ινα μηδεν αυτοισ λειπη ");
INSERT INTO grcmt_vpl VALUES ("TT3_14","086_3_14","TIT","3","14","14","μανθανετωσαν δε και οι ημετεροι καλων εργων προιστασθαι εισ τασ αναγκαιασ χρειασ ινα μη ωσιν ακαρποι ");
INSERT INTO grcmt_vpl VALUES ("TT3_15","086_3_15","TIT","3","15","15","ασπαζονται σε οι μετ εμου παντεσ ασπασαι τουσ φιλουντασ ημασ εν πιστει η χαρισ μετα παντων υμων αμην ");
INSERT INTO grcmt_vpl VALUES ("PM1_1","087_1_1","PHM","1","1","1","παυλοσ δεσμιοσ χριστου ιησου και τιμοθεοσ ο αδελφοσ φιλημονι τω αγαπητω και συνεργω ημων ");
INSERT INTO grcmt_vpl VALUES ("PM1_2","087_1_2","PHM","1","2","2","και απφια τη αγαπητη και αρχιππω τω συστρατιωτη ημων και τη κατ οικον σου εκκλησια ");
