INSERT INTO grcmt_vpl VALUES ("HB4_16","088_4_16","HEB","4","16","16","προσερχωμεθα ουν μετα παρρησιασ τω θρονω τησ χαριτοσ ινα λαβωμεν ελεον και χαριν ευρωμεν εισ ευκαιρον βοηθειαν ");
INSERT INTO grcmt_vpl VALUES ("HB5_1","088_5_1","HEB","5","1","1","πασ γαρ αρχιερευσ εξ ανθρωπων λαμβανομενοσ υπερ ανθρωπων καθισταται τα προσ τον θεον ινα προσφερη δωρα τε και θυσιασ υπερ αμαρτιων ");
INSERT INTO grcmt_vpl VALUES ("HB5_2","088_5_2","HEB","5","2","2","μετριοπαθειν δυναμενοσ τοισ αγνοουσιν και πλανωμενοισ επει και αυτοσ περικειται ασθενειαν ");
INSERT INTO grcmt_vpl VALUES ("HB5_3","088_5_3","HEB","5","3","3","και δια ταυτην οφειλει καθωσ περι του λαου ουτωσ και περι εαυτου προσφερειν υπερ αμαρτιων ");
INSERT INTO grcmt_vpl VALUES ("HB5_4","088_5_4","HEB","5","4","4","και ουχ εαυτω τισ λαμβανει την τιμην αλλα καλουμενοσ υπο του θεου καθαπερ και ααρων ");
INSERT INTO grcmt_vpl VALUES ("HB5_5","088_5_5","HEB","5","5","5","ουτωσ και ο χριστοσ ουχ εαυτον εδοξασεν γενηθηναι αρχιερεα αλλ ο λαλησασ προσ αυτον υιοσ μου ει συ εγω σημερον γεγεννηκα σε ");
INSERT INTO grcmt_vpl VALUES ("HB5_6","088_5_6","HEB","5","6","6","καθωσ και εν ετερω λεγει συ ιερευσ εισ τον αιωνα κατα την ταξιν μελχισεδεκ ");
INSERT INTO grcmt_vpl VALUES ("HB5_7","088_5_7","HEB","5","7","7","οσ εν ταισ ημεραισ τησ σαρκοσ αυτου δεησεισ τε και ικετηριασ προσ τον δυναμενον σωζειν αυτον εκ θανατου μετα κραυγησ ισχυρασ και δακρυων προσενεγκασ και εισακουσθεισ απο τησ ευλαβειασ ");
INSERT INTO grcmt_vpl VALUES ("HB5_8","088_5_8","HEB","5","8","8","καιπερ ων υιοσ εμαθεν αφ ων επαθεν την υπακοην ");
INSERT INTO grcmt_vpl VALUES ("HB5_9","088_5_9","HEB","5","9","9","και τελειωθεισ εγενετο τοισ υπακουουσιν αυτω πασιν αιτιοσ σωτηριασ αιωνιου ");
INSERT INTO grcmt_vpl VALUES ("HB5_10","088_5_10","HEB","5","10","10","προσαγορευθεισ υπο του θεου αρχιερευσ κατα την ταξιν μελχισεδεκ ");
INSERT INTO grcmt_vpl VALUES ("HB5_11","088_5_11","HEB","5","11","11","περι ου πολυσ ημιν ο λογοσ και δυσερμηνευτοσ λεγειν επει νωθροι γεγονατε ταισ ακοαισ ");
INSERT INTO grcmt_vpl VALUES ("HB5_12","088_5_12","HEB","5","12","12","και γαρ οφειλοντεσ ειναι διδασκαλοι δια τον χρονον παλιν χρειαν εχετε του διδασκειν υμασ τινα τα στοιχεια τησ αρχησ των λογιων του θεου και γεγονατε χρειαν εχοντεσ γαλακτοσ και ου στερεασ τροφησ ");
INSERT INTO grcmt_vpl VALUES ("HB5_13","088_5_13","HEB","5","13","13","πασ γαρ ο μετεχων γαλακτοσ απειροσ λογου δικαιοσυνησ νηπιοσ γαρ εστιν ");
INSERT INTO grcmt_vpl VALUES ("HB5_14","088_5_14","HEB","5","14","14","τελειων δε εστιν η στερεα τροφη των δια την εξιν τα αισθητηρια γεγυμνασμενα εχοντων προσ διακρισιν καλου τε και κακου ");
INSERT INTO grcmt_vpl VALUES ("HB6_1","088_6_1","HEB","6","1","1","διο αφεντεσ τον τησ αρχησ του χριστου λογον επι την τελειοτητα φερωμεθα μη παλιν θεμελιον καταβαλλομενοι μετανοιασ απο νεκρων εργων και πιστεωσ επι θεον ");
INSERT INTO grcmt_vpl VALUES ("HB6_2","088_6_2","HEB","6","2","2","βαπτισμων διδαχησ επιθεσεωσ τε χειρων αναστασεωσ τε νεκρων και κριματοσ αιωνιου ");
INSERT INTO grcmt_vpl VALUES ("HB6_3","088_6_3","HEB","6","3","3","και τουτο ποιησωμεν εανπερ επιτρεπη ο θεοσ ");
INSERT INTO grcmt_vpl VALUES ("HB6_4","088_6_4","HEB","6","4","4","αδυνατον γαρ τουσ απαξ φωτισθεντασ γευσαμενουσ τε τησ δωρεασ τησ επουρανιου και μετοχουσ γενηθεντασ πνευματοσ αγιου ");
INSERT INTO grcmt_vpl VALUES ("HB6_5","088_6_5","HEB","6","5","5","και καλον γευσαμενουσ θεου ρημα δυναμεισ τε μελλοντοσ αιωνοσ ");
INSERT INTO grcmt_vpl VALUES ("HB6_6","088_6_6","HEB","6","6","6","και παραπεσοντασ παλιν ανακαινιζειν εισ μετανοιαν ανασταυρουντασ εαυτοισ τον υιον του θεου και παραδειγματιζοντασ ");
INSERT INTO grcmt_vpl VALUES ("HB6_7","088_6_7","HEB","6","7","7","γη γαρ η πιουσα τον επ αυτησ πολλακισ ερχομενον υετον και τικτουσα βοτανην ευθετον εκεινοισ δι ουσ και γεωργειται μεταλαμβανει ευλογιασ απο του θεου ");
INSERT INTO grcmt_vpl VALUES ("HB6_8","088_6_8","HEB","6","8","8","εκφερουσα δε ακανθασ και τριβολουσ αδοκιμοσ και καταρασ εγγυσ ησ το τελοσ εισ καυσιν ");
INSERT INTO grcmt_vpl VALUES ("HB6_9","088_6_9","HEB","6","9","9","πεπεισμεθα δε περι υμων αγαπητοι τα κρεισσονα και εχομενα σωτηριασ ει και ουτωσ λαλουμεν ");
INSERT INTO grcmt_vpl VALUES ("HB6_10","088_6_10","HEB","6","10","10","ου γαρ αδικοσ ο θεοσ επιλαθεσθαι του εργου υμων και του κοπου τησ αγαπησ ησ ενεδειξασθε εισ το ονομα αυτου διακονησαντεσ τοισ αγιοισ και διακονουντεσ ");
INSERT INTO grcmt_vpl VALUES ("HB6_11","088_6_11","HEB","6","11","11","επιθυμουμεν δε εκαστον υμων την αυτην ενδεικνυσθαι σπουδην προσ την πληροφοριαν τησ ελπιδοσ αχρι τελουσ ");
INSERT INTO grcmt_vpl VALUES ("HB6_12","088_6_12","HEB","6","12","12","ινα μη νωθροι γενησθε μιμηται δε των δια πιστεωσ και μακροθυμιασ κληρονομουντων τασ επαγγελιασ ");
INSERT INTO grcmt_vpl VALUES ("HB6_13","088_6_13","HEB","6","13","13","τω γαρ αβρααμ επαγγειλαμενοσ ο θεοσ επει κατ ουδενοσ ειχεν μειζονοσ ομοσαι ωμοσεν καθ εαυτου ");
INSERT INTO grcmt_vpl VALUES ("HB6_14","088_6_14","HEB","6","14","14","λεγων η μην ευλογων ευλογησω σε και πληθυνων πληθυνω σε ");
INSERT INTO grcmt_vpl VALUES ("HB6_15","088_6_15","HEB","6","15","15","και ουτωσ μακροθυμησασ επετυχεν τησ επαγγελιασ ");
INSERT INTO grcmt_vpl VALUES ("HB6_16","088_6_16","HEB","6","16","16","ανθρωποι μεν γαρ κατα του μειζονοσ ομνυουσιν και πασησ αυτοισ αντιλογιασ περασ εισ βεβαιωσιν ο ορκοσ ");
INSERT INTO grcmt_vpl VALUES ("HB6_17","088_6_17","HEB","6","17","17","εν ω περισσοτερον βουλομενοσ ο θεοσ επιδειξαι τοισ κληρονομοισ τησ επαγγελιασ το αμεταθετον τησ βουλησ αυτου εμεσιτευσεν ορκω ");
INSERT INTO grcmt_vpl VALUES ("HB6_18","088_6_18","HEB","6","18","18","ινα δια δυο πραγματων αμεταθετων εν οισ αδυνατον ψευσασθαι θεον ισχυραν παρακλησιν εχωμεν οι καταφυγοντεσ κρατησαι τησ προκειμενησ ελπιδοσ ");
INSERT INTO grcmt_vpl VALUES ("HB6_19","088_6_19","HEB","6","19","19","ην ωσ αγκυραν εχομεν τησ ψυχησ ασφαλη τε και βεβαιαν και εισερχομενην εισ το εσωτερον του καταπετασματοσ ");
INSERT INTO grcmt_vpl VALUES ("HB6_20","088_6_20","HEB","6","20","20","οπου προδρομοσ υπερ ημων εισηλθεν ιησουσ κατα την ταξιν μελχισεδεκ αρχιερευσ γενομενοσ εισ τον αιωνα ");
INSERT INTO grcmt_vpl VALUES ("HB7_1","088_7_1","HEB","7","1","1","ουτοσ γαρ ο μελχισεδεκ βασιλευσ σαλημ ιερευσ του θεου του υψιστου ο συναντησασ αβρααμ υποστρεφοντι απο τησ κοπησ των βασιλεων και ευλογησασ αυτον ");
INSERT INTO grcmt_vpl VALUES ("HB7_2","088_7_2","HEB","7","2","2","ω και δεκατην απο παντων εμερισεν αβρααμ πρωτον μεν ερμηνευομενοσ βασιλευσ δικαιοσυνησ επειτα δε και βασιλευσ σαλημ ο εστιν βασιλευσ ειρηνησ ");
INSERT INTO grcmt_vpl VALUES ("HB7_3","088_7_3","HEB","7","3","3","απατωρ αμητωρ αγενεαλογητοσ μητε αρχην ημερων μητε ζωησ τελοσ εχων αφωμοιωμενοσ δε τω υιω του θεου μενει ιερευσ εισ το διηνεκεσ ");
INSERT INTO grcmt_vpl VALUES ("HB7_4","088_7_4","HEB","7","4","4","θεωρειτε δε πηλικοσ ουτοσ ω και δεκατην αβρααμ εδωκεν εκ των ακροθινιων ο πατριαρχησ ");
INSERT INTO grcmt_vpl VALUES ("HB7_5","088_7_5","HEB","7","5","5","και οι μεν εκ των υιων λευι την ιερατειαν λαμβανοντεσ εντολην εχουσιν αποδεκατουν τον λαον κατα τον νομον τουτ εστιν τουσ αδελφουσ αυτων καιπερ εξεληλυθοτασ εκ τησ οσφυοσ αβρααμ ");
INSERT INTO grcmt_vpl VALUES ("HB7_6","088_7_6","HEB","7","6","6","ο δε μη γενεαλογουμενοσ εξ αυτων δεδεκατωκεν τον αβρααμ και τον εχοντα τασ επαγγελιασ ευλογηκεν ");
INSERT INTO grcmt_vpl VALUES ("HB7_7","088_7_7","HEB","7","7","7","χωρισ δε πασησ αντιλογιασ το ελαττον υπο του κρειττονοσ ευλογειται ");
INSERT INTO grcmt_vpl VALUES ("HB7_8","088_7_8","HEB","7","8","8","και ωδε μεν δεκατασ αποθνησκοντεσ ανθρωποι λαμβανουσιν εκει δε μαρτυρουμενοσ οτι ζη ");
INSERT INTO grcmt_vpl VALUES ("HB7_9","088_7_9","HEB","7","9","9","και ωσ εποσ ειπειν δια αβρααμ και λευι ο δεκατασ λαμβανων δεδεκατωται ");
INSERT INTO grcmt_vpl VALUES ("HB7_10","088_7_10","HEB","7","10","10","ετι γαρ εν τη οσφυι του πατροσ ην οτε συνηντησεν αυτω ο μελχισεδεκ ");
INSERT INTO grcmt_vpl VALUES ("HB7_11","088_7_11","HEB","7","11","11","ει μεν ουν τελειωσισ δια τησ λευιτικησ ιερωσυνησ ην ο λαοσ γαρ επ αυτη νενομοθετητο τισ ετι χρεια κατα την ταξιν μελχισεδεκ ετερον ανιστασθαι ιερεα και ου κατα την ταξιν ααρων λεγεσθαι ");
INSERT INTO grcmt_vpl VALUES ("HB7_12","088_7_12","HEB","7","12","12","μετατιθεμενησ γαρ τησ ιερωσυνησ εξ αναγκησ και νομου μεταθεσισ γινεται ");
INSERT INTO grcmt_vpl VALUES ("HB7_13","088_7_13","HEB","7","13","13","εφ ον γαρ λεγεται ταυτα φυλησ ετερασ μετεσχηκεν αφ ησ ουδεισ προσεσχηκεν τω θυσιαστηριω ");
INSERT INTO grcmt_vpl VALUES ("HB7_14","088_7_14","HEB","7","14","14","προδηλον γαρ οτι εξ ιουδα ανατεταλκεν ο κυριοσ ημων εισ ην φυλην ουδεν περι ιερωσυνησ μωυσησ ελαλησεν ");
INSERT INTO grcmt_vpl VALUES ("HB7_15","088_7_15","HEB","7","15","15","και περισσοτερον ετι καταδηλον εστιν ει κατα την ομοιοτητα μελχισεδεκ ανισταται ιερευσ ετεροσ ");
INSERT INTO grcmt_vpl VALUES ("HB7_16","088_7_16","HEB","7","16","16","οσ ου κατα νομον εντολησ σαρκικησ γεγονεν αλλα κατα δυναμιν ζωησ ακαταλυτου ");
INSERT INTO grcmt_vpl VALUES ("HB7_17","088_7_17","HEB","7","17","17","μαρτυρει γαρ οτι συ ιερευσ εισ τον αιωνα κατα την ταξιν μελχισεδεκ ");
INSERT INTO grcmt_vpl VALUES ("HB7_18","088_7_18","HEB","7","18","18","αθετησισ μεν γαρ γινεται προαγουσησ εντολησ δια το αυτησ ασθενεσ και ανωφελεσ ");
INSERT INTO grcmt_vpl VALUES ("HB7_19","088_7_19","HEB","7","19","19","ουδεν γαρ ετελειωσεν ο νομοσ επεισαγωγη δε κρειττονοσ ελπιδοσ δι ησ εγγιζομεν τω θεω ");
INSERT INTO grcmt_vpl VALUES ("HB7_20","088_7_20","HEB","7","20","20","και καθ οσον ου χωρισ ορκωμοσιασ οι μεν γαρ χωρισ ορκωμοσιασ εισιν ιερεισ γεγονοτεσ ");
INSERT INTO grcmt_vpl VALUES ("HB7_21","088_7_21","HEB","7","21","21","ο δε μετα ορκωμοσιασ δια του λεγοντοσ προσ αυτον ωμοσεν κυριοσ και ου μεταμεληθησεται συ ιερευσ εισ τον αιωνα κατα την ταξιν μελχισεδεκ ");
INSERT INTO grcmt_vpl VALUES ("HB7_22","088_7_22","HEB","7","22","22","κατα τοσουτον κρειττονοσ διαθηκησ γεγονεν εγγυοσ ιησουσ ");
INSERT INTO grcmt_vpl VALUES ("HB7_23","088_7_23","HEB","7","23","23","και οι μεν πλειονεσ εισιν γεγονοτεσ ιερεισ δια το θανατω κωλυεσθαι παραμενειν ");
INSERT INTO grcmt_vpl VALUES ("HB7_24","088_7_24","HEB","7","24","24","ο δε δια το μενειν αυτον εισ τον αιωνα απαραβατον εχει την ιερωσυνην ");
INSERT INTO grcmt_vpl VALUES ("HB7_25","088_7_25","HEB","7","25","25","οθεν και σωζειν εισ το παντελεσ δυναται τουσ προσερχομενουσ δι αυτου τω θεω παντοτε ζων εισ το εντυγχανειν υπερ αυτων ");
INSERT INTO grcmt_vpl VALUES ("HB7_26","088_7_26","HEB","7","26","26","τοιουτοσ γαρ ημιν επρεπεν αρχιερευσ οσιοσ ακακοσ αμιαντοσ κεχωρισμενοσ απο των αμαρτωλων και υψηλοτεροσ των ουρανων γενομενοσ ");
INSERT INTO grcmt_vpl VALUES ("HB7_27","088_7_27","HEB","7","27","27","οσ ουκ εχει καθ ημεραν αναγκην ωσπερ οι αρχιερεισ προτερον υπερ των ιδιων αμαρτιων θυσιασ αναφερειν επειτα των του λαου τουτο γαρ εποιησεν εφαπαξ εαυτον ανενεγκασ ");
INSERT INTO grcmt_vpl VALUES ("HB7_28","088_7_28","HEB","7","28","28","ο νομοσ γαρ ανθρωπουσ καθιστησιν αρχιερεισ εχοντασ ασθενειαν ο λογοσ δε τησ ορκωμοσιασ τησ μετα τον νομον υιον εισ τον αιωνα τετελειωμενον ");
INSERT INTO grcmt_vpl VALUES ("HB8_1","088_8_1","HEB","8","1","1","κεφαλαιον δε επι τοισ λεγομενοισ τοιουτον εχομεν αρχιερεα οσ εκαθισεν εν δεξια του θρονου τησ μεγαλωσυνησ εν τοισ ουρανοισ ");
INSERT INTO grcmt_vpl VALUES ("HB8_2","088_8_2","HEB","8","2","2","των αγιων λειτουργοσ και τησ σκηνησ τησ αληθινησ ην επηξεν ο κυριοσ και ουκ ανθρωποσ ");
INSERT INTO grcmt_vpl VALUES ("HB8_3","088_8_3","HEB","8","3","3","πασ γαρ αρχιερευσ εισ το προσφερειν δωρα τε και θυσιασ καθισταται οθεν αναγκαιον εχειν τι και τουτον ο προσενεγκη ");
INSERT INTO grcmt_vpl VALUES ("HB8_4","088_8_4","HEB","8","4","4","ει μεν γαρ ην επι γησ ουδ αν ην ιερευσ οντων των ιερεων των προσφεροντων κατα τον νομον τα δωρα ");
INSERT INTO grcmt_vpl VALUES ("HB8_5","088_8_5","HEB","8","5","5","οιτινεσ υποδειγματι και σκια λατρευουσιν των επουρανιων καθωσ κεχρηματισται μωυσησ μελλων επιτελειν την σκηνην ορα γαρ φησιν ποιησεισ παντα κατα τον τυπον τον δειχθεντα σοι εν τω ορει ");
INSERT INTO grcmt_vpl VALUES ("HB8_6","088_8_6","HEB","8","6","6","νυνι δε διαφορωτερασ τετυχεν λειτουργιασ οσω και κρειττονοσ εστιν διαθηκησ μεσιτησ ητισ επι κρειττοσιν επαγγελιαισ νενομοθετηται ");
INSERT INTO grcmt_vpl VALUES ("HB8_7","088_8_7","HEB","8","7","7","ει γαρ η πρωτη εκεινη ην αμεμπτοσ ουκ αν δευτερασ εζητειτο τοποσ ");
INSERT INTO grcmt_vpl VALUES ("HB8_8","088_8_8","HEB","8","8","8","μεμφομενοσ γαρ αυτοισ λεγει ιδου ημεραι ερχονται λεγει κυριοσ και συντελεσω επι τον οικον ισραηλ και επι τον οικον ιουδα διαθηκην καινην ");
INSERT INTO grcmt_vpl VALUES ("HB8_9","088_8_9","HEB","8","9","9","ου κατα την διαθηκην ην εποιησα τοισ πατρασιν αυτων εν ημερα επιλαβομενου μου τησ χειροσ αυτων εξαγαγειν αυτουσ εκ γησ αιγυπτου οτι αυτοι ουκ ενεμειναν εν τη διαθηκη μου καγω ημελησα αυτων λεγει κυριοσ ");
INSERT INTO grcmt_vpl VALUES ("HB8_10","088_8_10","HEB","8","10","10","οτι αυτη η διαθηκη ην διαθησομαι τω οικω ισραηλ μετα τασ ημερασ εκεινασ λεγει κυριοσ διδουσ νομουσ μου εισ την διανοιαν αυτων και επι καρδιασ αυτων επιγραψω αυτουσ και εσομαι αυτοισ εισ θεον και αυτοι εσονται μοι εισ λαον ");
INSERT INTO grcmt_vpl VALUES ("HB8_11","088_8_11","HEB","8","11","11","και ου μη διδαξωσιν εκαστοσ τον πολιτην αυτου και εκαστοσ τον αδελφον αυτου λεγων γνωθι τον κυριον οτι παντεσ ειδησουσιν με απο μικρου αυτων εωσ μεγαλου αυτων ");
INSERT INTO grcmt_vpl VALUES ("HB8_12","088_8_12","HEB","8","12","12","οτι ιλεωσ εσομαι ταισ αδικιαισ αυτων και των αμαρτιων αυτων και των ανομιων αυτων ου μη μνησθω ετι ");
INSERT INTO grcmt_vpl VALUES ("HB8_13","088_8_13","HEB","8","13","13","εν τω λεγειν καινην πεπαλαιωκεν την πρωτην το δε παλαιουμενον και γηρασκον εγγυσ αφανισμου ");
INSERT INTO grcmt_vpl VALUES ("HB9_1","088_9_1","HEB","9","1","1","ειχεν μεν ουν και η πρωτη δικαιωματα λατρειασ το τε αγιον κοσμικον ");
INSERT INTO grcmt_vpl VALUES ("HB9_2","088_9_2","HEB","9","2","2","σκηνη γαρ κατεσκευασθη η πρωτη εν η η τε λυχνια και η τραπεζα και η προθεσισ των αρτων ητισ λεγεται αγια ");
INSERT INTO grcmt_vpl VALUES ("HB9_3","088_9_3","HEB","9","3","3","μετα δε το δευτερον καταπετασμα σκηνη η λεγομενη αγια αγιων ");
INSERT INTO grcmt_vpl VALUES ("HB9_4","088_9_4","HEB","9","4","4","χρυσουν εχουσα θυμιατηριον και την κιβωτον τησ διαθηκησ περικεκαλυμμενην παντοθεν χρυσιω εν η σταμνοσ χρυση εχουσα το μαννα και η ραβδοσ ααρων η βλαστησασα και αι πλακεσ τησ διαθηκησ ");
INSERT INTO grcmt_vpl VALUES ("HB9_5","088_9_5","HEB","9","5","5","υπερανω δε αυτησ χερουβιμ δοξησ κατασκιαζοντα το ιλαστηριον περι ων ουκ εστιν νυν λεγειν κατα μεροσ ");
INSERT INTO grcmt_vpl VALUES ("HB9_6","088_9_6","HEB","9","6","6","τουτων δε ουτωσ κατεσκευασμενων εισ μεν την πρωτην σκηνην δια παντοσ εισιασιν οι ιερεισ τασ λατρειασ επιτελουντεσ ");
INSERT INTO grcmt_vpl VALUES ("HB9_7","088_9_7","HEB","9","7","7","εισ δε την δευτεραν απαξ του ενιαυτου μονοσ ο αρχιερευσ ου χωρισ αιματοσ ο προσφερει υπερ εαυτου και των του λαου αγνοηματων ");
INSERT INTO grcmt_vpl VALUES ("HB9_8","088_9_8","HEB","9","8","8","τουτο δηλουντοσ του πνευματοσ του αγιου μηπω πεφανερωσθαι την των αγιων οδον ετι τησ πρωτησ σκηνησ εχουσησ στασιν ");
INSERT INTO grcmt_vpl VALUES ("HB9_9","088_9_9","HEB","9","9","9","ητισ παραβολη εισ τον καιρον τον ενεστηκοτα καθ ον δωρα τε και θυσιαι προσφερονται μη δυναμεναι κατα συνειδησιν τελειωσαι τον λατρευοντα ");
INSERT INTO grcmt_vpl VALUES ("HB9_10","088_9_10","HEB","9","10","10","μονον επι βρωμασιν και πομασιν και διαφοροισ βαπτισμοισ και δικαιωμασιν σαρκοσ μεχρι καιρου διορθωσεωσ επικειμενα ");
INSERT INTO grcmt_vpl VALUES ("HB9_11","088_9_11","HEB","9","11","11","χριστοσ δε παραγενομενοσ αρχιερευσ των μελλοντων αγαθων δια τησ μειζονοσ και τελειοτερασ σκηνησ ου χειροποιητου τουτ εστιν ου ταυτησ τησ κτισεωσ ");
INSERT INTO grcmt_vpl VALUES ("HB9_12","088_9_12","HEB","9","12","12","ουδε δι αιματοσ τραγων και μοσχων δια δε του ιδιου αιματοσ εισηλθεν εφαπαξ εισ τα αγια αιωνιαν λυτρωσιν ευραμενοσ ");
INSERT INTO grcmt_vpl VALUES ("HB9_13","088_9_13","HEB","9","13","13","ει γαρ το αιμα ταυρων και τραγων και σποδοσ δαμαλεωσ ραντιζουσα τουσ κεκοινωμενουσ αγιαζει προσ την τησ σαρκοσ καθαροτητα ");
INSERT INTO grcmt_vpl VALUES ("HB9_14","088_9_14","HEB","9","14","14","ποσω μαλλον το αιμα του χριστου οσ δια πνευματοσ αιωνιου εαυτον προσηνεγκεν αμωμον τω θεω καθαριει την συνειδησιν υμων απο νεκρων εργων εισ το λατρευειν θεω ζωντι ");
INSERT INTO grcmt_vpl VALUES ("HB9_15","088_9_15","HEB","9","15","15","και δια τουτο διαθηκησ καινησ μεσιτησ εστιν οπωσ θανατου γενομενου εισ απολυτρωσιν των επι τη πρωτη διαθηκη παραβασεων την επαγγελιαν λαβωσιν οι κεκλημενοι τησ αιωνιου κληρονομιασ ");
INSERT INTO grcmt_vpl VALUES ("HB9_16","088_9_16","HEB","9","16","16","οπου γαρ διαθηκη θανατον αναγκη φερεσθαι του διαθεμενου ");
INSERT INTO grcmt_vpl VALUES ("HB9_17","088_9_17","HEB","9","17","17","διαθηκη γαρ επι νεκροισ βεβαια επει μηποτε ισχυει οτε ζη ο διαθεμενοσ ");
INSERT INTO grcmt_vpl VALUES ("HB9_18","088_9_18","HEB","9","18","18","οθεν ουδ η πρωτη χωρισ αιματοσ εγκεκαινισται ");
INSERT INTO grcmt_vpl VALUES ("HB9_19","088_9_19","HEB","9","19","19","λαληθεισησ γαρ πασησ εντολησ κατα νομον υπο μωυσεωσ παντι τω λαω λαβων το αιμα των μοσχων και τραγων μετα υδατοσ και εριου κοκκινου και υσσωπου αυτο τε το βιβλιον και παντα τον λαον ερραντισεν ");
INSERT INTO grcmt_vpl VALUES ("HB9_20","088_9_20","HEB","9","20","20","λεγων τουτο το αιμα τησ διαθηκησ ησ ενετειλατο προσ υμασ ο θεοσ ");
INSERT INTO grcmt_vpl VALUES ("HB9_21","088_9_21","HEB","9","21","21","και την σκηνην δε και παντα τα σκευη τησ λειτουργιασ τω αιματι ομοιωσ ερραντισεν ");
INSERT INTO grcmt_vpl VALUES ("HB9_22","088_9_22","HEB","9","22","22","και σχεδον εν αιματι παντα καθαριζεται κατα τον νομον και χωρισ αιματεκχυσιασ ου γινεται αφεσισ ");
INSERT INTO grcmt_vpl VALUES ("HB9_23","088_9_23","HEB","9","23","23","αναγκη ουν τα μεν υποδειγματα των εν τοισ ουρανοισ τουτοισ καθαριζεσθαι αυτα δε τα επουρανια κρειττοσιν θυσιαισ παρα ταυτασ ");
INSERT INTO grcmt_vpl VALUES ("HB9_24","088_9_24","HEB","9","24","24","ου γαρ εισ χειροποιητα αγια εισηλθεν ο χριστοσ αντιτυπα των αληθινων αλλ εισ αυτον τον ουρανον νυν εμφανισθηναι τω προσωπω του θεου υπερ ημων ");
INSERT INTO grcmt_vpl VALUES ("HB9_25","088_9_25","HEB","9","25","25","ουδ ινα πολλακισ προσφερη εαυτον ωσπερ ο αρχιερευσ εισερχεται εισ τα αγια κατ ενιαυτον εν αιματι αλλοτριω ");
INSERT INTO grcmt_vpl VALUES ("HB9_26","088_9_26","HEB","9","26","26","επει εδει αυτον πολλακισ παθειν απο καταβολησ κοσμου νυν δε απαξ επι συντελεια των αιωνων εισ αθετησιν αμαρτιασ δια τησ θυσιασ αυτου πεφανερωται ");
INSERT INTO grcmt_vpl VALUES ("HB9_27","088_9_27","HEB","9","27","27","και καθ οσον αποκειται τοισ ανθρωποισ απαξ αποθανειν μετα δε τουτο κρισισ ");
INSERT INTO grcmt_vpl VALUES ("HB9_28","088_9_28","HEB","9","28","28","ουτωσ και ο χριστοσ απαξ προσενεχθεισ εισ το πολλων ανενεγκειν αμαρτιασ εκ δευτερου χωρισ αμαρτιασ οφθησεται τοισ αυτον απεκδεχομενοισ εισ σωτηριαν ");
INSERT INTO grcmt_vpl VALUES ("HB10_1","088_10_1","HEB","10","1","1","σκιαν γαρ εχων ο νομοσ των μελλοντων αγαθων ουκ αυτην την εικονα των πραγματων κατ ενιαυτον ταισ αυταισ θυσιαισ ασ προσφερουσιν εισ το διηνεκεσ ουδεποτε δυνανται τουσ προσερχομενουσ τελειωσαι ");
INSERT INTO grcmt_vpl VALUES ("HB10_2","088_10_2","HEB","10","2","2","επει ουκ αν επαυσαντο προσφερομεναι δια το μηδεμιαν εχειν ετι συνειδησιν αμαρτιων τουσ λατρευοντασ απαξ κεκαθαρμενουσ ");
INSERT INTO grcmt_vpl VALUES ("HB10_3","088_10_3","HEB","10","3","3","αλλ εν αυταισ αναμνησισ αμαρτιων κατ ενιαυτον ");
INSERT INTO grcmt_vpl VALUES ("HB10_4","088_10_4","HEB","10","4","4","αδυνατον γαρ αιμα ταυρων και τραγων αφαιρειν αμαρτιασ ");
INSERT INTO grcmt_vpl VALUES ("HB10_5","088_10_5","HEB","10","5","5","διο εισερχομενοσ εισ τον κοσμον λεγει θυσιαν και προσφοραν ουκ ηθελησασ σωμα δε κατηρτισω μοι ");
INSERT INTO grcmt_vpl VALUES ("HB10_6","088_10_6","HEB","10","6","6","ολοκαυτωματα και περι αμαρτιασ ουκ ευδοκησασ ");
INSERT INTO grcmt_vpl VALUES ("HB10_7","088_10_7","HEB","10","7","7","τοτε ειπον ιδου ηκω εν κεφαλιδι βιβλιου γεγραπται περι εμου του ποιησαι ο θεοσ το θελημα σου ");
INSERT INTO grcmt_vpl VALUES ("HB10_8","088_10_8","HEB","10","8","8","ανωτερον λεγων οτι θυσιαν και προσφοραν και ολοκαυτωματα και περι αμαρτιασ ουκ ηθελησασ ουδε ευδοκησασ αιτινεσ κατα τον νομον προσφερονται ");
INSERT INTO grcmt_vpl VALUES ("HB10_9","088_10_9","HEB","10","9","9","τοτε ειρηκεν ιδου ηκω του ποιησαι ο θεοσ το θελημα σου αναιρει το πρωτον ινα το δευτερον στηση ");
INSERT INTO grcmt_vpl VALUES ("HB10_10","088_10_10","HEB","10","10","10","εν ω θεληματι ηγιασμενοι εσμεν οι δια τησ προσφορασ του σωματοσ ιησου χριστου εφαπαξ ");
INSERT INTO grcmt_vpl VALUES ("HB10_11","088_10_11","HEB","10","11","11","και πασ μεν ιερευσ εστηκεν καθ ημεραν λειτουργων και τασ αυτασ πολλακισ προσφερων θυσιασ αιτινεσ ουδεποτε δυνανται περιελειν αμαρτιασ ");
INSERT INTO grcmt_vpl VALUES ("HB10_12","088_10_12","HEB","10","12","12","αυτοσ δε μιαν υπερ αμαρτιων προσενεγκασ θυσιαν εισ το διηνεκεσ εκαθισεν εν δεξια του θεου ");
INSERT INTO grcmt_vpl VALUES ("HB10_13","088_10_13","HEB","10","13","13","το λοιπον εκδεχομενοσ εωσ τεθωσιν οι εχθροι αυτου υποποδιον των ποδων αυτου ");
INSERT INTO grcmt_vpl VALUES ("HB10_14","088_10_14","HEB","10","14","14","μια γαρ προσφορα τετελειωκεν εισ το διηνεκεσ τουσ αγιαζομενουσ ");
INSERT INTO grcmt_vpl VALUES ("HB10_15","088_10_15","HEB","10","15","15","μαρτυρει δε ημιν και το πνευμα το αγιον μετα γαρ το προειρηκεναι ");
INSERT INTO grcmt_vpl VALUES ("HB10_16","088_10_16","HEB","10","16","16","αυτη η διαθηκη ην διαθησομαι προσ αυτουσ μετα τασ ημερασ εκεινασ λεγει κυριοσ διδουσ νομουσ μου επι καρδιασ αυτων και επι των διανοιων αυτων επιγραψω αυτουσ ");
INSERT INTO grcmt_vpl VALUES ("HB10_17","088_10_17","HEB","10","17","17","και των αμαρτιων αυτων και των ανομιων αυτων ου μη μνησθω ετι ");
INSERT INTO grcmt_vpl VALUES ("HB10_18","088_10_18","HEB","10","18","18","οπου δε αφεσισ τουτων ουκετι προσφορα περι αμαρτιασ ");
INSERT INTO grcmt_vpl VALUES ("HB10_19","088_10_19","HEB","10","19","19","εχοντεσ ουν αδελφοι παρρησιαν εισ την εισοδον των αγιων εν τω αιματι ιησου ");
INSERT INTO grcmt_vpl VALUES ("HB10_20","088_10_20","HEB","10","20","20","ην ενεκαινισεν ημιν οδον προσφατον και ζωσαν δια του καταπετασματοσ τουτ εστιν τησ σαρκοσ αυτου ");
INSERT INTO grcmt_vpl VALUES ("HB10_21","088_10_21","HEB","10","21","21","και ιερεα μεγαν επι τον οικον του θεου ");
INSERT INTO grcmt_vpl VALUES ("HB10_22","088_10_22","HEB","10","22","22","προσερχωμεθα μετα αληθινησ καρδιασ εν πληροφορια πιστεωσ ερραντισμενοι τασ καρδιασ απο συνειδησεωσ πονηρασ και λελουμενοι το σωμα υδατι καθαρω ");
INSERT INTO grcmt_vpl VALUES ("HB10_23","088_10_23","HEB","10","23","23","κατεχωμεν την ομολογιαν τησ ελπιδοσ ακλινη πιστοσ γαρ ο επαγγειλαμενοσ ");
INSERT INTO grcmt_vpl VALUES ("HB10_24","088_10_24","HEB","10","24","24","και κατανοωμεν αλληλουσ εισ παροξυσμον αγαπησ και καλων εργων ");
INSERT INTO grcmt_vpl VALUES ("HB10_25","088_10_25","HEB","10","25","25","μη εγκαταλειποντεσ την επισυναγωγην εαυτων καθωσ εθοσ τισιν αλλα παρακαλουντεσ και τοσουτω μαλλον οσω βλεπετε εγγιζουσαν την ημεραν ");
INSERT INTO grcmt_vpl VALUES ("HB10_26","088_10_26","HEB","10","26","26","εκουσιωσ γαρ αμαρτανοντων ημων μετα το λαβειν την επιγνωσιν τησ αληθειασ ουκετι περι αμαρτιων απολειπεται θυσια ");
INSERT INTO grcmt_vpl VALUES ("HB10_27","088_10_27","HEB","10","27","27","φοβερα δε τισ εκδοχη κρισεωσ και πυροσ ζηλοσ εσθιειν μελλοντοσ τουσ υπεναντιουσ ");
INSERT INTO grcmt_vpl VALUES ("HB10_28","088_10_28","HEB","10","28","28","αθετησασ τισ νομον μωυσεωσ χωρισ οικτιρμων επι δυσιν η τρισιν μαρτυσιν αποθνησκει ");
INSERT INTO grcmt_vpl VALUES ("HB10_29","088_10_29","HEB","10","29","29","ποσω δοκειτε χειρονοσ αξιωθησεται τιμωριασ ο τον υιον του θεου καταπατησασ και το αιμα τησ διαθηκησ κοινον ηγησαμενοσ εν ω ηγιασθη και το πνευμα τησ χαριτοσ ενυβρισασ ");
INSERT INTO grcmt_vpl VALUES ("HB10_30","088_10_30","HEB","10","30","30","οιδαμεν γαρ τον ειποντα εμοι εκδικησισ εγω ανταποδωσω λεγει κυριοσ και παλιν κυριοσ κρινει τον λαον αυτου ");
INSERT INTO grcmt_vpl VALUES ("HB10_31","088_10_31","HEB","10","31","31","φοβερον το εμπεσειν εισ χειρασ θεου ζωντοσ ");
INSERT INTO grcmt_vpl VALUES ("HB10_32","088_10_32","HEB","10","32","32","αναμιμνησκεσθε δε τασ προτερον ημερασ εν αισ φωτισθεντεσ πολλην αθλησιν υπεμεινατε παθηματων ");
INSERT INTO grcmt_vpl VALUES ("HB10_33","088_10_33","HEB","10","33","33","τουτο μεν ονειδισμοισ τε και θλιψεσιν θεατριζομενοι τουτο δε κοινωνοι των ουτωσ αναστρεφομενων γενηθεντεσ ");
INSERT INTO grcmt_vpl VALUES ("HB10_34","088_10_34","HEB","10","34","34","και γαρ τοισ δεσμοισ μου συνεπαθησατε και την αρπαγην των υπαρχοντων υμων μετα χαρασ προσεδεξασθε γινωσκοντεσ εχειν εαυτοισ κρειττονα υπαρξιν εν ουρανοισ και μενουσαν ");
INSERT INTO grcmt_vpl VALUES ("HB10_35","088_10_35","HEB","10","35","35","μη αποβαλητε ουν την παρρησιαν υμων ητισ εχει μισθαποδοσιαν μεγαλην ");
INSERT INTO grcmt_vpl VALUES ("HB10_36","088_10_36","HEB","10","36","36","υπομονησ γαρ εχετε χρειαν ινα το θελημα του θεου ποιησαντεσ κομισησθε την επαγγελιαν ");
INSERT INTO grcmt_vpl VALUES ("HB10_37","088_10_37","HEB","10","37","37","ετι γαρ μικρον οσον οσον ο ερχομενοσ ηξει και ου χρονιει ");
INSERT INTO grcmt_vpl VALUES ("HB10_38","088_10_38","HEB","10","38","38","ο δε δικαιοσ εκ πιστεωσ ζησεται και εαν υποστειληται ουκ ευδοκει η ψυχη μου εν αυτω ");
INSERT INTO grcmt_vpl VALUES ("HB10_39","088_10_39","HEB","10","39","39","ημεισ δε ουκ εσμεν υποστολησ εισ απωλειαν αλλα πιστεωσ εισ περιποιησιν ψυχησ ");
INSERT INTO grcmt_vpl VALUES ("HB11_1","088_11_1","HEB","11","1","1","εστιν δε πιστισ ελπιζομενων υποστασισ πραγματων ελεγχοσ ου βλεπομενων ");
INSERT INTO grcmt_vpl VALUES ("HB11_2","088_11_2","HEB","11","2","2","εν ταυτη γαρ εμαρτυρηθησαν οι πρεσβυτεροι ");
INSERT INTO grcmt_vpl VALUES ("HB11_3","088_11_3","HEB","11","3","3","πιστει νοουμεν κατηρτισθαι τουσ αιωνασ ρηματι θεου εισ το μη εκ φαινομενων τα βλεπομενα γεγονεναι ");
INSERT INTO grcmt_vpl VALUES ("HB11_4","088_11_4","HEB","11","4","4","πιστει πλειονα θυσιαν αβελ παρα καιν προσηνεγκεν τω θεω δι ησ εμαρτυρηθη ειναι δικαιοσ μαρτυρουντοσ επι τοισ δωροισ αυτου του θεου και δι αυτησ αποθανων ετι λαλειται ");
INSERT INTO grcmt_vpl VALUES ("HB11_5","088_11_5","HEB","11","5","5","πιστει ενωχ μετετεθη του μη ιδειν θανατον και ουχ ευρισκετο διοτι μετεθηκεν αυτον ο θεοσ προ γαρ τησ μεταθεσεωσ αυτου μεμαρτυρηται ευηρεστηκεναι τω θεω ");
INSERT INTO grcmt_vpl VALUES ("HB11_6","088_11_6","HEB","11","6","6","χωρισ δε πιστεωσ αδυνατον ευαρεστησαι πιστευσαι γαρ δει τον προσερχομενον τω θεω οτι εστιν και τοισ εκζητουσιν αυτον μισθαποδοτησ γινεται ");
INSERT INTO grcmt_vpl VALUES ("HB11_7","088_11_7","HEB","11","7","7","πιστει χρηματισθεισ νωε περι των μηδεπω βλεπομενων ευλαβηθεισ κατεσκευασεν κιβωτον εισ σωτηριαν του οικου αυτου δι ησ κατεκρινεν τον κοσμον και τησ κατα πιστιν δικαιοσυνησ εγενετο κληρονομοσ ");
INSERT INTO grcmt_vpl VALUES ("HB11_8","088_11_8","HEB","11","8","8","πιστει καλουμενοσ αβρααμ υπηκουσεν εξελθειν εισ τον τοπον ον ημελλεν λαμβανειν εισ κληρονομιαν και εξηλθεν μη επισταμενοσ που ερχεται ");
INSERT INTO grcmt_vpl VALUES ("HB11_9","088_11_9","HEB","11","9","9","πιστει παρωκησεν εισ γην τησ επαγγελιασ ωσ αλλοτριαν εν σκηναισ κατοικησασ μετα ισαακ και ιακωβ των συγκληρονομων τησ επαγγελιασ τησ αυτησ ");
INSERT INTO grcmt_vpl VALUES ("HB11_10","088_11_10","HEB","11","10","10","εξεδεχετο γαρ την τουσ θεμελιουσ εχουσαν πολιν ησ τεχνιτησ και δημιουργοσ ο θεοσ ");
INSERT INTO grcmt_vpl VALUES ("HB11_11","088_11_11","HEB","11","11","11","πιστει και αυτη σαρρα δυναμιν εισ καταβολην σπερματοσ ελαβεν και παρα καιρον ηλικιασ ετεκεν επει πιστον ηγησατο τον επαγγειλαμενον ");
INSERT INTO grcmt_vpl VALUES ("HB11_12","088_11_12","HEB","11","12","12","διο και αφ ενοσ εγεννηθησαν και ταυτα νενεκρωμενου καθωσ τα αστρα του ουρανου τω πληθει και ωσ η αμμοσ η παρα το χειλοσ τησ θαλασσησ η αναριθμητοσ ");
INSERT INTO grcmt_vpl VALUES ("HB11_13","088_11_13","HEB","11","13","13","κατα πιστιν απεθανον ουτοι παντεσ μη λαβοντεσ τασ επαγγελιασ αλλα πορρωθεν αυτασ ιδοντεσ και ασπασαμενοι και ομολογησαντεσ οτι ξενοι και παρεπιδημοι εισιν επι τησ γησ ");
INSERT INTO grcmt_vpl VALUES ("HB11_14","088_11_14","HEB","11","14","14","οι γαρ τοιαυτα λεγοντεσ εμφανιζουσιν οτι πατριδα επιζητουσιν ");
INSERT INTO grcmt_vpl VALUES ("HB11_15","088_11_15","HEB","11","15","15","και ει μεν εκεινησ εμνημονευον αφ ησ εξηλθον ειχον αν καιρον ανακαμψαι ");
INSERT INTO grcmt_vpl VALUES ("HB11_16","088_11_16","HEB","11","16","16","νυν δε κρειττονοσ ορεγονται τουτ εστιν επουρανιου διο ουκ επαισχυνεται αυτουσ ο θεοσ θεοσ επικαλεισθαι αυτων ητοιμασεν γαρ αυτοισ πολιν ");
INSERT INTO grcmt_vpl VALUES ("HB11_17","088_11_17","HEB","11","17","17","πιστει προσενηνοχεν αβρααμ τον ισαακ πειραζομενοσ και τον μονογενη προσεφερεν ο τασ επαγγελιασ αναδεξαμενοσ ");
INSERT INTO grcmt_vpl VALUES ("HB11_18","088_11_18","HEB","11","18","18","προσ ον ελαληθη οτι εν ισαακ κληθησεται σοι σπερμα ");
INSERT INTO grcmt_vpl VALUES ("HB11_19","088_11_19","HEB","11","19","19","λογισαμενοσ οτι και εκ νεκρων εγειρειν δυνατοσ ο θεοσ οθεν αυτον και εν παραβολη εκομισατο ");
INSERT INTO grcmt_vpl VALUES ("HB11_20","088_11_20","HEB","11","20","20","πιστει περι μελλοντων ευλογησεν ισαακ τον ιακωβ και τον ησαυ ");
INSERT INTO grcmt_vpl VALUES ("HB11_21","088_11_21","HEB","11","21","21","πιστει ιακωβ αποθνησκων εκαστον των υιων ιωσηφ ευλογησεν και προσεκυνησεν επι το ακρον τησ ραβδου αυτου ");
INSERT INTO grcmt_vpl VALUES ("HB11_22","088_11_22","HEB","11","22","22","πιστει ιωσηφ τελευτων περι τησ εξοδου των υιων ισραηλ εμνημονευσεν και περι των οστεων αυτου ενετειλατο ");
INSERT INTO grcmt_vpl VALUES ("HB11_23","088_11_23","HEB","11","23","23","πιστει μωυσησ γεννηθεισ εκρυβη τριμηνον υπο των πατερων αυτου διοτι ειδον αστειον το παιδιον και ουκ εφοβηθησαν το διαταγμα του βασιλεωσ ");
INSERT INTO grcmt_vpl VALUES ("HB11_24","088_11_24","HEB","11","24","24","πιστει μωυσησ μεγασ γενομενοσ ηρνησατο λεγεσθαι υιοσ θυγατροσ φαραω ");
INSERT INTO grcmt_vpl VALUES ("HB11_25","088_11_25","HEB","11","25","25","μαλλον ελομενοσ συγκακουχεισθαι τω λαω του θεου η προσκαιρον εχειν αμαρτιασ απολαυσιν ");
INSERT INTO grcmt_vpl VALUES ("HB11_26","088_11_26","HEB","11","26","26","μειζονα πλουτον ηγησαμενοσ των αιγυπτου θησαυρων τον ονειδισμον του χριστου απεβλεπεν γαρ εισ την μισθαποδοσιαν ");
