INSERT INTO grcmt_vpl VALUES ("JM1_23","089_1_23","JAS","1","23","23","οτι ει τισ ακροατησ λογου εστιν και ου ποιητησ ουτοσ εοικεν ανδρι κατανοουντι το προσωπον τησ γενεσεωσ αυτου εν εσοπτρω ");
INSERT INTO grcmt_vpl VALUES ("JM1_24","089_1_24","JAS","1","24","24","κατενοησεν γαρ εαυτον και απεληλυθεν και ευθεωσ επελαθετο οποιοσ ην ");
INSERT INTO grcmt_vpl VALUES ("JM1_25","089_1_25","JAS","1","25","25","ο δε παρακυψασ εισ νομον τελειον τον τησ ελευθεριασ και παραμεινασ ουτοσ ουκ ακροατησ επιλησμονησ γενομενοσ αλλα ποιητησ εργου ουτοσ μακαριοσ εν τη ποιησει αυτου εσται ");
INSERT INTO grcmt_vpl VALUES ("JM1_26","089_1_26","JAS","1","26","26","ει τισ δοκει θρησκοσ ειναι εν υμιν μη χαλιναγωγων γλωσσαν αυτου αλλα απατων καρδιαν αυτου τουτου ματαιοσ η θρησκεια ");
