INSERT INTO grcmt_vpl VALUES ("JM2_1","089_2_1","JAS","2","1","1","αδελφοι μου μη εν προσωποληψιαισ εχετε την πιστιν του κυριου ημων ιησου χριστου τησ δοξησ ");
INSERT INTO grcmt_vpl VALUES ("JM2_2","089_2_2","JAS","2","2","2","εαν γαρ εισελθη εισ την συναγωγην υμων ανηρ χρυσοδακτυλιοσ εν εσθητι λαμπρα εισελθη δε και πτωχοσ εν ρυπαρα εσθητι ");
INSERT INTO grcmt_vpl VALUES ("JM2_3","089_2_3","JAS","2","3","3","και επιβλεψητε επι τον φορουντα την εσθητα την λαμπραν και ειπητε αυτω συ καθου ωδε καλωσ και τω πτωχω ειπητε συ στηθι εκει η καθου ωδε υπο το υποποδιον μου ");
INSERT INTO grcmt_vpl VALUES ("JM2_4","089_2_4","JAS","2","4","4","και ου διεκριθητε εν εαυτοισ και εγενεσθε κριται διαλογισμων πονηρων ");
INSERT INTO grcmt_vpl VALUES ("JM2_5","089_2_5","JAS","2","5","5","ακουσατε αδελφοι μου αγαπητοι ουχ ο θεοσ εξελεξατο τουσ πτωχουσ του κοσμου πλουσιουσ εν πιστει και κληρονομουσ τησ βασιλειασ ησ επηγγειλατο τοισ αγαπωσιν αυτον ");
INSERT INTO grcmt_vpl VALUES ("JM2_6","089_2_6","JAS","2","6","6","υμεισ δε ητιμασατε τον πτωχον ουχ οι πλουσιοι καταδυναστευουσιν υμων και αυτοι ελκουσιν υμασ εισ κριτηρια ");
INSERT INTO grcmt_vpl VALUES ("JM2_7","089_2_7","JAS","2","7","7","ουκ αυτοι βλασφημουσιν το καλον ονομα το επικληθεν εφ υμασ ");
INSERT INTO grcmt_vpl VALUES ("JM2_8","089_2_8","JAS","2","8","8","ει μεντοι νομον τελειτε βασιλικον κατα την γραφην αγαπησεισ τον πλησιον σου ωσ σεαυτον καλωσ ποιειτε ");
INSERT INTO grcmt_vpl VALUES ("JM2_9","089_2_9","JAS","2","9","9","ει δε προσωποληπτειτε αμαρτιαν εργαζεσθε ελεγχομενοι υπο του νομου ωσ παραβαται ");
INSERT INTO grcmt_vpl VALUES ("JM2_10","089_2_10","JAS","2","10","10","οστισ γαρ ολον τον νομον τηρησει πταισει δε εν ενι γεγονεν παντων ενοχοσ ");
INSERT INTO grcmt_vpl VALUES ("JM2_11","089_2_11","JAS","2","11","11","ο γαρ ειπων μη μοιχευσεισ ειπεν και μη φονευσεισ ει δε ου μοιχευσεισ φονευσεισ δε γεγονασ παραβατησ νομου ");
