INSERT INTO grcmt_vpl VALUES ("JM2_16","089_2_16","JAS","2","16","16","ειπη δε τισ αυτοισ εξ υμων υπαγετε εν ειρηνη θερμαινεσθε και χορταζεσθε μη δωτε δε αυτοισ τα επιτηδεια του σωματοσ τι το οφελοσ ");
INSERT INTO grcmt_vpl VALUES ("JM2_17","089_2_17","JAS","2","17","17","ουτωσ και η πιστισ εαν μη εργα εχη νεκρα εστιν καθ εαυτην ");
INSERT INTO grcmt_vpl VALUES ("JM2_18","089_2_18","JAS","2","18","18","αλλ ερει τισ συ πιστιν εχεισ καγω εργα εχω δειξον μοι την πιστιν σου εκ των εργων σου καγω δειξω σοι εκ των εργων μου την πιστιν μου ");
INSERT INTO grcmt_vpl VALUES ("JM2_19","089_2_19","JAS","2","19","19","συ πιστευεισ οτι ο θεοσ εισ εστιν καλωσ ποιεισ και τα δαιμονια πιστευουσιν και φρισσουσιν ");
INSERT INTO grcmt_vpl VALUES ("JM2_20","089_2_20","JAS","2","20","20","θελεισ δε γνωναι ω ανθρωπε κενε οτι η πιστισ χωρισ των εργων νεκρα εστιν ");
INSERT INTO grcmt_vpl VALUES ("JM2_21","089_2_21","JAS","2","21","21","αβρααμ ο πατηρ ημων ουκ εξ εργων εδικαιωθη ανενεγκασ ισαακ τον υιον αυτου επι το θυσιαστηριον ");
