INSERT INTO grcmt_vpl VALUES ("JM2_23","089_2_23","JAS","2","23","23","και επληρωθη η γραφη η λεγουσα επιστευσεν δε αβρααμ τω θεω και ελογισθη αυτω εισ δικαιοσυνην και φιλοσ θεου εκληθη ");
INSERT INTO grcmt_vpl VALUES ("JM2_24","089_2_24","JAS","2","24","24","ορατε 3708 V-PAI-2P τοινυν οτι εξ εργων δικαιουται ανθρωποσ και ουκ εκ πιστεωσ μονον ");
INSERT INTO grcmt_vpl VALUES ("JM2_25","089_2_25","JAS","2","25","25","ομοιωσ δε και ρααβ η πορνη ουκ εξ εργων εδικαιωθη υποδεξαμενη τουσ αγγελουσ και ετερα οδω εκβαλουσα ");
INSERT INTO grcmt_vpl VALUES ("JM2_26","089_2_26","JAS","2","26","26","ωσπερ γαρ το σωμα χωρισ πνευματοσ νεκρον εστιν ουτωσ και η πιστισ χωρισ των εργων νεκρα εστιν ");
INSERT INTO grcmt_vpl VALUES ("JM3_1","089_3_1","JAS","3","1","1","μη πολλοι διδασκαλοι γινεσθε αδελφοι μου ειδοτεσ οτι μειζον κριμα ληψομεθα ");
