INSERT INTO grcmt_vpl VALUES ("JM4_5","089_4_5","JAS","4","5","5","η δοκειτε οτι κενωσ η γραφη λεγει προσ φθονον επιποθει το 3588 T-NSN πνευμα 4151 N-NSN ο κατωκησεν εν ημιν ");
INSERT INTO grcmt_vpl VALUES ("JM4_6","089_4_6","JAS","4","6","6","μειζονα δε διδωσιν χαριν διο λεγει ο θεοσ υπερηφανοισ αντιτασσεται ταπεινοισ δε διδωσιν χαριν ");
