INSERT INTO grcmt_vpl VALUES ("JM4_8","089_4_8","JAS","4","8","8","εγγισατε τω θεω και εγγιει υμιν καθαρισατε χειρασ αμαρτωλοι και αγνισατε καρδιασ διψυχοι ");
