INSERT INTO grcmt_vpl VALUES ("JM4_10","089_4_10","JAS","4","10","10","ταπεινωθητε ενωπιον του κυριου και υψωσει υμασ ");
INSERT INTO grcmt_vpl VALUES ("JM4_11","089_4_11","JAS","4","11","11","μη καταλαλειτε αλληλων αδελφοι ο καταλαλων αδελφου και κρινων τον αδελφον αυτου καταλαλει νομου και κρινει νομον ει δε νομον κρινεισ ουκ ει ποιητησ νομου αλλα κριτησ ");
