INSERT INTO grcmt_vpl VALUES ("JM4_15","089_4_15","JAS","4","15","15","αντι του λεγειν υμασ εαν ο κυριοσ θεληση και ζησωμεν και ποιησωμεν τουτο η εκεινο ");
INSERT INTO grcmt_vpl VALUES ("JM4_16","089_4_16","JAS","4","16","16","νυν δε καυχασθε εν ταισ αλαζονειαισ υμων πασα καυχησισ τοιαυτη πονηρα εστιν ");
INSERT INTO grcmt_vpl VALUES ("JM4_17","089_4_17","JAS","4","17","17","ειδοτι ουν καλον ποιειν και μη ποιουντι αμαρτια αυτω εστιν ");
INSERT INTO grcmt_vpl VALUES ("JM5_1","089_5_1","JAS","5","1","1","αγε νυν οι πλουσιοι κλαυσατε ολολυζοντεσ επι ταισ ταλαιπωριαισ υμων ταισ επερχομεναισ ");
INSERT INTO grcmt_vpl VALUES ("JM5_2","089_5_2","JAS","5","2","2","ο πλουτοσ υμων σεσηπεν και τα ιματια υμων σητοβρωτα γεγονεν ");
INSERT INTO grcmt_vpl VALUES ("JM5_3","089_5_3","JAS","5","3","3","ο χρυσοσ υμων και ο αργυροσ κατιωται και ο ιοσ αυτων εισ μαρτυριον υμιν εσται και φαγεται τασ σαρκασ υμων ωσ πυρ εθησαυρισατε εν εσχαταισ ημεραισ ");
INSERT INTO grcmt_vpl VALUES ("JM5_4","089_5_4","JAS","5","4","4","ιδου ο μισθοσ των εργατων των αμησαντων τασ χωρασ υμων ο απεστερημενοσ αφ υμων κραζει και αι βοαι των θερισαντων εισ τα ωτα κυριου σαβαωθ εισεληλυθασιν ");
INSERT INTO grcmt_vpl VALUES ("JM5_5","089_5_5","JAS","5","5","5","ετρυφησατε επι τησ γησ και εσπαταλησατε εθρεψατε τασ καρδιασ υμων ωσ εν ημερα σφαγησ ");
INSERT INTO grcmt_vpl VALUES ("JM5_6","089_5_6","JAS","5","6","6","κατεδικασατε εφονευσατε τον δικαιον ουκ αντιτασσεται υμιν ");
INSERT INTO grcmt_vpl VALUES ("JM5_7","089_5_7","JAS","5","7","7","μακροθυμησατε ουν αδελφοι εωσ τησ παρουσιασ του κυριου ιδου ο γεωργοσ εκδεχεται τον τιμιον καρπον τησ γησ μακροθυμων επ αυτον εωσ λαβη υετον πρωιμον και οψιμον ");
INSERT INTO grcmt_vpl VALUES ("JM5_8","089_5_8","JAS","5","8","8","μακροθυμησατε και υμεισ στηριξατε τασ καρδιασ υμων οτι η παρουσια του κυριου ηγγικεν ");
INSERT INTO grcmt_vpl VALUES ("JM5_9","089_5_9","JAS","5","9","9","μη στεναζετε κατ αλληλων αδελφοι ινα μη κριθητε ιδου ο κριτησ προ των θυρων εστηκεν ");
INSERT INTO grcmt_vpl VALUES ("JM5_10","089_5_10","JAS","5","10","10","υποδειγμα λαβετε αδελφοι μου τησ κακοπαθειασ και τησ μακροθυμιασ τουσ προφητασ οι ελαλησαν τω ονοματι κυριου ");
INSERT INTO grcmt_vpl VALUES ("JM5_11","089_5_11","JAS","5","11","11","ιδου μακαριζομεν τουσ υπομενοντασ την υπομονην ιωβ ηκουσατε και το τελοσ κυριου ιδετε οτι πολυσπλαγχνοσ εστιν και οικτιρμων ");
INSERT INTO grcmt_vpl VALUES ("JM5_12","089_5_12","JAS","5","12","12","προ παντων δε αδελφοι μου μη ομνυετε μητε τον ουρανον μητε την γην μητε αλλον τινα ορκον ητω δε υμων το ναι ναι και το ου ου ινα μη εισ υποκρισιν πεσητε ");
INSERT INTO grcmt_vpl VALUES ("JM5_13","089_5_13","JAS","5","13","13","κακοπαθει τισ εν υμιν προσευχεσθω ευθυμει τισ ψαλλετω ");
INSERT INTO grcmt_vpl VALUES ("JM5_14","089_5_14","JAS","5","14","14","ασθενει τισ εν υμιν προσκαλεσασθω τουσ πρεσβυτερουσ τησ εκκλησιασ και προσευξασθωσαν επ αυτον αλειψαντεσ αυτον ελαιω εν τω ονοματι του κυριου ");
INSERT INTO grcmt_vpl VALUES ("JM5_15","089_5_15","JAS","5","15","15","και η ευχη τησ πιστεωσ σωσει τον καμνοντα και εγερει αυτον ο κυριοσ καν αμαρτιασ η πεποιηκωσ αφεθησεται αυτω ");
INSERT INTO grcmt_vpl VALUES ("JM5_16","089_5_16","JAS","5","16","16","εξομολογεισθε αλληλοισ τα παραπτωματα και ευχεσθε υπερ αλληλων οπωσ ιαθητε πολυ ισχυει δεησισ δικαιου ενεργουμενη ");
INSERT INTO grcmt_vpl VALUES ("JM5_17","089_5_17","JAS","5","17","17","ηλιασ ανθρωποσ ην ομοιοπαθησ ημιν και προσευχη προσηυξατο του μη βρεξαι και ουκ εβρεξεν επι τησ γησ ενιαυτουσ τρεισ και μηνασ εξ ");
INSERT INTO grcmt_vpl VALUES ("JM5_18","089_5_18","JAS","5","18","18","και παλιν προσηυξατο και ο ουρανοσ υετον εδωκεν και η γη εβλαστησεν τον καρπον αυτησ ");
