INSERT INTO grcmt_vpl VALUES ("P23_14","091_3_14","2PE","3","14","14","διο αγαπητοι ταυτα προσδοκωντεσ σπουδασατε ασπιλοι και αμωμητοι αυτω ευρεθηναι εν ειρηνη ");
INSERT INTO grcmt_vpl VALUES ("P23_15","091_3_15","2PE","3","15","15","και την του κυριου ημων μακροθυμιαν σωτηριαν ηγεισθε καθωσ και ο αγαπητοσ ημων αδελφοσ παυλοσ κατα την αυτω δοθεισαν σοφιαν εγραψεν υμιν ");
INSERT INTO grcmt_vpl VALUES ("P23_16","091_3_16","2PE","3","16","16","ωσ και εν πασαισ ταισ επιστολαισ λαλων εν αυταισ περι τουτων εν οισ εστιν δυσνοητα τινα α οι αμαθεισ και αστηρικτοι στρεβλουσιν ωσ και τασ λοιπασ γραφασ προσ την ιδιαν αυτων απωλειαν ");
INSERT INTO grcmt_vpl VALUES ("P23_17","091_3_17","2PE","3","17","17","υμεισ ουν αγαπητοι προγινωσκοντεσ φυλασσεσθε ινα μη τη των αθεσμων πλανη συναπαχθεντεσ εκπεσητε του ιδιου στηριγμου ");
INSERT INTO grcmt_vpl VALUES ("P23_18","091_3_18","2PE","3","18","18","αυξανετε δε εν χαριτι και γνωσει του κυριου ημων και σωτηροσ ιησου χριστου αυτω η δοξα και νυν και εισ ημεραν αιωνοσ αμην ");
INSERT INTO grcmt_vpl VALUES ("J11_1","092_1_1","1JN","1","1","1","ο ην απ αρχησ ο ακηκοαμεν ο εωρακαμεν τοισ οφθαλμοισ ημων ο εθεασαμεθα και αι χειρεσ ημων εψηλαφησαν περι του λογου τησ ζωησ ");
INSERT INTO grcmt_vpl VALUES ("J11_2","092_1_2","1JN","1","2","2","και η ζωη εφανερωθη και εωρακαμεν και μαρτυρουμεν και απαγγελλομεν υμιν την ζωην την αιωνιον ητισ ην προσ τον πατερα και εφανερωθη ημιν ");
INSERT INTO grcmt_vpl VALUES ("J11_3","092_1_3","1JN","1","3","3","ο εωρακαμεν και ακηκοαμεν απαγγελλομεν υμιν ινα και υμεισ κοινωνιαν εχητε μεθ ημων και η κοινωνια δε η ημετερα μετα του πατροσ και μετα του υιου αυτου ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("J11_4","092_1_4","1JN","1","4","4","και ταυτα γραφομεν υμιν ινα η χαρα ημων η πεπληρωμενη ");
INSERT INTO grcmt_vpl VALUES ("J11_5","092_1_5","1JN","1","5","5","και εστιν αυτη η αγγελια ην ακηκοαμεν απ αυτου και αναγγελλομεν υμιν οτι ο θεοσ φωσ εστιν και σκοτια εν αυτω ουκ εστιν ουδεμια ");
INSERT INTO grcmt_vpl VALUES ("J11_6","092_1_6","1JN","1","6","6","εαν ειπωμεν οτι κοινωνιαν εχομεν μετ αυτου και εν τω σκοτει περιπατωμεν ψευδομεθα και ου ποιουμεν την αληθειαν ");
INSERT INTO grcmt_vpl VALUES ("J11_7","092_1_7","1JN","1","7","7","εαν δε εν τω φωτι περιπατωμεν ωσ αυτοσ εστιν εν τω φωτι κοινωνιαν εχομεν μετ αλληλων και το αιμα ιησου χριστου του υιου αυτου καθαριζει ημασ απο πασησ αμαρτιασ ");
INSERT INTO grcmt_vpl VALUES ("J11_8","092_1_8","1JN","1","8","8","εαν ειπωμεν οτι αμαρτιαν ουκ εχομεν εαυτουσ πλανωμεν και η αληθεια ουκ εστιν εν ημιν ");
INSERT INTO grcmt_vpl VALUES ("J11_9","092_1_9","1JN","1","9","9","εαν ομολογωμεν τασ αμαρτιασ ημων πιστοσ εστιν και δικαιοσ ινα αφη ημιν τασ αμαρτιασ και καθαριση ημασ απο πασησ αδικιασ ");
INSERT INTO grcmt_vpl VALUES ("J11_10","092_1_10","1JN","1","10","10","εαν ειπωμεν οτι ουχ ημαρτηκαμεν ψευστην ποιουμεν αυτον και ο λογοσ αυτου ουκ εστιν εν ημιν ");
INSERT INTO grcmt_vpl VALUES ("J12_1","092_2_1","1JN","2","1","1","τεκνια μου ταυτα γραφω υμιν ινα μη αμαρτητε και εαν τισ αμαρτη παρακλητον εχομεν προσ τον πατερα ιησουν χριστον δικαιον ");
INSERT INTO grcmt_vpl VALUES ("J12_2","092_2_2","1JN","2","2","2","και αυτοσ ιλασμοσ εστιν περι των αμαρτιων ημων ου περι των ημετερων δε μονον αλλα και περι ολου του κοσμου ");
INSERT INTO grcmt_vpl VALUES ("J12_3","092_2_3","1JN","2","3","3","και εν τουτω γινωσκομεν οτι εγνωκαμεν αυτον εαν τασ εντολασ αυτου τηρωμεν ");
INSERT INTO grcmt_vpl VALUES ("J12_4","092_2_4","1JN","2","4","4","ο λεγων εγνωκα αυτον και τασ εντολασ αυτου μη τηρων ψευστησ εστιν και εν τουτω η αληθεια ουκ εστιν ");
INSERT INTO grcmt_vpl VALUES ("J12_5","092_2_5","1JN","2","5","5","οσ δ αν τηρη αυτου τον λογον αληθωσ εν τουτω η αγαπη του θεου τετελειωται εν τουτω γινωσκομεν οτι εν αυτω εσμεν ");
INSERT INTO grcmt_vpl VALUES ("J12_6","092_2_6","1JN","2","6","6","ο λεγων εν αυτω μενειν οφειλει καθωσ εκεινοσ περιεπατησεν και αυτοσ ουτωσ περιπατειν ");
INSERT INTO grcmt_vpl VALUES ("J12_7","092_2_7","1JN","2","7","7","αδελφοι ουκ εντολην καινην γραφω υμιν αλλ εντολην παλαιαν ην ειχετε απ αρχησ η εντολη η παλαια εστιν ο λογοσ ον ηκουσατε απ αρχησ ");
INSERT INTO grcmt_vpl VALUES ("J12_8","092_2_8","1JN","2","8","8","παλιν εντολην καινην γραφω υμιν ο εστιν αληθεσ εν αυτω και εν υμιν οτι η σκοτια παραγεται και το φωσ το αληθινον ηδη φαινει ");
INSERT INTO grcmt_vpl VALUES ("J12_9","092_2_9","1JN","2","9","9","ο λεγων εν τω φωτι ειναι και τον αδελφον αυτου μισων εν τη σκοτια εστιν εωσ αρτι ");
INSERT INTO grcmt_vpl VALUES ("J12_10","092_2_10","1JN","2","10","10","ο αγαπων τον αδελφον αυτου εν τω φωτι μενει και σκανδαλον εν αυτω ουκ εστιν ");
INSERT INTO grcmt_vpl VALUES ("J12_11","092_2_11","1JN","2","11","11","ο δε μισων τον αδελφον αυτου εν τη σκοτια εστιν και εν τη σκοτια περιπατει και ουκ οιδεν που υπαγει οτι η σκοτια ετυφλωσεν τουσ οφθαλμουσ αυτου ");
INSERT INTO grcmt_vpl VALUES ("J12_12","092_2_12","1JN","2","12","12","γραφω υμιν τεκνια οτι αφεωνται υμιν αι αμαρτιαι δια το ονομα αυτου ");
INSERT INTO grcmt_vpl VALUES ("J12_13","092_2_13","1JN","2","13","13","γραφω υμιν πατερεσ οτι εγνωκατε τον απ αρχησ γραφω υμιν νεανισκοι οτι νενικηκατε τον πονηρον γραφω υμιν παιδια οτι εγνωκατε τον πατερα ");
INSERT INTO grcmt_vpl VALUES ("J12_14","092_2_14","1JN","2","14","14","εγραψα υμιν πατερεσ οτι εγνωκατε τον απ αρχησ εγραψα υμιν νεανισκοι οτι ισχυροι εστε και ο λογοσ του θεου εν υμιν μενει και νενικηκατε τον πονηρον ");
INSERT INTO grcmt_vpl VALUES ("J12_15","092_2_15","1JN","2","15","15","μη αγαπατε τον κοσμον μηδε τα εν τω κοσμω εαν τισ αγαπα τον κοσμον ουκ εστιν η αγαπη του πατροσ εν αυτω ");
INSERT INTO grcmt_vpl VALUES ("J12_16","092_2_16","1JN","2","16","16","οτι παν το εν τω κοσμω η επιθυμια τησ σαρκοσ και η επιθυμια των οφθαλμων και η αλαζονεια του βιου ουκ εστιν εκ του πατροσ αλλ εκ του κοσμου εστιν ");
INSERT INTO grcmt_vpl VALUES ("J12_17","092_2_17","1JN","2","17","17","και ο κοσμοσ παραγεται και η επιθυμια αυτου ο δε ποιων το θελημα του θεου μενει εισ τον αιωνα ");
INSERT INTO grcmt_vpl VALUES ("J12_18","092_2_18","1JN","2","18","18","παιδια εσχατη ωρα εστιν και καθωσ ηκουσατε οτι ο αντιχριστοσ ερχεται και νυν αντιχριστοι πολλοι γεγονασιν οθεν γινωσκομεν οτι εσχατη ωρα εστιν ");
INSERT INTO grcmt_vpl VALUES ("J12_19","092_2_19","1JN","2","19","19","εξ ημων εξηλθον αλλ ουκ ησαν εξ ημων ει γαρ ησαν εξ ημων μεμενηκεισαν αν μεθ ημων αλλ ινα φανερωθωσιν οτι ουκ εισιν παντεσ εξ ημων ");
INSERT INTO grcmt_vpl VALUES ("J12_20","092_2_20","1JN","2","20","20","και υμεισ χρισμα εχετε απο του αγιου και οιδατε παντα ");
INSERT INTO grcmt_vpl VALUES ("J12_21","092_2_21","1JN","2","21","21","ουκ εγραψα υμιν οτι ουκ οιδατε την αληθειαν αλλ οτι οιδατε αυτην και οτι παν ψευδοσ εκ τησ αληθειασ ουκ εστιν ");
INSERT INTO grcmt_vpl VALUES ("J12_22","092_2_22","1JN","2","22","22","τισ εστιν ο ψευστησ ει μη ο αρνουμενοσ οτι ιησουσ ουκ εστιν ο χριστοσ ουτοσ εστιν ο αντιχριστοσ ο αρνουμενοσ τον πατερα και τον υιον ");
INSERT INTO grcmt_vpl VALUES ("J12_23","092_2_23","1JN","2","23","23","πασ ο αρνουμενοσ τον υιον ουδε τον πατερα εχει ");
INSERT INTO grcmt_vpl VALUES ("J12_24","092_2_24","1JN","2","24","24","υμεισ ουν ο ηκουσατε απ αρχησ εν υμιν μενετω εαν εν υμιν μεινη ο απ αρχησ ηκουσατε και υμεισ εν τω υιω και εν τω πατρι μενειτε ");
INSERT INTO grcmt_vpl VALUES ("J12_25","092_2_25","1JN","2","25","25","και αυτη εστιν η επαγγελια ην αυτοσ επηγγειλατο ημιν την ζωην την αιωνιον ");
INSERT INTO grcmt_vpl VALUES ("J12_26","092_2_26","1JN","2","26","26","ταυτα εγραψα υμιν περι των πλανωντων υμασ ");
INSERT INTO grcmt_vpl VALUES ("J12_27","092_2_27","1JN","2","27","27","και υμεισ το χρισμα ο ελαβετε απ αυτου εν υμιν μενει και ου χρειαν εχετε ινα τισ διδασκη υμασ αλλ ωσ το αυτο χρισμα διδασκει υμασ περι παντων και αληθεσ εστιν και ουκ εστιν ψευδοσ και καθωσ εδιδαξεν υμασ μενειτε εν αυτω ");
INSERT INTO grcmt_vpl VALUES ("J12_28","092_2_28","1JN","2","28","28","και νυν τεκνια μενετε εν αυτω ινα οταν φανερωθη εχωμεν παρρησιαν και μη αισχυνθωμεν απ αυτου εν τη παρουσια αυτου ");
INSERT INTO grcmt_vpl VALUES ("J12_29","092_2_29","1JN","2","29","29","εαν ειδητε οτι δικαιοσ εστιν γινωσκετε οτι πασ ο ποιων την δικαιοσυνην εξ αυτου γεγεννηται ");
INSERT INTO grcmt_vpl VALUES ("J13_1","092_3_1","1JN","3","1","1","ιδετε ποταπην αγαπην δεδωκεν ημιν ο πατηρ ινα τεκνα θεου κληθωμεν δια τουτο ο κοσμοσ ου γινωσκει υμασ οτι ουκ εγνω αυτον ");
INSERT INTO grcmt_vpl VALUES ("J13_2","092_3_2","1JN","3","2","2","αγαπητοι νυν τεκνα θεου εσμεν και ουπω εφανερωθη τι εσομεθα οιδαμεν δε οτι εαν φανερωθη ομοιοι αυτω εσομεθα οτι οψομεθα αυτον καθωσ εστιν ");
INSERT INTO grcmt_vpl VALUES ("J13_3","092_3_3","1JN","3","3","3","και πασ ο εχων την ελπιδα ταυτην επ αυτω αγνιζει εαυτον καθωσ εκεινοσ αγνοσ εστιν ");
INSERT INTO grcmt_vpl VALUES ("J13_4","092_3_4","1JN","3","4","4","πασ ο ποιων την αμαρτιαν και την ανομιαν ποιει και η αμαρτια εστιν η ανομια ");
INSERT INTO grcmt_vpl VALUES ("J13_5","092_3_5","1JN","3","5","5","και οιδατε οτι εκεινοσ εφανερωθη ινα τασ αμαρτιασ ημων αρη και αμαρτια εν αυτω ουκ εστιν ");
INSERT INTO grcmt_vpl VALUES ("J13_6","092_3_6","1JN","3","6","6","πασ ο εν αυτω μενων ουχ αμαρτανει πασ ο αμαρτανων ουχ εωρακεν αυτον ουδε εγνωκεν αυτον ");
INSERT INTO grcmt_vpl VALUES ("J13_7","092_3_7","1JN","3","7","7","τεκνια μηδεισ πλανατω υμασ ο ποιων την δικαιοσυνην δικαιοσ εστιν καθωσ εκεινοσ δικαιοσ εστιν ");
INSERT INTO grcmt_vpl VALUES ("J13_8","092_3_8","1JN","3","8","8","ο ποιων την αμαρτιαν εκ του διαβολου εστιν οτι απ αρχησ ο διαβολοσ αμαρτανει εισ τουτο εφανερωθη ο υιοσ του θεου ινα λυση τα εργα του διαβολου ");
INSERT INTO grcmt_vpl VALUES ("J13_9","092_3_9","1JN","3","9","9","πασ ο γεγεννημενοσ εκ του θεου αμαρτιαν ου ποιει οτι σπερμα αυτου εν αυτω μενει και ου δυναται αμαρτανειν οτι εκ του θεου γεγεννηται ");
INSERT INTO grcmt_vpl VALUES ("J13_10","092_3_10","1JN","3","10","10","εν τουτω φανερα εστιν τα τεκνα του θεου και τα τεκνα του διαβολου πασ ο μη ποιων δικαιοσυνην ουκ εστιν εκ του θεου και ο μη αγαπων τον αδελφον αυτου ");
INSERT INTO grcmt_vpl VALUES ("J13_11","092_3_11","1JN","3","11","11","οτι αυτη εστιν η αγγελια ην ηκουσατε απ αρχησ ινα αγαπωμεν αλληλουσ ");
INSERT INTO grcmt_vpl VALUES ("J13_12","092_3_12","1JN","3","12","12","ου καθωσ καιν εκ του πονηρου ην και εσφαξεν τον αδελφον αυτου και χαριν τινοσ εσφαξεν αυτον οτι τα εργα αυτου πονηρα ην τα δε του αδελφου αυτου δικαια ");
INSERT INTO grcmt_vpl VALUES ("J13_13","092_3_13","1JN","3","13","13","μη θαυμαζετε αδελφοι μου ει μισει υμασ ο κοσμοσ ");
INSERT INTO grcmt_vpl VALUES ("J13_14","092_3_14","1JN","3","14","14","ημεισ οιδαμεν οτι μεταβεβηκαμεν εκ του θανατου εισ την ζωην οτι αγαπωμεν τουσ αδελφουσ ο μη αγαπων τον αδελφον μενει εν τω θανατω ");
INSERT INTO grcmt_vpl VALUES ("J13_15","092_3_15","1JN","3","15","15","πασ ο μισων τον αδελφον αυτου ανθρωποκτονοσ εστιν και οιδατε οτι πασ ανθρωποκτονοσ ουκ εχει ζωην αιωνιον εν εαυτω μενουσαν ");
INSERT INTO grcmt_vpl VALUES ("J13_16","092_3_16","1JN","3","16","16","εν τουτω εγνωκαμεν την αγαπην οτι εκεινοσ υπερ ημων την ψυχην αυτου εθηκεν και ημεισ οφειλομεν υπερ των αδελφων τασ ψυχασ τιθεναι ");
INSERT INTO grcmt_vpl VALUES ("J13_17","092_3_17","1JN","3","17","17","οσ δ αν εχη τον βιον του κοσμου και θεωρη τον αδελφον αυτου χρειαν εχοντα και κλειση τα σπλαγχνα αυτου απ αυτου πωσ η αγαπη του θεου μενει εν αυτω ");
INSERT INTO grcmt_vpl VALUES ("J13_18","092_3_18","1JN","3","18","18","τεκνια μου μη αγαπωμεν λογω μηδε τη γλωσση αλλ εν εργω και αληθεια ");
INSERT INTO grcmt_vpl VALUES ("J13_19","092_3_19","1JN","3","19","19","και εν τουτω γινωσκομεν οτι εκ τησ αληθειασ εσμεν και εμπροσθεν αυτου πεισομεν τασ καρδιασ ημων ");
INSERT INTO grcmt_vpl VALUES ("J13_20","092_3_20","1JN","3","20","20","οτι εαν καταγινωσκη ημων η καρδια οτι μειζων εστιν ο θεοσ τησ καρδιασ ημων και γινωσκει παντα ");
INSERT INTO grcmt_vpl VALUES ("J13_21","092_3_21","1JN","3","21","21","αγαπητοι εαν η καρδια ημων μη καταγινωσκη ημων παρρησιαν εχομεν προσ τον θεον ");
INSERT INTO grcmt_vpl VALUES ("J13_22","092_3_22","1JN","3","22","22","και ο εαν αιτωμεν λαμβανομεν παρ αυτου οτι τασ εντολασ αυτου τηρουμεν και τα αρεστα ενωπιον αυτου ποιουμεν ");
INSERT INTO grcmt_vpl VALUES ("J13_23","092_3_23","1JN","3","23","23","και αυτη εστιν η εντολη αυτου ινα πιστευσωμεν τω ονοματι του υιου αυτου ιησου χριστου και αγαπωμεν αλληλουσ καθωσ εδωκεν εντολην ");
INSERT INTO grcmt_vpl VALUES ("J13_24","092_3_24","1JN","3","24","24","και ο τηρων τασ εντολασ αυτου εν αυτω μενει και αυτοσ εν αυτω και εν τουτω γινωσκομεν οτι μενει εν ημιν εκ του πνευματοσ ου ημιν εδωκεν ");
INSERT INTO grcmt_vpl VALUES ("J14_1","092_4_1","1JN","4","1","1","αγαπητοι μη παντι πνευματι πιστευετε αλλα δοκιμαζετε τα πνευματα ει εκ του θεου εστιν οτι πολλοι ψευδοπροφηται εξεληλυθασιν εισ τον κοσμον ");
INSERT INTO grcmt_vpl VALUES ("J14_2","092_4_2","1JN","4","2","2","εν τουτω γινωσκεται το πνευμα του θεου παν πνευμα ο ομολογει ιησουν χριστον εν σαρκι εληλυθοτα εκ του θεου εστιν ");
INSERT INTO grcmt_vpl VALUES ("J14_3","092_4_3","1JN","4","3","3","και παν πνευμα ο μη ομολογει ιησουν χριστον εν σαρκι εληλυθοτα εκ του θεου ουκ εστιν και τουτο εστιν το του αντιχριστου ο ακηκοατε οτι ερχεται και νυν εν τω κοσμω εστιν ηδη ");
INSERT INTO grcmt_vpl VALUES ("J14_4","092_4_4","1JN","4","4","4","υμεισ εκ του θεου εστε τεκνια και νενικηκατε αυτουσ οτι μειζων εστιν ο εν υμιν η ο εν τω κοσμω ");
INSERT INTO grcmt_vpl VALUES ("J14_5","092_4_5","1JN","4","5","5","αυτοι εκ του κοσμου εισιν δια τουτο εκ του κοσμου λαλουσιν και ο κοσμοσ αυτων ακουει ");
INSERT INTO grcmt_vpl VALUES ("J14_6","092_4_6","1JN","4","6","6","ημεισ εκ του θεου εσμεν ο γινωσκων τον θεον ακουει ημων οσ ουκ εστιν εκ του θεου ουκ ακουει ημων εκ τουτου γινωσκομεν το πνευμα τησ αληθειασ και το πνευμα τησ πλανησ ");
INSERT INTO grcmt_vpl VALUES ("J14_7","092_4_7","1JN","4","7","7","αγαπητοι αγαπωμεν αλληλουσ οτι η αγαπη εκ του θεου εστιν και πασ ο αγαπων εκ του θεου γεγεννηται και γινωσκει τον θεον ");
INSERT INTO grcmt_vpl VALUES ("J14_8","092_4_8","1JN","4","8","8","ο μη αγαπων ουκ εγνω τον θεον οτι ο θεοσ αγαπη εστιν ");
INSERT INTO grcmt_vpl VALUES ("J14_9","092_4_9","1JN","4","9","9","εν τουτω εφανερωθη η αγαπη του θεου εν ημιν οτι τον υιον αυτου τον μονογενη απεσταλκεν ο θεοσ εισ τον κοσμον ινα ζησωμεν δι αυτου ");
INSERT INTO grcmt_vpl VALUES ("J14_10","092_4_10","1JN","4","10","10","εν τουτω εστιν η αγαπη ουχ οτι ημεισ ηγαπησαμεν τον θεον αλλ οτι αυτοσ ηγαπησεν ημασ και απεστειλεν τον υιον αυτου ιλασμον περι των αμαρτιων ημων ");
INSERT INTO grcmt_vpl VALUES ("J14_11","092_4_11","1JN","4","11","11","αγαπητοι ει ουτωσ ο θεοσ ηγαπησεν ημασ και ημεισ οφειλομεν αλληλουσ αγαπαν ");
INSERT INTO grcmt_vpl VALUES ("J14_12","092_4_12","1JN","4","12","12","θεον ουδεισ πωποτε τεθεαται εαν αγαπωμεν αλληλουσ ο θεοσ εν ημιν μενει και η αγαπη αυτου τετελειωμενη εστιν εν ημιν ");
INSERT INTO grcmt_vpl VALUES ("J14_13","092_4_13","1JN","4","13","13","εν τουτω γινωσκομεν οτι εν αυτω μενομεν και αυτοσ εν ημιν οτι εκ του πνευματοσ αυτου δεδωκεν ημιν ");
INSERT INTO grcmt_vpl VALUES ("J14_14","092_4_14","1JN","4","14","14","και ημεισ τεθεαμεθα και μαρτυρουμεν οτι ο πατηρ απεσταλκεν τον υιον σωτηρα του κοσμου ");
INSERT INTO grcmt_vpl VALUES ("J14_15","092_4_15","1JN","4","15","15","οσ αν ομολογηση οτι ιησουσ εστιν ο υιοσ του θεου ο θεοσ εν αυτω μενει και αυτοσ εν τω θεω ");
INSERT INTO grcmt_vpl VALUES ("J14_16","092_4_16","1JN","4","16","16","και ημεισ εγνωκαμεν και πεπιστευκαμεν την αγαπην ην εχει ο θεοσ εν ημιν ο θεοσ αγαπη εστιν και ο μενων εν τη αγαπη εν τω θεω μενει και ο θεοσ εν αυτω μενει ");
INSERT INTO grcmt_vpl VALUES ("J14_17","092_4_17","1JN","4","17","17","εν τουτω τετελειωται η αγαπη μεθ ημων ινα παρρησιαν εχωμεν εν τη ημερα τησ κρισεωσ οτι καθωσ εκεινοσ εστιν και ημεισ εσμεν εν τω κοσμω τουτω ");
INSERT INTO grcmt_vpl VALUES ("J14_18","092_4_18","1JN","4","18","18","φοβοσ ουκ εστιν εν τη αγαπη αλλ η τελεια αγαπη εξω βαλλει τον φοβον οτι ο φοβοσ κολασιν εχει ο δε φοβουμενοσ ου τετελειωται εν τη αγαπη ");
INSERT INTO grcmt_vpl VALUES ("J14_19","092_4_19","1JN","4","19","19","ημεισ αγαπωμεν αυτον οτι αυτοσ πρωτοσ ηγαπησεν ημασ ");
INSERT INTO grcmt_vpl VALUES ("J14_20","092_4_20","1JN","4","20","20","εαν τισ ειπη οτι αγαπω τον θεον και τον αδελφον αυτου μιση ψευστησ εστιν ο γαρ μη αγαπων τον αδελφον αυτου ον εωρακεν τον θεον ον ουχ εωρακεν πωσ δυναται αγαπαν ");
INSERT INTO grcmt_vpl VALUES ("J14_21","092_4_21","1JN","4","21","21","και ταυτην την εντολην εχομεν απ αυτου ινα ο αγαπων τον θεον αγαπα και τον αδελφον αυτου ");
INSERT INTO grcmt_vpl VALUES ("J15_1","092_5_1","1JN","5","1","1","πασ ο πιστευων οτι ιησουσ εστιν ο χριστοσ εκ του θεου γεγεννηται και πασ ο αγαπων τον γεννησαντα αγαπα 25 V-PAI-3S και τον γεγεννημενον εξ αυτου ");
INSERT INTO grcmt_vpl VALUES ("J15_2","092_5_2","1JN","5","2","2","εν τουτω γινωσκομεν οτι αγαπωμεν τα τεκνα του θεου οταν τον θεον αγαπωμεν και τασ εντολασ αυτου τηρωμεν ");
INSERT INTO grcmt_vpl VALUES ("J15_3","092_5_3","1JN","5","3","3","αυτη γαρ εστιν η αγαπη του θεου ινα τασ εντολασ αυτου τηρωμεν και αι εντολαι αυτου βαρειαι ουκ εισιν ");
INSERT INTO grcmt_vpl VALUES ("J15_4","092_5_4","1JN","5","4","4","οτι παν το γεγεννημενον εκ του θεου νικα τον κοσμον και αυτη εστιν η νικη η νικησασα τον κοσμον η πιστισ ημων ");
INSERT INTO grcmt_vpl VALUES ("J15_5","092_5_5","1JN","5","5","5","τισ εστιν ο νικων τον κοσμον ει μη ο πιστευων οτι ιησουσ εστιν ο υιοσ του θεου ");
INSERT INTO grcmt_vpl VALUES ("J15_6","092_5_6","1JN","5","6","6","ουτοσ εστιν ο ελθων δι υδατοσ και αιματοσ ιησουσ χριστοσ ουκ εν τω υδατι μονον αλλ εν τω υδατι και τω αιματι και το πνευμα εστιν το μαρτυρουν οτι το πνευμα εστιν η αληθεια ");
INSERT INTO grcmt_vpl VALUES ("J15_7","092_5_7","1JN","5","7","7","οτι τρεισ εισιν οι μαρτυρουντεσ ");
INSERT INTO grcmt_vpl VALUES ("J15_8","092_5_8","1JN","5","8","8","το πνευμα και το υδωρ και το αιμα και οι τρεισ εισ το εν εισιν ");
INSERT INTO grcmt_vpl VALUES ("J15_9","092_5_9","1JN","5","9","9","ει την μαρτυριαν των ανθρωπων λαμβανομεν η μαρτυρια του θεου μειζων εστιν οτι αυτη εστιν η μαρτυρια του θεου ην μεμαρτυρηκεν περι του υιου αυτου ");
INSERT INTO grcmt_vpl VALUES ("J15_10","092_5_10","1JN","5","10","10","ο πιστευων εισ τον υιον του θεου εχει την μαρτυριαν εν αυτω ο μη πιστευων τω θεω ψευστην πεποιηκεν αυτον οτι ου πεπιστευκεν εισ την μαρτυριαν ην μεμαρτυρηκεν ο θεοσ περι του υιου αυτου ");
INSERT INTO grcmt_vpl VALUES ("J15_11","092_5_11","1JN","5","11","11","και αυτη εστιν η μαρτυρια οτι ζωην αιωνιον εδωκεν ημιν ο θεοσ και αυτη η ζωη εν τω υιω αυτου εστιν ");
INSERT INTO grcmt_vpl VALUES ("J15_12","092_5_12","1JN","5","12","12","ο εχων τον υιον εχει την ζωην ο μη εχων τον υιον του θεου την ζωην ουκ εχει ");
INSERT INTO grcmt_vpl VALUES ("J15_13","092_5_13","1JN","5","13","13","ταυτα εγραψα υμιν τοισ πιστευουσιν εισ το ονομα του υιου του θεου ινα ειδητε οτι ζωην αιωνιον εχετε και ινα πιστευητε εισ το ονομα του υιου του θεου ");
INSERT INTO grcmt_vpl VALUES ("J15_14","092_5_14","1JN","5","14","14","και αυτη εστιν η παρρησια ην εχομεν προσ αυτον οτι εαν τι αιτωμεθα κατα το θελημα αυτου ακουει ημων ");
INSERT INTO grcmt_vpl VALUES ("J15_15","092_5_15","1JN","5","15","15","και εαν οιδαμεν οτι ακουει ημων ο εαν αιτωμεθα οιδαμεν οτι εχομεν τα αιτηματα α ητηκαμεν παρ αυτου ");
INSERT INTO grcmt_vpl VALUES ("J15_16","092_5_16","1JN","5","16","16","εαν τισ ιδη τον αδελφον αυτου αμαρτανοντα αμαρτιαν μη προσ θανατον αιτησει και δωσει αυτω ζωην τοισ αμαρτανουσιν μη προσ θανατον εστιν αμαρτια προσ θανατον ου περι εκεινησ λεγω ινα ερωτηση ");
INSERT INTO grcmt_vpl VALUES ("J15_17","092_5_17","1JN","5","17","17","πασα αδικια αμαρτια εστιν και εστιν αμαρτια ου προσ θανατον ");
INSERT INTO grcmt_vpl VALUES ("J15_18","092_5_18","1JN","5","18","18","οιδαμεν οτι πασ ο γεγεννημενοσ εκ του θεου ουχ αμαρτανει αλλ ο γεννηθεισ εκ του θεου τηρει εαυτον και ο πονηροσ ουχ απτεται αυτου ");
INSERT INTO grcmt_vpl VALUES ("J15_19","092_5_19","1JN","5","19","19","οιδαμεν οτι εκ του θεου εσμεν και ο κοσμοσ ολοσ εν τω πονηρω κειται ");
INSERT INTO grcmt_vpl VALUES ("J15_20","092_5_20","1JN","5","20","20","οιδαμεν δε οτι ο υιοσ του θεου ηκει και δεδωκεν ημιν διανοιαν ινα γινωσκωμεν τον αληθινον και εσμεν εν τω αληθινω εν τω υιω αυτου ιησου χριστω ουτοσ εστιν ο αληθινοσ θεοσ και ζωη αιωνιοσ ");
INSERT INTO grcmt_vpl VALUES ("J15_21","092_5_21","1JN","5","21","21","τεκνια φυλαξατε εαυτα απο των ειδωλων αμην ");
INSERT INTO grcmt_vpl VALUES ("J21_1","093_1_1","2JN","1","1","1","ο πρεσβυτεροσ εκλεκτη κυρια και τοισ τεκνοισ αυτησ ουσ εγω αγαπω εν αληθεια και ουκ εγω μονοσ αλλα και παντεσ οι εγνωκοτεσ την αληθειαν ");
INSERT INTO grcmt_vpl VALUES ("J21_2","093_1_2","2JN","1","2","2","δια την αληθειαν την μενουσαν εν ημιν και μεθ ημων εσται εισ τον αιωνα ");
INSERT INTO grcmt_vpl VALUES ("J21_3","093_1_3","2JN","1","3","3","εσται μεθ ημων χαρισ ελεοσ ειρηνη παρα θεου πατροσ και παρα κυριου ιησου χριστου του υιου του πατροσ εν αληθεια και αγαπη ");
INSERT INTO grcmt_vpl VALUES ("J21_4","093_1_4","2JN","1","4","4","εχαρην λιαν οτι ευρηκα εκ των τεκνων σου περιπατουντασ εν αληθεια καθωσ εντολην ελαβομεν παρα του πατροσ ");
INSERT INTO grcmt_vpl VALUES ("J21_5","093_1_5","2JN","1","5","5","και νυν ερωτω σε κυρια ουχ ωσ εντολην γραφων σοι καινην αλλα ην ειχομεν απ αρχησ ινα αγαπωμεν αλληλουσ ");
INSERT INTO grcmt_vpl VALUES ("J21_6","093_1_6","2JN","1","6","6","και αυτη εστιν η αγαπη ινα περιπατωμεν κατα τασ εντολασ αυτου αυτη εστιν η εντολη καθωσ ηκουσατε απ αρχησ ινα εν αυτη περιπατητε ");
INSERT INTO grcmt_vpl VALUES ("J21_7","093_1_7","2JN","1","7","7","οτι πολλοι πλανοι εισηλθον εισ τον κοσμον οι μη ομολογουντεσ ιησουν χριστον ερχομενον εν σαρκι ουτοσ εστιν ο πλανοσ και ο αντιχριστοσ ");
INSERT INTO grcmt_vpl VALUES ("J21_8","093_1_8","2JN","1","8","8","βλεπετε εαυτουσ ινα μη απολεσωμεν α ειργασαμεθα αλλα μισθον πληρη απολαβωμεν ");
INSERT INTO grcmt_vpl VALUES ("J21_9","093_1_9","2JN","1","9","9","πασ ο παραβαινων και μη μενων εν τη διδαχη του χριστου θεον ουκ εχει ο μενων εν τη διδαχη του χριστου ουτοσ και τον πατερα και τον υιον εχει ");
INSERT INTO grcmt_vpl VALUES ("J21_10","093_1_10","2JN","1","10","10","ει τισ ερχεται προσ υμασ και ταυτην την διδαχην ου φερει μη λαμβανετε αυτον εισ οικιαν και χαιρειν αυτω μη λεγετε ");
INSERT INTO grcmt_vpl VALUES ("J21_11","093_1_11","2JN","1","11","11","ο γαρ λεγων αυτω χαιρειν κοινωνει τοισ εργοισ αυτου τοισ πονηροισ ");
INSERT INTO grcmt_vpl VALUES ("J21_12","093_1_12","2JN","1","12","12","πολλα εχων υμιν γραφειν ουκ εβουληθην δια χαρτου και μελανοσ αλλα ελπιζω ελθειν προσ υμασ και στομα προσ στομα λαλησαι ινα η χαρα ημων η πεπληρωμενη ");
INSERT INTO grcmt_vpl VALUES ("J21_13","093_1_13","2JN","1","13","13","ασπαζεται σε τα τεκνα τησ αδελφησ σου τησ εκλεκτησ αμην ");
INSERT INTO grcmt_vpl VALUES ("J31_1","094_1_1","3JN","1","1","1","ο πρεσβυτεροσ γαιω τω αγαπητω ον εγω αγαπω εν αληθεια ");
INSERT INTO grcmt_vpl VALUES ("J31_2","094_1_2","3JN","1","2","2","αγαπητε περι παντων ευχομαι σε ευοδουσθαι και υγιαινειν καθωσ ευοδουται σου η ψυχη ");
INSERT INTO grcmt_vpl VALUES ("J31_3","094_1_3","3JN","1","3","3","εχαρην γαρ λιαν ερχομενων αδελφων και μαρτυρουντων σου τη αληθεια καθωσ συ εν αληθεια περιπατεισ ");
INSERT INTO grcmt_vpl VALUES ("J31_4","094_1_4","3JN","1","4","4","μειζοτεραν τουτων ουκ εχω χαραν ινα ακουω τα εμα τεκνα εν αληθεια περιπατουντα ");
INSERT INTO grcmt_vpl VALUES ("J31_5","094_1_5","3JN","1","5","5","αγαπητε πιστον ποιεισ ο εαν εργαση εισ τουσ αδελφουσ και εισ τουσ ξενουσ ");
INSERT INTO grcmt_vpl VALUES ("J31_6","094_1_6","3JN","1","6","6","οι εμαρτυρησαν σου τη αγαπη ενωπιον εκκλησιασ ουσ καλωσ ποιησεισ προπεμψασ αξιωσ του θεου ");
INSERT INTO grcmt_vpl VALUES ("J31_7","094_1_7","3JN","1","7","7","υπερ γαρ του ονοματοσ εξηλθον μηδεν λαμβανοντεσ απο των εθνων ");
INSERT INTO grcmt_vpl VALUES ("J31_8","094_1_8","3JN","1","8","8","ημεισ ουν οφειλομεν απολαμβανειν τουσ τοιουτουσ ινα συνεργοι γινωμεθα τη αληθεια ");
INSERT INTO grcmt_vpl VALUES ("J31_9","094_1_9","3JN","1","9","9","εγραψα τη εκκλησια αλλ ο φιλοπρωτευων αυτων διοτρεφησ ουκ επιδεχεται ημασ ");
INSERT INTO grcmt_vpl VALUES ("J31_10","094_1_10","3JN","1","10","10","δια τουτο εαν ελθω υπομνησω αυτου τα εργα α ποιει λογοισ πονηροισ φλυαρων ημασ και μη αρκουμενοσ επι τουτοισ ουτε αυτοσ επιδεχεται τουσ αδελφουσ και τουσ βουλομενουσ κωλυει και εκ τησ εκκλησιασ εκβαλλει ");
INSERT INTO grcmt_vpl VALUES ("J31_11","094_1_11","3JN","1","11","11","αγαπητε μη μιμου το κακον αλλα το αγαθον ο αγαθοποιων εκ του θεου εστιν ο κακοποιων ουχ εωρακεν τον θεον ");
INSERT INTO grcmt_vpl VALUES ("J31_12","094_1_12","3JN","1","12","12","δημητριω μεμαρτυρηται υπο παντων και υπ αυτησ τησ αληθειασ και ημεισ δε μαρτυρουμεν και οιδατε οτι η μαρτυρια ημων αληθησ εστιν ");
INSERT INTO grcmt_vpl VALUES ("J31_13","094_1_13","3JN","1","13","13","πολλα ειχον γραφειν αλλ ου θελω δια μελανοσ και καλαμου σοι γραψαι ");
INSERT INTO grcmt_vpl VALUES ("J31_14","094_1_14","3JN","1","14","14","ελπιζω δε ευθεωσ ιδειν σε και στομα προσ στομα λαλησομεν ειρηνη σοι ασπαζονται σε οι φιλοι ασπαζου τουσ φιλουσ κατ ονομα ");
INSERT INTO grcmt_vpl VALUES ("JD1_1","095_1_1","JUD","1","1","1","ιουδασ ιησου χριστου δουλοσ αδελφοσ δε ιακωβου τοισ εν θεω πατρι ηγιασμενοισ και ιησου χριστω τετηρημενοισ κλητοισ ");
INSERT INTO grcmt_vpl VALUES ("JD1_2","095_1_2","JUD","1","2","2","ελεοσ υμιν και ειρηνη και αγαπη πληθυνθειη ");
INSERT INTO grcmt_vpl VALUES ("JD1_3","095_1_3","JUD","1","3","3","αγαπητοι πασαν σπουδην ποιουμενοσ γραφειν υμιν περι τησ κοινησ σωτηριασ αναγκην εσχον γραψαι υμιν παρακαλων επαγωνιζεσθαι τη απαξ παραδοθειση τοισ αγιοισ πιστει ");
INSERT INTO grcmt_vpl VALUES ("JD1_4","095_1_4","JUD","1","4","4","παρεισεδυσαν γαρ τινεσ ανθρωποι οι παλαι προγεγραμμενοι εισ τουτο το κριμα ασεβεισ την του θεου ημων χαριν μετατιθεντεσ εισ ασελγειαν και τον μονον δεσποτην θεον και κυριον ημων ιησουν χριστον αρνουμενοι ");
INSERT INTO grcmt_vpl VALUES ("JD1_5","095_1_5","JUD","1","5","5","υπομνησαι δε υμασ βουλομαι ειδοτασ υμασ απαξ τουτο οτι ο κυριοσ λαον εκ γησ αιγυπτου σωσασ το δευτερον τουσ μη πιστευσαντασ απωλεσεν ");
INSERT INTO grcmt_vpl VALUES ("JD1_6","095_1_6","JUD","1","6","6","αγγελουσ τε τουσ μη τηρησαντασ την εαυτων αρχην αλλα απολιποντασ το ιδιον οικητηριον εισ κρισιν μεγαλησ ημερασ δεσμοισ αιδιοισ υπο ζοφον τετηρηκεν ");
INSERT INTO grcmt_vpl VALUES ("JD1_7","095_1_7","JUD","1","7","7","ωσ σοδομα και γομορρα και αι περι αυτασ πολεισ τον ομοιον τουτοισ τροπον εκπορνευσασαι και απελθουσαι οπισω σαρκοσ ετερασ προκεινται δειγμα πυροσ αιωνιου δικην υπεχουσαι ");
INSERT INTO grcmt_vpl VALUES ("JD1_8","095_1_8","JUD","1","8","8","ομοιωσ μεντοι και ουτοι ενυπνιαζομενοι σαρκα μεν μιαινουσιν κυριοτητα δε αθετουσιν δοξασ δε βλασφημουσιν ");
INSERT INTO grcmt_vpl VALUES ("JD1_9","095_1_9","JUD","1","9","9","ο δε μιχαηλ ο αρχαγγελοσ οτε τω διαβολω διακρινομενοσ διελεγετο περι του μωυσεωσ σωματοσ ουκ ετολμησεν κρισιν επενεγκειν βλασφημιασ αλλ ειπεν επιτιμησαι σοι κυριοσ ");
INSERT INTO grcmt_vpl VALUES ("JD1_10","095_1_10","JUD","1","10","10","ουτοι δε οσα μεν ουκ οιδασιν βλασφημουσιν οσα δε φυσικωσ ωσ τα αλογα ζωα επιστανται εν τουτοισ φθειρονται ");
INSERT INTO grcmt_vpl VALUES ("JD1_11","095_1_11","JUD","1","11","11","ουαι αυτοισ οτι τη οδω του καιν επορευθησαν και τη πλανη του βαλααμ μισθου εξεχυθησαν και τη αντιλογια του κορε απωλοντο ");
INSERT INTO grcmt_vpl VALUES ("JD1_12","095_1_12","JUD","1","12","12","ουτοι εισιν εν ταισ αγαπαισ υμων σπιλαδεσ συνευωχουμενοι αφοβωσ εαυτουσ ποιμαινοντεσ νεφελαι ανυδροι υπο ανεμων παραφερομεναι δενδρα φθινοπωρινα ακαρπα δισ αποθανοντα εκριζωθεντα ");
INSERT INTO grcmt_vpl VALUES ("JD1_13","095_1_13","JUD","1","13","13","κυματα αγρια θαλασσησ επαφριζοντα τασ εαυτων αισχυνασ αστερεσ πλανηται οισ ο ζοφοσ του σκοτουσ εισ αιωνα τετηρηται ");
INSERT INTO grcmt_vpl VALUES ("JD1_14","095_1_14","JUD","1","14","14","προεφητευσεν δε και τουτοισ εβδομοσ απο αδαμ ενωχ λεγων ιδου ηλθεν κυριοσ εν αγιαισ μυριασιν αυτου ");
INSERT INTO grcmt_vpl VALUES ("JD1_15","095_1_15","JUD","1","15","15","ποιησαι κρισιν κατα παντων και ελεγξαι παντασ τουσ ασεβεισ αυτων περι παντων των εργων ασεβειασ αυτων ων ησεβησαν και περι παντων των σκληρων ων ελαλησαν κατ αυτου αμαρτωλοι ασεβεισ ");
INSERT INTO grcmt_vpl VALUES ("JD1_16","095_1_16","JUD","1","16","16","ουτοι εισιν γογγυσται μεμψιμοιροι κατα τασ επιθυμιασ αυτων πορευομενοι και το στομα αυτων λαλει υπερογκα θαυμαζοντεσ προσωπα ωφελειασ χαριν ");
INSERT INTO grcmt_vpl VALUES ("JD1_17","095_1_17","JUD","1","17","17","υμεισ δε αγαπητοι μνησθητε των ρηματων των προειρημενων υπο των αποστολων του κυριου ημων ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("JD1_18","095_1_18","JUD","1","18","18","οτι ελεγον υμιν οτι εν εσχατω χρονω εσονται εμπαικται κατα τασ εαυτων επιθυμιασ πορευομενοι των ασεβειων ");
INSERT INTO grcmt_vpl VALUES ("JD1_19","095_1_19","JUD","1","19","19","ουτοι εισιν οι αποδιοριζοντεσ ψυχικοι πνευμα μη εχοντεσ ");
INSERT INTO grcmt_vpl VALUES ("JD1_20","095_1_20","JUD","1","20","20","υμεισ δε αγαπητοι τη αγιωτατη υμων πιστει εποικοδομουντεσ εαυτουσ εν πνευματι αγιω προσευχομενοι ");
INSERT INTO grcmt_vpl VALUES ("JD1_21","095_1_21","JUD","1","21","21","εαυτουσ εν αγαπη θεου τηρησατε προσδεχομενοι το ελεοσ του κυριου ημων ιησου χριστου εισ ζωην αιωνιον ");
INSERT INTO grcmt_vpl VALUES ("JD1_22","095_1_22","JUD","1","22","22","και ουσ μεν ελεειτε διακρινομενοι ");
INSERT INTO grcmt_vpl VALUES ("JD1_23","095_1_23","JUD","1","23","23","ουσ δε εν φοβω σωζετε εκ πυροσ αρπαζοντεσ μισουντεσ και τον απο τησ σαρκοσ εσπιλωμενον χιτωνα ");
INSERT INTO grcmt_vpl VALUES ("JD1_24","095_1_24","JUD","1","24","24","τω δε δυναμενω φυλαξαι αυτουσ απταιστουσ και στησαι κατενωπιον τησ δοξησ αυτου αμωμουσ εν αγαλλιασει ");
INSERT INTO grcmt_vpl VALUES ("JD1_25","095_1_25","JUD","1","25","25","μονω σοφω θεω σωτηρι ημων δοξα και μεγαλωσυνη κρατοσ και εξουσια και νυν και εισ παντασ τουσ αιωνασ αμην ");
INSERT INTO grcmt_vpl VALUES ("RV1_1","096_1_1","REV","1","1","1","αποκαλυψισ ιησου χριστου ην εδωκεν αυτω ο θεοσ δειξαι τοισ δουλοισ αυτου α δει γενεσθαι εν ταχει και εσημανεν αποστειλασ δια του αγγελου αυτου τω δουλω αυτου ιωαννη ");
INSERT INTO grcmt_vpl VALUES ("RV1_2","096_1_2","REV","1","2","2","οσ εμαρτυρησεν τον λογον του θεου και την μαρτυριαν ιησου χριστου οσα ειδεν ");
INSERT INTO grcmt_vpl VALUES ("RV1_3","096_1_3","REV","1","3","3","μακαριοσ ο αναγινωσκων και οι ακουοντεσ τουσ λογουσ τησ προφητειασ και τηρουντεσ τα εν αυτη γεγραμμενα ο γαρ καιροσ εγγυσ ");
INSERT INTO grcmt_vpl VALUES ("RV1_4","096_1_4","REV","1","4","4","ιωαννησ ταισ επτα εκκλησιαισ ταισ εν τη ασια χαρισ υμιν και ειρηνη απο θεου ο ων και ο ην και ο ερχομενοσ και απο των επτα πνευματων α ενωπιον του θρονου αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV1_5","096_1_5","REV","1","5","5","και απο ιησου χριστου ο μαρτυσ ο πιστοσ ο πρωτοτοκοσ των νεκρων και ο αρχων των βασιλεων τησ γησ τω αγαπωντι ημασ και λουσαντι ημασ απο των αμαρτιων ημων εν τω αιματι αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV1_6","096_1_6","REV","1","6","6","και εποιησεν ημασ βασιλειαν ιερεισ τω θεω και πατρι αυτου αυτω η δοξα και το κρατοσ εισ τουσ αιωνασ των αιωνων αμην ");
INSERT INTO grcmt_vpl VALUES ("RV1_7","096_1_7","REV","1","7","7","ιδου ερχεται μετα των νεφελων και οψεται αυτον πασ οφθαλμοσ και οιτινεσ αυτον εξεκεντησαν και κοψονται επ αυτον πασαι αι φυλαι τησ γησ ναι αμην ");
INSERT INTO grcmt_vpl VALUES ("RV1_8","096_1_8","REV","1","8","8","εγω ειμι το αλφα και το ω λεγει κυριοσ ο θεοσ ο ων και ο ην και ο ερχομενοσ ο παντοκρατωρ ");
INSERT INTO grcmt_vpl VALUES ("RV1_9","096_1_9","REV","1","9","9","εγω ιωαννησ ο αδελφοσ υμων και κοινωνοσ εν τη θλιψει και βασιλεια και υπομονη εν χριστω ιησου εγενομην εν τη νησω τη καλουμενη πατμω δια τον λογον του θεου και δια την μαρτυριαν ιησου χριστου ");
INSERT INTO grcmt_vpl VALUES ("RV1_10","096_1_10","REV","1","10","10","εγενομην εν πνευματι εν τη κυριακη ημερα και ηκουσα φωνην οπισω μου μεγαλην ωσ σαλπιγγοσ ");
INSERT INTO grcmt_vpl VALUES ("RV1_11","096_1_11","REV","1","11","11","λεγουσησ ο βλεπεισ γραψον εισ βιβλιον και πεμψον ταισ επτα εκκλησιαισ εισ εφεσον και εισ σμυρναν και εισ περγαμον και εισ θυατειρα και εισ σαρδεισ και εισ φιλαδελφειαν και εισ λαοδικειαν ");
INSERT INTO grcmt_vpl VALUES ("RV1_12","096_1_12","REV","1","12","12","και εκει επεστρεψα βλεπειν την φωνην ητισ ελαλει μετ εμου και επιστρεψασ ειδον επτα λυχνιασ χρυσασ ");
INSERT INTO grcmt_vpl VALUES ("RV1_13","096_1_13","REV","1","13","13","και εν μεσω των επτα λυχνιων ομοιον υιω ανθρωπου ενδεδυμενον ποδηρη και περιεζωσμενον προσ τοισ μαστοισ ζωνην χρυσην ");
INSERT INTO grcmt_vpl VALUES ("RV1_14","096_1_14","REV","1","14","14","η δε κεφαλη αυτου και αι τριχεσ λευκαι ωσ εριον λευκον ωσ χιων και οι οφθαλμοι αυτου ωσ φλοξ πυροσ ");
INSERT INTO grcmt_vpl VALUES ("RV1_15","096_1_15","REV","1","15","15","και οι ποδεσ αυτου ομοιοι χαλκολιβανω ωσ εν καμινω πεπυρωμενοι και η φωνη αυτου ωσ φωνη υδατων πολλων ");
INSERT INTO grcmt_vpl VALUES ("RV1_16","096_1_16","REV","1","16","16","και εχων εν τη δεξια αυτου χειρι αστερασ επτα και εκ του στοματοσ αυτου ρομφαια διστομοσ οξεια εκπορευομενη και η οψισ αυτου ωσ ο ηλιοσ φαινει εν τη δυναμει αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV1_17","096_1_17","REV","1","17","17","και οτε ειδον αυτον επεσα προσ τουσ ποδασ αυτου ωσ νεκροσ και εθηκεν την δεξιαν αυτου επ εμε λεγων μη φοβου εγω ειμι ο πρωτοσ και ο εσχατοσ ");
INSERT INTO grcmt_vpl VALUES ("RV1_18","096_1_18","REV","1","18","18","και ο ζων και εγενομην νεκροσ και ιδου ζων ειμι εισ τουσ αιωνασ των αιωνων αμην και εχω τασ κλεισ του θανατου και του αδου ");
INSERT INTO grcmt_vpl VALUES ("RV1_19","096_1_19","REV","1","19","19","γραψον ουν α ειδεσ και α εισιν και α μελλει γινεσθαι μετα ταυτα ");
INSERT INTO grcmt_vpl VALUES ("RV1_20","096_1_20","REV","1","20","20","το μυστηριον των επτα αστερων ων ειδεσ επι τησ δεξιασ μου και τασ επτα λυχνιασ τασ χρυσασ οι επτα αστερεσ αγγελοι των επτα εκκλησιων εισιν και αι λυχνιαι αι επτα επτα εκκλησιαι εισιν ");
INSERT INTO grcmt_vpl VALUES ("RV2_1","096_2_1","REV","2","1","1","τω αγγελω τησ εν εφεσω εκκλησιασ γραψον ταδε λεγει ο κρατων τουσ επτα αστερασ εν τη δεξια αυτου ο περιπατων εν μεσω των επτα λυχνιων των χρυσων ");
INSERT INTO grcmt_vpl VALUES ("RV2_2","096_2_2","REV","2","2","2","οιδα τα εργα σου και τον κοπον σου και την υπομονην σου και οτι ου δυνη βαστασαι κακουσ και επειρασασ τουσ λεγοντασ εαυτουσ αποστολουσ ειναι και ουκ εισιν και ευρεσ αυτουσ ψευδεισ ");
INSERT INTO grcmt_vpl VALUES ("RV2_3","096_2_3","REV","2","3","3","και υπομονην εχεισ και εβαστασασ δια το ονομα μου και ουκ εκοπιασασ ");
INSERT INTO grcmt_vpl VALUES ("RV2_4","096_2_4","REV","2","4","4","αλλα εχω κατα σου οτι την αγαπην σου την πρωτην αφηκασ ");
INSERT INTO grcmt_vpl VALUES ("RV2_5","096_2_5","REV","2","5","5","μνημονευε ουν ποθεν πεπτωκασ και μετανοησον και τα πρωτα εργα ποιησον ει δε μη ερχομαι σοι ταχυ και κινησω την λυχνιαν σου εκ του τοπου αυτησ εαν μη μετανοησησ ");
INSERT INTO grcmt_vpl VALUES ("RV2_6","096_2_6","REV","2","6","6","αλλα τουτο εχεισ οτι μισεισ τα εργα των νικολαιτων α καγω μισω ");
INSERT INTO grcmt_vpl VALUES ("RV2_7","096_2_7","REV","2","7","7","ο εχων ουσ ακουσατω τι το πνευμα λεγει ταισ εκκλησιαισ τω νικωντι δωσω αυτω φαγειν εκ του ξυλου τησ ζωησ ο εστιν εν τω παραδεισω του θεου μου ");
INSERT INTO grcmt_vpl VALUES ("RV2_8","096_2_8","REV","2","8","8","και τω αγγελω τησ εν σμυρνη εκκλησιασ γραψον ταδε λεγει ο πρωτοσ και ο εσχατοσ οσ εγενετο νεκροσ και εζησεν ");
INSERT INTO grcmt_vpl VALUES ("RV2_9","096_2_9","REV","2","9","9","οιδα σου τα εργα και την θλιψιν και την πτωχειαν αλλα πλουσιοσ ει και την βλασφημιαν εκ των λεγοντων ιουδαιουσ ειναι εαυτουσ και ουκ εισιν αλλα συναγωγη του σατανα ");
INSERT INTO grcmt_vpl VALUES ("RV2_10","096_2_10","REV","2","10","10","μηδεν φοβου α μελλεισ παθειν ιδου δη μελλει βαλειν ο διαβολοσ εξ υμων εισ φυλακην ινα πειρασθητε και εξετε θλιψιν ημερων δεκα γινου πιστοσ αχρι θανατου και δωσω σοι τον στεφανον τησ ζωησ ");
INSERT INTO grcmt_vpl VALUES ("RV2_11","096_2_11","REV","2","11","11","ο εχων ουσ ακουσατω τι το πνευμα λεγει ταισ εκκλησιαισ ο νικων ου μη αδικηθη εκ του θανατου του δευτερου ");
INSERT INTO grcmt_vpl VALUES ("RV2_12","096_2_12","REV","2","12","12","και τω αγγελω τησ εν περγαμω εκκλησιασ γραψον ταδε λεγει ο εχων την ρομφαιαν την διστομον την οξειαν ");
INSERT INTO grcmt_vpl VALUES ("RV2_13","096_2_13","REV","2","13","13","οιδα τα εργα σου και που κατοικεισ οπου ο θρονοσ του σατανα και κρατεισ το ονομα μου και ουκ ηρνησω την πιστιν μου εν ταισ ημεραισ εν αισ αντιπασ ο μαρτυσ μου ο πιστοσ οσ απεκτανθη παρ υμιν οπου ο σατανασ κατοικει ");
INSERT INTO grcmt_vpl VALUES ("RV2_14","096_2_14","REV","2","14","14","αλλ εχω κατα σου ολιγα οτι εχεισ εκει κρατουντασ την διδαχην βαλααμ οσ εδιδαξεν τον βαλακ βαλειν σκανδαλον ενωπιον των υιων ισραηλ και φαγειν ειδωλοθυτα και πορνευσαι ");
