INSERT INTO grcmt_vpl VALUES ("RV2_16","096_2_16","REV","2","16","16","μετανοησον ουν ει δε μη ερχομαι σοι ταχυ και πολεμησω μετ αυτων εν τη ρομφαια του στοματοσ μου ");
INSERT INTO grcmt_vpl VALUES ("RV2_17","096_2_17","REV","2","17","17","ο εχων ουσ ακουσατω τι το πνευμα λεγει ταισ εκκλησιαισ τω νικωντι δωσω αυτω του μαννα του κεκρυμμενου και δωσω αυτω ψηφον λευκην και επι την ψηφον ονομα καινον γεγραμμενον ο ουδεισ οιδεν ει μη ο λαμβανων ");
INSERT INTO grcmt_vpl VALUES ("RV2_18","096_2_18","REV","2","18","18","και τω αγγελω τησ εν θυατειροισ εκκλησιασ γραψον ταδε λεγει ο υιοσ του θεου ο εχων τουσ οφθαλμουσ αυτου ωσ φλογα πυροσ και οι ποδεσ αυτου ομοιοι χαλκολιβανω ");
INSERT INTO grcmt_vpl VALUES ("RV2_19","096_2_19","REV","2","19","19","οιδα σου τα εργα και την αγαπην και την πιστιν και την διακονιαν και την υπομονην σου και τα εργα σου τα εσχατα πλειονα των πρωτων ");
INSERT INTO grcmt_vpl VALUES ("RV2_20","096_2_20","REV","2","20","20","αλλ εχω κατα σου οτι αφεισ την γυναικα σου ιεζαβελ η λεγει εαυτην προφητιν και διδασκει και πλανα τουσ εμουσ δουλουσ πορνευσαι και φαγειν ειδωλοθυτα ");
