INSERT INTO grcmt_vpl VALUES ("RV2_22","096_2_22","REV","2","22","22","ιδου βαλλω αυτην εισ κλινην και τουσ μοιχευοντασ μετ αυτησ εισ θλιψιν μεγαλην εαν μη μετανοησωσιν εκ των εργων αυτησ ");
