INSERT INTO grcmt_vpl VALUES ("RV2_29","096_2_29","REV","2","29","29","ο εχων ουσ ακουσατω τι το πνευμα λεγει ταισ εκκλησιαισ ");
INSERT INTO grcmt_vpl VALUES ("RV3_1","096_3_1","REV","3","1","1","και τω αγγελω τησ εν σαρδεσιν εκκλησιασ γραψον ταδε λεγει ο εχων τα επτα πνευματα του θεου και τουσ επτα αστερασ οιδα σου τα εργα οτι ονομα εχεισ οτι ζησ και νεκροσ ει ");
