INSERT INTO grcmt_vpl VALUES ("RV3_4","096_3_4","REV","3","4","4","αλλ ολιγα εχεισ ονοματα εν σαρδεσιν α ουκ εμολυναν τα ιματια αυτων και περιπατησουσιν μετ εμου εν λευκοισ οτι αξιοι εισιν ");
INSERT INTO grcmt_vpl VALUES ("RV3_5","096_3_5","REV","3","5","5","ο νικων ουτοσ περιβαλειται εν ιματιοισ λευκοισ και ου μη εξαλειψω το ονομα αυτου εκ τησ βιβλου τησ ζωησ και ομολογησω το ονομα αυτου ενωπιον του πατροσ μου και ενωπιον των αγγελων αυτου ");
