INSERT INTO grcmt_vpl VALUES ("RV3_7","096_3_7","REV","3","7","7","και τω αγγελω τησ εν φιλαδελφεια εκκλησιασ γραψον ταδε λεγει ο αγιοσ ο αληθινοσ ο εχων την κλειν του δαυιδ ο ανοιγων και ουδεισ κλεισει αυτην ει μη ο ανοιγων και ουδεισ ανοιξει ");
INSERT INTO grcmt_vpl VALUES ("RV3_8","096_3_8","REV","3","8","8","οιδα σου τα εργα ιδου δεδωκα ενωπιον σου θυραν ανεωγμενην ην ουδεισ δυναται κλεισαι αυτην οτι μικραν εχεισ δυναμιν και ετηρησασ μου τον λογον και ουκ ηρνησω το ονομα μου ");
INSERT INTO grcmt_vpl VALUES ("RV3_9","096_3_9","REV","3","9","9","ιδου διδωμι εκ τησ συναγωγησ του σατανα των λεγοντων εαυτουσ ιουδαιουσ ειναι και ουκ εισιν αλλα ψευδονται ιδου ποιησω αυτουσ ινα ηξωσιν και προσκυνησωσιν ενωπιον των ποδων σου και γνωσιν οτι ηγαπησα σε ");
INSERT INTO grcmt_vpl VALUES ("RV3_10","096_3_10","REV","3","10","10","οτι ετηρησασ τον λογον τησ υπομονησ μου καγω σε τηρησω εκ τησ ωρασ του πειρασμου τησ μελλουσησ ερχεσθαι επι τησ οικουμενησ ολησ πειρασαι τουσ κατοικουντασ επι τησ γησ ");
INSERT INTO grcmt_vpl VALUES ("RV3_11","096_3_11","REV","3","11","11","ερχομαι ταχυ κρατει ο εχεισ ινα μηδεισ λαβη τον στεφανον σου ");
