INSERT INTO grcmt_vpl VALUES ("RV3_13","096_3_13","REV","3","13","13","ο εχων ουσ ακουσατω τι το πνευμα λεγει ταισ εκκλησιαισ ");
INSERT INTO grcmt_vpl VALUES ("RV3_14","096_3_14","REV","3","14","14","και τω αγγελω τησ εν λαοδικεια εκκλησιασ γραψον ταδε λεγει ο αμην ο μαρτυσ ο πιστοσ και αληθινοσ η αρχη τησ κτισεωσ του θεου ");
INSERT INTO grcmt_vpl VALUES ("RV3_15","096_3_15","REV","3","15","15","οιδα σου τα εργα οτι ουτε ψυχροσ ει ουτε ζεστοσ οφελον ψυχροσ ησ η ζεστοσ ");
