INSERT INTO grcmt_vpl VALUES ("RV3_17","096_3_17","REV","3","17","17","οτι λεγεισ πλουσιοσ ειμι και πεπλουτηκα και ουδενοσ 3762 A-GSN-N χρειαν εχω και ουκ οιδασ οτι συ ει ο ταλαιπωροσ και ο ελεεινοσ και πτωχοσ και τυφλοσ και γυμνοσ ");
INSERT INTO grcmt_vpl VALUES ("RV3_18","096_3_18","REV","3","18","18","συμβουλευω σοι αγορασαι χρυσιον παρ εμου πεπυρωμενον εκ πυροσ ινα πλουτησησ και ιματια λευκα ινα περιβαλη και μη φανερωθη η αισχυνη τησ γυμνοτητοσ σου και κολλυριον ινα εγχριση τουσ οφθαλμουσ σου ινα βλεπησ ");
INSERT INTO grcmt_vpl VALUES ("RV3_19","096_3_19","REV","3","19","19","εγω οσουσ εαν φιλω ελεγχω και παιδευω ζηλωσον ουν και μετανοησον ");
INSERT INTO grcmt_vpl VALUES ("RV3_20","096_3_20","REV","3","20","20","ιδου εστηκα επι την θυραν και κρουω εαν τισ ακουση τησ φωνησ μου και ανοιξη την θυραν και εισελευσομαι προσ αυτον και δειπνησω μετ αυτου και αυτοσ μετ εμου ");
INSERT INTO grcmt_vpl VALUES ("RV3_21","096_3_21","REV","3","21","21","ο νικων δωσω αυτω καθισαι μετ εμου εν τω θρονω μου ωσ καγω ενικησα και εκαθισα μετα του πατροσ μου εν τω θρονω αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV3_22","096_3_22","REV","3","22","22","ο εχων ουσ ακουσατω τι το πνευμα λεγει ταισ εκκλησιαισ ");
INSERT INTO grcmt_vpl VALUES ("RV4_1","096_4_1","REV","4","1","1","μετα ταυτα ειδον και ιδου θυρα ανεωγμενη εν τω ουρανω και η φωνη η πρωτη ην ηκουσα ωσ σαλπιγγοσ λαλουσησ μετ εμου λεγων αναβα ωδε και δειξω σοι α δει γενεσθαι μετα ταυτα ");
