INSERT INTO grcmt_vpl VALUES ("RV4_3","096_4_3","REV","4","3","3","ομοιοσ ορασει λιθω ιασπιδι και σαρδιω και ιρισ κυκλοθεν του θρονου ομοιωσ ορασισ σμαραγδινων ");
INSERT INTO grcmt_vpl VALUES ("RV4_4","096_4_4","REV","4","4","4","και κυκλοθεν του θρονου θρονοι εικοσι τεσσαρεσ και επι τουσ θρονουσ τουσ εικοσι τεσσαρασ πρεσβυτερουσ καθημενουσ περιβεβλημενουσ εν ιματιοισ λευκοισ και επι τασ κεφαλασ αυτων στεφανουσ χρυσουσ ");
INSERT INTO grcmt_vpl VALUES ("RV4_5","096_4_5","REV","4","5","5","και εκ του θρονου εκπορευονται αστραπαι και φωναι και βρονται και επτα λαμπαδεσ πυροσ καιομεναι ενωπιον του θρονου αυτου αι εισιν επτα πνευματα του θεου ");
INSERT INTO grcmt_vpl VALUES ("RV4_6","096_4_6","REV","4","6","6","και ενωπιον του θρονου ωσ θαλασσα υαλινη ομοια κρυσταλλω και εν μεσω του θρονου και κυκλω του θρονου τεσσαρα ζωα γεμοντα οφθαλμων εμπροσθεν και οπισθεν ");
INSERT INTO grcmt_vpl VALUES ("RV4_7","096_4_7","REV","4","7","7","και το ζωον το πρωτον ομοιον λεοντι και το δευτερον ζωον ομοιον μοσχω και το τριτον ζωον εχον προσωπον ανθρωπου και το τεταρτον ζωον ομοιον αετω πετομενω ");
INSERT INTO grcmt_vpl VALUES ("RV4_8","096_4_8","REV","4","8","8","και τα τεσσαρα ζωα εν καθ εν εχον ανα πτερυγασ εξ κυκλοθεν και εσωθεν γεμουσιν οφθαλμων και αναπαυσιν ουκ εχουσιν ημερασ και νυκτοσ λεγοντεσ αγιοσ αγιοσ αγιοσ κυριοσ ο θεοσ ο παντοκρατωρ ο ην και ο ων και ο ερχομενοσ ");
INSERT INTO grcmt_vpl VALUES ("RV4_9","096_4_9","REV","4","9","9","και οταν δωσιν τα ζωα δοξαν και τιμην και ευχαριστιαν τω καθημενω επι του θρονου τω ζωντι εισ τουσ αιωνασ των αιωνων ");
INSERT INTO grcmt_vpl VALUES ("RV4_10","096_4_10","REV","4","10","10","πεσουνται οι εικοσι τεσσαρεσ πρεσβυτεροι ενωπιον του καθημενου επι του θρονου και προσκυνησουσιν τω ζωντι εισ τουσ αιωνασ των αιωνων και βαλουσιν τουσ στεφανουσ αυτων ενωπιον του θρονου λεγοντεσ ");
INSERT INTO grcmt_vpl VALUES ("RV4_11","096_4_11","REV","4","11","11","αξιοσ ει ο κυριοσ και ο θεοσ ημων ο αγιοσ λαβειν την δοξαν και την τιμην και την δυναμιν οτι συ εκτισασ παντα και δια το θελημα σου ησαν και εκτισθησαν ");
INSERT INTO grcmt_vpl VALUES ("RV5_1","096_5_1","REV","5","1","1","και ειδον επι την δεξιαν του καθημενου επι του θρονου βιβλιον γεγραμμενον εσωθεν και εξωθεν κατεσφραγισμενον σφραγισιν επτα ");
INSERT INTO grcmt_vpl VALUES ("RV5_2","096_5_2","REV","5","2","2","και ειδον αγγελον ισχυρον κηρυσσοντα εν φωνη μεγαλη τισ αξιοσ εστιν ανοιξαι το βιβλιον και λυσαι τασ σφραγιδασ αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV5_3","096_5_3","REV","5","3","3","και ουδεισ εδυνατο εν τω ουρανω ανω ουτε επι τησ γησ ουτε υποκατω τησ γησ ανοιξαι το βιβλιον ουτε βλεπειν αυτο ");
INSERT INTO grcmt_vpl VALUES ("RV5_4","096_5_4","REV","5","4","4","και εγω εκλαιον πολυ οτι ουδεισ αξιοσ ευρεθη ανοιξαι το βιβλιον ουτε βλεπειν αυτο ");
INSERT INTO grcmt_vpl VALUES ("RV5_5","096_5_5","REV","5","5","5","και εισ εκ των πρεσβυτερων λεγει μοι μη κλαιε ιδου ενικησεν ο λεων ο εκ τησ φυλησ ιουδα η ριζα δαυιδ ο ανοιγων το βιβλιον και τασ επτα σφραγιδασ αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV5_6","096_5_6","REV","5","6","6","και ειδον εν μεσω του θρονου και των τεσσαρων ζωων και εν μεσω των πρεσβυτερων αρνιον εστηκοσ ωσ εσφαγμενον εχον κερατα επτα και οφθαλμουσ επτα α εισιν τα επτα πνευματα του θεου αποστελλομενα εισ πασαν την γην ");
INSERT INTO grcmt_vpl VALUES ("RV5_7","096_5_7","REV","5","7","7","και ηλθεν και ειληφεν εκ τησ δεξιασ του καθημενου επι του θρονου ");
INSERT INTO grcmt_vpl VALUES ("RV5_8","096_5_8","REV","5","8","8","και οτε ελαβεν το βιβλιον τα τεσσαρα ζωα και οι εικοσι τεσσαρεσ πρεσβυτεροι επεσον ενωπιον του αρνιου εχοντεσ εκαστοσ κιθαραν και φιαλασ χρυσασ γεμουσασ θυμιαματων αι εισιν προσευχαι των αγιων ");
INSERT INTO grcmt_vpl VALUES ("RV5_9","096_5_9","REV","5","9","9","και αδουσιν ωδην καινην λεγοντεσ αξιοσ ει λαβειν το βιβλιον και ανοιξαι τασ σφραγιδασ αυτου οτι εσφαγησ και ηγορασασ τω θεω ημασ εν τω αιματι σου εκ πασησ φυλησ και γλωσσησ και λαου και εθνουσ ");
INSERT INTO grcmt_vpl VALUES ("RV5_10","096_5_10","REV","5","10","10","και εποιησασ αυτουσ τω θεω ημων βασιλεισ και ιερεισ και βασιλευσουσιν επι τησ γησ ");
INSERT INTO grcmt_vpl VALUES ("RV5_11","096_5_11","REV","5","11","11","και ειδον και ηκουσα ωσ φωνην αγγελων πολλων κυκλω του θρονου και των ζωων και των πρεσβυτερων και ην ο αριθμοσ αυτων μυριαδεσ μυριαδων και χιλιαδεσ χιλιαδων ");
INSERT INTO grcmt_vpl VALUES ("RV5_12","096_5_12","REV","5","12","12","λεγοντεσ φωνη μεγαλη αξιον εστιν το αρνιον το εσφαγμενον λαβειν την δυναμιν και τον πλουτον και σοφιαν και ισχυν και τιμην και δοξαν και ευλογιαν ");
INSERT INTO grcmt_vpl VALUES ("RV5_13","096_5_13","REV","5","13","13","και παν κτισμα ο εν τω ουρανω και επι τησ γησ και υποκατω τησ γησ και επι τησ θαλασσησ εστιν και τα εν αυτοισ παντασ ηκουσα λεγοντασ τω καθημενω επι του θρονου και τω αρνιω η ευλογια και η τιμη και η δοξα και το κρατοσ εισ τουσ αιωνασ των αιωνων αμην ");
INSERT INTO grcmt_vpl VALUES ("RV5_14","096_5_14","REV","5","14","14","και τα τεσσαρα ζωα λεγοντα το αμην και οι πρεσβυτεροι επεσον και προσεκυνησαν ");
INSERT INTO grcmt_vpl VALUES ("RV6_1","096_6_1","REV","6","1","1","και ειδον οτι ηνοιξεν το αρνιον μιαν εκ των επτα σφραγιδων και ηκουσα ενοσ εκ των τεσσαρων ζωων λεγοντοσ ωσ φωνη βροντησ ερχου και ιδε ");
INSERT INTO grcmt_vpl VALUES ("RV6_2","096_6_2","REV","6","2","2","και ιδου ιπποσ λευκοσ και ο καθημενοσ επ αυτον εχων τοξον και εδοθη αυτω στεφανοσ και εξηλθεν νικων και ινα νικηση ");
INSERT INTO grcmt_vpl VALUES ("RV6_3","096_6_3","REV","6","3","3","και οτε ηνοιξεν την δευτεραν σφραγιδα ηκουσα του δευτερου ζωου λεγοντοσ ερχου ");
INSERT INTO grcmt_vpl VALUES ("RV6_4","096_6_4","REV","6","4","4","και εξηλθεν αλλοσ ιπποσ πυροσ και τω καθημενω επ αυτον εδοθη αυτω λαβειν την ειρηνην εκ τησ γησ ινα αλληλουσ σφαξωσιν και εδοθη αυτω μαχαιρα μεγαλη ");
INSERT INTO grcmt_vpl VALUES ("RV6_5","096_6_5","REV","6","5","5","και οτε ηνοιξεν την σφραγιδα την τριτην ηκουσα του τριτου ζωου λεγοντοσ ερχου και ιδε και ιδου ιπποσ μελασ και ο καθημενοσ επ αυτον εχων ζυγον εν τη χειρι αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV6_6","096_6_6","REV","6","6","6","και ηκουσα φωνην εν μεσω των τεσσαρων ζωων λεγουσαν χοινιξ σιτου δηναριου και τρεισ χοινικεσ κριθησ δηναριου και το ελαιον και τον οινον μη αδικησησ ");
INSERT INTO grcmt_vpl VALUES ("RV6_7","096_6_7","REV","6","7","7","και οτε ηνοιξεν την σφραγιδα την τεταρτην ηκουσα του τεταρτου ζωου λεγοντοσ ερχου και ιδε ");
INSERT INTO grcmt_vpl VALUES ("RV6_8","096_6_8","REV","6","8","8","και ιδου ιπποσ χλωροσ και ο καθημενοσ επανω αυτου ονομα αυτω ο θανατοσ και ο αδησ ηκολουθει αυτω και εδοθη αυτω εξουσια επι το τεταρτον τησ γησ αποκτειναι εν ρομφαια και εν λιμω και εν θανατω και υπο των θηριων τησ γησ ");
INSERT INTO grcmt_vpl VALUES ("RV6_9","096_6_9","REV","6","9","9","και οτε ηνοιξεν την πεμπτην σφραγιδα ειδον υποκατω του θυσιαστηριου τασ ψυχασ των εσφαγμενων δια τον λογον του θεου και δια την μαρτυριαν του αρνιου ην ειχον ");
INSERT INTO grcmt_vpl VALUES ("RV6_10","096_6_10","REV","6","10","10","και εκραξαν φωνη μεγαλη λεγοντεσ εωσ ποτε ο δεσποτησ ο αγιοσ και αληθινοσ ου κρινεισ και εκδικεισ το αιμα ημων εκ των κατοικουντων επι τησ γησ ");
INSERT INTO grcmt_vpl VALUES ("RV6_11","096_6_11","REV","6","11","11","και εδοθη αυτοισ εκαστω στολη λευκη και ερρεθη αυτοισ ινα αναπαυσωνται ετι χρονον εωσ πληρωσωσιν και οι συνδουλοι αυτων και οι αδελφοι αυτων και οι μελλοντεσ αποκτενεσθαι ωσ και αυτοι ");
INSERT INTO grcmt_vpl VALUES ("RV6_12","096_6_12","REV","6","12","12","και ειδον οτε ηνοιξεν την σφραγιδα την εκτην και σεισμοσ μεγασ εγενετο και ο ηλιοσ μελασ εγενετο ωσ σακκοσ τριχινοσ και η σεληνη ολη εγενετο ωσ αιμα ");
INSERT INTO grcmt_vpl VALUES ("RV6_13","096_6_13","REV","6","13","13","και οι αστερεσ του ουρανου επεσον εισ την γην ωσ συκη βαλουσα τουσ ολυνθουσ αυτησ υπο ανεμου μεγαλου σειομενη ");
INSERT INTO grcmt_vpl VALUES ("RV6_14","096_6_14","REV","6","14","14","και ο ουρανοσ απεχωρισθη ωσ βιβλιον ελισσομενον και παν οροσ και νησοσ εκ των τοπων αυτων εκινηθησαν ");
INSERT INTO grcmt_vpl VALUES ("RV6_15","096_6_15","REV","6","15","15","και οι βασιλεισ τησ γησ και οι μεγιστανεσ και οι χιλιαρχοι και οι πλουσιοι και οι ισχυροι και πασ δουλοσ και ελευθεροσ εκρυψαν εαυτουσ εισ τα σπηλαια και εισ τασ πετρασ των ορεων ");
INSERT INTO grcmt_vpl VALUES ("RV6_16","096_6_16","REV","6","16","16","και λεγουσιν τοισ ορεσιν και ταισ πετραισ πεσετε εφ ημασ και κρυψατε ημασ απο προσωπου του καθημενου επι του θρονου και απο τησ οργησ του αρνιου ");
INSERT INTO grcmt_vpl VALUES ("RV6_17","096_6_17","REV","6","17","17","οτι ηλθεν η ημερα η μεγαλη τησ οργησ αυτου και τισ δυναται σταθηναι ");
INSERT INTO grcmt_vpl VALUES ("RV7_1","096_7_1","REV","7","1","1","και μετα τουτο ειδον τεσσαρασ αγγελουσ εστωτασ επι τασ τεσσαρασ γωνιασ τησ γησ κρατουντασ τουσ τεσσαρασ ανεμουσ τησ γησ ινα μη πνεη ανεμοσ επι τησ γησ μητε επι τησ θαλασσησ μητε επι τι δενδρον ");
INSERT INTO grcmt_vpl VALUES ("RV7_2","096_7_2","REV","7","2","2","και ειδον αλλον αγγελον αναβαινοντα απο ανατολησ ηλιου εχοντα σφραγιδα θεου ζωντοσ και εκραξεν φωνη μεγαλη τοισ τεσσαρσιν αγγελοισ οισ εδοθη αυτοισ αδικησαι την γην και την θαλασσαν ");
INSERT INTO grcmt_vpl VALUES ("RV7_3","096_7_3","REV","7","3","3","λεγων μη αδικησητε την γην μητε την θαλασσαν μητε τα δενδρα αχρι ου σφραγισωμεν τουσ δουλουσ του θεου ημων επι των μετωπων αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV7_4","096_7_4","REV","7","4","4","και ηκουσα τον αριθμον των εσφραγισμενων εκατον και τεσσαρακοντα τεσσαρεσ χιλιαδεσ εσφραγισμενων εκ πασησ φυλησ υιων ισραηλ ");
INSERT INTO grcmt_vpl VALUES ("RV7_5","096_7_5","REV","7","5","5","εκ φυλησ ιουδα δωδεκα χιλιαδεσ εσφραγισμεναι εκ φυλησ ρουβιμ δωδεκα χιλιαδεσ εκ φυλησ γαδ δωδεκα χιλιαδεσ ");
INSERT INTO grcmt_vpl VALUES ("RV7_6","096_7_6","REV","7","6","6","εκ φυλησ ασηρ δωδεκα χιλιαδεσ εκ φυλησ νεφθαλειμ δωδεκα χιλιαδεσ εκ φυλησ μανασση δωδεκα χιλιαδεσ ");
INSERT INTO grcmt_vpl VALUES ("RV7_7","096_7_7","REV","7","7","7","εκ φυλησ συμεων δωδεκα χιλιαδεσ εκ φυλησ λευι δωδεκα χιλιαδεσ εκ φυλησ ισαχαρ δωδεκα χιλιαδεσ ");
INSERT INTO grcmt_vpl VALUES ("RV7_8","096_7_8","REV","7","8","8","εκ φυλησ ζαβουλων δωδεκα χιλιαδεσ εκ φυλησ ιωσηφ δωδεκα χιλιαδεσ εκ φυλησ βενιαμιν δωδεκα χιλιαδεσ εσφραγισμεναι ");
INSERT INTO grcmt_vpl VALUES ("RV7_9","096_7_9","REV","7","9","9","μετα ταυτα ειδον και ιδου οχλοσ πολυσ ον αριθμησαι ουδεισ εδυνατο εκ παντοσ εθνουσ και φυλων και λαων και γλωσσων εστωτασ ενωπιον του θρονου και ενωπιον του αρνιου περιβεβλημενουσ στολασ λευκασ και φοινικασ εν ταισ χερσιν αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV7_10","096_7_10","REV","7","10","10","και κραζουσιν φωνη μεγαλη λεγοντεσ η σωτηρια τω θεω ημων τω καθημενω επι τω θρονω και τω αρνιω ");
INSERT INTO grcmt_vpl VALUES ("RV7_11","096_7_11","REV","7","11","11","και παντεσ οι αγγελοι ειστηκεισαν κυκλω του θρονου και των πρεσβυτερων και των τεσσαρων ζωων και επεσον ενωπιον του θρονου επι τα προσωπα αυτων και προσεκυνησαν τω θεω ");
INSERT INTO grcmt_vpl VALUES ("RV7_12","096_7_12","REV","7","12","12","λεγοντεσ αμην η ευλογια και η δοξα και η σοφια και η ευχαριστια και η τιμη και η δυναμισ και η ισχυσ τω θεω ημων εισ τουσ αιωνασ των αιωνων αμην ");
INSERT INTO grcmt_vpl VALUES ("RV7_13","096_7_13","REV","7","13","13","και απεκριθη εισ εκ των πρεσβυτερων λεγων μοι ουτοι οι περιβεβλημενοι τασ στολασ τασ λευκασ τινεσ εισιν και ποθεν ηλθον ");
INSERT INTO grcmt_vpl VALUES ("RV7_14","096_7_14","REV","7","14","14","και ειπον αυτω κυριε μου συ οιδασ και ειπεν μοι ουτοι εισιν οι ερχομενοι εκ τησ θλιψεωσ τησ μεγαλησ και επλυναν τασ στολασ αυτων και ελευκαναν εν τω αιματι του αρνιου ");
INSERT INTO grcmt_vpl VALUES ("RV7_15","096_7_15","REV","7","15","15","δια τουτο εισιν ενωπιον του θρονου του θεου και λατρευουσιν αυτω ημερασ και νυκτοσ εν τω ναω αυτου και ο καθημενοσ επι τω θρονω σκηνωσει επ αυτουσ ");
INSERT INTO grcmt_vpl VALUES ("RV7_16","096_7_16","REV","7","16","16","ου πεινασουσιν ετι ουδε διψησουσιν ετι ουδ ου μη πεση επ αυτουσ ο ηλιοσ ουδε παν καυμα ");
INSERT INTO grcmt_vpl VALUES ("RV7_17","096_7_17","REV","7","17","17","οτι το αρνιον το ανα μεσον του θρονου ποιμαινει αυτουσ και οδηγει αυτουσ επι ζωησ πηγασ υδατων και εξαλειψει ο θεοσ παν δακρυον εκ των οφθαλμων αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV8_1","096_8_1","REV","8","1","1","και οτε ηνοιξεν την σφραγιδα την εβδομην εγενετο σιγη εν τω ουρανω ωσ ημιωριον ");
INSERT INTO grcmt_vpl VALUES ("RV8_2","096_8_2","REV","8","2","2","και ειδον τουσ επτα αγγελουσ οι ενωπιον του θεου εστηκασιν και εδοθησαν αυτοισ επτα σαλπιγγεσ ");
INSERT INTO grcmt_vpl VALUES ("RV8_3","096_8_3","REV","8","3","3","και αλλοσ αγγελοσ ηλθεν και εσταθη επι του θυσιαστηριου εχων λιβανωτον χρυσουν και εδοθη αυτω θυμιαματα πολλα ινα δωση ταισ προσευχαισ των αγιων παντων επι το θυσιαστηριον το χρυσουν το ενωπιον του θρονου ");
INSERT INTO grcmt_vpl VALUES ("RV8_4","096_8_4","REV","8","4","4","και ανεβη ο καπνοσ των θυμιαματων ταισ προσευχαισ των αγιων εκ χειροσ του αγγελου ενωπιον του θεου ");
INSERT INTO grcmt_vpl VALUES ("RV8_5","096_8_5","REV","8","5","5","και ειληφεν ο αγγελοσ τον λιβανωτον και εγεμισεν αυτον εκ του πυροσ του θυσιαστηριου και εβαλεν εισ την γην και εγενοντο βρονται και φωναι και αστραπαι και σεισμοσ ");
INSERT INTO grcmt_vpl VALUES ("RV8_6","096_8_6","REV","8","6","6","και οι επτα αγγελοι οι εχοντεσ τασ επτα σαλπιγγασ ητοιμασαν εαυτουσ ινα σαλπισωσιν ");
INSERT INTO grcmt_vpl VALUES ("RV8_7","096_8_7","REV","8","7","7","και ο πρωτοσ εσαλπισεν και εγενετο χαλαζα και πυρ μεμιγμενα εν αιματι και εβληθη εισ την γην και το τριτον τησ γησ κατεκαη και το τριτον των δενδρων κατεκαη και πασ χορτοσ χλωροσ κατεκαη ");
INSERT INTO grcmt_vpl VALUES ("RV8_8","096_8_8","REV","8","8","8","και ο δευτεροσ αγγελοσ εσαλπισεν και ωσ οροσ μεγα καιομενον εβληθη εισ την θαλασσαν και εγενετο το τριτον τησ θαλασσησ αιμα ");
INSERT INTO grcmt_vpl VALUES ("RV8_9","096_8_9","REV","8","9","9","και απεθανεν το τριτον των κτισματων εν τη θαλασση τα εχοντα ψυχασ και το τριτον των πλοιων διεφθαρη ");
INSERT INTO grcmt_vpl VALUES ("RV8_10","096_8_10","REV","8","10","10","και ο τριτοσ αγγελοσ εσαλπισεν και επεσεν εκ του ουρανου αστηρ μεγασ καιομενοσ ωσ λαμπασ και επεσεν επι το τριτον των ποταμων και επι τασ πηγασ των υδατων ");
INSERT INTO grcmt_vpl VALUES ("RV8_11","096_8_11","REV","8","11","11","και το ονομα του αστεροσ λεγεται ο αψινθοσ και εγενετο το τριτον των υδατων εισ αψινθον και πολλοι των ανθρωπων απεθανον εκ των υδατων οτι επικρανθησαν ");
INSERT INTO grcmt_vpl VALUES ("RV8_12","096_8_12","REV","8","12","12","και ο τεταρτοσ αγγελοσ εσαλπισεν και επληγη το τριτον του ηλιου και το τριτον τησ σεληνησ και το τριτον των αστερων ινα σκοτισθη το τριτον αυτων και το τριτον αυτησ μη φανη η ημερα και η νυξ ομοιωσ ");
INSERT INTO grcmt_vpl VALUES ("RV8_13","096_8_13","REV","8","13","13","και ειδον και ηκουσα ενοσ αετου πετομενου εν μεσουρανηματι λεγοντοσ φωνη μεγαλη ουαι ουαι ουαι τοισ κατοικουσιν επι τησ γησ εκ των λοιπων φωνων τησ σαλπιγγοσ των τριων αγγελων των μελλοντων σαλπιζειν ");
INSERT INTO grcmt_vpl VALUES ("RV9_1","096_9_1","REV","9","1","1","και ο πεμπτοσ αγγελοσ εσαλπισεν και ειδον αστερα εκ του ουρανου πεπτωκοτα εισ την γην και εδοθη αυτω η κλεισ του φρεατοσ τησ αβυσσου ");
INSERT INTO grcmt_vpl VALUES ("RV9_2","096_9_2","REV","9","2","2","και ηνοιξεν το φρεαρ τησ αβυσσου και ανεβη καπνοσ εκ του φρεατοσ ωσ καπνοσ καμινου καιομενησ και εσκοτισθη ο ηλιοσ και ο αηρ εκ του καπνου του φρεατοσ ");
INSERT INTO grcmt_vpl VALUES ("RV9_3","096_9_3","REV","9","3","3","και εκ του καπνου εξηλθον ακριδεσ εισ την γην και εδοθη αυταισ εξουσια ωσ εχουσιν εξουσιαν οι σκορπιοι τησ γησ ");
INSERT INTO grcmt_vpl VALUES ("RV9_4","096_9_4","REV","9","4","4","και ερρεθη αυταισ ινα μη αδικησωσιν τον χορτον τησ γησ ουδε παν χλωρον ουδε παν δενδρον ει μη τουσ ανθρωπουσ οιτινεσ ουκ εχουσιν την σφραγιδα του θεου επι των μετωπων αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV9_5","096_9_5","REV","9","5","5","και εδοθη αυταισ ινα μη αποκτεινωσιν αυτουσ αλλ ινα βασανισθωσιν μηνασ πεντε και ο βασανισμοσ αυτων ωσ βασανισμοσ σκορπιου οταν παιση ανθρωπον ");
INSERT INTO grcmt_vpl VALUES ("RV9_6","096_9_6","REV","9","6","6","και εν ταισ ημεραισ εκειναισ ζητησουσιν οι ανθρωποι τον θανατον και ου μη ευρησουσιν αυτον και επιθυμησουσιν αποθανειν και φευξεται απ αυτων ο θανατοσ ");
INSERT INTO grcmt_vpl VALUES ("RV9_7","096_9_7","REV","9","7","7","και τα ομοιωματα των ακριδων ομοια ιπποισ ητοιμασμενοισ εισ πολεμον και επι τασ κεφαλασ αυτων ωσ στεφανοι χρυσοι και τα προσωπα αυτων ωσ προσωπα ανθρωπων ");
INSERT INTO grcmt_vpl VALUES ("RV9_8","096_9_8","REV","9","8","8","και ειχον τριχασ ωσ τριχασ γυναικων και οι οδοντεσ αυτων ωσ λεοντων ησαν ");
INSERT INTO grcmt_vpl VALUES ("RV9_9","096_9_9","REV","9","9","9","και ειχον θωρακασ ωσ θωρακασ σιδηρουσ και η φωνη των πτερυγων αυτων ωσ φωνη αρματων ιππων πολλων τρεχοντων εισ πολεμον ");
INSERT INTO grcmt_vpl VALUES ("RV9_10","096_9_10","REV","9","10","10","και εχουσιν ουρασ ομοιασ σκορπιοισ και κεντρα και εν ταισ ουραισ αυτων εξουσιαν εχουσιν του αδικησαι τουσ ανθρωπουσ μηνασ πεντε ");
INSERT INTO grcmt_vpl VALUES ("RV9_11","096_9_11","REV","9","11","11","εχουσαι βασιλεα επ αυτων αγγελον τησ αβυσσου ονομα αυτω εβραιστι αββαδων εν δε τη ελληνικη ονομα εχει απολλυων ");
INSERT INTO grcmt_vpl VALUES ("RV9_12","096_9_12","REV","9","12","12","η ουαι η μια απηλθεν ιδου ερχεται ετι δυο ουαι μετα ταυτα ");
INSERT INTO grcmt_vpl VALUES ("RV9_13","096_9_13","REV","9","13","13","και ο εκτοσ αγγελοσ εσαλπισεν και ηκουσα φωνην μιαν εκ των τεσσαρων κερατων του θυσιαστηριου του χρυσου του ενωπιον του θεου ");
INSERT INTO grcmt_vpl VALUES ("RV9_14","096_9_14","REV","9","14","14","λεγουσαν τω εκτω αγγελω ο εχων την σαλπιγγα λυσον τουσ τεσσαρασ αγγελουσ τουσ δεδεμενουσ επι τω ποταμω τω μεγαλω ευφρατη ");
INSERT INTO grcmt_vpl VALUES ("RV9_15","096_9_15","REV","9","15","15","και ελυθησαν οι τεσσαρεσ αγγελοι οι ητοιμασμενοι εισ την ωραν και εισ την ημεραν και μηνα και ενιαυτον ινα αποκτεινωσιν το τριτον των ανθρωπων ");
INSERT INTO grcmt_vpl VALUES ("RV9_16","096_9_16","REV","9","16","16","και ο αριθμοσ των στρατευματων του ιππου μυριαδεσ μυριαδων ηκουσα τον αριθμον αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV9_17","096_9_17","REV","9","17","17","και ουτωσ ειδον τουσ ιππουσ εν τη ορασει και τουσ καθημενουσ επ αυτων εχοντασ θωρακασ πυρινουσ και υακινθινουσ και θειωδεισ και αι κεφαλαι των ιππων ωσ κεφαλαι λεοντων και εκ των στοματων αυτων εκπορευεται πυρ και καπνοσ και θειον ");
INSERT INTO grcmt_vpl VALUES ("RV9_18","096_9_18","REV","9","18","18","απο των τριων πληγων τουτων απεκτανθησαν το τριτον των ανθρωπων απο του πυροσ και του καπνου και του θειου του εκπορευομενου εκ των στοματων αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV9_19","096_9_19","REV","9","19","19","η γαρ εξουσια των ιππων εν τω στοματι αυτων εστιν και εν ταισ ουραισ αυτων αι γαρ ουραι αυτων ομοιαι οφεων εχουσαι κεφαλασ και εν αυταισ αδικουσιν ");
INSERT INTO grcmt_vpl VALUES ("RV9_20","096_9_20","REV","9","20","20","και οι λοιποι των ανθρωπων οι ουκ απεκτανθησαν εν ταισ πληγαισ ταυταισ ου μετενοησαν εκ των εργων των χειρων αυτων ινα μη προσκυνησωσιν τα δαιμονια και τα ειδωλα τα χρυσα και τα αργυρα και τα χαλκα και τα λιθινα και τα ξυλινα α ουτε βλεπειν δυναται ουτε ακουειν ουτε περιπατειν ");
INSERT INTO grcmt_vpl VALUES ("RV9_21","096_9_21","REV","9","21","21","και ου μετενοησαν εκ των φονων αυτων ουτε εκ των φαρμακειων αυτων ουτε εκ τησ πορνειασ αυτων ουτε εκ των κλεμματων αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV10_1","096_10_1","REV","10","1","1","και ειδον αγγελον ισχυρον καταβαινοντα εκ του ουρανου περιβεβλημενον νεφελην και η ιρισ επι τησ κεφαλησ αυτου και το προσωπον αυτου ωσ ο ηλιοσ και οι ποδεσ αυτου ωσ στυλοι πυροσ ");
INSERT INTO grcmt_vpl VALUES ("RV10_2","096_10_2","REV","10","2","2","και εχων εν τη χειρι αυτου βιβλιον ανεωγμενον και εθηκεν τον ποδα αυτου τον δεξιον επι τησ θαλασσησ τον δε ευωνυμον επι τησ γησ ");
INSERT INTO grcmt_vpl VALUES ("RV10_3","096_10_3","REV","10","3","3","και εκραξεν φωνη μεγαλη ωσπερ λεων μυκαται και οτε εκραξεν ελαλησαν αι επτα βρονται τασ εαυτων φωνασ ");
INSERT INTO grcmt_vpl VALUES ("RV10_4","096_10_4","REV","10","4","4","και οτε ελαλησαν αι επτα βρονται εμελλον γραφειν και ηκουσα φωνην εκ του ουρανου λεγουσαν σφραγισον α ελαλησαν αι επτα βρονται και μη αυτα γραψησ ");
INSERT INTO grcmt_vpl VALUES ("RV10_5","096_10_5","REV","10","5","5","και ο αγγελοσ ον ειδον εστωτα επι τησ θαλασσησ και επι τησ γησ ηρεν την χειρα αυτου την δεξιαν εισ τον ουρανον ");
INSERT INTO grcmt_vpl VALUES ("RV10_6","096_10_6","REV","10","6","6","και ωμοσεν τω ζωντι εισ τουσ αιωνασ των αιωνων οσ εκτισεν τον ουρανον και τα εν αυτω και την γην και τα εν αυτη και την θαλασσαν και τα εν αυτη οτι χρονοσ ουκετι εσται ");
INSERT INTO grcmt_vpl VALUES ("RV10_7","096_10_7","REV","10","7","7","αλλ εν ταισ ημεραισ τησ φωνησ του εβδομου αγγελου οταν μελλη σαλπιζειν και ετελεσθη το μυστηριον του θεου ωσ ευηγγελισεν τουσ δουλουσ αυτου τουσ προφητασ ");
INSERT INTO grcmt_vpl VALUES ("RV10_8","096_10_8","REV","10","8","8","και η φωνη ην ηκουσα εκ του ουρανου παλιν λαλουσα μετ εμου και λεγουσα υπαγε λαβε το βιβλιδαριον το ανεωγμενον εν τη χειρι του αγγελου του εστωτοσ επι τησ θαλασσησ και επι τησ γησ ");
INSERT INTO grcmt_vpl VALUES ("RV10_9","096_10_9","REV","10","9","9","και απηλθον προσ τον αγγελον λεγων αυτω δουναι μοι το βιβλιδαριον και λεγει μοι λαβε και καταφαγε αυτο και πικρανει σου την κοιλιαν αλλ εν τω στοματι σου εσται γλυκυ ωσ μελι ");
INSERT INTO grcmt_vpl VALUES ("RV10_10","096_10_10","REV","10","10","10","και ελαβον το βιβλιον εκ τησ χειροσ του αγγελου και κατεφαγον αυτο και ην εν τω στοματι μου ωσ μελι γλυκυ και οτε εφαγον αυτο επικρανθη η κοιλια μου ");
INSERT INTO grcmt_vpl VALUES ("RV10_11","096_10_11","REV","10","11","11","και λεγουσιν μοι δει σε παλιν προφητευσαι επι λαοισ και επι εθνεσιν και γλωσσαισ και βασιλευσιν πολλοισ ");
INSERT INTO grcmt_vpl VALUES ("RV11_1","096_11_1","REV","11","1","1","και εδοθη μοι καλαμοσ ομοιοσ ραβδω λεγων εγειραι και μετρησον τον ναον του θεου και το θυσιαστηριον και τουσ προσκυνουντασ εν αυτω ");
INSERT INTO grcmt_vpl VALUES ("RV11_2","096_11_2","REV","11","2","2","και την αυλην την εξωθεν του ναου εκβαλε εξω και μη αυτην μετρησησ οτι εδοθη τοισ εθνεσιν και την πολιν την αγιαν πατησουσιν μηνασ τεσσαρακοντα και δυο ");
INSERT INTO grcmt_vpl VALUES ("RV11_3","096_11_3","REV","11","3","3","και δωσω τοισ δυσιν μαρτυσιν μου και προφητευσουσιν ημερασ χιλιασ διακοσιασ εξηκοντα περιβεβλημενοι σακκουσ ");
INSERT INTO grcmt_vpl VALUES ("RV11_4","096_11_4","REV","11","4","4","ουτοι εισιν αι δυο ελαιαι και αι δυο λυχνιαι αι ενωπιον του κυριου τησ γησ εστωσαι ");
INSERT INTO grcmt_vpl VALUES ("RV11_5","096_11_5","REV","11","5","5","και ει τισ αυτουσ θελει αδικησαι πυρ εκπορευεται εκ του στοματοσ αυτων και κατεσθιει τουσ εχθρουσ αυτων και ει τισ θελει αυτουσ αδικησαι ουτωσ δει αυτον αποκτανθηναι ");
INSERT INTO grcmt_vpl VALUES ("RV11_6","096_11_6","REV","11","6","6","ουτοι εχουσιν τον ουρανον εξουσιαν κλεισαι ινα μη υετοσ βρεχη τασ ημερασ τησ προφητειασ αυτων και εξουσιαν εχουσιν επι των υδατων στρεφειν αυτα εισ αιμα και παταξαι την γην οσακισ εαν θελησωσιν εν παση πληγη ");
INSERT INTO grcmt_vpl VALUES ("RV11_7","096_11_7","REV","11","7","7","και οταν τελεσωσιν την μαρτυριαν αυτων το θηριον το αναβαινον εκ τησ αβυσσου ποιησει μετ αυτων πολεμον και νικησει αυτουσ και αποκτενει αυτουσ ");
INSERT INTO grcmt_vpl VALUES ("RV11_8","096_11_8","REV","11","8","8","και το πτωμα αυτων επι τησ πλατειασ τησ πολεωσ τησ μεγαλησ ητισ καλειται πνευματικωσ σοδομα και αιγυπτοσ οπου και ο κυριοσ αυτων εσταυρωθη ");
INSERT INTO grcmt_vpl VALUES ("RV11_9","096_11_9","REV","11","9","9","και βλεπουσιν εκ των λαων και φυλων και γλωσσων και εθνων το πτωμα αυτων ημερασ τρεισ ημισυ και τα πτωματα αυτων ουκ αφησουσιν τεθηναι εισ μνημα ");
INSERT INTO grcmt_vpl VALUES ("RV11_10","096_11_10","REV","11","10","10","και οι κατοικουντεσ επι τησ γησ χαιρουσιν επ αυτοισ και ευφρανθησονται και δωρα δωσουσιν αλληλοισ οτι ουτοι οι δυο προφηται εβασανισαν τουσ κατοικουντασ επι τησ γησ ");
INSERT INTO grcmt_vpl VALUES ("RV11_11","096_11_11","REV","11","11","11","και μετα τασ τρεισ ημερασ και ημισυ πνευμα ζωησ εκ του θεου εισηλθεν εισ αυτουσ και εστησαν επι τουσ ποδασ αυτων και φοβοσ μεγασ επεσεν επι τουσ θεωρουντασ αυτουσ ");
INSERT INTO grcmt_vpl VALUES ("RV11_12","096_11_12","REV","11","12","12","και ηκουσα φωνην μεγαλην εκ του ουρανου λεγουσαν αυτοισ αναβητε ωδε και ανεβησαν εισ τον ουρανον εν τη νεφελη και εθεωρησαν αυτουσ οι εχθροι αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV11_13","096_11_13","REV","11","13","13","και εν εκεινη τη ημερα εγενετο σεισμοσ μεγασ και το δεκατον τησ πολεωσ επεσεν και απεκτανθησαν εν τω σεισμω ονοματα ανθρωπων χιλιαδεσ επτα και οι λοιποι εμφοβοι εγενοντο και εδωκαν δοξαν τω θεω του ουρανου ");
INSERT INTO grcmt_vpl VALUES ("RV11_14","096_11_14","REV","11","14","14","η ουαι η δευτερα απηλθεν η ουαι η τριτη ιδου ερχεται ταχυ ");
INSERT INTO grcmt_vpl VALUES ("RV11_15","096_11_15","REV","11","15","15","και ο εβδομοσ αγγελοσ εσαλπισεν και εγενοντο φωναι μεγαλαι εν τω ουρανω λεγουσαι εγενετο η βασιλεια του κοσμου του κυριου ημων και του χριστου αυτου και βασιλευσει εισ τουσ αιωνασ των αιωνων ");
INSERT INTO grcmt_vpl VALUES ("RV11_16","096_11_16","REV","11","16","16","και οι εικοσι τεσσαρεσ πρεσβυτεροι οι ενωπιον του θρονου του θεου καθημενοι επι τουσ θρονουσ αυτων επεσον επι τα προσωπα αυτων και προσεκυνησαν τω θεω ");
INSERT INTO grcmt_vpl VALUES ("RV11_17","096_11_17","REV","11","17","17","λεγοντεσ ευχαριστουμεν σοι κυριε ο θεοσ ο παντοκρατωρ ο ων και ο ην οτι ειληφασ την δυναμιν σου την μεγαλην και εβασιλευσασ ");
INSERT INTO grcmt_vpl VALUES ("RV11_18","096_11_18","REV","11","18","18","και τα εθνη ωργισθησαν και ηλθεν η οργη σου και ο καιροσ των νεκρων κριθηναι και δουναι τον μισθον τοισ δουλοισ σου τοισ προφηταισ και τοισ αγιοισ και τοισ φοβουμενοισ το ονομα σου τοισ μικροισ και τοισ μεγαλοισ και διαφθειραι τουσ διαφθειροντασ την γην ");
INSERT INTO grcmt_vpl VALUES ("RV11_19","096_11_19","REV","11","19","19","και ηνοιγη ο ναοσ του θεου εν τω ουρανω και ωφθη η κιβωτοσ τησ διαθηκησ του κυριου εν τω ναω αυτου και εγενοντο αστραπαι και φωναι και βρονται και χαλαζα μεγαλη ");
INSERT INTO grcmt_vpl VALUES ("RV12_1","096_12_1","REV","12","1","1","και σημειον μεγα ωφθη εν τω ουρανω γυνη περιβεβλημενη τον ηλιον και η σεληνη υποκατω των ποδων αυτησ και επι τησ κεφαλησ αυτησ στεφανοσ αστερων δωδεκα ");
INSERT INTO grcmt_vpl VALUES ("RV12_2","096_12_2","REV","12","2","2","και εν γαστρι εχουσα εκραζεν ωδινουσα και βασανιζομενη τεκειν ");
INSERT INTO grcmt_vpl VALUES ("RV12_3","096_12_3","REV","12","3","3","και ωφθη αλλο σημειον εν τω ουρανω και ιδου δρακων πυροσ μεγασ εχων κεφαλασ επτα και κερατα δεκα και επι τασ κεφαλασ αυτου επτα διαδηματα ");
INSERT INTO grcmt_vpl VALUES ("RV12_4","096_12_4","REV","12","4","4","και η ουρα αυτου συρει το τριτον των αστερων του ουρανου και εβαλεν αυτουσ εισ την γην και ο δρακων εστηκεν ενωπιον τησ γυναικοσ τησ μελλουσησ τεκειν ινα οταν τεκη το τεκνον αυτησ καταφαγη ");
INSERT INTO grcmt_vpl VALUES ("RV12_5","096_12_5","REV","12","5","5","και ετεκεν υιον αρρενα οσ μελλει ποιμαινειν παντα τα εθνη εν ραβδω σιδηρα και ηρπασθη το τεκνον αυτησ προσ τον θεον και προσ τον θρονον αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV12_6","096_12_6","REV","12","6","6","και η γυνη εφυγεν εισ την ερημον οπου εχει εκει τοπον ητοιμασμενον υπο του θεου ινα εκει εκτρεφωσιν αυτην ημερασ χιλιασ διακοσιασ εξηκοντα ");
INSERT INTO grcmt_vpl VALUES ("RV12_7","096_12_7","REV","12","7","7","και εγενετο πολεμοσ εν τω ουρανω ο μιχαηλ και οι αγγελοι αυτου πολεμησαι μετα του δρακοντοσ και ο δρακων επολεμησεν και οι αγγελοι αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV12_8","096_12_8","REV","12","8","8","και ουκ ισχυσεν ουδε τοποσ ευρεθη αυτω ετι εν τω ουρανω ");
INSERT INTO grcmt_vpl VALUES ("RV12_9","096_12_9","REV","12","9","9","και εβληθη ο δρακων ο μεγασ ο οφισ ο αρχαιοσ ο καλουμενοσ διαβολοσ και σατανασ ο πλανων την οικουμενην ολην εβληθη εισ την γην και οι αγγελοι αυτου μετ αυτου εβληθησαν ");
INSERT INTO grcmt_vpl VALUES ("RV12_10","096_12_10","REV","12","10","10","και ηκουσα φωνην μεγαλην εν τω ουρανω λεγουσαν αρτι εγενετο η σωτηρια και η δυναμισ και η βασιλεια του θεου ημων και η εξουσια του χριστου αυτου οτι εβληθη ο κατηγοροσ των αδελφων ημων ο κατηγορων αυτων ενωπιον του θεου ημων ημερασ και νυκτοσ ");
INSERT INTO grcmt_vpl VALUES ("RV12_11","096_12_11","REV","12","11","11","και αυτοι ενικησαν αυτον δια το αιμα του αρνιου και δια τον λογον τησ μαρτυριασ αυτων και ουκ ηγαπησαν την ψυχην αυτων αχρι θανατου ");
INSERT INTO grcmt_vpl VALUES ("RV12_12","096_12_12","REV","12","12","12","δια τουτο ευφραινεσθε ουρανοι και οι εν αυτοισ σκηνουντεσ ουαι τη γη και τη θαλασση οτι κατεβη ο διαβολοσ προσ υμασ εχων θυμον μεγαν ειδωσ οτι ολιγον καιρον εχει ");
INSERT INTO grcmt_vpl VALUES ("RV12_13","096_12_13","REV","12","13","13","και οτε ειδεν ο δρακων οτι εβληθη εισ την γην εδιωξεν την γυναικα ητισ ετεκεν τον αρρενα ");
INSERT INTO grcmt_vpl VALUES ("RV12_14","096_12_14","REV","12","14","14","και εδοθησαν τη γυναικι δυο πτερυγεσ του αετου του μεγαλου ινα πετηται εισ την ερημον εισ τον τοπον αυτησ οπωσ τρεφηται εκει καιρον και καιρουσ και ημισυ καιρου απο προσωπου του οφεωσ ");
INSERT INTO grcmt_vpl VALUES ("RV12_15","096_12_15","REV","12","15","15","και εβαλεν ο οφισ εκ του στοματοσ αυτου οπισω τησ γυναικοσ υδωρ ωσ ποταμον ινα αυτην ποταμοφορητον ποιηση ");
INSERT INTO grcmt_vpl VALUES ("RV12_16","096_12_16","REV","12","16","16","και εβοηθησεν η γη τη γυναικι και ηνοιξεν η γη το στομα αυτησ και κατεπιεν τον ποταμον ον εβαλεν ο δρακων εκ του στοματοσ αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV12_17","096_12_17","REV","12","17","17","και ωργισθη ο δρακων επι τη γυναικι και απηλθεν ποιησαι πολεμον μετα των λοιπων του σπερματοσ αυτησ των τηρουντων τασ εντολασ του θεου και εχοντων την μαρτυριαν ιησου ");
INSERT INTO grcmt_vpl VALUES ("RV13_1","096_13_1","REV","13","1","1","και εσταθην επι την αμμον τησ θαλασσησ και ειδον εκ τησ θαλασσησ θηριον αναβαινον εχον κερατα δεκα και κεφαλασ επτα και επι των κερατων αυτου δεκα διαδηματα και επι τασ κεφαλασ αυτου ονοματα βλασφημιασ ");
INSERT INTO grcmt_vpl VALUES ("RV13_2","096_13_2","REV","13","2","2","και το θηριον ο ειδον ην ομοιον παρδαλει και οι ποδεσ αυτου ωσ αρκου και το στομα αυτου ωσ στομα λεοντοσ και εδωκεν αυτω ο δρακων την δυναμιν αυτου και τον θρονον αυτου και εξουσιαν μεγαλην ");
INSERT INTO grcmt_vpl VALUES ("RV13_3","096_13_3","REV","13","3","3","και μιαν εκ των κεφαλων αυτου ωσει εσφαγμενην εισ θανατον και η πληγη του θανατου αυτου εθεραπευθη και εθαυμασεν ολη η γη οπισω του θηριου ");
INSERT INTO grcmt_vpl VALUES ("RV13_4","096_13_4","REV","13","4","4","και προσεκυνησαν τω δρακοντι τω δεδωκοτι την εξουσιαν τω θηριω και προσεκυνησαν τω θηριω λεγοντεσ τισ ομοιοσ τω θηριω και τισ δυνατοσ πολεμησαι μετ αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV13_5","096_13_5","REV","13","5","5","και εδοθη αυτω στομα λαλουν μεγαλα και βλασφημιαν και εδοθη αυτω εξουσια πολεμον ποιησαι μηνασ τεσσαρακοντα δυο ");
INSERT INTO grcmt_vpl VALUES ("RV13_6","096_13_6","REV","13","6","6","και ηνοιξεν το στομα αυτου εισ βλασφημιαν προσ τον θεον βλασφημησαι το ονομα αυτου και την σκηνην αυτου τουσ εν τω ουρανω σκηνουντασ ");
INSERT INTO grcmt_vpl VALUES ("RV13_7","096_13_7","REV","13","7","7","και εδοθη αυτω ποιησαι πολεμον μετα των αγιων και νικησαι αυτουσ και εδοθη αυτω εξουσια επι πασαν φυλην και λαον και γλωσσαν και εθνοσ ");
INSERT INTO grcmt_vpl VALUES ("RV13_8","096_13_8","REV","13","8","8","και προσκυνησουσιν αυτω παντεσ οι κατοικουντεσ επι τησ γησ ων ου γεγραπται το ονομα εν τω βιβλιω τησ ζωησ του αρνιου του εσφαγμενου απο καταβολησ κοσμου ");
INSERT INTO grcmt_vpl VALUES ("RV13_9","096_13_9","REV","13","9","9","ει τισ εχει ουσ ακουσατω ");
INSERT INTO grcmt_vpl VALUES ("RV13_10","096_13_10","REV","13","10","10","ει τισ εχει αιχμαλωσιαν υπαγει ει τισ εν μαχαιρα αποκτενει δει αυτον εν μαχαιρα αποκτανθηναι ωδε εστιν η υπομονη και η πιστισ των αγιων ");
INSERT INTO grcmt_vpl VALUES ("RV13_11","096_13_11","REV","13","11","11","και ειδον αλλο θηριον αναβαινον εκ τησ γησ και ειχεν κερατα δυο ομοια αρνιω και ελαλει ωσ δρακων ");
INSERT INTO grcmt_vpl VALUES ("RV13_12","096_13_12","REV","13","12","12","και την εξουσιαν του πρωτου θηριου πασαν ποιει ενωπιον αυτου και εποιει την γην και τουσ εν αυτη κατοικουντασ ινα προσκυνησωσιν το θηριον το πρωτον ου εθεραπευθη η πληγη του θανατου αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV13_13","096_13_13","REV","13","13","13","και ποιει σημεια μεγαλα και πυρ ινα εκ του ουρανου καταβαινη επι την γην ενωπιον των ανθρωπων ");
INSERT INTO grcmt_vpl VALUES ("RV13_14","096_13_14","REV","13","14","14","και πλανα τουσ εμουσ τουσ κατοικουντασ επι τησ γησ δια τα σημεια α εδοθη αυτω ποιησαι ενωπιον του θηριου λεγων τοισ κατοικουσιν επι τησ γησ ποιησαι εικονα τω θηριω ο ειχεν την πληγην και εζησεν απο τησ μαχαιρασ ");
INSERT INTO grcmt_vpl VALUES ("RV13_15","096_13_15","REV","13","15","15","και εδοθη αυτω πνευμα δουναι τη εικονι του θηριου ινα και λαληση η εικων του θηριου και ποιηση οσοι εαν μη προσκυνησωσιν τη εικονι του θηριου αποκτανθωσιν ");
INSERT INTO grcmt_vpl VALUES ("RV13_16","096_13_16","REV","13","16","16","και ποιει παντασ τουσ μικρουσ και τουσ μεγαλουσ και τουσ πλουσιουσ και τουσ πτωχουσ και τουσ ελευθερουσ και τουσ δουλουσ ινα δωσωσιν αυτοισ χαραγματα επι τησ χειροσ αυτων τησ δεξιασ η επι το μετωπον αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV13_17","096_13_17","REV","13","17","17","και ινα μη τισ δυναται αγορασαι η πωλησαι ει μη ο εχων το χαραγμα το ονομα του θηριου η τον αριθμον του ονοματοσ αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV13_18","096_13_18","REV","13","18","18","ωδε η σοφια εστιν ο εχων νουν ψηφισατω τον αριθμον του θηριου αριθμοσ γαρ ανθρωπου εστιν και ο αριθμοσ αυτου εστιν εξακοσια εξηκοντα εξ ");
INSERT INTO grcmt_vpl VALUES ("RV14_1","096_14_1","REV","14","1","1","και ειδον και ιδου το αρνιον εστηκοσ επι το οροσ σιων και μετ αυτου αριθμοσ εκατον τεσσαρακοντα τεσσαρεσ χιλιαδεσ εχουσαι το ονομα αυτου και το ονομα του πατροσ αυτου γεγραμμενον επι των μετωπων αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV14_2","096_14_2","REV","14","2","2","και ηκουσα φωνην εκ του ουρανου ωσ φωνην υδατων πολλων και ωσ φωνην βροντησ μεγαλησ και η φωνη ην ηκουσα ωσ κιθαρωδων κιθαριζοντων εν ταισ κιθαραισ αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV14_3","096_14_3","REV","14","3","3","και αδουσιν ωδην καινην ενωπιον του θρονου και ενωπιον των τεσσαρων ζωων και των πρεσβυτερων και ουδεισ εδυνατο μαθειν την ωδην ει μη αι εκατον τεσσαρακοντα τεσσαρεσ χιλιαδεσ οι ηγορασμενοι απο τησ γησ ");
INSERT INTO grcmt_vpl VALUES ("RV14_4","096_14_4","REV","14","4","4","ουτοι εισιν οι μετα γυναικων ουκ εμολυνθησαν παρθενοι γαρ εισιν ουτοι εισιν οι ακολουθουντεσ τω αρνιω οπου αν υπαγη ουτοι υπο ιησου ηγορασθησαν απο των ανθρωπων απαρχη τω θεω και τω αρνιω ");
INSERT INTO grcmt_vpl VALUES ("RV14_5","096_14_5","REV","14","5","5","και ουχ ευρεθη εν τω στοματι αυτων ψευδοσ αμωμοι γαρ εισιν ");
INSERT INTO grcmt_vpl VALUES ("RV14_6","096_14_6","REV","14","6","6","και ειδον αγγελον πετομενον εν μεσουρανηματι εχοντα ευαγγελιον αιωνιον ευαγγελισαι τουσ καθημενουσ επι τησ γησ και επι παν εθνοσ και φυλην και γλωσσαν και λαον ");
INSERT INTO grcmt_vpl VALUES ("RV14_7","096_14_7","REV","14","7","7","λεγων εν φωνη μεγαλη φοβηθητε τον κυριον και δοτε αυτω δοξαν οτι ηλθεν η ωρα τησ κρισεωσ αυτου και προσκυνησατε αυτον τον ποιησαντα τον ουρανον και την γην και την θαλασσαν και πηγασ υδατων ");
INSERT INTO grcmt_vpl VALUES ("RV14_8","096_14_8","REV","14","8","8","και αλλοσ δευτεροσ αγγελοσ ηκολουθησεν λεγων επεσεν βαβυλων η μεγαλη εκ του οινου του θυμου τησ πορνειασ αυτησ πεποτικεν παντα τα εθνη ");
INSERT INTO grcmt_vpl VALUES ("RV14_9","096_14_9","REV","14","9","9","και αλλοσ αγγελοσ τριτοσ ηκολουθησεν αυτοισ λεγων εν φωνη μεγαλη ει τισ προσκυνει το θηριον και την εικονα αυτου και λαμβανει χαραγμα επι του μετωπου αυτου η επι την χειρα αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV14_10","096_14_10","REV","14","10","10","και αυτοσ πιεται εκ του οινου του θυμου του θεου του κεκερασμενου ακρατου εν τω ποτηριω τησ οργησ αυτου και βασανισθησεται εν πυρι και θειω ενωπιον των αγιων αγγελων και ενωπιον του αρνιου ");
INSERT INTO grcmt_vpl VALUES ("RV14_11","096_14_11","REV","14","11","11","και ο καπνοσ του βασανισμου αυτων εισ αιωνασ αιωνων αναβαινει και ουκ εχουσιν αναπαυσιν ημερασ και νυκτοσ οι προσκυνουντεσ το θηριον και την εικονα αυτου και ει τισ λαμβανει το χαραγμα του ονοματοσ αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV14_12","096_14_12","REV","14","12","12","ωδε η υπομονη των αγιων εστιν οι τηρουντεσ τασ εντολασ του θεου και την πιστιν ιησου ");
INSERT INTO grcmt_vpl VALUES ("RV14_13","096_14_13","REV","14","13","13","και ηκουσα φωνησ εκ του ουρανου λεγουσησ γραψον μακαριοι οι νεκροι οι εν κυριω αποθνησκοντεσ απ αρτι λεγει ναι το πνευμα ινα αναπαυσωνται εκ των κοπων αυτων τα δε εργα αυτων ακολουθει μετ αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV14_14","096_14_14","REV","14","14","14","και ειδον και ιδου νεφελη λευκη και επι την νεφελην καθημενον ομοιον υιω ανθρωπου εχων επι τησ κεφαλησ αυτου στεφανον χρυσουν και εν τη χειρι αυτου δρεπανον οξυ ");
INSERT INTO grcmt_vpl VALUES ("RV14_15","096_14_15","REV","14","15","15","και αλλοσ αγγελοσ εξηλθεν εκ του ναου κραζων εν φωνη μεγαλη τω καθημενω επι τησ νεφελησ πεμψον το δρεπανον σου και θερισον οτι ηλθεν η ωρα θερισαι οτι εξηρανθη ο θερισμοσ τησ γησ ");
INSERT INTO grcmt_vpl VALUES ("RV14_16","096_14_16","REV","14","16","16","και εβαλεν ο καθημενοσ επι την νεφελην το δρεπανον αυτου επι την γην και εθερισθη η γη ");
INSERT INTO grcmt_vpl VALUES ("RV14_17","096_14_17","REV","14","17","17","και αλλοσ αγγελοσ εξηλθεν εκ του ναου του εν τω ουρανω εχων και αυτοσ δρεπανον οξυ ");
INSERT INTO grcmt_vpl VALUES ("RV14_18","096_14_18","REV","14","18","18","και αλλοσ αγγελοσ εξηλθεν εκ του θυσιαστηριου εχων εξουσιαν επι του πυροσ και εφωνησεν κραυγη μεγαλη τω εχοντι το δρεπανον το οξυ λεγων πεμψον σου το δρεπανον το οξυ και τρυγησον τουσ βοτρυασ τησ αμπελου τησ γησ οτι ηκμασαν αι σταφυλαι αυτησ ");
INSERT INTO grcmt_vpl VALUES ("RV14_19","096_14_19","REV","14","19","19","και εβαλεν ο αγγελοσ το δρεπανον αυτου εισ την γην και ετρυγησεν την αμπελον τησ γησ και εβαλεν εισ την ληνον του θυμου του θεου τον μεγαν ");
INSERT INTO grcmt_vpl VALUES ("RV14_20","096_14_20","REV","14","20","20","και επατηθη η ληνοσ εξωθεν τησ πολεωσ και εξηλθεν αιμα εκ τησ ληνου αχρι των χαλινων των ιππων απο σταδιων χιλιων εξακοσιων ");
INSERT INTO grcmt_vpl VALUES ("RV15_1","096_15_1","REV","15","1","1","και ειδον αλλο σημειον εν τω ουρανω μεγα και θαυμαστον αγγελουσ επτα εχοντασ πληγασ επτα τασ εσχατασ οτι εν αυταισ ετελεσθη ο θυμοσ του θεου ");
INSERT INTO grcmt_vpl VALUES ("RV15_2","096_15_2","REV","15","2","2","και ειδον ωσ θαλασσαν υαλινην μεμιγμενην πυρι και τουσ νικωντασ εκ του θηριου και εκ τησ εικονοσ αυτου και εκ του αριθμου του ονοματοσ αυτου εστωτασ επι την θαλασσαν την υαλινην εχοντασ κιθαρασ του θεου ");
INSERT INTO grcmt_vpl VALUES ("RV15_3","096_15_3","REV","15","3","3","και αδουσιν την ωδην μωυσεωσ του δουλου του θεου και την ωδην του αρνιου λεγοντεσ μεγαλα και θαυμαστα τα εργα σου κυριε ο θεοσ ο παντοκρατωρ δικαιαι και αληθιναι αι οδοι σου ο βασιλευσ των εθνων ");
INSERT INTO grcmt_vpl VALUES ("RV15_4","096_15_4","REV","15","4","4","τισ ου μη φοβηθη σε κυριε και δοξαση το ονομα σου οτι μονοσ αγιοσ οτι παντα τα εθνη ηξουσιν και προσκυνησουσιν ενωπιον σου οτι τα δικαιωματα σου εφανερωθησαν ");
INSERT INTO grcmt_vpl VALUES ("RV15_5","096_15_5","REV","15","5","5","και μετα ταυτα ειδον και ηνοιγη ο ναοσ τησ σκηνησ του μαρτυριου εν τω ουρανω ");
INSERT INTO grcmt_vpl VALUES ("RV15_6","096_15_6","REV","15","6","6","και εξηλθον οι επτα αγγελοι οι εχοντεσ τασ επτα πληγασ εκ του ναου οι ησαν ενδεδυμενοι λινον καθαρον λαμπρον και περιεζωσμενοι περι τα στηθη ζωνασ χρυσασ ");
INSERT INTO grcmt_vpl VALUES ("RV15_7","096_15_7","REV","15","7","7","και εν εκ των τεσσαρων ζωων εδωκεν τοισ επτα αγγελοισ επτα φιαλασ χρυσασ γεμουσασ του θυμου του θεου του ζωντοσ εισ τουσ αιωνασ των αιωνων ");
INSERT INTO grcmt_vpl VALUES ("RV15_8","096_15_8","REV","15","8","8","και εγεμισθη ο ναοσ καπνου εκ τησ δοξησ του θεου και εκ τησ δυναμεωσ αυτου και ουδεισ εδυνατο εισελθειν εισ τον ναον αχρι τελεσθωσιν αι επτα πληγαι των επτα αγγελων ");
INSERT INTO grcmt_vpl VALUES ("RV16_1","096_16_1","REV","16","1","1","και ηκουσα φωνησ μεγαλησ εκ του ναου λεγουσησ τοισ επτα αγγελοισ υπαγετε και εκχεατε τασ επτα φιαλασ του θυμου του θεου εισ την γην ");
INSERT INTO grcmt_vpl VALUES ("RV16_2","096_16_2","REV","16","2","2","και απηλθεν ο πρωτοσ και εξεχεεν την φιαλην αυτου εισ την γην και εγενετο ελκοσ κακον και πονηρον επι τουσ ανθρωπουσ τουσ εχοντασ το χαραγμα του θηριου και τουσ προσκυνουντασ τη εικονι αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV16_3","096_16_3","REV","16","3","3","και ο δευτεροσ αγγελοσ εξεχεεν την φιαλην αυτου εισ την θαλασσαν και εγενετο αιμα ωσ νεκρου και πασα ψυχη ζωσα απεθανεν εν τη θαλασση ");
INSERT INTO grcmt_vpl VALUES ("RV16_4","096_16_4","REV","16","4","4","και ο τριτοσ εξεχεεν την φιαλην αυτου εισ τουσ ποταμουσ και εισ τασ πηγασ των υδατων και εγενετο αιμα ");
INSERT INTO grcmt_vpl VALUES ("RV16_5","096_16_5","REV","16","5","5","και ηκουσα του αγγελου των υδατων λεγοντοσ δικαιοσ ει ο ων και ο ην ο οσιοσ οτι ταυτα εκρινασ ");
INSERT INTO grcmt_vpl VALUES ("RV16_6","096_16_6","REV","16","6","6","οτι αιμα αγιων και προφητων εξεχεαν και αιμα αυτοισ εδωκασ πιειν αξιοι εισιν ");
INSERT INTO grcmt_vpl VALUES ("RV16_7","096_16_7","REV","16","7","7","και ηκουσα του θυσιαστηριου λεγοντοσ ναι κυριε ο θεοσ ο παντοκρατωρ αληθιναι και δικαιαι αι κρισεισ σου ");
INSERT INTO grcmt_vpl VALUES ("RV16_8","096_16_8","REV","16","8","8","και ο τεταρτοσ αγγελοσ εξεχεεν την φιαλην αυτου επι τον ηλιον και εδοθη αυτω καυματισαι εν πυρι τουσ ανθρωπουσ ");
INSERT INTO grcmt_vpl VALUES ("RV16_9","096_16_9","REV","16","9","9","και εκαυματισθησαν οι ανθρωποι καυμα μεγα και εβλασφημησαν οι ανθρωποι το ονομα του θεου του εχοντοσ εξουσιαν επι τασ πληγασ ταυτασ και ου μετενοησαν δουναι αυτω δοξαν ");
INSERT INTO grcmt_vpl VALUES ("RV16_10","096_16_10","REV","16","10","10","και ο πεμπτοσ εξεχεεν την φιαλην αυτου επι τον θρονον του θηριου και εγενετο η βασιλεια αυτου εσκοτωμενη και εμασωντο τασ γλωσσασ αυτων εκ του πονου ");
INSERT INTO grcmt_vpl VALUES ("RV16_11","096_16_11","REV","16","11","11","και εβλασφημησαν τον θεον του ουρανου εκ των πονων αυτων και εκ των ελκων αυτων και ου μετενοησαν εκ των εργων αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV16_12","096_16_12","REV","16","12","12","και ο εκτοσ εξεχεεν την φιαλην αυτου επι τον ποταμον τον μεγαν ευφρατην και εξηρανθη το υδωρ αυτου ινα ετοιμασθη η οδοσ των βασιλεων των απο ανατολησ ηλιου ");
INSERT INTO grcmt_vpl VALUES ("RV16_13","096_16_13","REV","16","13","13","και ειδον εκ του στοματοσ του δρακοντοσ και εκ του στοματοσ του θηριου και εκ του στοματοσ του ψευδοπροφητου πνευματα ακαθαρτα τρια ωσ βατραχοι ");
INSERT INTO grcmt_vpl VALUES ("RV16_14","096_16_14","REV","16","14","14","εισιν γαρ πνευματα δαιμονιων ποιουντα σημεια α εκπορευεται επι τουσ βασιλεισ τησ οικουμενησ ολησ συναγαγειν αυτουσ εισ τον πολεμον τησ ημερασ εκεινησ τησ μεγαλησ του θεου του παντοκρατοροσ ");
INSERT INTO grcmt_vpl VALUES ("RV16_15","096_16_15","REV","16","15","15","ιδου ερχομαι ωσ κλεπτησ μακαριοσ ο γρηγορων και τηρων τα ιματια αυτου ινα μη γυμνοσ περιπατη και βλεπωσιν την ασχημοσυνην αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV16_16","096_16_16","REV","16","16","16","και συνηγαγεν αυτουσ εισ τον τοπον τον καλουμενον εβραιστι αρμαγεδων ");
INSERT INTO grcmt_vpl VALUES ("RV16_17","096_16_17","REV","16","17","17","και ο εβδομοσ εξεχεεν την φιαλην αυτου επι τον αερα και εξηλθεν φωνη μεγαλη απο του ναου του ουρανου απο του θρονου λεγουσα γεγονεν ");
INSERT INTO grcmt_vpl VALUES ("RV16_18","096_16_18","REV","16","18","18","και εγενοντο αστραπαι και βρονται και φωναι και σεισμοσ μεγασ οιοσ ουκ εγενετο αφ ου οι ανθρωποι εγενοντο επι τησ γησ τηλικουτοσ σεισμοσ ουτωσ μεγασ ");
INSERT INTO grcmt_vpl VALUES ("RV16_19","096_16_19","REV","16","19","19","και εγενετο η πολισ η μεγαλη εισ τρια μερη και αι πολεισ των εθνων επεσον και βαβυλων η μεγαλη εμνησθη ενωπιον του θεου δουναι αυτη το ποτηριον του οινου του θυμου τησ οργησ αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV16_20","096_16_20","REV","16","20","20","και πασα νησοσ εφυγεν και ορη ουχ ευρεθησαν ");
INSERT INTO grcmt_vpl VALUES ("RV16_21","096_16_21","REV","16","21","21","και χαλαζα μεγαλη ωσ ταλαντιαια καταβαινει εκ του ουρανου επι τουσ ανθρωπουσ και εβλασφημησαν οι ανθρωποι τον θεον εκ τησ πληγησ τησ χαλαζησ οτι μεγαλη εστιν η πληγη αυτησ σφοδρα ");
INSERT INTO grcmt_vpl VALUES ("RV17_1","096_17_1","REV","17","1","1","και ηλθεν εισ εκ των επτα αγγελων των εχοντων τασ επτα φιαλασ και ελαλησεν μετ εμου λεγων δευρο δειξω σοι το κριμα τησ πορνησ τησ μεγαλησ τησ καθημενησ επι των υδατων των πολλων ");
INSERT INTO grcmt_vpl VALUES ("RV17_2","096_17_2","REV","17","2","2","μεθ ησ επορνευσαν οι βασιλεισ τησ γησ και εμεθυσθησαν οι κατοικουντεσ την γην εκ του οινου τησ πορνειασ αυτησ ");
INSERT INTO grcmt_vpl VALUES ("RV17_3","096_17_3","REV","17","3","3","και απηνεγκεν με εισ ερημον εν πνευματι και ειδον γυναικα καθημενην επι θηριον κοκκινον γεμον ονοματα βλασφημιασ εχον κεφαλασ επτα και κερατα δεκα ");
INSERT INTO grcmt_vpl VALUES ("RV17_4","096_17_4","REV","17","4","4","και η γυνη ην περιβεβλημενη πορφυρουν και κοκκινον κεχρυσωμενη χρυσιω και λιθω τιμιω και μαργαριταισ εχουσα ποτηριον χρυσουν εν τη χειρι αυτησ γεμον βδελυγματων και τα ακαθαρτα τησ πορνειασ αυτησ ");
INSERT INTO grcmt_vpl VALUES ("RV17_5","096_17_5","REV","17","5","5","και επι το μετωπον αυτησ ονομα γεγραμμενον μυστηριον βαβυλων η μεγαλη η μητηρ των πορνων και των βδελυγματων τησ γησ ");
INSERT INTO grcmt_vpl VALUES ("RV17_6","096_17_6","REV","17","6","6","και ειδον την γυναικα μεθυουσαν εκ του αιματοσ των αγιων εκ του αιματοσ των μαρτυρων ιησου και εθαυμασα ιδων αυτην θαυμα μεγα ");
INSERT INTO grcmt_vpl VALUES ("RV17_7","096_17_7","REV","17","7","7","και ειπεν μοι ο αγγελοσ δια τι εθαυμασασ εγω ερω σοι το μυστηριον τησ γυναικοσ και του θηριου του βασταζοντοσ αυτην του εχοντοσ τασ επτα κεφαλασ και τα δεκα κερατα ");
INSERT INTO grcmt_vpl VALUES ("RV17_8","096_17_8","REV","17","8","8","το θηριον ο ειδεσ ην και ουκ εστιν και μελλει αναβαινειν εκ τησ αβυσσου και εισ απωλειαν υπαγειν και θαυμασονται οι κατοικουντεσ επι τησ γησ ων ου γεγραπται τα ονοματα επι το βιβλιον τησ ζωησ απο καταβολησ κοσμου βλεποντων οτι ην το θηριον και ουκ εστιν και παρεσται ");
INSERT INTO grcmt_vpl VALUES ("RV17_9","096_17_9","REV","17","9","9","ωδε ο νουσ ο εχων σοφιαν αι επτα κεφαλαι επτα ορη εισιν οπου η γυνη καθηται επ αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV17_10","096_17_10","REV","17","10","10","και βασιλεισ εισιν επτα οι πεντε επεσον ο εισ εστιν ο αλλοσ ουπω ηλθεν και οταν ελθη ολιγον δει αυτον μειναι ");
INSERT INTO grcmt_vpl VALUES ("RV17_11","096_17_11","REV","17","11","11","και το θηριον ο ην και ουκ εστιν και αυτοσ ογδοοσ εστιν και εκ των επτα εστιν και εισ απωλειαν υπαγει ");
INSERT INTO grcmt_vpl VALUES ("RV17_12","096_17_12","REV","17","12","12","και τα δεκα κερατα α ειδεσ δεκα βασιλεισ εισιν οιτινεσ βασιλειαν ουπω ελαβον αλλ εξουσιαν ωσ βασιλεισ μιαν ωραν λαμβανουσιν μετα του θηριου ");
INSERT INTO grcmt_vpl VALUES ("RV17_13","096_17_13","REV","17","13","13","ουτοι μιαν εχουσιν γνωμην και την δυναμιν και την εξουσιαν αυτων τω θηριω διδοασιν ");
INSERT INTO grcmt_vpl VALUES ("RV17_14","096_17_14","REV","17","14","14","ουτοι μετα του αρνιου πολεμησουσιν και το αρνιον νικησει αυτουσ οτι κυριοσ κυριων εστιν και βασιλευσ βασιλεων και οι μετ αυτου κλητοι και εκλεκτοι και πιστοι ");
INSERT INTO grcmt_vpl VALUES ("RV17_15","096_17_15","REV","17","15","15","και λεγει μοι τα υδατα α ειδεσ ου η πορνη καθηται λαοι και οχλοι εισιν και εθνη και γλωσσαι ");
INSERT INTO grcmt_vpl VALUES ("RV17_16","096_17_16","REV","17","16","16","και τα δεκα κερατα α ειδεσ και το θηριον ουτοι μισησουσιν την πορνην και ηρημωμενην ποιησουσιν αυτην και γυμνην ποιησουσιν αυτην και τασ σαρκασ αυτησ φαγονται και αυτην κατακαυσουσιν εν πυρι ");
INSERT INTO grcmt_vpl VALUES ("RV17_17","096_17_17","REV","17","17","17","ο γαρ θεοσ εδωκεν εισ τασ καρδιασ αυτων ποιησαι την γνωμην αυτου και ποιησαι γνωμην μιαν και δουναι την βασιλειαν αυτων τω θηριω αχρι τελεσθωσιν οι λογοι του θεου ");
INSERT INTO grcmt_vpl VALUES ("RV17_18","096_17_18","REV","17","18","18","και η γυνη ην ειδεσ εστιν η πολισ η μεγαλη η εχουσα βασιλειαν επι των βασιλεων τησ γησ ");
INSERT INTO grcmt_vpl VALUES ("RV18_1","096_18_1","REV","18","1","1","μετα ταυτα ειδον αλλον αγγελον καταβαινοντα εκ του ουρανου εχοντα εξουσιαν μεγαλην και η γη εφωτισθη εκ τησ δοξησ αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV18_2","096_18_2","REV","18","2","2","και εκραξεν ισχυρα φωνη λεγων επεσεν βαβυλων η μεγαλη και εγενετο κατοικητηριον δαιμονων και φυλακη παντοσ πνευματοσ ακαθαρτου και φυλακη παντοσ ορνεου ακαθαρτου και μεμισημενου ");
INSERT INTO grcmt_vpl VALUES ("RV18_3","096_18_3","REV","18","3","3","οτι εκ του οινου του θυμου τησ πορνειασ αυτησ πεπτωκασιν παντα τα εθνη και οι βασιλεισ τησ γησ μετ αυτησ επορνευσαν και οι εμποροι τησ γησ εκ τησ δυναμεωσ του στρηνουσ αυτησ επλουτησαν ");
INSERT INTO grcmt_vpl VALUES ("RV18_4","096_18_4","REV","18","4","4","και ηκουσα αλλην φωνην εκ του ουρανου λεγουσαν εξελθε εξ αυτησ ο λαοσ μου ινα μη συγκοινωνησητε ταισ αμαρτιαισ αυτησ και εκ των πληγων αυτησ ινα μη λαβητε ");
INSERT INTO grcmt_vpl VALUES ("RV18_5","096_18_5","REV","18","5","5","οτι εκολληθησαν αυτησ αι αμαρτιαι αχρι του ουρανου και εμνημονευσεν ο θεοσ τα αδικηματα αυτησ ");
INSERT INTO grcmt_vpl VALUES ("RV18_6","096_18_6","REV","18","6","6","αποδοτε αυτη ωσ και αυτη απεδωκεν και διπλωσατε αυτη διπλα κατα τα εργα αυτησ εν τω ποτηριω ω εκερασεν κερασατε αυτη διπλουν ");
INSERT INTO grcmt_vpl VALUES ("RV18_7","096_18_7","REV","18","7","7","οσα εδοξασεν αυτην και εστρηνιασεν τοσουτον δοτε αυτη βασανισμον και πενθοσ οτι εν τη καρδια αυτησ λεγει οτι καθημαι βασιλισσα και χηρα ουκ ειμι και πενθοσ ου μη ιδω ");
INSERT INTO grcmt_vpl VALUES ("RV18_8","096_18_8","REV","18","8","8","δια τουτο εν μια ημερα ηξουσιν αι πληγαι αυτησ θανατοσ και πενθοσ και λιμοσ και εν πυρι κατακαυθησεται οτι ισχυροσ κυριοσ ο θεοσ ο κρινασ αυτην ");
INSERT INTO grcmt_vpl VALUES ("RV18_9","096_18_9","REV","18","9","9","και κλαυσουσιν και κοψονται επ αυτην οι βασιλεισ τησ γησ οι μετ αυτησ πορνευσαντεσ και στρηνιασαντεσ οταν βλεπωσιν τον καπνον τησ πυρωσεωσ αυτησ ");
INSERT INTO grcmt_vpl VALUES ("RV18_10","096_18_10","REV","18","10","10","απο μακροθεν εστηκοτεσ δια τον φοβον του βασανισμου αυτησ λεγοντεσ ουαι ουαι η πολισ η μεγαλη βαβυλων η πολισ η ισχυρα οτι μια ωρα ηλθεν η κρισισ σου ");
INSERT INTO grcmt_vpl VALUES ("RV18_11","096_18_11","REV","18","11","11","και οι εμποροι τησ γησ κλαυσουσιν και πενθησουσιν επ αυτη οτι τον γομον αυτων ουδεισ αγοραζει ουκετι ");
INSERT INTO grcmt_vpl VALUES ("RV18_12","096_18_12","REV","18","12","12","γομον χρυσου και αργυρου και λιθου τιμιου και μαργαριτου και βυσσινου και πορφυρου και σηρικου και κοκκινου και παν ξυλον θυινον και παν σκευοσ ελεφαντινον και παν σκευοσ εκ ξυλου τιμιωτατου και χαλκου και σιδηρου και μαρμαρου ");
INSERT INTO grcmt_vpl VALUES ("RV18_13","096_18_13","REV","18","13","13","και κιναμωμον και θυμιαματα και μυρον και λιβανον και οινον και ελαιον και σεμιδαλιν και σιτον και προβατα και κτηνη και ιππων και ραιδων και σωματων και ψυχασ ανθρωπων ");
INSERT INTO grcmt_vpl VALUES ("RV18_14","096_18_14","REV","18","14","14","και η οπωρα τησ επιθυμιασ τησ ψυχησ σου απηλθεν απο σου και παντα τα λιπαρα και τα λαμπρα απωλετο απο σου και ουκετι αυτα ου μη ευρησ ");
INSERT INTO grcmt_vpl VALUES ("RV18_15","096_18_15","REV","18","15","15","οι εμποροι τουτων οι πλουτησαντεσ απ αυτησ απο μακροθεν στησονται δια τον φοβον του βασανισμου αυτησ κλαιοντεσ και πενθουντεσ ");
INSERT INTO grcmt_vpl VALUES ("RV18_16","096_18_16","REV","18","16","16","και λεγοντεσ ουαι ουαι η πολισ η μεγαλη η περιβεβλημενη βυσσινον και πορφυρουν και κοκκινον και κεχρυσωμενη χρυσιω και λιθω τιμιω και μαργαριταισ ");
INSERT INTO grcmt_vpl VALUES ("RV18_17","096_18_17","REV","18","17","17","οτι μια ωρα ηρημωθη ο τοσουτοσ πλουτοσ και πασ κυβερνητησ και πασ ο επι τοπον πλεων και ναυται και οσοι την θαλασσαν εργαζονται απο μακροθεν εστησαν ");
INSERT INTO grcmt_vpl VALUES ("RV18_18","096_18_18","REV","18","18","18","και εκραζον βλεποντεσ τον καπνον τησ πυρωσεωσ αυτησ λεγοντεσ τισ ομοια τη πολει τη μεγαλη ");
INSERT INTO grcmt_vpl VALUES ("RV18_19","096_18_19","REV","18","19","19","και εβαλον χουν επι τασ κεφαλασ αυτων και εκραζον κλαιοντεσ και πενθουντεσ και λεγοντεσ ουαι ουαι η πολισ η μεγαλη εν η επλουτησαν παντεσ οι εχοντεσ τα πλοια εν τη θαλασση εκ τησ τιμιοτητοσ αυτησ οτι μια ωρα ηρημωθη ");
INSERT INTO grcmt_vpl VALUES ("RV18_20","096_18_20","REV","18","20","20","ευφραινου επ αυτη ουρανε και οι αγιοι και οι αποστολοι και οι προφηται οτι εκρινεν ο θεοσ το κριμα υμων εξ αυτησ ");
INSERT INTO grcmt_vpl VALUES ("RV18_21","096_18_21","REV","18","21","21","και ηρεν εισ αγγελοσ ισχυροσ λιθον ωσ μυλον μεγαν και εβαλεν εισ την θαλασσαν λεγων ουτωσ ορμηματι βληθησεται βαβυλων η μεγαλη πολισ και ου μη ευρεθη ετι ");
INSERT INTO grcmt_vpl VALUES ("RV18_22","096_18_22","REV","18","22","22","και φωνη κιθαρωδων και μουσικων και αυλητων και σαλπιστων ου μη ακουσθη εν σοι ετι και πασ τεχνιτησ πασησ τεχνησ ου μη ευρεθη εν σοι ετι και φωνη μυλου ου μη ακουσθη εν σοι ετι ");
INSERT INTO grcmt_vpl VALUES ("RV18_23","096_18_23","REV","18","23","23","και φωσ λυχνου ου μη φανη εν σοι ετι και φωνη νυμφιου και νυμφησ ου μη ακουσθη εν σοι ετι οτι οι εμποροι σου ησαν οι μεγιστανεσ τησ γησ οτι εν τη φαρμακεια σου επλανηθησαν παντα τα εθνη ");
INSERT INTO grcmt_vpl VALUES ("RV18_24","096_18_24","REV","18","24","24","και εν αυτη αιματα προφητων και αγιων ευρεθη και παντων των εσφαγμενων επι τησ γησ ");
INSERT INTO grcmt_vpl VALUES ("RV19_1","096_19_1","REV","19","1","1","μετα ταυτα ηκουσα ωσ φωνην μεγαλην οχλου πολλου εν τω ουρανω λεγοντων αλληλουια η σωτηρια και η δυναμισ και η δοξα του θεου ημων ");
INSERT INTO grcmt_vpl VALUES ("RV19_2","096_19_2","REV","19","2","2","οτι αληθιναι και δικαιαι αι κρισεισ αυτου οτι εκρινεν την πορνην την μεγαλην ητισ διεφθειρεν την γην εν τη πορνεια αυτησ και εξεδικησεν το αιμα των δουλων αυτου εκ χειροσ αυτησ ");
INSERT INTO grcmt_vpl VALUES ("RV19_3","096_19_3","REV","19","3","3","και δευτερον ειρηκεν αλληλουια και ο καπνοσ αυτησ αναβαινει εισ τουσ αιωνασ των αιωνων ");
INSERT INTO grcmt_vpl VALUES ("RV19_4","096_19_4","REV","19","4","4","και επεσον οι πρεσβυτεροι οι εικοσι τεσσαρεσ και τα τεσσαρα ζωα και προσεκυνησαν τω θεω τω καθημενω επι του θρονου λεγοντεσ αμην αλληλουια ");
INSERT INTO grcmt_vpl VALUES ("RV19_5","096_19_5","REV","19","5","5","και φωνη απο του θρονου εξηλθεν λεγουσα αινειτε τον θεον ημων παντεσ οι δουλοι αυτου και οι φοβουμενοι αυτον οι μικροι και οι μεγαλοι ");
INSERT INTO grcmt_vpl VALUES ("RV19_6","096_19_6","REV","19","6","6","και ηκουσα ωσ φωνην οχλου πολλου και ωσ φωνην υδατων πολλων και ωσ φωνην βροντων ισχυρων λεγοντεσ αλληλουια οτι εβασιλευσεν κυριοσ ο θεοσ ημων ο παντοκρατωρ ");
INSERT INTO grcmt_vpl VALUES ("RV19_7","096_19_7","REV","19","7","7","χαιρωμεν και αγαλλιωμεθα και δωμεν την δοξαν αυτω οτι ηλθεν ο γαμοσ του αρνιου και η γυνη αυτου ητοιμασεν εαυτην ");
INSERT INTO grcmt_vpl VALUES ("RV19_8","096_19_8","REV","19","8","8","και εδοθη αυτη ινα περιβαληται βυσσινον λαμπρον και καθαρον το γαρ βυσσινον τα δικαιωματα των αγιων εστιν ");
INSERT INTO grcmt_vpl VALUES ("RV19_9","096_19_9","REV","19","9","9","και λεγει μοι γραψον μακαριοι οι εισ το δειπνον του γαμου του αρνιου κεκλημενοι και λεγει μοι ουτοι οι λογοι αληθινοι του θεου εισιν ");
INSERT INTO grcmt_vpl VALUES ("RV19_10","096_19_10","REV","19","10","10","και επεσα εμπροσθεν των ποδων αυτου προσκυνησαι αυτω και λεγει μοι ορα μη συνδουλοσ σου ειμι και των αδελφων σου των εχοντων την μαρτυριαν ιησου τω θεω προσκυνησον η γαρ μαρτυρια του ιησου εστιν το πνευμα τησ προφητειασ ");
INSERT INTO grcmt_vpl VALUES ("RV19_11","096_19_11","REV","19","11","11","και ειδον τον ουρανον ανεωγμενον και ιδου ιπποσ λευκοσ και ο καθημενοσ επ αυτον καλουμενοσ πιστοσ και αληθινοσ και εν δικαιοσυνη κρινει και πολεμει ");
INSERT INTO grcmt_vpl VALUES ("RV19_12","096_19_12","REV","19","12","12","οι δε οφθαλμοι αυτου φλοξ πυροσ και επι την κεφαλην αυτου διαδηματα πολλα εχων ονοματα γεγραμμενα και ονομα γεγραμμενον ο ουδεισ οιδεν ει μη αυτοσ ");
INSERT INTO grcmt_vpl VALUES ("RV19_13","096_19_13","REV","19","13","13","και περιβεβλημενοσ ιματιον βεβαμμενον αιματι και καλειται το ονομα αυτου ο λογοσ του θεου ");
INSERT INTO grcmt_vpl VALUES ("RV19_14","096_19_14","REV","19","14","14","και τα στρατευματα τα εν τω ουρανω ηκολουθει αυτω επι ιπποισ λευκοισ ενδεδυμενοι βυσσινον λευκον καθαρον ");
INSERT INTO grcmt_vpl VALUES ("RV19_15","096_19_15","REV","19","15","15","και εκ του στοματοσ αυτου εκπορευεται ρομφαια διστομοσ οξεια ινα εν αυτη παταξη τα εθνη και αυτοσ ποιμανει αυτουσ εν ραβδω σιδηρα και αυτοσ πατει την ληνον του οινου του θυμου τησ οργησ του θεου του παντοκρατοροσ ");
INSERT INTO grcmt_vpl VALUES ("RV19_16","096_19_16","REV","19","16","16","και εχει επι το ιματιον και επι τον μηρον αυτου ονομα γεγραμμενον βασιλευσ βασιλεων και κυριοσ κυριων ");
INSERT INTO grcmt_vpl VALUES ("RV19_17","096_19_17","REV","19","17","17","και ειδον αγγελον εστωτα εν τω ηλιω και εκραξεν φωνη μεγαλη λεγων πασιν τοισ ορνεοισ τοισ πετομενοισ εν μεσουρανηματι δευτε συναχθητε εισ το δειπνον το μεγα του θεου ");
INSERT INTO grcmt_vpl VALUES ("RV19_18","096_19_18","REV","19","18","18","ινα φαγητε σαρκασ βασιλεων και σαρκασ χιλιαρχων και σαρκασ ισχυρων και σαρκασ ιππων και των καθημενων επ αυτων και σαρκασ παντων ελευθερων τε και δουλων και μικρων τε και μεγαλων ");
INSERT INTO grcmt_vpl VALUES ("RV19_19","096_19_19","REV","19","19","19","και ειδον το θηριον και τουσ βασιλεισ τησ γησ και τα στρατευματα αυτων συνηγμενα ποιησαι πολεμον μετα του καθημενου επι του ιππου και μετα του στρατευματοσ αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV19_20","096_19_20","REV","19","20","20","και επιασθη το θηριον και ο μετ αυτου ψευδοπροφητησ ο ποιησασ τα σημεια ενωπιον αυτου εν οισ επλανησεν τουσ λαβοντασ το χαραγμα του θηριου και τουσ προσκυνουντασ τη εικονι αυτου ζωντεσ εβληθησαν οι δυο εισ την λιμνην του πυροσ την καιομενην εν θειω ");
INSERT INTO grcmt_vpl VALUES ("RV19_21","096_19_21","REV","19","21","21","και οι λοιποι απεκτανθησαν εν τη ρομφαια του καθημενου επι του ιππου τη εξελθουση εκ του στοματοσ αυτου και παντα τα ορνεα εχορτασθησαν εκ των σαρκων αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV20_1","096_20_1","REV","20","1","1","και ειδον αγγελον καταβαινοντα εκ του ουρανου εχοντα την κλειν τησ αβυσσου και αλυσιν μεγαλην επι την χειρα αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV20_2","096_20_2","REV","20","2","2","και εκρατησεν τον δρακοντα τον οφιν τον αρχαιον οσ εστιν διαβολοσ και ο σατανασ ο πλανων την οικουμενην ολην και εδησεν αυτον χιλια ετη ");
INSERT INTO grcmt_vpl VALUES ("RV20_3","096_20_3","REV","20","3","3","και εβαλεν αυτον εισ την αβυσσον και εκλεισεν και εσφραγισεν επανω αυτου ινα μη πλανα ετι τα εθνη αχρι τελεσθη τα χιλια ετη και μετα ταυτα δει αυτον λυθηναι μικρον χρονον ");
INSERT INTO grcmt_vpl VALUES ("RV20_4","096_20_4","REV","20","4","4","και ειδον θρονουσ και εκαθισαν επ αυτουσ και κριμα εδοθη αυτοισ και τασ ψυχασ των πεπελεκισμενων δια την μαρτυριαν ιησου και δια τον λογον του θεου και οιτινεσ ου προσεκυνησαν το θηριον ουδε την εικονα αυτου και ουκ ελαβον το χαραγμα επι το μετωπον και επι την χειρα αυτων και εζησαν και εβασιλευσαν μετα του χριστου τα χιλια ετη ");
INSERT INTO grcmt_vpl VALUES ("RV20_5","096_20_5","REV","20","5","5","και οι λοιποι των νεκρων ουκ εζησαν αχρι τελεσθη τα χιλια ετη αυτη η αναστασισ η πρωτη ");
INSERT INTO grcmt_vpl VALUES ("RV20_6","096_20_6","REV","20","6","6","μακαριοσ και αγιοσ ο εχων μεροσ εν τη αναστασει τη πρωτη επι τουτων ο δευτεροσ θανατοσ ουκ εχει εξουσιαν αλλ εσονται ιερεισ του θεου και του χριστου και βασιλευσουσιν μετ αυτου χιλια ετη ");
INSERT INTO grcmt_vpl VALUES ("RV20_7","096_20_7","REV","20","7","7","και οταν τελεσθη τα χιλια ετη λυθησεται ο σατανασ εκ τησ φυλακησ αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV20_8","096_20_8","REV","20","8","8","και εξελευσεται πλανησαι τα εθνη τα εν ταισ τεσσαρσιν γωνιαισ τησ γησ τον γωγ και τον μαγωγ συναγαγειν αυτουσ εισ τον πολεμον ων ο αριθμοσ ωσ η αμμοσ τησ θαλασσησ ");
INSERT INTO grcmt_vpl VALUES ("RV20_9","096_20_9","REV","20","9","9","και ανεβησαν επι το πλατοσ τησ γησ και εκυκλωσαν την παρεμβολην των αγιων και την πολιν την ηγαπημενην και κατεβη πυρ εκ του ουρανου απο του θεου και κατεφαγεν αυτουσ ");
INSERT INTO grcmt_vpl VALUES ("RV20_10","096_20_10","REV","20","10","10","και ο διαβολοσ ο πλανων αυτουσ εβληθη εισ την λιμνην του πυροσ και θειου οπου και το θηριον και ο ψευδοπροφητησ και βασανισθησονται ημερασ και νυκτοσ εισ τουσ αιωνασ των αιωνων ");
INSERT INTO grcmt_vpl VALUES ("RV20_11","096_20_11","REV","20","11","11","και ειδον θρονον μεγαν λευκον και τον καθημενον επ αυτον ου απο προσωπου εφυγεν η γη και ο ουρανοσ και τοποσ ουχ ευρεθη αυτοισ ");
INSERT INTO grcmt_vpl VALUES ("RV20_12","096_20_12","REV","20","12","12","και ειδον τουσ νεκρουσ τουσ μεγαλουσ και τουσ μικρουσ εστωτασ ενωπιον του θρονου και βιβλια ηνεωχθησαν και αλλο βιβλιον ηνεωχθη ο εστιν τησ ζωησ και εκριθησαν οι νεκροι εκ των γεγραμμενων εν τοισ βιβλιοισ κατα τα εργα αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV20_13","096_20_13","REV","20","13","13","και εδωκεν η θαλασσα τουσ νεκρουσ τουσ εν αυτη και ο θανατοσ και ο αδησ εδωκαν τουσ νεκρουσ τουσ εν αυτοισ και εκριθησαν εκαστοσ κατα τα εργα αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV20_14","096_20_14","REV","20","14","14","και ο θανατοσ και ο αδησ εβληθησαν εισ την λιμνην του πυροσ ουτοσ ο θανατοσ ο δευτεροσ εστιν η λιμνη του πυροσ ");
INSERT INTO grcmt_vpl VALUES ("RV20_15","096_20_15","REV","20","15","15","και ει τισ ουχ ευρεθη εν τω βιβλιω τησ ζωησ γεγραμμενοσ εβληθη εισ την λιμνην του πυροσ ");
INSERT INTO grcmt_vpl VALUES ("RV21_1","096_21_1","REV","21","1","1","και ειδον ουρανον καινον και γην καινην ο γαρ πρωτοσ ουρανοσ και η πρωτη γη απηλθον και η θαλασσα ουκ εστιν ετι ");
INSERT INTO grcmt_vpl VALUES ("RV21_2","096_21_2","REV","21","2","2","και την πολιν την αγιαν ιερουσαλημ καινην ειδον καταβαινουσαν εκ του ουρανου απο του θεου ητοιμασμενην ωσ νυμφην κεκοσμημενην τω ανδρι αυτησ ");
INSERT INTO grcmt_vpl VALUES ("RV21_3","096_21_3","REV","21","3","3","και ηκουσα φωνησ μεγαλησ εκ του ουρανου λεγουσησ ιδου η σκηνη του θεου μετα των ανθρωπων και σκηνωσει μετ αυτων και αυτοι λαοσ αυτου εσονται και αυτοσ ο θεοσ εσται μετ αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV21_4","096_21_4","REV","21","4","4","και εξαλειψει παν δακρυον απο των οφθαλμων αυτων και ο θανατοσ ουκ εσται ετι ουτε πενθοσ ουτε κραυγη ουτε πονοσ ουκ εσται ετι οτι τα πρωτα απηλθον ");
INSERT INTO grcmt_vpl VALUES ("RV21_5","096_21_5","REV","21","5","5","και ειπεν ο καθημενοσ επι τω θρονω ιδου παντα καινα ποιω και λεγει μοι γραψον οτι ουτοι οι λογοι αληθινοι και πιστοι εισιν ");
INSERT INTO grcmt_vpl VALUES ("RV21_6","096_21_6","REV","21","6","6","και ειπεν μοι γεγονα το αλφα και το ω η αρχη και το τελοσ εγω τω διψωντι δωσω εκ τησ πηγησ του υδατοσ τησ ζωησ δωρεαν ");
INSERT INTO grcmt_vpl VALUES ("RV21_7","096_21_7","REV","21","7","7","ο νικων κληρονομησει ταυτα και εσομαι αυτω θεοσ και αυτοσ εσται μοι υιοσ ");
INSERT INTO grcmt_vpl VALUES ("RV21_8","096_21_8","REV","21","8","8","τοισ δε δειλοισ και απιστοισ και αμαρτωλοισ και εβδελυγμενοισ και φονευσιν και πορνοισ και φαρμακοισ και ειδωλολατραισ και πασιν τοισ ψευδεσιν το μεροσ αυτων εν τη λιμνη τη καιομενη πυρι και θειω ο εστιν ο θανατοσ ο δευτεροσ ");
INSERT INTO grcmt_vpl VALUES ("RV21_9","096_21_9","REV","21","9","9","και ηλθεν εισ εκ των επτα αγγελων των εχοντων τασ επτα φιαλασ γεμουσασ των επτα πληγων των εσχατων και ελαλησεν μετ εμου λεγων δευρο δειξω σοι την γυναικα την νυμφην του αρνιου ");
INSERT INTO grcmt_vpl VALUES ("RV21_10","096_21_10","REV","21","10","10","και απηνεγκεν με εν πνευματι επ οροσ μεγα και υψηλον και εδειξεν μοι την πολιν την μεγαλην την αγιαν ιερουσαλημ καταβαινουσαν εκ του ουρανου απο του θεου ");
INSERT INTO grcmt_vpl VALUES ("RV21_11","096_21_11","REV","21","11","11","εχουσαν την δοξαν του θεου ο φωστηρ αυτησ ομοιοσ λιθω τιμιωτατω ωσ λιθω ιασπιδι κρυσταλλιζοντι ");
INSERT INTO grcmt_vpl VALUES ("RV21_12","096_21_12","REV","21","12","12","εχουσα τειχοσ μεγα και υψηλον εχουσα πυλωνασ δωδεκα και επι τοισ πυλωσιν αγγελουσ δωδεκα και ονοματα επιγεγραμμενα α εστιν ονοματα των δωδεκα φυλων των υιων ισραηλ ");
INSERT INTO grcmt_vpl VALUES ("RV21_13","096_21_13","REV","21","13","13","απο ανατολων πυλωνεσ τρεισ και απο βορρα πυλωνεσ τρεισ και απο νοτου πυλωνεσ τρεισ και απο δυσμων πυλωνεσ τρεισ ");
INSERT INTO grcmt_vpl VALUES ("RV21_14","096_21_14","REV","21","14","14","και το τειχοσ τησ πολεωσ εχον θεμελιουσ δωδεκα και επ αυτων δωδεκα ονοματα των δωδεκα αποστολων του αρνιου ");
INSERT INTO grcmt_vpl VALUES ("RV21_15","096_21_15","REV","21","15","15","και ο λαλων μετ εμου ειχεν μετρον καλαμον χρυσουν ινα μετρηση την πολιν και τουσ πυλωνασ αυτησ και το τειχοσ αυτησ ");
INSERT INTO grcmt_vpl VALUES ("RV21_16","096_21_16","REV","21","16","16","και η πολισ τετραγωνοσ κειται και το μηκοσ αυτησ οσον το πλατοσ και εμετρησεν την πολιν τω καλαμω επι σταδιουσ δωδεκα χιλιαδων δωδεκα το μηκοσ και το πλατοσ και το υψοσ αυτησ ισα εστιν ");
INSERT INTO grcmt_vpl VALUES ("RV21_17","096_21_17","REV","21","17","17","και εμετρησεν το τειχοσ αυτησ εκατον τεσσαρακοντα τεσσαρων πηχων μετρον ανθρωπου ο εστιν αγγελου ");
INSERT INTO grcmt_vpl VALUES ("RV21_18","096_21_18","REV","21","18","18","και ην η ενδομησισ του τειχουσ αυτησ ιασπισ και η πολισ χρυσιον καθαρον ομοιον υελω καθαρω ");
INSERT INTO grcmt_vpl VALUES ("RV21_19","096_21_19","REV","21","19","19","οι θεμελιοι του τειχουσ τησ πολεωσ παντι λιθω τιμιω κεκοσμημενοι ο θεμελιοσ ο πρωτοσ ιασπισ ο δευτεροσ σαπφειροσ ο τριτοσ χαλκηδων ο τεταρτοσ σμαραγδοσ ");
INSERT INTO grcmt_vpl VALUES ("RV21_20","096_21_20","REV","21","20","20","ο πεμπτοσ σαρδονυξ ο εκτοσ σαρδιον ο εβδομοσ χρυσολιθοσ ο ογδοοσ βηρυλλοσ ο ενατοσ τοπαζιον ο δεκατοσ χρυσοπρασοσ ο ενδεκατοσ υακινθοσ ο δωδεκατοσ αμεθυσοσ ");
INSERT INTO grcmt_vpl VALUES ("RV21_21","096_21_21","REV","21","21","21","και οι δωδεκα πυλωνεσ δωδεκα μαργαριται ανα εισ εκαστοσ των πυλωνων ην εξ ενοσ μαργαριτου και η πλατεια τησ πολεωσ χρυσιον καθαρον ωσ υελοσ διαυγησ ");
INSERT INTO grcmt_vpl VALUES ("RV21_22","096_21_22","REV","21","22","22","και ναον ουκ ειδον εν αυτη ο γαρ κυριοσ ο θεοσ ο παντοκρατωρ ναοσ αυτησ εστιν και το αρνιον ");
INSERT INTO grcmt_vpl VALUES ("RV21_23","096_21_23","REV","21","23","23","και η πολισ ου χρειαν εχει του ηλιου ουδε τησ σεληνησ ινα φαινωσιν αυτη η γαρ δοξα του θεου εφωτισεν αυτην και ο λυχνοσ αυτησ το αρνιον ");
INSERT INTO grcmt_vpl VALUES ("RV21_24","096_21_24","REV","21","24","24","και περιπατησουσιν τα εθνη δια του φωτοσ αυτησ και οι βασιλεισ τησ γησ φερουσιν αυτω δοξαν και τιμην των εθνων εισ αυτην ");
INSERT INTO grcmt_vpl VALUES ("RV21_25","096_21_25","REV","21","25","25","και οι πυλωνεσ αυτησ ου μη κλεισθωσιν ημερασ νυξ γαρ ουκ εσται εκει ");
INSERT INTO grcmt_vpl VALUES ("RV21_26","096_21_26","REV","21","26","26","και οισουσιν την δοξαν και την τιμην των εθνων εισ αυτην ");
INSERT INTO grcmt_vpl VALUES ("RV21_27","096_21_27","REV","21","27","27","και ου μη εισελθη εισ αυτην παν κοινον και ποιουν βδελυγμα και ψευδοσ ει μη οι γεγραμμενοι εν τω βιβλιω τησ ζωησ του αρνιου ");
INSERT INTO grcmt_vpl VALUES ("RV22_1","096_22_1","REV","22","1","1","και εδειξεν μοι ποταμον καθαρον υδατοσ ζωησ λαμπρον ωσ κρυσταλλον εκπορευομενον εκ του θρονου του θεου και του αρνιου ");
INSERT INTO grcmt_vpl VALUES ("RV22_2","096_22_2","REV","22","2","2","εν μεσω τησ πλατειασ αυτησ και του ποταμου εντευθεν και εκειθεν ξυλον ζωησ ποιουν καρπουσ δωδεκα κατα μηνα εκαστον αποδιδουσ τον καρπον αυτου και τα φυλλα του ξυλου εισ θεραπειαν των εθνων ");
INSERT INTO grcmt_vpl VALUES ("RV22_3","096_22_3","REV","22","3","3","και παν καταθεμα ουκ εσται ετι και ο θρονοσ του θεου και του αρνιου εν αυτη εσται και οι δουλοι αυτου λατρευσουσιν αυτω ");
INSERT INTO grcmt_vpl VALUES ("RV22_4","096_22_4","REV","22","4","4","και οψονται το προσωπον αυτου και το ονομα αυτου επι των μετωπων αυτων ");
INSERT INTO grcmt_vpl VALUES ("RV22_5","096_22_5","REV","22","5","5","και νυξ ουκ εσται εκει και χρειαν ουκ εχουσιν λυχνου και φωτοσ ηλιου οτι κυριοσ ο θεοσ φωτιει αυτουσ και βασιλευσουσιν εισ τουσ αιωνασ των αιωνων ");
INSERT INTO grcmt_vpl VALUES ("RV22_6","096_22_6","REV","22","6","6","και λεγει μοι ουτοι οι λογοι πιστοι και αληθινοι και κυριοσ ο θεοσ των πνευματων των προφητων απεστειλεν τον αγγελον αυτου δειξαι τοισ δουλοισ αυτου α δει γενεσθαι εν ταχει ");
INSERT INTO grcmt_vpl VALUES ("RV22_7","096_22_7","REV","22","7","7","και ιδου ερχομαι ταχυ μακαριοσ ο τηρων τουσ λογουσ τησ προφητειασ του βιβλιου τουτου ");
INSERT INTO grcmt_vpl VALUES ("RV22_8","096_22_8","REV","22","8","8","καγω ιωαννησ ο ακουων και βλεπων ταυτα και οτε ηκουσα και εβλεψα επεσον προσκυνησαι εμπροσθεν των ποδων του αγγελου του δεικνυοντοσ μοι ταυτα ");
INSERT INTO grcmt_vpl VALUES ("RV22_9","096_22_9","REV","22","9","9","και λεγει μοι ορα μη συνδουλοσ σου ειμι και των αδελφων σου των προφητων και των τηρουντων τουσ λογουσ του βιβλιου τουτου τω θεω προσκυνησον ");
INSERT INTO grcmt_vpl VALUES ("RV22_10","096_22_10","REV","22","10","10","και λεγει μοι μη σφραγισησ τουσ λογουσ τησ προφητειασ του βιβλιου τουτου ο καιροσ γαρ εγγυσ εστιν ");
INSERT INTO grcmt_vpl VALUES ("RV22_11","096_22_11","REV","22","11","11","ο αδικων αδικησατω ετι και ο ρυπαροσ ρυπαρευθητω ετι και ο δικαιοσ δικαιοσυνην ποιησατω ετι και ο αγιοσ αγιασθητω ετι ");
INSERT INTO grcmt_vpl VALUES ("RV22_12","096_22_12","REV","22","12","12","ιδου ερχομαι ταχυ και ο μισθοσ μου μετ εμου αποδουναι εκαστω ωσ το εργον εσται αυτου ");
INSERT INTO grcmt_vpl VALUES ("RV22_13","096_22_13","REV","22","13","13","εγω το αλφα και το ω ο πρωτοσ και ο εσχατοσ η αρχη και το τελοσ ");
INSERT INTO grcmt_vpl VALUES ("RV22_14","096_22_14","REV","22","14","14","μακαριοι οι ποιουντεσ τασ εντολασ αυτου ινα εσται η εξουσια αυτων επι το ξυλον τησ ζωησ και τοισ πυλωσιν εισελθωσιν εισ την πολιν ");
INSERT INTO grcmt_vpl VALUES ("RV22_15","096_22_15","REV","22","15","15","εξω οι κυνεσ και οι φαρμακοι και οι πορνοι και οι φονεισ και οι ειδωλολατραι και πασ φιλων και ποιων ψευδοσ ");
INSERT INTO grcmt_vpl VALUES ("RV22_16","096_22_16","REV","22","16","16","εγω ιησουσ επεμψα τον αγγελον μου μαρτυρησαι υμιν ταυτα επι ταισ εκκλησιαισ εγω ειμι η ριζα και το γενοσ δαυιδ ο αστηρ ο λαμπροσ ο πρωινοσ ");
INSERT INTO grcmt_vpl VALUES ("RV22_17","096_22_17","REV","22","17","17","και το πνευμα και η νυμφη λεγουσιν ερχου και ο ακουων ειπατω ερχου και ο διψων ερχεσθω ο θελων λαβετω υδωρ ζωησ δωρεαν ");
INSERT INTO grcmt_vpl VALUES ("RV22_18","096_22_18","REV","22","18","18","μαρτυρω εγω παντι τω ακουοντι τουσ λογουσ τησ προφητειασ του βιβλιου τουτου εαν τισ επιθη επ αυτα επιθησαι ο θεοσ επ αυτον τασ πληγασ τασ γεγραμμενασ εν τω βιβλιω τουτω ");
INSERT INTO grcmt_vpl VALUES ("RV22_19","096_22_19","REV","22","19","19","και εαν τισ αφελη απο των λογων του βιβλιου τησ προφητειασ ταυτησ αφελοι ο θεοσ το μεροσ αυτου απο του ξυλου τησ ζωησ και εκ τησ πολεωσ τησ αγιασ των γεγραμμενων εν τω βιβλιω τουτω ");
INSERT INTO grcmt_vpl VALUES ("RV22_20","096_22_20","REV","22","20","20","λεγει ο μαρτυρων ταυτα ναι ερχομαι ταχυ αμην ναι ερχου κυριε ιησου ");
INSERT INTO grcmt_vpl VALUES ("RV22_21","096_22_21","REV","22","21","21","η χαρισ του κυριου ιησου χριστου μετα παντων των αγιων αμην ");
